export type Message = {
  id: string
  roomId: string
  sender: string
  text: string
  timestamp: string
}

export type Room = {
  id: string
  name: string
  createdAt: string
  members: string[]
}

export type RoomMeta = {
  rooms: Room[]
  unread: Record<string, Record<string, number>> // { [userId]: { [roomId]: count } }
}

export type TypingState = {
  roomId: string
  user: string
  active: boolean
}

import { h } from '@plaited/template'
import type { Template } from '@plaited/template'

export const formatText = (text: string): Template[] => {
  const parts: Template[] = []
  let remaining = text

  const regex = /(\*([^*]+)\*)|(_([^_]+)_)/g
  let lastIndex = 0
  let match: RegExpExecArray | null

  while ((match = regex.exec(remaining)) !== null) {
    if (match.index > lastIndex) {
      parts.push(h('span', {}, remaining.slice(lastIndex, match.index)))
    }

    if (match[1]) {
      parts.push(h('strong', {}, match[2]))
    } else if (match[3]) {
      parts.push(h('em', {}, match[4]))
    }

    lastIndex = match.index + match[0].length
  }

  if (lastIndex < remaining.length) {
    parts.push(h('span', {}, remaining.slice(lastIndex)))
  }

  return parts
}

import type { Message, Room, RoomMeta } from './types'

const DATA_DIR = './data'
const ROOMS_FILE = `${DATA_DIR}/rooms.json`

const generateId = (): string => crypto.randomUUID()

const readRoomMeta = async (): Promise<RoomMeta> => {
  const file = Bun.file(ROOMS_FILE)
  if (await file.exists()) {
    return file.json()
  }
  return { rooms: [], unread: {} }
}

const writeRoomMeta = async (meta: RoomMeta): Promise<void> => {
  await Bun.write(ROOMS_FILE, JSON.stringify(meta, null, 2))
}

const roomFilePath = (roomId: string): string => `${DATA_DIR}/${roomId}.jsonl`

export const createRoom = async (name: string, creatorId: string): Promise<Room> => {
  const meta = await readRoomMeta()
  const existing = meta.rooms.find((r) => r.name === name)
  if (existing) return existing

  const room: Room = {
    id: generateId(),
    name,
    createdAt: new Date().toISOString(),
    members: [creatorId],
  }

  meta.rooms.push(room)
  if (!meta.unread[creatorId]) meta.unread[creatorId] = {}
  meta.unread[creatorId][room.id] = 0
  await writeRoomMeta(meta)
  return room
}

export const joinRoom = async (roomId: string, userId: string): Promise<Room | null> => {
  const meta = await readRoomMeta()
  const room = meta.rooms.find((r) => r.id === roomId)
  if (!room) return null

  if (!room.members.includes(userId)) {
    room.members.push(userId)
  }

  if (!meta.unread[userId]) meta.unread[userId] = {}
  meta.unread[userId][roomId] = 0
  await writeRoomMeta(meta)
  return room
}

export const listRooms = async (userId?: string): Promise<(Room & { unreadCount: number })[]> => {
  const meta = await readRoomMeta()
  return meta.rooms.map((room) => ({
    ...room,
    unreadCount: userId ? (meta.unread[userId]?.[room.id] ?? 0) : 0,
  }))
}

export const sendMessage = async (roomId: string, sender: string, text: string): Promise<Message> => {
  const meta = await readRoomMeta()
  const room = meta.rooms.find((r) => r.id === roomId)
  if (!room) throw new Error(`Room ${roomId} not found`)

  const message: Message = {
    id: generateId(),
    roomId,
    sender,
    text,
    timestamp: new Date().toISOString(),
  }

  const filePath = roomFilePath(roomId)
  const file = Bun.file(filePath)
  const existing = (await file.exists()) ? await file.text() : ''
  await Bun.write(filePath, existing + JSON.stringify(message) + '\n')

  // Increment unread for all members except sender
  for (const memberId of room.members) {
    if (memberId === sender) continue
    if (!meta.unread[memberId]) meta.unread[memberId] = {}
    meta.unread[memberId][roomId] = (meta.unread[memberId][roomId] ?? 0) + 1
  }
  await writeRoomMeta(meta)

  return message
}

export const getRoomMessages = async (roomId: string): Promise<Message[]> => {
  const filePath = roomFilePath(roomId)
  const file = Bun.file(filePath)
  if (!(await file.exists())) return []

  const content = await file.text()
  return content
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Message)
}

export const markRead = async (roomId: string, userId: string): Promise<void> => {
  const meta = await readRoomMeta()
  if (!meta.unread[userId]) meta.unread[userId] = {}
  meta.unread[userId][roomId] = 0
  await writeRoomMeta(meta)
}

