import { h } from 'plaited'
import type { TemplateObject } from 'plaited'

type TextNode = string | TemplateObject

export const formatMarkdown = (text: string): TemplateObject => {
  const nodes: TextNode[] = []
  let remaining = text

  const boldRe = /\*\*(.+?)\*\*/
  const italicRe = /\*(.+?)\*/

  while (remaining.length > 0) {
    const boldMatch = boldRe.exec(remaining)
    const italicMatch = italicRe.exec(remaining)

    let earliestMatch: RegExpExecArray | null = null
    let matchType: 'bold' | 'italic' | null = null

    if (boldMatch && italicMatch) {
      if (boldMatch.index <= italicMatch.index) {
        earliestMatch = boldMatch
        matchType = 'bold'
      } else {
        earliestMatch = italicMatch
        matchType = 'italic'
      }
    } else if (boldMatch) {
      earliestMatch = boldMatch
      matchType = 'bold'
    } else if (italicMatch) {
      earliestMatch = italicMatch
      matchType = 'italic'
    }

    if (!earliestMatch || !matchType) {
      nodes.push(remaining)
      break
    }

    if (earliestMatch.index > 0) {
      nodes.push(remaining.slice(0, earliestMatch.index))
    }

    const inner = earliestMatch[1]
    const tag = matchType === 'bold' ? 'strong' : 'em'
    nodes.push(h(tag, {}, inner))

    remaining = remaining.slice(earliestMatch.index + earliestMatch[0].length)
  }

  return h('span', {}, ...nodes)
}

import type { Room } from './types'
import { loadRoomState, saveRoomState, loadUnread, saveUnread } from './store'

const generateId = (): string =>
  crypto.randomUUID()

export const createRoom = async (name: string): Promise<Room> => {
  const state = await loadRoomState()
  const existing = state.rooms.find((r) => r.name === name)
  if (existing) return existing

  const room: Room = {
    id: generateId(),
    name,
    createdAt: new Date().toISOString(),
    lastMessageAt: null,
  }

  state.rooms.push(room)
  await saveRoomState(state)
  return room
}

export const listRooms = async (): Promise<Room[]> => {
  const state = await loadRoomState()
  return state.rooms
}

export const getRoom = async (roomId: string): Promise<Room | undefined> => {
  const state = await loadRoomState()
  return state.rooms.find((r) => r.id === roomId)
}

export const getRoomByName = async (name: string): Promise<Room | undefined> => {
  const state = await loadRoomState()
  return state.rooms.find((r) => r.name === name)
}

export const getUnreadCount = async (userId: string, roomId: string): Promise<number> => {
  const unread = await loadUnread()
  return unread[userId]?.[roomId] ?? 0
}

export const markAsRead = async (userId: string, roomId: string): Promise<void> => {
  const unread = await loadUnread()
  if (!unread[userId]) unread[userId] = {}
  unread[userId][roomId] = 0
  await saveUnread(unread)
}

export const incrementUnread = async (roomId: string, excludeSender: string): Promise<void> => {
  const unread = await loadUnread()
  for (const userId of Object.keys(unread)) {
    if (userId === excludeSender) continue
    if (!unread[userId][roomId]) unread[userId][roomId] = 0
    unread[userId][roomId] += 1
  }
  await saveUnread(unread)
}

export const registerUser = async (userId: string): Promise<void> => {
  const unread = await loadUnread()
  if (!unread[userId]) {
    unread[userId] = {}
    await saveUnread(unread)
  }
}

import type { Message } from './types'
import { loadMessages, saveMessages, loadRoomState, saveRoomState } from './store'
import { incrementUnread } from './rooms'

const generateId = (): string =>
  crypto.randomUUID()

export const sendMessage = async (
  roomId: string,
  params: { sender: string; text: string }
): Promise<Message> => {
  const message: Message = {
    id: generateId(),
    roomId,
    sender: params.sender,
    text: params.text,
    timestamp: new Date().toISOString(),
  }

  const messages = await loadMessages(roomId)
  messages.push(message)
  await saveMessages(roomId, messages)

  const state = await loadRoomState()
  const room = state.rooms.find((r) => r.id === roomId)
  if (room) {
    room.lastMessageAt = message.timestamp
    await saveRoomState(state)
  }

  await incrementUnread(roomId, params.sender)

  return message
}

export const getMessages = async (
  roomId: string,
  limit?: number
): Promise<Message[]> => {
  const messages = await loadMessages(roomId)
  if (limit) return messages.slice(-limit)
  return messages
}

export const getLatestMessage = async (roomId: string): Promise<Message | undefined> => {
  const messages = await loadMessages(roomId)
  return messages.at(-1)
}

