import { h } from '@plaited/template';
import type { TemplateObject } from '@plaited/template';

export const formatMessageText = (text: string): TemplateObject => {
  const parts: TemplateObject[] = [];
  let remaining = text;
  let key = 0;

  const patterns: { regex: RegExp; tag: string }[] = [
    { regex: /\*([^*]+)\*/, tag: 'strong' },
    { regex: /_([^_]+)_/, tag: 'em' },
  ];

  const processNext = (): void => {
    if (remaining.length === 0) return;

    let earliestMatch: RegExpExecArray | null = null;
    let earliestTag = '';
    let earliestIndex = Infinity;

    for (const { regex, tag } of patterns) {
      const match = regex.exec(remaining);
      if (match && match.index < earliestIndex) {
        earliestMatch = match;
        earliestTag = tag;
        earliestIndex = match.index;
      }
    }

    if (!earliestMatch) {
      parts.push(h('span', { key: String(key++) }, remaining));
      remaining = '';
      return;
    }

    if (earliestIndex > 0) {
      parts.push(h('span', { key: String(key++) }, remaining.slice(0, earliestIndex)));
    }

    parts.push(h(earliestTag, { key: String(key++) }, earliestMatch[1]));
    remaining = remaining.slice(earliestIndex + earliestMatch[0].length);
    processNext();
  };

  processNext();
  return h('span', {}, ...parts);
};

import type { Room, RoomData, Message, ReadReceipt } from './types';

const DATA_DIR = `${import.meta.dir}/data`;

const roomFilePath = (roomId: string): string => `${DATA_DIR}/room-${roomId}.json`;
const receiptsFilePath = (): string => `${DATA_DIR}/read-receipts.json`;

const generateId = (): string => crypto.randomUUID();

const readJson = async <T>(path: string, fallback: T): Promise<T> => {
  const file = Bun.file(path);
  if (await file.exists()) {
    return file.json() as Promise<T>;
  }
  return fallback;
};

const writeJson = async <T>(path: string, data: T): Promise<void> => {
  await Bun.write(path, JSON.stringify(data, null, 2));
};

export const createRoom = async (name: string, createdBy: string): Promise<Room> => {
  const room: Room = {
    id: generateId(),
    name,
    createdBy,
    createdAt: new Date().toISOString(),
    members: [createdBy],
  };

  const roomData: RoomData = { room, messages: [] };
  await writeJson(roomFilePath(room.id), roomData);

  const rooms = await listRooms();
  rooms.push(room);
  await writeJson(`${DATA_DIR}/rooms-index.json`, rooms);

  return room;
};

export const listRooms = async (): Promise<Room[]> => {
  return readJson<Room[]>(`${DATA_DIR}/rooms-index.json`, []);
};

export const getRoom = async (roomId: string): Promise<RoomData | null> => {
  const file = Bun.file(roomFilePath(roomId));
  if (await file.exists()) {
    return file.json() as Promise<RoomData>;
  }
  return null;
};

export const joinRoom = async (roomId: string, userId: string): Promise<Room | null> => {
  const data = await getRoom(roomId);
  if (!data) return null;

  if (!data.room.members.includes(userId)) {
    data.room.members.push(userId);
    await writeJson(roomFilePath(roomId), data);

    const rooms = await listRooms();
    const idx = rooms.findIndex((r) => r.id === roomId);
    if (idx >= 0) {
      rooms[idx] = data.room;
      await writeJson(`${DATA_DIR}/rooms-index.json`, rooms);
    }
  }

  return data.room;
};

export const postMessage = async (roomId: string, sender: string, text: string): Promise<Message | null> => {
  const data = await getRoom(roomId);
  if (!data) return null;

  const message: Message = {
    id: generateId(),
    roomId,
    sender,
    text,
    timestamp: new Date().toISOString(),
  };

  data.messages.push(message);
  await writeJson(roomFilePath(roomId), data);

  return message;
};

export const getMessages = async (roomId: string): Promise<Message[]> => {
  const data = await getRoom(roomId);
  return data?.messages ?? [];
};

export const getReadReceipts = async (): Promise<ReadReceipt[]> => {
  return readJson<ReadReceipt[]>(receiptsFilePath(), []);
};

export const markRead = async (userId: string, roomId: string): Promise<void> => {
  const receipts = await getReadReceipts();
  const existing = receipts.find((r) => r.userId === userId && r.roomId === roomId);

  if (existing) {
    existing.lastReadTimestamp = new Date().toISOString();
  } else {
    receipts.push({ userId, roomId, lastReadTimestamp: new Date().toISOString() });
  }

  await writeJson(receiptsFilePath(), receipts);
};

export const getUnreadCount = async (userId: string, roomId: string): Promise<number> => {
  const receipts = await getReadReceipts();
  const receipt = receipts.find((r) => r.userId === userId && r.roomId === roomId);
  const messages = await getMessages(roomId);

  if (!receipt) return messages.length;

  return messages.filter((m) => m.timestamp > receipt.lastReadTimestamp && m.sender !== userId).length;
};

