# Diet Tracker

Track daily food intake by logging meals with calorie counts, food category tags, and timestamps.

## Features

- **Meal Logging** — Record meals with a name, list of food items (each with calories and category tags), and an automatic timestamp.
- **Food Categories** — Tag each food item as protein, carbs, fat, or fiber to understand macronutrient balance.
- **Daily Totals** — View aggregated calorie counts for any given day.
- **Weekly Bar Chart** — Visualize the past 7 days of calorie intake as an inline bar chart.
- **Daily Goal** — Set a daily calorie target and see progress toward it.
- **Persistence** — All meal data and settings are stored as JSONL/JSON in the `data/` directory.

## Usage

```ts
import { logMeal, getDailyTotal, getWeeklyChart, setDailyGoal, getDailyGoal } from "./index";

// Set a daily calorie goal
await setDailyGoal(2000);

// Log a meal
await logMeal({
  name: "Lunch",
  items: [
    { food: "Grilled Chicken", calories: 350, tags: ["protein"] },
    { food: "Brown Rice", calories: 220, tags: ["carbs", "fiber"] },
    { food: "Avocado", calories: 160, tags: ["fat", "fiber"] },
  ],
});

// Get today's total
const total = await getDailyTotal(); // { calories: 730, goal: 2000, remaining: 1270 }

// Render a weekly bar chart
const chart = await getWeeklyChart();
```

export type FoodCategory = "protein" | "carbs" | "fat" | "fiber";

export type FoodItem = {
  food: string;
  calories: number;
  tags: FoodCategory[];
};

export type MealEntry = {
  id: string;
  name: string;
  items: FoodItem[];
  totalCalories: number;
  timestamp: string;
};

export type MealInput = {
  name: string;
  items: FoodItem[];
  timestamp?: string;
};

export type DailyTotal = {
  date: string;
  calories: number;
  goal: number;
  remaining: number;
  meals: MealEntry[];
};

export type DaySummary = {
  date: string;
  label: string;
  calories: number;
  goal: number;
};

export type Settings = {
  dailyGoal: number;
};

import type { MealEntry, Settings } from "./types";

const DATA_DIR = `${import.meta.dir}/data`;
const MEALS_FILE = `${DATA_DIR}/meals.jsonl`;
const SETTINGS_FILE = `${DATA_DIR}/settings.json`;

const DEFAULT_SETTINGS: Settings = { dailyGoal: 2000 };

export const readMeals = async (): Promise<MealEntry[]> => {
  const file = Bun.file(MEALS_FILE);
  const exists = await file.exists();
  if (!exists) return [];

  const text = await file.text();
  return text
    .trim()
    .split("\n")
    .filter(Boolean)
    .map((line) => JSON.parse(line) as MealEntry);
};

export const appendMeal = async (meal: MealEntry): Promise<void> => {
  const file = Bun.file(MEALS_FILE);
  const exists = await file.exists();
  const line = JSON.stringify(meal) + "\n";

  if (exists) {
    const existing = await file.text();
    await Bun.write(MEALS_FILE, existing + line);
  } else {
    await Bun.write(MEALS_FILE, line);
  }
};

export const readSettings = async (): Promise<Settings> => {
  const file = Bun.file(SETTINGS_FILE);
  const exists = await file.exists();
  if (!exists) return { ...DEFAULT_SETTINGS };

  const text = await file.text();
  return JSON.parse(text) as Settings;
};

export const writeSettings = async (settings: Settings): Promise<void> => {
  await Bun.write(SETTINGS_FILE, JSON.stringify(settings, null, 2) + "\n");
};

import type { MealInput, MealEntry, DailyTotal, DaySummary, FoodCategory } from "./types";
import { readMeals, appendMeal, readSettings, writeSettings } from "./store";

const generateId = (): string => crypto.randomUUID();

const toDateString = (date: Date): string => date.toISOString().slice(0, 10);

const today = (): string => toDateString(new Date());

export const logMeal = async (input: MealInput): Promise<MealEntry> => {
  const totalCalories = input.items.reduce((sum, item) => sum + item.calories, 0);
  const entry: MealEntry = {
    id: generateId(),
    name: input.name,
    items: input.items,
    totalCalories,
    timestamp: input.timestamp ?? new Date().toISOString(),
  };
  await appendMeal(entry);
  return entry;
};

export const getMealsForDate = async (date?: string): Promise<MealEntry[]> => {
  const targetDate = date ?? today();
  const meals = await readMeals();
  return meals.filter((m) => m.timestamp.slice(0, 10) === targetDate);
};

export const getDailyTotal = async (date?: string): Promise<DailyTotal> => {
  const targetDate = date ?? today();
  const meals = await getMealsForDate(targetDate);
  const settings = await readSettings();
  const calories = meals.reduce((sum, m) => sum + m.totalCalories, 0);

  return {
    date: targetDate,
    calories,
    goal: settings.dailyGoal,
    remaining: Math.max(0, settings.dailyGoal - calories),
    meals,
  };
};

export const getWeeklySummary = async (endDate?: string): Promise<DaySummary[]> => {
  const end = endDate ? new Date(endDate) : new Date();
  const settings = await readSettings();
  const meals = await readMeals();

  const days: DaySummary[] = [];
  for (let i = 6; i >= 0; i--) {
    const d = new Date(end);
    d.setDate(d.getDate() - i);
    const dateStr = toDateString(d);
    const dayLabel = d.toLocaleDateString("en-US", { weekday: "short" });
    const dayMeals = meals.filter((m) => m.timestamp.slice(0, 10) === dateStr);
    const calories = dayMeals.reduce((sum, m) => sum + m.totalCalories, 0);

    days.push({
      date: dateStr,
      label: dayLabel,
      calories,
      goal: settings.dailyGoal,
    });
  }

  return days;
};

export const getCategoryBreakdown = async (
  date?: string
): Promise<Record<FoodCategory, number>> => {
  const meals = await getMealsForDate(date);
  const breakdown: Record<FoodCategory, number> = {
    protein: 0,
    carbs: 0,
    fat: 0,
    fiber: 0,
  };

  for (const meal of meals) {
    for (const item of meal.items) {
      for (const tag of item.tags) {
        breakdown[tag] += item.calories;
      }
    }
  }

  return breakdown;
};

export const setDailyGoal = async (calories: number): Promise<void> => {
  const settings = await readSettings();
  settings.dailyGoal = calories;
  await writeSettings(settings);
};

export const getDailyGoal = async (): Promise<number> => {
  const settings = await readSettings();
  return settings.dailyGoal;
};

import { h } from "plaited";
import type { DaySummary } from "./types";

const BAR_MAX_HEIGHT = 160;

const barColor = (calories: number, goal: number): string => {
  if (calories === 0) return "#e0e0e0";
  if (calories <= goal) return "#4caf50";
  return "#f44336";
};

export const renderWeeklyChart = (days: DaySummary[]) => {
  const maxCal = Math.max(...days.map((d) => d.calories), ...days.map((d) => d.goal));
  const ceiling = maxCal > 0 ? maxCal : 2000;

  const bars = days.map((day) => {
    const barHeight = ceiling > 0 ? Math.round((day.calories / ceiling) * BAR_MAX_HEIGHT) : 0;
    const goalLineY = ceiling > 0 ? Math.round((day.goal / ceiling) * BAR_MAX_HEIGHT) : 0;
    const color = barColor(day.calories, day.goal);

    return h(
      "div",
      {
        style: {
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
