export type UserSettings = {
  dailyGoal: number;
};

import type { Meal, UserSettings } from './types';

const DATA_DIR = new URL('./data/', import.meta.url).pathname;
const MEALS_FILE = `${DATA_DIR}meals.jsonl`;
const SETTINGS_FILE = `${DATA_DIR}settings.json`;

const DEFAULT_SETTINGS: UserSettings = {
  dailyGoal: 2000,
};

export const loadSettings = async (): Promise<UserSettings> => {
  const file = Bun.file(SETTINGS_FILE);
  if (await file.exists()) {
    return await file.json();
  }
  return { ...DEFAULT_SETTINGS };
};

export const saveSettings = async (settings: UserSettings): Promise<void> => {
  await Bun.write(SETTINGS_FILE, JSON.stringify(settings, null, 2));
};

export const appendMeal = async (meal: Meal): Promise<void> => {
  const file = Bun.file(MEALS_FILE);
  const existing = (await file.exists()) ? await file.text() : '';
  const line = JSON.stringify(meal) + '\n';
  await Bun.write(MEALS_FILE, existing + line);
};

export const loadAllMeals = async (): Promise<Meal[]> => {
  const file = Bun.file(MEALS_FILE);
  if (!(await file.exists())) {
    return [];
  }
  const text = await file.text();
  return text
    .trim()
    .split('\n')
    .filter((line) => line.length > 0)
    .map((line) => JSON.parse(line) as Meal);
};

export const loadMealsByDate = async (date: string): Promise<Meal[]> => {
  const all = await loadAllMeals();
  return all.filter((meal) => meal.timestamp.startsWith(date));
};

export const deleteMeal = async (id: string): Promise<boolean> => {
  const meals = await loadAllMeals();
  const filtered = meals.filter((m) => m.id !== id);
  if (filtered.length === meals.length) return false;
  const content = filtered.map((m) => JSON.stringify(m)).join('\n') + (filtered.length > 0 ? '\n' : '');
  await Bun.write(MEALS_FILE, content);
  return true;
};

import type { Meal, FoodItem, FoodCategory, DailySummary, WeeklyData } from './types';
import { loadMealsByDate, loadAllMeals, appendMeal, loadSettings, saveSettings } from './data';

const generateId = (): string => crypto.randomUUID();

const toDateString = (d: Date): string => d.toISOString().slice(0, 10);

const getDayLabel = (dateStr: string): string => {
  const d = new Date(dateStr + 'T12:00:00');
  return ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'][d.getDay()];
};

export const logMeal = async (
  name: string,
  items: { name: string; calories: number; categories: FoodCategory[] }[],
  timestamp?: string,
): Promise<Meal> => {
  const foodItems: FoodItem[] = items.map((item) => ({
    name: item.name,
    calories: item.calories,
    categories: item.categories,
  }));

  const meal: Meal = {
    id: generateId(),
    name,
    items: foodItems,
    timestamp: timestamp ?? new Date().toISOString(),
    totalCalories: foodItems.reduce((sum, item) => sum + item.calories, 0),
  };

  await appendMeal(meal);
  return meal;
};

export const getDailySummary = async (date?: string): Promise<DailySummary> => {
  const targetDate = date ?? toDateString(new Date());
  const meals = await loadMealsByDate(targetDate);
  const settings = await loadSettings();
  const totalCalories = meals.reduce((sum, meal) => sum + meal.totalCalories, 0);

  return {
    date: targetDate,
    meals,
    totalCalories,
    goal: settings.dailyGoal,
    remaining: settings.dailyGoal - totalCalories,
    overGoal: totalCalories > settings.dailyGoal,
  };
};

export const getWeeklyData = async (endDate?: string): Promise<WeeklyData> => {
  const end = endDate ? new Date(endDate + 'T12:00:00') : new Date();
  const settings = await loadSettings();
  const allMeals = await loadAllMeals();

  const days: WeeklyData['days'] = [];

  for (let i = 6; i >= 0; i--) {
    const d = new Date(end);
    d.setDate(d.getDate() - i);
    const dateStr = toDateString(d);
    const dayMeals = allMeals.filter((m) => m.timestamp.startsWith(dateStr));
    const totalCalories = dayMeals.reduce((sum, m) => sum + m.totalCalories, 0);

    days.push({
      date: dateStr,
      label: getDayLabel(dateStr),
      totalCalories,
      goal: settings.dailyGoal,
    });
  }

  const maxCalories = Math.max(...days.map((d) => d.totalCalories), settings.dailyGoal);

  return { days, maxCalories };
};

export const setDailyGoal = async (calories: number): Promise<void> => {
  const settings = await loadSettings();
  settings.dailyGoal = calories;
  await saveSettings(settings);
};

export const filterMealsByCategory = async (
  category: FoodCategory,
  date?: string,
): Promise<Meal[]> => {
  const meals = date ? await loadMealsByDate(date) : await loadAllMeals();
  return meals.filter((meal) =>
    meal.items.some((item) => item.categories.includes(category)),
  );
};

