import type { Meal, GoalConfig } from './types'

const DATA_DIR = import.meta.dir + '/data'
const MEALS_PATH = `${DATA_DIR}/meals.jsonl`
const GOAL_PATH = `${DATA_DIR}/goal.json`

const DEFAULT_GOAL: GoalConfig = { dailyCalories: 2000 }

export const readMeals = async (): Promise<Meal[]> => {
  const file = Bun.file(MEALS_PATH)
  const exists = await file.exists()
  if (!exists) return []

  const text = await file.text()
  if (!text.trim()) return []

  return text
    .trim()
    .split('\n')
    .map((line) => JSON.parse(line) as Meal)
}

export const appendMeal = async (meal: Meal): Promise<void> => {
  const file = Bun.file(MEALS_PATH)
  const exists = await file.exists()
  const line = JSON.stringify(meal) + '\n'

  if (exists) {
    const existing = await file.text()
    await Bun.write(MEALS_PATH, existing + line)
  } else {
    await Bun.write(MEALS_PATH, line)
  }
}

export const deleteMeal = async (id: string): Promise<boolean> => {
  const meals = await readMeals()
  const filtered = meals.filter((m) => m.id !== id)
  if (filtered.length === meals.length) return false

  const content = filtered.map((m) => JSON.stringify(m)).join('\n') + (filtered.length ? '\n' : '')
  await Bun.write(MEALS_PATH, content)
  return true
}

export const readGoal = async (): Promise<GoalConfig> => {
  const file = Bun.file(GOAL_PATH)
  const exists = await file.exists()
  if (!exists) return DEFAULT_GOAL

  const text = await file.text()
  if (!text.trim()) return DEFAULT_GOAL

  return JSON.parse(text) as GoalConfig
}

export const writeGoal = async (goal: GoalConfig): Promise<void> => {
  await Bun.write(GOAL_PATH, JSON.stringify(goal, null, 2) + '\n')
}

import type { Meal, MealInput, DailySummary, FoodCategory, WeeklyData } from './types'
import { readMeals, appendMeal, deleteMeal, readGoal, writeGoal } from './store'

const generateId = (): string =>
  crypto.randomUUID()

const toDateString = (iso: string): string =>
  iso.slice(0, 10)

export const logMeal = async (input: MealInput): Promise<Meal> => {
  const timestamp = input.timestamp ?? new Date().toISOString()
  const totalCalories = input.items.reduce((sum, item) => sum + item.calories, 0)

  const meal: Meal = {
    id: generateId(),
    name: input.name,
    items: input.items,
    timestamp,
    totalCalories,
  }

  await appendMeal(meal)
  return meal
}

export const removeMeal = async (id: string): Promise<boolean> =>
  deleteMeal(id)

export const getMealsForDate = async (date: string): Promise<Meal[]> => {
  const meals = await readMeals()
  return meals.filter((m) => toDateString(m.timestamp) === date)
}

export const getDailySummary = async (date: string): Promise<DailySummary> => {
  const meals = await getMealsForDate(date)
  const goal = await readGoal()

  const totalCalories = meals.reduce((sum, m) => sum + m.totalCalories, 0)

  const byCategory: Record<FoodCategory, number> = {
    protein: 0,
    carbs: 0,
    fat: 0,
    fiber: 0,
  }

  for (const meal of meals) {
    for (const item of meal.items) {
      byCategory[item.category] += item.calories
    }
  }

  return {
    date,
    totalCalories,
    goal: goal.dailyCalories,
    meals,
    byCategory,
  }
}

export const getWeeklyData = async (endDate?: string): Promise<WeeklyData> => {
  const end = endDate ? new Date(endDate) : new Date()
  const goal = await readGoal()
  const meals = await readMeals()

  const result: WeeklyData = []

  for (let i = 6; i >= 0; i--) {
    const d = new Date(end)
    d.setDate(d.getDate() - i)
    const dateStr = d.toISOString().slice(0, 10)

    const dayMeals = meals.filter((m) => toDateString(m.timestamp) === dateStr)
    const totalCalories = dayMeals.reduce((sum, m) => sum + m.totalCalories, 0)

    result.push({
      date: dateStr,
      totalCalories,
      goal: goal.dailyCalories,
    })
  }

  return result
}

export const setDailyGoal = async (calories: number): Promise<void> => {
  await writeGoal({ dailyCalories: calories })
}

export const getDailyGoal = async (): Promise<number> => {
  const goal = await readGoal()
  return goal.dailyCalories
}

import { h } from 'plaited'
import type { WeeklyData } from './types'
import { getWeeklyData } from './tracker'

const BAR_MAX_HEIGHT = 200
const BAR_WIDTH = 40
const GAP = 12
const CHART_PADDING = 24

const dayLabel = (dateStr: string): string => {
  const d = new Date(dateStr + 'T00:00:00')
  return ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'][d.getDay()]
}

const barColor = (calories: number, goal: number): string =>
  calories > goal ? '#ef4444' : calories >= goal * 0.8 ? '#f59e0b' : '#22c55e'

export const renderWeeklyChart = async (endDate?: string) => {
  const data = await getWeeklyData(endDate)
  const maxCal = Math.max(...data.map((d) => d.totalCalories), data[0]?.goal ?? 2000)

  const chartWidth = data.length * (BAR_WIDTH + GAP) - GAP + CHART_PADDING * 2
  const chartHeight = BAR_MAX_HEIGHT + 80

  const bars = data.map((day, i) => {
    const barHeight = maxCal > 0 ? (day.totalCalories / maxCal) * BAR_MAX_HEIGHT : 0
    const x = CHART_PADDING + i * (BAR_WIDTH + GAP)
    const y = BAR_MAX_HEIGHT - barHeight + 20
    const color = barColor(day.totalCalories, day.goal)

    return h('g', {},
      h('rect', {
        x: String(x),
        y: String(y),
        width: String(BAR_WIDTH),
        height: String(Math.max(barHeight, 1)),
        fill: color,
        rx: '4',
      }),
      h('text', {
        x: String(x + BAR_WIDTH / 2),
        y: String(y - 6),
        'text-anchor': 'middle',
        'font-size': '11',
        fill: '#374151',
      }, String(day.totalCalories)),
      h('text', {
        x: String(x + BAR_WIDTH / 2),
        y: String(BAR_MAX_HEIGHT + 38),
        'text-anchor': 'middle',
        'font-size': '12',
        fill: '#6b7280',
      }, dayLabel(day.date)),
      h('text', {
        x: String(x + BAR_WIDTH / 2),
        y: String(BAR_MAX_HEIGHT + 54),
        'text-anchor': 'middle',
        'font-size': '10',
        fill: '#9ca3af',
      }, day.date.slice(5)),
    )
  })

  const goalY = maxCal > 0 ? BAR_MAX_HEIGHT - (data[0].goal / maxCal) * BAR_MAX_HEIGHT + 20 : 20
  const goalLine = h('line', {
    x1: String(CHART_PADDING - 8),
    y1: String(goalY),
    x2: String(chartWidth - CHART_PADDING + 8),
    y2: String(goalY),
    stroke: '#3b82f6',
    'stroke-dasharray': '6,4',
    'stroke-width': '2',
  })

  const goalLabel = h('text', {
    x: String(chartWidth - CHART_PADDING + 12),
    y: String(goalY + 4),
    'font-size': '10',
    fill: '#3b82f6',
  }, `Goal: ${data[0]?.goal ?? 2000}`)

  return h('svg', {
    width: String(chartWidth + 60),
    height: String(chartHeight),
    viewBox: `0 0 ${chartWidth + 60} ${chartHeight}`,
    xmlns: 'http://www.w3.org/2000/svg',
  }, goalLine, goalLabel, ...bars)
}

export const renderWeeklyChartData = async (endDate?: string): Promise<WeeklyData> =>
  getWeeklyData(endDate)

