import type { Book, BookInput, BookUpdate, ReadingStats, FilterOptions } from './types'

const DATA_PATH = `${import.meta.dir}/data/books.json`

const loadBooks = async (): Promise<Book[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text.trim() ? JSON.parse(text) : []
}

const saveBooks = async (books: Book[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(books, null, 2))
}

const generateId = (): string =>
  crypto.randomUUID()

export const addBook = async (input: BookInput): Promise<Book> => {
  const books = await loadBooks()
  const now = new Date().toISOString()
  const book: Book = {
    id: generateId(),
    title: input.title,
    author: input.author,
    genre: input.genre,
    pageCount: input.pageCount,
    coverImageUrl: input.coverImageUrl,
    currentPage: 0,
    status: 'want-to-read',
    createdAt: now,
    updatedAt: now,
  }
  books.push(book)
  await saveBooks(books)
  return book
}

export const getBook = async (id: string): Promise<Book | undefined> => {
  const books = await loadBooks()
  return books.find((b) => b.id === id)
}

export const updateBook = async (id: string, update: BookUpdate): Promise<Book | undefined> => {
  const books = await loadBooks()
  const index = books.findIndex((b) => b.id === id)
  if (index === -1) return undefined

  const book = books[index]

  if (update.currentPage !== undefined) {
    book.currentPage = Math.max(0, Math.min(update.currentPage, book.pageCount))
    if (book.currentPage >= book.pageCount) {
      book.status = 'completed'
    }
  }

  if (update.status !== undefined) {
    book.status = update.status
    if (update.status === 'completed') {
      book.currentPage = book.pageCount
    } else if (update.status === 'want-to-read') {
      book.currentPage = 0
    }
  }

  book.updatedAt = new Date().toISOString()
  books[index] = book
  await saveBooks(books)
  return book
}

export const deleteBook = async (id: string): Promise<boolean> => {
  const books = await loadBooks()
  const filtered = books.filter((b) => b.id !== id)
  if (filtered.length === books.length) return false
  await saveBooks(filtered)
  return true
}

export const listBooks = async (filters?: FilterOptions): Promise<Book[]> => {
  let books = await loadBooks()

  if (filters?.status) {
    books = books.filter((b) => b.status === filters.status)
  }
  if (filters?.genre) {
    books = books.filter((b) => b.genre.toLowerCase() === filters.genre!.toLowerCase())
  }

  return books
}

export const getGenres = async (): Promise<string[]> => {
  const books = await loadBooks()
  return [...new Set(books.map((b) => b.genre))].sort()
}

export const getStats = async (): Promise<ReadingStats> => {
  const books = await loadBooks()

  const booksCompleted = books.filter((b) => b.status === 'completed').length
  const booksReading = books.filter((b) => b.status === 'reading').length
  const booksWantToRead = books.filter((b) => b.status === 'want-to-read').length
  const totalPagesRead = books.reduce((sum, b) => sum + b.currentPage, 0)
  const totalPages = books.reduce((sum, b) => sum + b.pageCount, 0)
  const averageProgress =
    books.length > 0
      ? books.reduce((sum, b) => sum + (b.pageCount > 0 ? b.currentPage / b.pageCount : 0), 0) / books.length
      : 0

  return {
    totalBooks: books.length,
    booksCompleted,
    booksReading,
    booksWantToRead,
    totalPagesRead,
    totalPages,
    averageProgress: Math.round(averageProgress * 100),
  }
}

