    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const parseBody = async <T>(req: Request): Promise<T> => {
  const contentType = req.headers.get('Content-Type') ?? ''
  if (contentType.includes('application/json')) {
    return req.json() as Promise<T>
  }
  const formData = await req.formData()
  const obj: Record<string, unknown> = {}
  formData.forEach((value, key) => {
    obj[key] = key === 'pageCount' || key === 'currentPage' ? Number(value) : value
  })
  return obj as T
}

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname
  const method = req.method

  // HTML view
  if (method === 'GET' && (path === '/' || path === '')) {
    const status = (url.searchParams.get('status') as ReadingStatus | null) ?? undefined
    const genre = url.searchParams.get('genre') ?? undefined
    const filters: FilterOptions = { status, genre }

    const [books, genres, stats] = await Promise.all([
      listBooks(filters),
      getGenres(),
      getStats(),
    ])

    const html = renderReadingList({ books, stats, genres, filters })
    return htmlResponse(html)
  }

  // API: List books
  if (method === 'GET' && path === '/api/books') {
    const status = (url.searchParams.get('status') as ReadingStatus | null) ?? undefined
    const genre = url.searchParams.get('genre') ?? undefined
    const books = await listBooks({ status, genre })
    return jsonResponse(books)
  }

  // API: Get stats
  if (method === 'GET' && path === '/api/stats') {
    const stats = await getStats()
    return jsonResponse(stats)
  }

  // API: Get genres
  if (method === 'GET' && path === '/api/genres') {
    const genres = await getGenres()
    return jsonResponse(genres)
  }

  // API: Add book
  if (method === 'POST' && path === '/api/books') {
    const input = await parseBody<BookInput>(req)

    if (!input.title || !input.author || !input.genre || !input.pageCount) {
      return jsonResponse({ error: 'title, author, genre, and pageCount are required' }, 400)
    }

    if (input.pageCount < 1) {
      return jsonResponse({ error: 'pageCount must be at least 1' }, 400)
    }

    const book = await addBook({
      title: String(input.title),
      author: String(input.author),
      genre: String(input.genre),
      pageCount: Number(input.pageCount),
      coverImageUrl: input.coverImageUrl ? String(input.coverImageUrl) : '',
    })

    return jsonResponse(book, 201)
  }

  // API: Get single book
  const bookMatch = path.match(/^\/api\/books\/([^/]+)$/)
  if (method === 'GET' && bookMatch) {
    const book = await getBook(bookMatch[1])
    if (!book) return jsonResponse({ error: 'Book not found' }, 404)
    return jsonResponse(book)
  }

  // API: Update book
  if (method === 'PATCH' && bookMatch) {
    const update = await parseBody<BookUpdate>(req)

    if (update.status && !validStatuses.includes(update.status)) {
      return jsonResponse({ error: `status must be one of: ${validStatuses.join(', ')}` }, 400)
    }

    if (update.currentPage !== undefined && (typeof update.currentPage !== 'number' || update.currentPage < 0)) {
      return jsonResponse({ error: 'currentPage must be a non-negative number' }, 400)
    }

    const book = await updateBook(bookMatch[1], update)
    if (!book) return jsonResponse({ error: 'Book not found' }, 404)
    return jsonResponse(book)
  }

  // API: Delete book
  if (method === 'DELETE' && bookMatch) {
    const deleted = await deleteBook(bookMatch[1])
    if (!deleted) return jsonResponse({ error: 'Book not found' }, 404)
    return jsonResponse({ success: true })
  }

  return jsonResponse({ error: 'Not found' }, 404)
}

export default {
  port: 3000,
  fetch: handleRequest,
}

