import {
  loadBooks,
  addBook,
  updateProgress,
  updateStatus,
  removeBook,
  filterBooks,
  getGenres,
  getStats,
} from './store'
import { renderPage } from './render'
import { createSSR } from 'plaited'
import type { BookInput, FilterOptions, ReadingStatus } from './types'

export type { Book, BookInput, FilterOptions, ReadingStats, ReadingStatus } from './types'

export const handleAddBook = async (input: BookInput) => {
  const book = await addBook(input)
  return book
}

export const handleUpdateProgress = async (bookId: string, currentPage: number) => {
  const book = await updateProgress(bookId, currentPage)
  return book
}

export const handleUpdateStatus = async (bookId: string, status: ReadingStatus) => {
  const book = await updateStatus(bookId, status)
  return book
}

export const handleRemoveBook = async (bookId: string) => {
  return removeBook(bookId)
}

export const handleFilter = async (options: FilterOptions) => {
  return filterBooks(options)
}

export const handleGetStats = async () => {
  return getStats()
}

export const handleRender = async (filters: FilterOptions = {}) => {
  const books = await filterBooks(filters)
  const stats = await getStats()
  const genres = await getGenres()
  const template = renderPage(books, stats, filters, genres)
  const ssr = createSSR()
  return ssr(template)
}

