  addBook: handleAddBook,
  updateProgress: handleUpdateProgress,
  updateStatus: handleUpdateStatus,
  removeBook: handleRemoveBook,
  filter: handleFilter,
  getStats: handleGetStats,
  render: handleRender,
}

