import type { InventoryItem, InventoryStore, BulkImportEntry } from './types'

const DATA_PATH = `${import.meta.dir}/data/inventory.json`

const readStore = async (): Promise<InventoryStore> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return { items: [] }
  const text = await file.text()
  return JSON.parse(text) as InventoryStore
}

const writeStore = async (store: InventoryStore): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(store, null, 2))
}

const generateId = (): string =>
  crypto.randomUUID()

const now = (): string =>
  new Date().toISOString()

export const getAllItems = async (): Promise<InventoryItem[]> => {
  const store = await readStore()
  return store.items
}

export const getItemById = async (id: string): Promise<InventoryItem | undefined> => {
  const store = await readStore()
  return store.items.find((item) => item.id === id)
}

export const getItemBySku = async (sku: string): Promise<InventoryItem | undefined> => {
  const store = await readStore()
  return store.items.find((item) => item.sku.toLowerCase() === sku.toLowerCase())
}

export const addItem = async (entry: BulkImportEntry): Promise<InventoryItem> => {
  const store = await readStore()
  const existing = store.items.find((item) => item.sku.toLowerCase() === entry.sku.toLowerCase())
  if (existing) {
    throw new Error(`Item with SKU "${entry.sku}" already exists`)
  }
  const item: InventoryItem = {
    id: generateId(),
    name: entry.name,
    sku: entry.sku,
    quantity: entry.quantity,
    category: entry.category,
    reorderThreshold: entry.reorderThreshold,
    createdAt: now(),
    updatedAt: now(),
  }
  store.items.push(item)
  await writeStore(store)
  return item
}

export const updateItem = async (
  id: string,
  updates: Partial<Omit<InventoryItem, 'id' | 'createdAt' | 'updatedAt'>>
): Promise<InventoryItem> => {
  const store = await readStore()
  const index = store.items.findIndex((item) => item.id === id)
  if (index === -1) {
    throw new Error(`Item with ID "${id}" not found`)
  }
  if (updates.sku) {
    const duplicate = store.items.find(
      (item) => item.sku.toLowerCase() === updates.sku!.toLowerCase() && item.id !== id
    )
    if (duplicate) {
      throw new Error(`Another item with SKU "${updates.sku}" already exists`)
    }
  }
  store.items[index] = {
    ...store.items[index],
    ...updates,
    updatedAt: now(),
  }
  await writeStore(store)
  return store.items[index]
}

export const deleteItem = async (id: string): Promise<void> => {
  const store = await readStore()
  const index = store.items.findIndex((item) => item.id === id)
  if (index === -1) {
    throw new Error(`Item with ID "${id}" not found`)
  }
  store.items.splice(index, 1)
  await writeStore(store)
}

export const bulkImport = async (entries: BulkImportEntry[]): Promise<{
  imported: InventoryItem[]
  skipped: { entry: BulkImportEntry; reason: string }[]
}> => {
  const store = await readStore()
  const imported: InventoryItem[] = []
  const skipped: { entry: BulkImportEntry; reason: string }[] = []
  const newSkus = new Set<string>()

  for (const entry of entries) {
    const skuLower = entry.sku.toLowerCase()
    const existsInStore = store.items.some((item) => item.sku.toLowerCase() === skuLower)
    const existsInBatch = newSkus.has(skuLower)

    if (existsInStore || existsInBatch) {
      skipped.push({ entry, reason: `Duplicate SKU: ${entry.sku}` })
      continue
    }

    if (!entry.name || !entry.sku || entry.quantity == null || !entry.category || entry.reorderThreshold == null) {
      skipped.push({ entry, reason: 'Missing required fields' })
      continue
    }

    const item: InventoryItem = {
      id: generateId(),
      name: entry.name,
      sku: entry.sku,
      quantity: entry.quantity,
      category: entry.category,
      reorderThreshold: entry.reorderThreshold,
      createdAt: now(),
      updatedAt: now(),
    }
    store.items.push(item)
    imported.push(item)
    newSkus.add(skuLower)
  }

  await writeStore(store)
  return { imported, skipped }
}

export const updateQuantity = async (id: string, quantity: number): Promise<InventoryItem> => {
  if (quantity < 0) {
    throw new Error('Quantity cannot be negative')
  }
  return updateItem(id, { quantity })
}

import type { InventoryItem, SearchParams, DashboardData } from './types'
import { getAllItems } from './store'

export const searchItems = async (params: SearchParams): Promise<InventoryItem[]> => {
  const items = await getAllItems()
  let results = [...items]

  if (params.query) {
    const q = params.query.toLowerCase()
    results = results.filter(
      (item) => item.name.toLowerCase().includes(q) || item.sku.toLowerCase().includes(q)
    )
  }

  if (params.category) {
    const cat = params.category.toLowerCase()
    results = results.filter((item) => item.category.toLowerCase() === cat)
  }

  if (params.lowStockOnly) {
    results = results.filter((item) => item.quantity <= item.reorderThreshold)
  }

  const sortBy = params.sortBy ?? 'name'
  const sortOrder = params.sortOrder ?? 'asc'
  results.sort((a, b) => {
    const aVal = a[sortBy]
    const bVal = b[sortBy]
    if (typeof aVal === 'string' && typeof bVal === 'string') {
      return sortOrder === 'asc' ? aVal.localeCompare(bVal) : bVal.localeCompare(aVal)
    }
    if (typeof aVal === 'number' && typeof bVal === 'number') {
      return sortOrder === 'asc' ? aVal - bVal : bVal - aVal
    }
    return 0
  })

  return results
}

export const getDashboardData = async (): Promise<DashboardData> => {
  const items = await getAllItems()
  const lowStockItems = items
    .filter((item) => item.quantity <= item.reorderThreshold)
    .sort((a, b) => {
      const aRatio = a.quantity / (a.reorderThreshold || 1)
      const bRatio = b.quantity / (b.reorderThreshold || 1)
      return aRatio - bRatio
    })

  const categories = [...new Set(items.map((item) => item.category))].sort()

  const totalQuantity = items.reduce((sum, item) => sum + item.quantity, 0)

  return {
    totalItems: items.length,
    totalQuantity,
    lowStockItems,
    categories,
    items,
  }
}

export const getCategories = async (): Promise<string[]> => {
  const items = await getAllItems()
  return [...new Set(items.map((item) => item.category))].sort()
}

