import { createSSR } from 'plaited'
import type { BulkImportEntry, SearchParams, InventoryItem } from './types'
import {
  getAllItems,
  getItemById,
  getItemBySku,
  addItem,
  updateItem,
  deleteItem,
  bulkImport,
  updateQuantity,
} from './store'
import { searchItems, getDashboardData } from './inventory'
import { renderDashboard } from './dashboard'

const json = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const html = (content: string, status = 200) =>
  new Response(content, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const parseBody = async <T>(request: Request): Promise<T> => {
  const text = await request.text()
  return JSON.parse(text) as T
}

export const handleRequest = async (request: Request): Promise<Response> => {
  const url = new URL(request.url)
  const path = url.pathname
  const method = request.method

  // Dashboard HTML
  if (path === '/' && method === 'GET') {
    const data = await getDashboardData()
    const template = renderDashboard(data)
    const ssr = createSSR()
    const rendered = ssr(template)
    return html(`<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Inventory Manager</title>
</head>
<body style="margin:0;background:#f8f9fa">
  ${rendered}
</body>
</html>`)
  }

  // API: Get all items
  if (path === '/api/items' && method === 'GET') {
    const items = await getAllItems()
    return json({ items, total: items.length })
  }

  // API: Search items
  if (path === '/api/items/search' && method === 'GET') {
    const params: SearchParams = {
      query: url.searchParams.get('q') ?? undefined,
      category: url.searchParams.get('category') ?? undefined,
      lowStockOnly: url.searchParams.get('lowStock') === 'true',
      sortBy: (url.searchParams.get('sortBy') as keyof InventoryItem) ?? undefined,
      sortOrder: (url.searchParams.get('sortOrder') as 'asc' | 'desc') ?? undefined,
    }
    const items = await searchItems(params)
    return json({ items, total: items.length })
  }

  // API: Barcode/SKU lookup
  if (path === '/api/items/barcode' && method === 'GET') {
    const sku = url.searchParams.get('sku')
    if (!sku) return json({ error: 'SKU parameter required' }, 400)
    const item = await getItemBySku(sku)
    if (!item) return json({ error: `No item found with SKU: ${sku}`, found: false }, 404)
    return json({ item, found: true })
  }

  // API: Get single item
  if (path.match(/^\/api\/items\/[^/]+$/) && method === 'GET') {
    const id = path.split('/').pop()!
    const item = await getItemById(id)
    if (!item) return json({ error: 'Item not found' }, 404)
    return json({ item })
  }

  // API: Add item
  if (path === '/api/items' && method === 'POST') {
    const body = await parseBody<BulkImportEntry>(request)
    if (!body.name || !body.sku || body.quantity == null || !body.category || body.reorderThreshold == null) {
      return json({ error: 'Missing required fields: name, sku, quantity, category, reorderThreshold' }, 400)
    }
    try {
      const item = await addItem(body)
      return json({ item }, 201)
    } catch (err) {
      return json({ error: (err as Error).message }, 409)
    }
  }

  // API: Update item
  if (path.match(/^\/api\/items\/[^/]+$/) && method === 'PATCH') {
    const id = path.split('/').pop()!
    const updates = await parseBody<Partial<InventoryItem>>(request)
    try {
      const item = await updateItem(id, updates)
      return json({ item })
    } catch (err) {
      return json({ error: (err as Error).message }, 404)
    }
  }

  // API: Update quantity
  if (path.match(/^\/api\/items\/[^/]+\/quantity$/) && method === 'PATCH') {
    const id = path.split('/')[3]
    const { quantity } = await parseBody<{ quantity: number }>(request)
    if (quantity == null) return json({ error: 'Quantity is required' }, 400)
    try {
      const item = await updateQuantity(id, quantity)
      return json({ item })
    } catch (err) {
      return json({ error: (err as Error).message }, 400)
    }
  }

  // API: Delete item
  if (path.match(/^\/api\/items\/[^/]+$/) && method === 'DELETE') {
    const id = path.split('/').pop()!
    try {
      await deleteItem(id)
      return json({ success: true })
    } catch (err) {
      return json({ error: (err as Error).message }, 404)
    }
  }

  // API: Bulk import
  if (path === '/api/items/bulk' && method === 'POST') {
    const entries = await parseBody<BulkImportEntry[]>(request)
    if (!Array.isArray(entries)) {
      return json({ error: 'Request body must be a JSON array of items' }, 400)
    }
    const result = await bulkImport(entries)
    return json({
      imported: result.imported.length,
      skipped: result.skipped.length,
      details: result,
    })
  }

  // API: Dashboard data
  if (path === '/api/dashboard' && method === 'GET') {
    const data = await getDashboardData()
    return json(data)
  }

  return json({ error: 'Not found' }, 404)
}

{
