import type { InventoryItem, NewItemInput, UpdateItemInput } from './types'

const DATA_PATH = new URL('./data/inventory.json', import.meta.url).pathname

const generateId = (): string => crypto.randomUUID()

const now = (): string => new Date().toISOString()

export const loadItems = async (): Promise<InventoryItem[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  if (!text.trim()) return []
  return JSON.parse(text) as InventoryItem[]
}

export const saveItems = async (items: InventoryItem[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(items, null, 2))
}

export const addItem = async (input: NewItemInput): Promise<InventoryItem> => {
  const items = await loadItems()
  const existing = items.find((i) => i.sku === input.sku)
  if (existing) {
    throw new Error(`Item with SKU "${input.sku}" already exists`)
  }
  const item: InventoryItem = {
    id: generateId(),
    ...input,
    createdAt: now(),
    updatedAt: now(),
  }
  items.push(item)
  await saveItems(items)
  return item
}

export const updateItem = async (id: string, updates: UpdateItemInput): Promise<InventoryItem> => {
  const items = await loadItems()
  const index = items.findIndex((i) => i.id === id)
  if (index === -1) throw new Error(`Item with id "${id}" not found`)
  if (updates.sku && updates.sku !== items[index].sku) {
    const duplicate = items.find((i) => i.sku === updates.sku && i.id !== id)
    if (duplicate) throw new Error(`Item with SKU "${updates.sku}" already exists`)
  }
  items[index] = { ...items[index], ...updates, updatedAt: now() }
  await saveItems(items)
  return items[index]
}

export const removeItem = async (id: string): Promise<void> => {
  const items = await loadItems()
  const filtered = items.filter((i) => i.id !== id)
  if (filtered.length === items.length) throw new Error(`Item with id "${id}" not found`)
  await saveItems(filtered)
}

export const getItem = async (id: string): Promise<InventoryItem | undefined> => {
  const items = await loadItems()
  return items.find((i) => i.id === id)
}

export const getItemBySku = async (sku: string): Promise<InventoryItem | undefined> => {
  const items = await loadItems()
  return items.find((i) => i.sku === sku)
}

export const bulkImport = async (inputs: NewItemInput[]): Promise<{ added: number; skipped: string[] }> => {
  const items = await loadItems()
  const existingSkus = new Set(items.map((i) => i.sku))
  const skipped: string[] = []
  const timestamp = now()

  for (const input of inputs) {
    if (existingSkus.has(input.sku)) {
      skipped.push(input.sku)
      continue
    }
    items.push({
      id: generateId(),
      ...input,
      createdAt: timestamp,
      updatedAt: timestamp,
    })
    existingSkus.add(input.sku)
  }

  await saveItems(items)
  return { added: inputs.length - skipped.length, skipped }
}

import type { InventoryItem, FilterOptions, StockStatus } from './types'
import { loadItems } from './store'

export const getStockStatus = (item: InventoryItem): StockStatus => {
  if (item.quantity === 0) return 'out'
  if (item.quantity < item.reorderThreshold) return 'low'
  return 'ok'
}

export const getLowStockItems = async (): Promise<InventoryItem[]> => {
  const items = await loadItems()
  return items.filter((i) => i.quantity < i.reorderThreshold)
}

export const getCategories = async (): Promise<string[]> => {
  const items = await loadItems()
  return [...new Set(items.map((i) => i.category))].sort()
}

export const searchItems = async (query: string): Promise<InventoryItem[]> => {
  const items = await loadItems()
  const q = query.toLowerCase()
  return items.filter(
    (i) => i.name.toLowerCase().includes(q) || i.sku.toLowerCase().includes(q)
  )
}

export const getFilteredItems = async (options: FilterOptions): Promise<InventoryItem[]> => {
  let items = await loadItems()

  if (options.search) {
    const q = options.search.toLowerCase()
    items = items.filter(
      (i) => i.name.toLowerCase().includes(q) || i.sku.toLowerCase().includes(q)
    )
  }

  if (options.category) {
    items = items.filter((i) => i.category === options.category)
  }

  if (options.lowStockOnly) {
    items = items.filter((i) => i.quantity < i.reorderThreshold)
  }

  const sortBy = options.sortBy ?? 'name'
  const sortOrder = options.sortOrder ?? 'asc'
  const direction = sortOrder === 'asc' ? 1 : -1

  items.sort((a, b) => {
    const aVal = a[sortBy]
    const bVal = b[sortBy]
    if (typeof aVal === 'string' && typeof bVal === 'string') {
      return aVal.localeCompare(bVal) * direction
    }
    return ((aVal as number) - (bVal as number)) * direction
  })

  return items
}

export const getDashboardStats = async (): Promise<{
  totalItems: number
  totalQuantity: number
  lowStockCount: number
  outOfStockCount: number
  categoryCount: number
}> => {
  const items = await loadItems()
  return {
    totalItems: items.length,
    totalQuantity: items.reduce((sum, i) => sum + i.quantity, 0),
    lowStockCount: items.filter((i) => i.quantity > 0 && i.quantity < i.reorderThreshold).length,
    outOfStockCount: items.filter((i) => i.quantity === 0).length,
    categoryCount: new Set(items.map((i) => i.category)).size,
  }
}

