export const handleBarcodeScan = async (barcode: string): Promise<{
  found: boolean
  item?: Awaited<ReturnType<typeof getItemBySku>>
}> => {
  const item = await getItemBySku(barcode.trim())
  return { found: !!item, item: item ?? undefined }
}

export const handleBulkImport = async (jsonString: string): Promise<{
  success: boolean
  added?: number
  skipped?: string[]
  error?: string
}> => {
  try {
    const parsed = JSON.parse(jsonString)
    if (!Array.isArray(parsed)) {
      return { success: false, error: 'Input must be a JSON array' }
    }

    const validated: NewItemInput[] = parsed.map((entry: Record<string, unknown>, i: number) => {
      if (!entry.name || !entry.sku) {
        throw new Error(`Item at index ${i} missing required fields (name, sku)`)
      }
      return {
        name: String(entry.name),
        sku: String(entry.sku),
        quantity: Number(entry.quantity ?? 0),
        category: String(entry.category ?? 'Uncategorized'),
        reorderThreshold: Number(entry.reorderThreshold ?? 5),
      }
    })

    const result = await bulkImport(validated)
    return { success: true, added: result.added, skipped: result.skipped }
  } catch (err) {
    return { success: false, error: err instanceof Error ? err.message : 'Invalid JSON' }
  }
}

