import type {
  InventoryItem,
  SortOptions,
  FilterOptions,
  BulkImportItem,
  DashboardStats,
} from './types'

const DATA_PATH = `${import.meta.dir}/data/inventory.json`

const generateId = (): string => crypto.randomUUID()

const now = (): string => new Date().toISOString()

export const loadInventory = async (): Promise<InventoryItem[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return JSON.parse(text) as InventoryItem[]
}

export const saveInventory = async (items: InventoryItem[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(items, null, 2))
}

export const addItem = async (input: BulkImportItem): Promise<InventoryItem> => {
  const items = await loadInventory()
  const existing = items.find((i) => i.sku === input.sku)
  if (existing) {
    throw new Error(`Item with SKU "${input.sku}" already exists`)
  }
  const item: InventoryItem = {
    id: generateId(),
    ...input,
    createdAt: now(),
    updatedAt: now(),
  }
  items.push(item)
  await saveInventory(items)
  return item
}

export const updateItem = async (
  id: string,
  updates: Partial<Omit<InventoryItem, 'id' | 'createdAt' | 'updatedAt'>>
): Promise<InventoryItem> => {
  const items = await loadInventory()
  const index = items.findIndex((i) => i.id === id)
  if (index === -1) {
    throw new Error(`Item with id "${id}" not found`)
  }
  if (updates.sku && updates.sku !== items[index].sku) {
    const duplicate = items.find((i) => i.sku === updates.sku && i.id !== id)
    if (duplicate) {
      throw new Error(`Item with SKU "${updates.sku}" already exists`)
    }
  }
  items[index] = { ...items[index], ...updates, updatedAt: now() }
  await saveInventory(items)
  return items[index]
}

export const deleteItem = async (id: string): Promise<void> => {
  const items = await loadInventory()
  const filtered = items.filter((i) => i.id !== id)
  if (filtered.length === items.length) {
    throw new Error(`Item with id "${id}" not found`)
  }
  await saveInventory(filtered)
}

export const bulkImport = async (input: BulkImportItem[]): Promise<{ added: number; skipped: string[] }> => {
  const items = await loadInventory()
  const existingSkus = new Set(items.map((i) => i.sku))
  const skipped: string[] = []
  const timestamp = now()

  for (const entry of input) {
    if (existingSkus.has(entry.sku)) {
      skipped.push(entry.sku)
      continue
    }
    items.push({
      id: generateId(),
      ...entry,
      createdAt: timestamp,
      updatedAt: timestamp,
    })
    existingSkus.add(entry.sku)
  }

  await saveInventory(items)
  return { added: input.length - skipped.length, skipped }
}

export const searchItems = async (query: string): Promise<InventoryItem[]> => {
  const items = await loadInventory()
  const lower = query.toLowerCase()
  return items.filter(
    (i) => i.name.toLowerCase().includes(lower) || i.sku.toLowerCase().includes(lower)
  )
}

export const lookupBySku = async (sku: string): Promise<InventoryItem | undefined> => {
  const items = await loadInventory()
  return items.find((i) => i.sku === sku)
}

export const getLowStockItems = async (): Promise<InventoryItem[]> => {
  const items = await loadInventory()
  return items.filter((i) => i.quantity <= i.reorderThreshold)
}

export const getCategories = async (): Promise<string[]> => {
  const items = await loadInventory()
  return [...new Set(items.map((i) => i.category))].sort()
}

export const sortItems = (items: InventoryItem[], options: SortOptions): InventoryItem[] => {
  const { field, direction } = options
  const multiplier = direction === 'asc' ? 1 : -1
  return [...items].sort((a, b) => {
    const aVal = a[field]
    const bVal = b[field]
    if (typeof aVal === 'number' && typeof bVal === 'number') {
      return (aVal - bVal) * multiplier
    }
    return String(aVal).localeCompare(String(bVal)) * multiplier
  })
}

export const filterItems = (items: InventoryItem[], options: FilterOptions): InventoryItem[] => {
  let result = items
  if (options.category) {
    result = result.filter((i) => i.category === options.category)
  }
  if (options.lowStockOnly) {
    result = result.filter((i) => i.quantity <= i.reorderThreshold)
  }
  if (options.search) {
    const lower = options.search.toLowerCase()
    result = result.filter(
      (i) => i.name.toLowerCase().includes(lower) || i.sku.toLowerCase().includes(lower)
    )
  }
  return result
}

export const getDashboardStats = async (): Promise<DashboardStats> => {
  const items = await loadInventory()
  const lowStockItems = items.filter((i) => i.quantity <= i.reorderThreshold)
  const categories = [...new Set(items.map((i) => i.category))].sort()
  return {
    totalItems: items.length,
    totalQuantity: items.reduce((sum, i) => sum + i.quantity, 0),
    lowStockCount: lowStockItems.length,
    categories,
  }
}

