import { createSSR } from 'plaited'
import type { BulkImportItem } from './types'
import {
  loadInventory,
  addItem,
  updateItem,
  deleteItem,
  bulkImport,
  searchItems,
  lookupBySku,
  getLowStockItems,
  getCategories,
  getDashboardStats,
  sortItems,
  filterItems,
} from './inventory'
import { renderDashboard, renderInventoryTable } from './views'

const ssr = createSSR()

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (template: ReturnType<typeof renderDashboard>) => {
  const html = ssr(template)
  return new Response(`<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Inventory Manager</title>
</head>
<body style="margin:0">
  ${html}
</body>
</html>`, {
    headers: { 'Content-Type': 'text/html' },
  })
}

const handleDashboard = async () => {
  const [stats, lowStockItems, items, categories] = await Promise.all([
    getDashboardStats(),
    getLowStockItems(),
    loadInventory(),
    getCategories(),
  ])
  return htmlResponse(renderDashboard(stats, lowStockItems, items, categories))
}

const handleApiItems = async (req: Request) => {
  const url = new URL(req.url)

  if (req.method === 'GET') {
    const search = url.searchParams.get('search')
    const category = url.searchParams.get('category')
    const lowStock = url.searchParams.get('lowStock')
    const sortField = url.searchParams.get('sortField')
    const sortDir = url.searchParams.get('sortDir')

    let items = search
      ? await searchItems(search)
      : await loadInventory()

    items = filterItems(items, {
      category: category ?? undefined,
      lowStockOnly: lowStock === 'true',
    })

    if (sortField) {
      items = sortItems(items, {
        field: sortField as 'name' | 'sku' | 'quantity' | 'category' | 'reorderThreshold',
        direction: (sortDir === 'desc' ? 'desc' : 'asc'),
      })
    }

    return jsonResponse(items)
  }

  if (req.method === 'POST') {
    const body = await req.json() as BulkImportItem
    const item = await addItem(body)
    return jsonResponse(item, 201)
  }

  return jsonResponse({ error: 'Method not allowed' }, 405)
}

const handleApiItemById = async (req: Request, id: string) => {
  if (req.method === 'PATCH') {
    const body = await req.json()
    const item = await updateItem(id, body)
    return jsonResponse(item)
  }

  if (req.method === 'DELETE') {
    await deleteItem(id)
    return jsonResponse({ success: true })
  }

  return jsonResponse({ error: 'Method not allowed' }, 405)
}

const handleBulkImport = async (req: Request) => {
  if (req.method !== 'POST') {
    return jsonResponse({ error: 'Method not allowed' }, 405)
  }
  const body = await req.json() as BulkImportItem[]
  if (!Array.isArray(body)) {
    return jsonResponse({ error: 'Request body must be a JSON array' }, 400)
  }
  const result = await bulkImport(body)
  return jsonResponse(result, 201)
}

const handleBarcodeLookup = async (req: Request) => {
  const url = new URL(req.url)
  const sku = url.searchParams.get('sku')
  if (!sku) {
    return jsonResponse({ error: 'Missing sku parameter' }, 400)
  }
  const item = await lookupBySku(sku)
  if (!item) {
    return jsonResponse({ error: `No item found with SKU "${sku}"` }, 404)
  }
  return jsonResponse(item)
}

const handleLowStock = async () => {
  const items = await getLowStockItems()
  return jsonResponse(items)
}

const handleStats = async () => {
  const stats = await getDashboardStats()
  return jsonResponse(stats)
}

export default {
  port: 3456,
  fetch: async (req: Request): Promise<Response> => {
    const url = new URL(req.url)
    const path = url.pathname

    try {
      if (path === '/' || path === '/dashboard') {
        return handleDashboard()
      }
      if (path === '/api/items' ) {
        return handleApiItems(req)
      }
      if (path === '/api/items/bulk') {
        return handleBulkImport(req)
      }
      if (path === '/api/barcode') {
        return handleBarcodeLookup(req)
      }
      if (path === '/api/low-stock') {
        return handleLowStock()
      }
      if (path === '/api/stats') {
        return handleStats()
      }

      const itemMatch = path.match(/^\/api\/items\/([a-f0-9-]+)$/)
      if (itemMatch) {
        return handleApiItemById(req, itemMatch[1])
      }

      return jsonResponse({ error: 'Not found' }, 404)
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Internal server error'
      return jsonResponse({ error: message }, 500)
    }
  },
}

