export type Category = 'food' | 'transport' | 'housing' | 'entertainment' | 'utilities' | 'other'

export const CATEGORIES: Category[] = ['food', 'transport', 'housing', 'entertainment', 'utilities', 'other']

export type Expense = {
  id: string
  amount: number
  category: Category
  date: string // YYYY-MM-DD
  notes?: string
  createdAt: string // ISO 8601
}

export type ExpenseInput = {
  amount: number
  category: Category
  date: string
  notes?: string
}

export type DateRange = {
  start?: string // YYYY-MM-DD
  end?: string   // YYYY-MM-DD
}

export type FilterOptions = {
  dateRange?: DateRange
  categories?: Category[]
}

export type CategorySummary = {
  category: Category
  total: number
  count: number
  percentage: number
}

export type MonthlySummary = {
  month: string // YYYY-MM
  totalSpent: number
  categoryBreakdowns: CategorySummary[]
  expenseCount: number
}

