import type { Expense, ExpenseInput, FilterOptions } from './types'

const DATA_PATH = new URL('./data/expenses.jsonl', import.meta.url).pathname

const generateId = (): string => crypto.randomUUID()

export const loadExpenses = async (): Promise<Expense[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []

  const text = await file.text()
  return text
    .split('\n')
    .filter((line) => line.trim().length > 0)
    .map((line) => JSON.parse(line) as Expense)
}

export const saveExpense = async (input: ExpenseInput): Promise<Expense> => {
  const expense: Expense = {
    id: generateId(),
    amount: Math.round(input.amount * 100) / 100,
    category: input.category,
    date: input.date,
    notes: input.notes,
    createdAt: new Date().toISOString(),
  }

  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  const existing = exists ? await file.text() : ''
  const newContent = existing.endsWith('\n') || existing === ''
    ? `${existing}${JSON.stringify(expense)}\n`
    : `${existing}\n${JSON.stringify(expense)}\n`

  await Bun.write(DATA_PATH, newContent)
  return expense
}

export const deleteExpense = async (id: string): Promise<boolean> => {
  const expenses = await loadExpenses()
  const filtered = expenses.filter((e) => e.id !== id)
  if (filtered.length === expenses.length) return false

  const content = filtered.map((e) => JSON.stringify(e)).join('\n') + (filtered.length > 0 ? '\n' : '')
  await Bun.write(DATA_PATH, content)
  return true
}

export const filterExpenses = (expenses: Expense[], options: FilterOptions): Expense[] => {
  let result = expenses

  if (options.categories && options.categories.length > 0) {
    result = result.filter((e) => options.categories!.includes(e.category))
  }

  if (options.dateRange?.start) {
    result = result.filter((e) => e.date >= options.dateRange!.start!)
  }

  if (options.dateRange?.end) {
    result = result.filter((e) => e.date <= options.dateRange!.end!)
  }

  return result.sort((a, b) => b.date.localeCompare(a.date))
}

import type { Expense, Category, CategorySummary, MonthlySummary } from './types'
import { CATEGORIES } from './types'

export const computeMonthlySummary = (expenses: Expense[], month: string): MonthlySummary => {
  const monthExpenses = expenses.filter((e) => e.date.startsWith(month))

  const totalSpent = monthExpenses.reduce((sum, e) => sum + e.amount, 0)

  const categoryBreakdowns: CategorySummary[] = CATEGORIES
    .map((category: Category) => {
      const catExpenses = monthExpenses.filter((e) => e.category === category)
      const total = catExpenses.reduce((sum, e) => sum + e.amount, 0)
      return {
        category,
        total: Math.round(total * 100) / 100,
        count: catExpenses.length,
        percentage: totalSpent > 0 ? Math.round((total / totalSpent) * 1000) / 10 : 0,
      }
    })
    .filter((s) => s.total > 0)
    .sort((a, b) => b.total - a.total)

  return {
    month,
    totalSpent: Math.round(totalSpent * 100) / 100,
    categoryBreakdowns,
    expenseCount: monthExpenses.length,
  }
}

export const getAvailableMonths = (expenses: Expense[]): string[] => {
  const months = new Set(expenses.map((e) => e.date.slice(0, 7)))
  return Array.from(months).sort().reverse()
}

import { h } from 'plaited'
import type { CategorySummary } from './types'
import { CATEGORY_COLORS, CATEGORY_LABELS } from './types'

type PieSlice = {
  category: CategorySummary['category']
  percentage: number
  startAngle: number
  endAngle: number
  color: string
}

const describeArc = (cx: number, cy: number, r: number, startAngle: number, endAngle: number): string => {
  const start = polarToCartesian(cx, cy, r, endAngle)
  const end = polarToCartesian(cx, cy, r, startAngle)
  const largeArc = endAngle - startAngle > 180 ? 1 : 0

  return [
    'M', cx, cy,
    'L', start.x, start.y,
    'A', r, r, 0, largeArc, 0, end.x, end.y,
    'Z',
  ].join(' ')
}

const polarToCartesian = (cx: number, cy: number, r: number, angleDeg: number) => {
  const angleRad = ((angleDeg - 90) * Math.PI) / 180
  return {
    x: cx + r * Math.cos(angleRad),
    y: cy + r * Math.sin(angleRad),
  }
}

const computeSlices = (breakdowns: CategorySummary[]): PieSlice[] => {
  const slices: PieSlice[] = []
  let currentAngle = 0

  for (const b of breakdowns) {
    const sliceAngle = (b.percentage / 100) * 360
    slices.push({
      category: b.category,
      percentage: b.percentage,
      startAngle: currentAngle,
      endAngle: currentAngle + sliceAngle,
      color: CATEGORY_COLORS[b.category],
    })
    currentAngle += sliceAngle
  }

  return slices
}

export const renderPieChart = (breakdowns: CategorySummary[], size = 240): ReturnType<typeof h> => {
  if (breakdowns.length === 0) {
    return h('p', { style: { color: '#999', fontStyle: 'italic' } }, 'No data to display')
  }

  const cx = size / 2
  const cy = size / 2
  const r = size / 2 - 10
  const slices = computeSlices(breakdowns)

  // Single category = full circle
  if (slices.length === 1) {
    const s = slices[0]
    return h('div', { style: { display: 'flex', alignItems: 'center', gap: '24px', flexWrap: 'wrap' } },
      h('svg', { width: String(size), height: String(size), viewBox: `0 0 ${size} ${size}` },
        h('circle', { cx: String(cx), cy: String(cy), r: String(r), fill: s.color }),
      ),
      renderLegend(breakdowns),
    )
  }

  return h('div', { style: { display: 'flex', alignItems: 'center', gap: '24px', flexWrap: 'wrap' } },
    h('svg', { width: String(size), height: String(size), viewBox: `0 0 ${size} ${size}` },
      ...slices.map((s) =>
        h('path', {
          d: describeArc(cx, cy, r, s.startAngle, s.endAngle),
          fill: s.color,
          stroke: '#fff',
          'stroke-width': '2',
        }),
      ),
    ),
    renderLegend(breakdowns),
  )
}

const renderLegend = (breakdowns: CategorySummary[]): ReturnType<typeof h> => {
  return h('div', { style: { display: 'flex', flexDirection: 'column', gap: '6px' } },
    ...breakdowns.map((b) =>
