const escapeCSVField = (value: string): string => {
  if (value.includes(',') || value.includes('"') || value.includes('\n')) {
    return `"${value.replace(/"/g, '""')}"`
  }
  return value
}

export const toCSV = (expenses: Expense[]): string => {
  const header = 'Date,Amount,Category,Notes'
  const rows = expenses
    .sort((a, b) => a.date.localeCompare(b.date))
    .map((e) =>
      [
        e.date,
        e.amount.toFixed(2),
        CATEGORY_LABELS[e.category],
        escapeCSVField(e.notes ?? ''),
      ].join(','),
    )

  return [header, ...rows].join('\n') + '\n'
}

export const exportToFile = async (expenses: Expense[], filename?: string): Promise<string> => {
  const name = filename ?? `expenses-${new Date().toISOString().slice(0, 10)}.csv`
  const exportPath = new URL(`./data/${name}`, import.meta.url).pathname
  const csv = toCSV(expenses)
  await Bun.write(exportPath, csv)
  return exportPath
}

