export const addExpense = async (input: ExpenseInput) => {
  if (input.amount <= 0) {
    throw new Error('Amount must be greater than zero')
  }
  if (!CATEGORIES.includes(input.category)) {
    throw new Error(`Invalid category. Must be one of: ${CATEGORIES.join(', ')}`)
  }
  if (!/^\d{4}-\d{2}-\d{2}$/.test(input.date)) {
    throw new Error('Date must be in YYYY-MM-DD format')
  }
  return saveExpense(input)
}

export const removeExpense = async (id: string) => {
  const removed = await deleteExpense(id)
  if (!removed) {
    throw new Error(`Expense with id "${id}" not found`)
  }
  return true
}

export const getExpenses = async (filters?: FilterOptions) => {
  const all = await loadExpenses()
  return filters ? filterExpenses(all, filters) : all.sort((a, b) => b.date.localeCompare(a.date))
}

export const getSummary = async (month?: string) => {
  const all = await loadExpenses()
  const targetMonth = month ?? getCurrentMonth()
  return computeMonthlySummary(all, targetMonth)
}

export const getMonths = async () => {
  const all = await loadExpenses()
  return getAvailableMonths(all)
}

export const exportCSV = async (filters?: FilterOptions, filename?: string) => {
  const expenses = await getExpenses(filters)
  return exportToFile(expenses, filename)
}

export const getCSVString = async (filters?: FilterOptions) => {
  const expenses = await getExpenses(filters)
  return toCSV(expenses)
}

export const render = async (filters?: FilterOptions, month?: string) => {
  const expenses = await getExpenses(filters)
  const targetMonth = month ?? getCurrentMonth()
  const all = await loadExpenses()
  const summary = computeMonthlySummary(all, targetMonth)
  return renderToHTML(expenses, summary, filters)
}

const getCurrentMonth = (): string => {
  const now = new Date()
  return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`
}

