import { type Expense, type ExpenseFilter, type MonthlySummary, type CategorySummary, CATEGORIES } from './types'

const DATA_PATH = `${import.meta.dir}/data/expenses.jsonl`

const generateId = (): string =>
  crypto.randomUUID()

const readAllExpenses = async (): Promise<Expense[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Expense)
}

const appendExpense = async (expense: Expense): Promise<void> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  const line = JSON.stringify(expense) + '\n'
  if (!exists) {
    await Bun.write(DATA_PATH, line)
  } else {
    const existing = await file.text()
    await Bun.write(DATA_PATH, existing + line)
  }
}

const writeAllExpenses = async (expenses: Expense[]): Promise<void> => {
  const content = expenses.map((e) => JSON.stringify(e)).join('\n') + (expenses.length ? '\n' : '')
  await Bun.write(DATA_PATH, content)
}

export const addExpense = async (
  amount: number,
  category: Expense['category'],
  date: string,
  notes?: string,
): Promise<Expense> => {
  const expense: Expense = {
    id: generateId(),
    amount: Math.round(amount * 100) / 100,
    category,
    date,
    notes: notes || undefined,
    createdAt: new Date().toISOString(),
  }
  await appendExpense(expense)
  return expense
}

export const deleteExpense = async (id: string): Promise<boolean> => {
  const expenses = await readAllExpenses()
  const filtered = expenses.filter((e) => e.id !== id)
  if (filtered.length === expenses.length) return false
  await writeAllExpenses(filtered)
  return true
}

export const getExpenses = async (filter?: ExpenseFilter): Promise<Expense[]> => {
  const all = await readAllExpenses()
  return all.filter((e) => {
    if (filter?.startDate && e.date < filter.startDate) return false
    if (filter?.endDate && e.date > filter.endDate) return false
    if (filter?.category && e.category !== filter.category) return false
    return true
  })
}

export const getMonthlySummary = async (month: string): Promise<MonthlySummary> => {
  const expenses = await getExpenses({
    startDate: `${month}-01`,
    endDate: `${month}-31`,
  })

  const total = expenses.reduce((sum, e) => sum + e.amount, 0)

  const categoryTotals = new Map<string, { total: number; count: number }>()
  for (const e of expenses) {
    const entry = categoryTotals.get(e.category) ?? { total: 0, count: 0 }
    entry.total += e.amount
    entry.count += 1
    categoryTotals.set(e.category, entry)
  }

  const categories: CategorySummary[] = CATEGORIES
    .filter((cat) => categoryTotals.has(cat))
    .map((cat) => {
      const entry = categoryTotals.get(cat)!
      return {
        category: cat,
        total: Math.round(entry.total * 100) / 100,
        count: entry.count,
        percentage: total > 0 ? Math.round((entry.total / total) * 1000) / 10 : 0,
      }
    })
    .sort((a, b) => b.total - a.total)

  return {
    month,
    total: Math.round(total * 100) / 100,
    categories,
  }
}

export const exportCsv = async (filter?: ExpenseFilter): Promise<string> => {
  const expenses = await getExpenses(filter)
  const header = 'id,amount,category,date,notes,createdAt'
  const rows = expenses.map((e) => {
    const notes = e.notes ? `"${e.notes.replace(/"/g, '""')}"` : ''
    return `${e.id},${e.amount},${e.category},${e.date},${notes},${e.createdAt}`
  })
  return [header, ...rows].join('\n')
}

import { h } from '@plaited/template'
import { type CategorySummary, CATEGORY_COLORS, CATEGORY_LABELS } from './types'

type SliceData = {
  category: string
  percentage: number
  color: string
  startAngle: number
  endAngle: number
}

const describeArc = (cx: number, cy: number, r: number, startAngle: number, endAngle: number): string => {
  const start = polarToCartesian(cx, cy, r, endAngle)
  const end = polarToCartesian(cx, cy, r, startAngle)
  const largeArc = endAngle - startAngle > 180 ? 1 : 0
  return [
    'M', cx, cy,
    'L', start.x, start.y,
    'A', r, r, 0, largeArc, 0, end.x, end.y,
    'Z',
  ].join(' ')
}

const polarToCartesian = (cx: number, cy: number, r: number, angleDeg: number) => {
  const rad = ((angleDeg - 90) * Math.PI) / 180
  return {
    x: cx + r * Math.cos(rad),
    y: cy + r * Math.sin(rad),
  }
}

export const renderPieChart = (categories: CategorySummary[], size = 280): ReturnType<typeof h> => {
  if (categories.length === 0) {
    return h('div', { style: 'text-align:center;color:#94a3b8;padding:2rem' }, 'No data for this month')
  }

  const cx = size / 2
  const cy = size / 2
  const r = size / 2 - 10

  let currentAngle = 0
  const slices: SliceData[] = categories.map((cat) => {
    const angle = (cat.percentage / 100) * 360
    const slice: SliceData = {
      category: CATEGORY_LABELS[cat.category],
      percentage: cat.percentage,
      color: CATEGORY_COLORS[cat.category],
      startAngle: currentAngle,
      endAngle: currentAngle + angle,
    }
    currentAngle += angle
    return slice
  })

  // Handle single-category case (full circle)
  const paths = slices.map((slice) => {
    if (slice.endAngle - slice.startAngle >= 359.9) {
      return h('circle', {
        cx: String(cx),
        cy: String(cy),
        r: String(r),
        fill: slice.color,
      })
    }
    return h('path', {
      d: describeArc(cx, cy, r, slice.startAngle, slice.endAngle),
      fill: slice.color,
    })
  })

  const legend = categories.map((cat) =>
    h('div', {
      style: 'display:flex;align-items:center;gap:0.5rem;font-size:0.875rem',
    },
      h('span', {
        style: `display:inline-block;width:12px;height:12px;border-radius:2px;background:${CATEGORY_COLORS[cat.category]}`,
      }),
      h('span', {}, `${CATEGORY_LABELS[cat.category]}: $${cat.total.toFixed(2)} (${cat.percentage}%)`),
    ),
  )

  return h('div', { style: 'display:flex;flex-wrap:wrap;gap:1.5rem;align-items:center' },
    h('svg', {
      width: String(size),
      height: String(size),
      viewBox: `0 0 ${size} ${size}`,
      style: 'flex-shrink:0',
    }, ...paths),
    h('div', { style: 'display:flex;flex-direction:column;gap:0.375rem' }, ...legend),
  )
}

