import { addExpense, deleteExpense, getExpenses, getMonthlySummary, exportCsv } from './store'
import { renderPage } from './views'
import { type Category, type ExpenseFilter, CATEGORIES } from './types'

const parseFilter = (url: URL): ExpenseFilter => {
  const startDate = url.searchParams.get('startDate') || undefined
  const endDate = url.searchParams.get('endDate') || undefined
  const rawCategory = url.searchParams.get('category') || undefined
  const category = rawCategory && CATEGORIES.includes(rawCategory as Category)
    ? (rawCategory as Category)
    : undefined
  return { startDate, endDate, category }
}

const currentMonth = (): string => new Date().toISOString().slice(0, 7)

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const { pathname } = url
  const method = req.method

  // GET / — main page
  if (method === 'GET' && pathname === '/') {
    const filter = parseFilter(url)
    const expenses = await getExpenses(filter)
    const summary = await getMonthlySummary(currentMonth())
    const html = renderPage(expenses, summary, filter)
    return new Response(html, {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  }

  // POST /expenses — add expense
  if (method === 'POST' && pathname === '/expenses') {
    const formData = await req.formData()
    const amount = parseFloat(formData.get('amount') as string)
    const category = formData.get('category') as Category
    const date = formData.get('date') as string
    const notes = (formData.get('notes') as string) || undefined

    if (isNaN(amount) || amount <= 0) {
      return new Response('Invalid amount', { status: 400 })
    }
    if (!CATEGORIES.includes(category)) {
      return new Response('Invalid category', { status: 400 })
    }
    if (!date || !/^\d{4}-\d{2}-\d{2}$/.test(date)) {
      return new Response('Invalid date', { status: 400 })
    }

    await addExpense(amount, category, date, notes)
    return Response.redirect(new URL('/', req.url).toString(), 303)
  }

  // POST /expenses/:id/delete — delete expense
  const deleteMatch = pathname.match(/^\/expenses\/([^/]+)\/delete$/)
  if (method === 'POST' && deleteMatch) {
    const id = deleteMatch[1]
    await deleteExpense(id)
    return Response.redirect(new URL('/', req.url).toString(), 303)
  }

  // GET /export/csv — export CSV
  if (method === 'GET' && pathname === '/export/csv') {
    const filter = parseFilter(url)
    const csv = await exportCsv(filter)
    return new Response(csv, {
      headers: {
        'Content-Type': 'text/csv; charset=utf-8',
        'Content-Disposition': `attachment; filename="expenses-${currentMonth()}.csv"`,
      },
    })
  }

  // GET /api/summary/:month — JSON summary
  const summaryMatch = pathname.match(/^\/api\/summary\/(\d{4}-\d{2})$/)
  if (method === 'GET' && summaryMatch) {
    const month = summaryMatch[1]
    const summary = await getMonthlySummary(month)
    return Response.json(summary)
  }

  // GET /api/expenses — JSON list
  if (method === 'GET' && pathname === '/api/expenses') {
    const filter = parseFilter(url)
    const expenses = await getExpenses(filter)
    return Response.json(expenses)
  }

  return new Response('Not Found', { status: 404 })
}

