export const CATEGORIES = [
  'food',
  'transport',
  'housing',
  'entertainment',
  'utilities',
  'other',
] as const

export type Category = (typeof CATEGORIES)[number]

export type Expense = {
  id: string
  amount: number
  category: Category
  date: string // ISO 8601 date string YYYY-MM-DD
  notes?: string
  createdAt: string // ISO 8601 datetime
}

export type ExpenseInput = {
  amount: number
  category: Category
  date: string
  notes?: string
}

export type DateRange = {
  start?: string
  end?: string
}

export type FilterParams = {
  dateRange?: DateRange
  category?: Category
}

export type CategorySummary = {
  category: Category
  total: number
  count: number
  percentage: number
}

export type MonthlySummary = {
  month: string // YYYY-MM
  total: number
