}

import { type Expense, type ExpenseInput, type FilterParams } from './types'

const DATA_PATH = `${import.meta.dir}/data/expenses.jsonl`

const generateId = (): string => crypto.randomUUID()

const parseJsonl = (content: string): Expense[] =>
  content
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Expense)

export const readExpenses = async (): Promise<Expense[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const content = await file.text()
  if (!content.trim()) return []
  return parseJsonl(content)
}

export const addExpense = async (input: ExpenseInput): Promise<Expense> => {
  const expense: Expense = {
    id: generateId(),
    amount: Math.round(input.amount * 100) / 100,
    category: input.category,
    date: input.date,
    notes: input.notes,
    createdAt: new Date().toISOString(),
  }
  const line = JSON.stringify(expense) + '\n'
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  const current = exists ? await file.text() : ''
  await Bun.write(DATA_PATH, current + line)
  return expense
}

export const deleteExpense = async (id: string): Promise<boolean> => {
  const expenses = await readExpenses()
  const filtered = expenses.filter((e) => e.id !== id)
  if (filtered.length === expenses.length) return false
  const content = filtered.map((e) => JSON.stringify(e)).join('\n') + (filtered.length ? '\n' : '')
  await Bun.write(DATA_PATH, content)
  return true
}

export const filterExpenses = (expenses: Expense[], params: FilterParams): Expense[] => {
  let result = expenses

  if (params.category) {
    result = result.filter((e) => e.category === params.category)
  }

  if (params.dateRange?.start) {
    result = result.filter((e) => e.date >= params.dateRange!.start!)
  }

  if (params.dateRange?.end) {
    result = result.filter((e) => e.date <= params.dateRange!.end!)
  }

  return result.sort((a, b) => b.date.localeCompare(a.date))
}

import { type Expense, type MonthlySummary, type CategorySummary, CATEGORIES } from './types'

export const buildMonthlySummary = (expenses: Expense[], month: string): MonthlySummary => {
  const monthExpenses = expenses.filter((e) => e.date.startsWith(month))
  const total = monthExpenses.reduce((sum, e) => sum + e.amount, 0)

  const categories: CategorySummary[] = CATEGORIES.map((category) => {
    const catExpenses = monthExpenses.filter((e) => e.category === category)
    const catTotal = catExpenses.reduce((sum, e) => sum + e.amount, 0)
    return {
      category,
      total: Math.round(catTotal * 100) / 100,
      count: catExpenses.length,
      percentage: total > 0 ? Math.round((catTotal / total) * 1000) / 10 : 0,
    }
  }).filter((c) => c.count > 0)

  return {
    month,
    total: Math.round(total * 100) / 100,
    categories,
  }
}

export const getAvailableMonths = (expenses: Expense[]): string[] => {
  const months = new Set(expenses.map((e) => e.date.slice(0, 7)))
  return [...months].sort().reverse()
}

import { h } from 'plaited'
import type { CategorySummary } from './types'

const COLORS: Record<string, string> = {
  food: '#4CAF50',
  transport: '#2196F3',
  housing: '#FF9800',
  entertainment: '#9C27B0',
  utilities: '#F44336',
  other: '#607D8B',
}

type SliceData = {
  category: string
  percentage: number
  startAngle: number
  endAngle: number
  color: string
}

const describeArc = (cx: number, cy: number, r: number, startAngle: number, endAngle: number): string => {
  const start = polarToCartesian(cx, cy, r, endAngle)
  const end = polarToCartesian(cx, cy, r, startAngle)
  const largeArc = endAngle - startAngle > 180 ? 1 : 0
  return `M ${cx} ${cy} L ${start.x} ${start.y} A ${r} ${r} 0 ${largeArc} 0 ${end.x} ${end.y} Z`
}

const polarToCartesian = (cx: number, cy: number, r: number, angleDeg: number) => {
  const rad = ((angleDeg - 90) * Math.PI) / 180
  return {
    x: cx + r * Math.cos(rad),
    y: cy + r * Math.sin(rad),
  }
}

const buildSlices = (categories: CategorySummary[]): SliceData[] => {
  let currentAngle = 0
  return categories.map((cat) => {
    const sliceAngle = (cat.percentage / 100) * 360
    const slice: SliceData = {
      category: cat.category,
      percentage: cat.percentage,
      startAngle: currentAngle,
      endAngle: currentAngle + sliceAngle,
      color: COLORS[cat.category] ?? '#999',
    }
    currentAngle += sliceAngle
    return slice
  })
}

export const renderPieChart = (categories: CategorySummary[]) => {
  if (categories.length === 0) {
    return h('p', { style: { color: '#888', textAlign: 'center' } }, 'No expenses to chart')
  }

  const cx = 120
  const cy = 120
  const r = 100
  const slices = buildSlices(categories)

  // Handle single-category case (full circle)
  const paths =
    slices.length === 1
      ? [h('circle', { cx: String(cx), cy: String(cy), r: String(r), fill: slices[0].color })]
      : slices.map((slice) =>
          h('path', {
            d: describeArc(cx, cy, r, slice.startAngle, slice.endAngle),
            fill: slice.color,
          })
        )

  const legend = categories.map((cat) =>
    h(
      'div',
      {
        style: {
          display: 'flex',
          alignItems: 'center',
          gap: '8px',
          marginBottom: '4px',
          fontSize: '14px',
        },
      },
      h('span', {
        style: {
          width: '14px',
          height: '14px',
          borderRadius: '3px',
          backgroundColor: COLORS[cat.category] ?? '#999',
          display: 'inline-block',
          flexShrink: '0',
        },
      }),
      h('span', {}, `${cat.category}: $${cat.total.toFixed(2)} (${cat.percentage}%)`)
    )
  )

  return h(
    'div',
    {
      style: {
        display: 'flex',
        flexWrap: 'wrap',
        gap: '24px',
        alignItems: 'center',
        justifyContent: 'center',
      },
    },
    h(
      'svg',
      {
        width: '240',
        height: '240',
        viewBox: '0 0 240 240',
        style: { maxWidth: '100%' },
      },
      ...paths
    ),
    h('div', { style: { minWidth: '180px' } }, ...legend)
  )
}

import type { Expense } from './types'

const escapeCSV = (value: string): string => {
  if (value.includes(',') || value.includes('"') || value.includes('\n')) {
    return `"${value.replace(/"/g, '""')}"`
  }
  return value
}

export const toCSV = (expenses: Expense[]): string => {
  const header = 'id,amount,category,date,notes,createdAt'
  const rows = expenses.map((e) =>
    [
      e.id,
      e.amount.toFixed(2),
      e.category,
      e.date,
      escapeCSV(e.notes ?? ''),
      e.createdAt,
    ].join(',')
  )
  return [header, ...rows].join('\n')
}

export const exportToFile = async (expenses: Expense[], filename?: string): Promise<string> => {
  const name = filename ?? `expenses-${new Date().toISOString().slice(0, 10)}.csv`
  const path = `${import.meta.dir}/data/${name}`
  const csv = toCSV(expenses)
  await Bun.write(path, csv)
  return path
}

