import { type Category, type ExpenseInput, type FilterParams, CATEGORIES } from './types'
import { readExpenses, addExpense, deleteExpense, filterExpenses } from './store'
import { buildMonthlySummary, getAvailableMonths } from './summary'
import { exportToFile } from './export'
import { renderPage } from './view'

const isValidCategory = (value: string): value is Category =>
  CATEGORIES.includes(value as Category)

const isValidDate = (value: string): boolean =>
  /^\d{4}-\d{2}-\d{2}$/.test(value) && !isNaN(Date.parse(value))

const parseExpenseInput = (body: Record<string, unknown>): ExpenseInput | string => {
  const { amount, category, date, notes } = body

  if (typeof amount !== 'number' || amount <= 0) {
    return 'Amount must be a positive number'
  }
  if (typeof category !== 'string' || !isValidCategory(category)) {
    return `Category must be one of: ${CATEGORIES.join(', ')}`
  }
  if (typeof date !== 'string' || !isValidDate(date)) {
    return 'Date must be in YYYY-MM-DD format'
  }

  return {
    amount,
    category,
    date,
    notes: typeof notes === 'string' && notes.trim() ? notes.trim() : undefined,
  }
}

const parseFilters = (url: URL): FilterParams => {
  const start = url.searchParams.get('start') ?? undefined
  const end = url.searchParams.get('end') ?? undefined
  const category = url.searchParams.get('category') ?? undefined

  return {
    dateRange:
      start || end
        ? {
            start: start && isValidDate(start) ? start : undefined,
            end: end && isValidDate(end) ? end : undefined,
          }
        : undefined,
    category: category && isValidCategory(category) ? category : undefined,
  }
}

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string) =>
  new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const { pathname } = url
  const method = req.method

  // GET / — render full page
  if (method === 'GET' && pathname === '/') {
    const allExpenses = await readExpenses()
    const filters = parseFilters(url)
    const filtered = filterExpenses(allExpenses, filters)
    const currentMonth =
      url.searchParams.get('month') ??
      getAvailableMonths(allExpenses)[0] ??
      new Date().toISOString().slice(0, 7)
    const summary = buildMonthlySummary(allExpenses, currentMonth)
    const html = renderPage(filtered, summary, filters)
    return htmlResponse(html)
  }

  // GET /api/expenses — list with optional filters
  if (method === 'GET' && pathname === '/api/expenses') {
    const allExpenses = await readExpenses()
    const filters = parseFilters(url)
    const filtered = filterExpenses(allExpenses, filters)
    return jsonResponse({ expenses: filtered, count: filtered.length })
  }

  // POST /api/expenses — add new expense
  if (method === 'POST' && pathname === '/api/expenses') {
    const body = (await req.json()) as Record<string, unknown>
    const result = parseExpenseInput(body)
    if (typeof result === 'string') {
      return jsonResponse({ error: result }, 400)
    }
    const expense = await addExpense(result)
    return jsonResponse({ expense }, 201)
  }

  // DELETE /api/expenses/:id — delete an expense
  if (method === 'DELETE' && pathname.startsWith('/api/expenses/')) {
    const id = pathname.slice('/api/expenses/'.length)
    const deleted = await deleteExpense(id)
    if (!deleted) {
      return jsonResponse({ error: 'Expense not found' }, 404)
    }
    return jsonResponse({ deleted: true })
  }

  // GET /api/summary — monthly summary
  if (method === 'GET' && pathname === '/api/summary') {
    const allExpenses = await readExpenses()
    const month =
      url.searchParams.get('month') ??
      getAvailableMonths(allExpenses)[0] ??
      new Date().toISOString().slice(0, 7)
    const summary = buildMonthlySummary(allExpenses, month)
    return jsonResponse(summary)
  }

  // GET /api/months — available months
  if (method === 'GET' && pathname === '/api/months') {
    const allExpenses = await readExpenses()
    return jsonResponse({ months: getAvailableMonths(allExpenses) })
  }

  // GET /api/export — CSV export
  if (method === 'GET' && pathname === '/api/export') {
    const allExpenses = await readExpenses()
    const filters = parseFilters(url)
    const filtered = filterExpenses(allExpenses, filters)
    const path = await exportToFile(filtered)
    return new Response(Bun.file(path), {
      headers: {
        'Content-Type': 'text/csv',
        'Content-Disposition': `attachment; filename="${path.split('/').pop()}"`,
      },
    })
  }

  return jsonResponse({ error: 'Not found' }, 404)
}

export default {
  port: 3000,
  fetch: handleRequest,
}

