import { BskyAgent } from '@atproto/api'
import type { SessionData } from './types'

const SESSION_PATH = new URL('../data/session.json', import.meta.url).pathname
const DEFAULT_SERVICE = 'https://bsky.social'

export const createAgent = (service = DEFAULT_SERVICE): BskyAgent => {
  return new BskyAgent({ service })
}

export const login = async (
  identifier: string,
  password: string,
  service = DEFAULT_SERVICE
): Promise<BskyAgent> => {
  const agent = createAgent(service)
  const response = await agent.login({ identifier, password })

  const sessionData: SessionData = {
    did: response.data.did,
    handle: response.data.handle,
    accessJwt: response.data.accessJwt,
    refreshJwt: response.data.refreshJwt,
    service,
  }

  await Bun.write(SESSION_PATH, JSON.stringify(sessionData, null, 2))
  return agent
}

export const restoreSession = async (): Promise<BskyAgent | null> => {
  const file = Bun.file(SESSION_PATH)
  const exists = await file.exists()
  if (!exists) return null

  try {
    const raw = await file.text()
    const sessionData: SessionData = JSON.parse(raw)
    const agent = createAgent(sessionData.service)

    await agent.resumeSession({
      did: sessionData.did,
      handle: sessionData.handle,
      accessJwt: sessionData.accessJwt,
      refreshJwt: sessionData.refreshJwt,
      active: true,
    })

    // Persist refreshed tokens
    if (agent.session) {
      const updated: SessionData = {
        did: agent.session.did,
        handle: agent.session.handle,
        accessJwt: agent.session.accessJwt,
        refreshJwt: agent.session.refreshJwt,
        service: sessionData.service,
      }
      await Bun.write(SESSION_PATH, JSON.stringify(updated, null, 2))
    }

    return agent
  } catch {
    return null
  }
}

export const logout = async (): Promise<void> => {
  const file = Bun.file(SESSION_PATH)
  const exists = await file.exists()
  if (exists) {
    await Bun.write(SESSION_PATH, '')
  }
}

export const getSessionInfo = async (): Promise<SessionData | null> => {
  const file = Bun.file(SESSION_PATH)
  const exists = await file.exists()
  if (!exists) return null

  try {
    const raw = await file.text()
    return JSON.parse(raw) as SessionData
  } catch {
    return null
  }
}

import type { BskyAgent } from '@atproto/api'
import type { FeedPost, TimelineResult } from './types'

const mapPost = (feedItem: Record<string, unknown>): FeedPost | null => {
  const post = feedItem.post as Record<string, unknown> | undefined
  if (!post) return null

  const author = post.author as Record<string, unknown>
  const record = post.record as Record<string, unknown>
  const viewer = post.viewer as Record<string, unknown> | undefined

  return {
    uri: post.uri as string,
    cid: post.cid as string,
    author: {
      did: author.did as string,
      handle: author.handle as string,
      displayName: (author.displayName as string) || (author.handle as string),
      avatar: author.avatar as string | undefined,
    },
    text: (record.text as string) || '',
    createdAt: record.createdAt as string,
    likeCount: (post.likeCount as number) || 0,
    repostCount: (post.repostCount as number) || 0,
    replyCount: (post.replyCount as number) || 0,
    viewerLike: viewer?.like as string | undefined,
  }
}

export const getTimeline = async (
  agent: BskyAgent,
  cursor?: string,
  limit = 25
): Promise<TimelineResult> => {
  const response = await agent.getTimeline({ cursor, limit })

  const posts = (response.data.feed as Record<string, unknown>[])
    .map(mapPost)
    .filter((p): p is FeedPost => p !== null)

  return {
    posts,
    cursor: response.data.cursor,
  }
}

export const getAuthorFeed = async (
  agent: BskyAgent,
  actor: string,
  cursor?: string,
  limit = 25
): Promise<TimelineResult> => {
  const response = await agent.getAuthorFeed({ actor, cursor, limit })

  const posts = (response.data.feed as Record<string, unknown>[])
    .map(mapPost)
    .filter((p): p is FeedPost => p !== null)

  return {
    posts,
    cursor: response.data.cursor,
  }
}

