import type { BskyAgent } from '@atproto/api'
import { login, restoreSession, logout } from './auth'
import { getTimeline } from './feed'
import { createPost, likePost, unlikePost } from './posts'
import { getProfile, followUser, unfollowUser } from './profiles'
import {
  renderFeed,
  renderProfile,
  renderComposer,
  renderLoginForm,
  renderToString,
} from './render'

type HandlerContext = {
  agent: BskyAgent | null
}

const ctx: HandlerContext = { agent: null }

export const handleInit = async (): Promise<string> => {
  ctx.agent = await restoreSession()
  if (ctx.agent) {
    return handleRefreshFeed()
  }
  return renderToString(renderLoginForm())
}

export const handleLogin = async (
  handle: string,
  password: string
): Promise<string> => {
  ctx.agent = await login(handle, password)
  return handleRefreshFeed()
}

export const handleLogout = async (): Promise<string> => {
  await logout()
  ctx.agent = null
  return renderToString(renderLoginForm())
}

export const handleRefreshFeed = async (cursor?: string): Promise<string> => {
  if (!ctx.agent) return renderToString(renderLoginForm())

  const timeline = await getTimeline(ctx.agent, cursor)
  const composerHtml = renderToString(renderComposer())
  const feedHtml = renderToString(renderFeed(timeline.posts, timeline.cursor))
  return composerHtml + feedHtml
}

export const handleCreatePost = async (text: string): Promise<string> => {
  if (!ctx.agent) return renderToString(renderLoginForm())

  await createPost(ctx.agent, text)
  return handleRefreshFeed()
}

export const handleLike = async (
  uri: string,
  cid: string
): Promise<string> => {
  if (!ctx.agent) return renderToString(renderLoginForm())

  await likePost(ctx.agent, uri, cid)
  return handleRefreshFeed()
}

export const handleUnlike = async (likeUri: string): Promise<string> => {
  if (!ctx.agent) return renderToString(renderLoginForm())

  await unlikePost(ctx.agent, likeUri)
  return handleRefreshFeed()
}

export const handleViewProfile = async (actor: string): Promise<string> => {
  if (!ctx.agent) return renderToString(renderLoginForm())

  const profile = await getProfile(ctx.agent, actor)
  return renderToString(renderProfile(profile))
}

export const handleFollow = async (did: string): Promise<string> => {
  if (!ctx.agent) return renderToString(renderLoginForm())

  await followUser(ctx.agent, did)
  return handleViewProfile(did)
}

export const handleUnfollow = async (
  followUri: string,
  did: string
): Promise<string> => {
  if (!ctx.agent) return renderToString(renderLoginForm())

  await unfollowUser(ctx.agent, followUri)
  return handleViewProfile(did)
}

