import { BskyAgent } from '@atproto/api'
import type { Credentials, SessionData } from './types'

const SESSION_PATH = './data/session.json'

export const saveSession = async (session: SessionData): Promise<void> => {
  await Bun.write(SESSION_PATH, JSON.stringify(session, null, 2))
}

export const loadSession = async (): Promise<SessionData | null> => {
  const file = Bun.file(SESSION_PATH)
  if (!(await file.exists())) return null
  try {
    return await file.json() as SessionData
  } catch {
    return null
  }
}

export const createAgent = async (credentials: Credentials): Promise<BskyAgent> => {
  const agent = new BskyAgent({ service: 'https://bsky.social' })

  const saved = await loadSession()
  if (saved) {
    try {
      agent.session = {
        did: saved.did,
        handle: saved.handle,
        accessJwt: saved.accessJwt,
        refreshJwt: saved.refreshJwt,
        active: true,
      }
      await agent.resumeSession(agent.session)
      return agent
    } catch {
      // Session expired, fall through to fresh login
    }
  }

  const response = await agent.login({
    identifier: credentials.identifier,
    password: credentials.password,
  })

  if (response.success && agent.session) {
    await saveSession({
      did: agent.session.did,
      handle: agent.session.handle,
      accessJwt: agent.session.accessJwt,
      refreshJwt: agent.session.refreshJwt,
    })
  }

  return agent
}

import type { BskyAgent } from '@atproto/api'
import type { TimelineOptions, TimelineResponse, PostView } from './types'
import { mapPostView } from './mappers'

export const getTimeline = async (
  agent: BskyAgent,
  options: TimelineOptions = {}
): Promise<TimelineResponse> => {
  const { limit = 25, cursor } = options

  const response = await agent.getTimeline({ limit, cursor })

  const posts: PostView[] = response.data.feed
    .filter((item) => item.post.record && typeof item.post.record === 'object')
    .map((item) => mapPostView(item.post))

  return {
    cursor: response.data.cursor,
    posts,
  }
}

export const getAuthorFeed = async (
  agent: BskyAgent,
  actor: string,
  options: TimelineOptions = {}
): Promise<TimelineResponse> => {
  const { limit = 25, cursor } = options

  const response = await agent.getAuthorFeed({ actor, limit, cursor })

  const posts: PostView[] = response.data.feed
    .filter((item) => item.post.record && typeof item.post.record === 'object')
    .map((item) => mapPostView(item.post))

  return {
    cursor: response.data.cursor,
    posts,
  }
}

import type { AppBskyFeedDefs } from '@atproto/api'
import type { PostView, AuthorView } from './types'

export const mapAuthorView = (author: AppBskyFeedDefs.PostView['author']): AuthorView => ({
  did: author.did,
  handle: author.handle,
  displayName: author.displayName ?? author.handle,
  avatar: author.avatar,
})

export const mapPostView = (post: AppBskyFeedDefs.PostView): PostView => {
  const record = post.record as { text?: string; createdAt?: string }

  return {
    uri: post.uri,
    cid: post.cid,
    author: mapAuthorView(post.author),
    text: record.text ?? '',
    createdAt: record.createdAt ?? new Date().toISOString(),
    likeCount: post.likeCount ?? 0,
    repostCount: post.repostCount ?? 0,
    replyCount: post.replyCount ?? 0,
    isLiked: !!post.viewer?.like,
    likeUri: post.viewer?.like,
  }
}

import type { BskyAgent } from '@atproto/api'
import type { CreatePostOptions, LikeOptions } from './types'

export const createPost = async (
  agent: BskyAgent,
  options: CreatePostOptions
): Promise<{ uri: string; cid: string }> => {
  const record: Record<string, unknown> = {
    text: options.text,
    createdAt: new Date().toISOString(),
  }

  if (options.replyTo) {
    record.reply = {
      root: { uri: options.replyTo.uri, cid: options.replyTo.cid },
      parent: { uri: options.replyTo.uri, cid: options.replyTo.cid },
    }
  }

  const response = await agent.post(record as Parameters<typeof agent.post>[0])

  return {
    uri: response.uri,
    cid: response.cid,
  }
}

export const likePost = async (
  agent: BskyAgent,
  options: LikeOptions
): Promise<{ uri: string }> => {
  const response = await agent.like(options.uri, options.cid)
  return { uri: response.uri }
}

export const unlikePost = async (
  agent: BskyAgent,
  likeUri: string
): Promise<void> => {
  await agent.deleteLike(likeUri)
}

import type { BskyAgent } from '@atproto/api'
import type { ProfileView, ProfileOptions, FollowOptions } from './types'

export const getProfile = async (
  agent: BskyAgent,
  options: ProfileOptions
): Promise<ProfileView> => {
  const response = await agent.getProfile({ actor: options.actor })
  const profile = response.data

  return {
    did: profile.did,
    handle: profile.handle,
    displayName: profile.displayName ?? profile.handle,
    description: profile.description,
    avatar: profile.avatar,
    banner: profile.banner,
    followersCount: profile.followersCount ?? 0,
    followsCount: profile.followsCount ?? 0,
    postsCount: profile.postsCount ?? 0,
    isFollowing: !!profile.viewer?.following,
    followUri: profile.viewer?.following,
  }
}

export const followUser = async (
  agent: BskyAgent,
  options: FollowOptions
): Promise<{ uri: string }> => {
  const response = await agent.follow(options.did)
  return { uri: response.uri }
}

export const unfollowUser = async (
  agent: BskyAgent,
  followUri: string
): Promise<void> => {
  await agent.deleteFollow(followUri)
}

