const formatTimestamp = (iso: string): string => {
  const date = new Date(iso)
  const now = new Date()
  const diffMs = now.getTime() - date.getTime()
  const diffMin = Math.floor(diffMs / 60000)
  const diffHr = Math.floor(diffMs / 3600000)
  const diffDay = Math.floor(diffMs / 86400000)

  if (diffMin < 1) return 'now'
  if (diffMin < 60) return `${diffMin}m`
  if (diffHr < 24) return `${diffHr}h`
  if (diffDay < 7) return `${diffDay}d`
  return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })
}

const renderAvatar = (avatar: string | undefined, displayName: string, size: 'small' | 'large' = 'small') => {
  const sizeStyles = size === 'large' ? styles.profileAvatar : styles.avatar
  const placeholderStyles = size === 'large'
    ? { ...styles.avatarPlaceholder, width: '72px', height: '72px', fontSize: '24px', border: '3px solid #ffffff' }
    : styles.avatarPlaceholder

  if (avatar) {
    return h('img', { src: avatar, alt: displayName, style: sizeStyles })
  }
  const initial = displayName.charAt(0).toUpperCase() || '?'
  return h('div', { style: placeholderStyles }, initial)
}

