          'data-cid': post.cid,
          'data-like-uri': post.likeUri ?? '',
        }, `${heartIcon} `, String(post.likeCount)),
      ),
    ),
  )

  return String(template)
}

export const renderTimeline = (timeline: TimelineResponse, showCompose = true): string => {
  const composeSection = showCompose
    ? h('div', { style: styles.composeArea },
        h('textarea', {
          style: styles.composeInput,
          placeholder: "What's on your mind?",
          maxlength: '300',
          'p-target': 'compose-input',
        }),
        h('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center' } },
          h('span', { style: styles.charCount, 'p-target': 'char-count' }, '0/300'),
          h('button', { style: styles.composeBtn, 'p-trigger': 'post' }, 'Post'),
        ),
      )
    : null

  const postsHtml = timeline.posts.map((post) => renderPost(post))

  const loadMore = timeline.cursor
    ? h('div', { style: { padding: '16px', textAlign: 'center' } },
        h('button', {
          style: { ...styles.actionBtn, margin: '0 auto', fontSize: '15px', color: '#0085ff' },
          'p-trigger': 'load-more',
          'data-cursor': timeline.cursor,
        }, 'Load more'),
      )
    : null

  const template = h(Fragment, {},
    h('header', { style: styles.header },
      h('span', { style: styles.headerTitle }, 'Bluesky'),
    ),
    composeSection,
    ...postsHtml.map((html) => h('div', { innerHTML: html })),
    loadMore,
  )

  const container = h('div', { style: styles.container }, template)
  return String(container)
}

export const renderProfile = (profile: ProfileView): string => {
  const bannerEl = profile.banner
    ? h('img', { src: profile.banner, alt: 'Banner', style: styles.banner })
