  const followBtnStyle = profile.isFollowing ? styles.unfollowBtn : styles.followBtn
  const followLabel = profile.isFollowing ? 'Following' : 'Follow'
  const followTrigger = profile.isFollowing ? 'unfollow' : 'follow'

  const template = h('div', { style: styles.container },
    h('div', { style: styles.profileCard },
      bannerEl,
      h('div', { style: styles.profileInfo },
