const toPostAuthor = (author: {
  did: string
  handle: string
  displayName?: string
  avatar?: string
}): PostAuthor => ({
  did: author.did,
  handle: author.handle,
  displayName: author.displayName ?? author.handle,
  avatar: author.avatar,
})

const toPostView = (feedItem: {
  post: {
    uri: string
    cid: string
    author: { did: string; handle: string; displayName?: string; avatar?: string }
    record: unknown
    likeCount?: number
    repostCount?: number
    replyCount?: number
    viewer?: { like?: string }
    indexedAt: string
  }
}): PostView => {
  const { post } = feedItem
  const record = post.record as { text?: string; createdAt?: string }

  return {
    uri: post.uri,
    cid: post.cid,
    author: toPostAuthor(post.author),
    text: record.text ?? '',
    createdAt: record.createdAt ?? post.indexedAt,
    likeCount: post.likeCount ?? 0,
    repostCount: post.repostCount ?? 0,
    replyCount: post.replyCount ?? 0,
    isLiked: !!post.viewer?.like,
    likeUri: post.viewer?.like,
  }
}

export const getTimeline = async (
  agent: BskyAgent,
  cursor?: string,
  limit: number = 25
): Promise<TimelineResponse> => {
  const response = await agent.getTimeline({ cursor, limit })

  return {
    posts: response.data.feed.map(toPostView),
    cursor: response.data.cursor,
  }
}

export const getAuthorFeed = async (
  agent: BskyAgent,
  actor: string,
  cursor?: string,
  limit: number = 25
): Promise<TimelineResponse> => {
  const response = await agent.getAuthorFeed({ actor, cursor, limit })

  return {
    posts: response.data.feed.map(toPostView),
    cursor: response.data.cursor,
  }
}

export const createPost = async (
  agent: BskyAgent,
  text: string
): Promise<ActionResult> => {
  if (text.length > 300) {
    return { success: false, error: 'Post text exceeds 300 character limit' }
  }

  try {
    const rt = new RichText({ text })
    await rt.detectFacets(agent)

    const response = await agent.post({
      text: rt.text,
      facets: rt.facets,
      createdAt: new Date().toISOString(),
    })

    return { success: true, uri: response.uri }
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Unknown error'
    return { success: false, error: message }
  }
}

export const deletePost = async (
  agent: BskyAgent,
  postUri: string
): Promise<ActionResult> => {
  try {
    await agent.deletePost(postUri)
    return { success: true }
