import type { Thread, Reply, VoteDirection, SortMode } from "./types";

const DATA_PATH = new URL("./data/threads.json", import.meta.url).pathname;

const readThreads = async (): Promise<Thread[]> => {
  const file = Bun.file(DATA_PATH);
  if (!(await file.exists())) return [];
  const text = await file.text();
  return text.trim() ? JSON.parse(text) : [];
};

const writeThreads = async (threads: Thread[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(threads, null, 2));
};

const generateId = (): string =>
  `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;

export const createThread = async (
  title: string,
  body: string,
  author: string
): Promise<Thread> => {
  const threads = await readThreads();
  const thread: Thread = {
    id: generateId(),
    title,
    body,
    author,
    createdAt: new Date().toISOString(),
    upvotes: 0,
    downvotes: 0,
    replies: [],
  };
  threads.push(thread);
  await writeThreads(threads);
  return thread;
};

export const getThread = async (threadId: string): Promise<Thread | null> => {
  const threads = await readThreads();
  return threads.find((t) => t.id === threadId) ?? null;
};

export const createReply = async (
  threadId: string,
  body: string,
  author: string,
  parentReplyId?: string
): Promise<Reply | null> => {
  const threads = await readThreads();
  const thread = threads.find((t) => t.id === threadId);
  if (!thread) return null;

  if (parentReplyId) {
    const parent = thread.replies.find((r) => r.id === parentReplyId);
    if (!parent || parent.parentReplyId !== null) return null;
  }

  const reply: Reply = {
    id: generateId(),
    threadId,
    parentReplyId: parentReplyId ?? null,
    body,
    author,
    createdAt: new Date().toISOString(),
    upvotes: 0,
    downvotes: 0,
  };
  thread.replies.push(reply);
  await writeThreads(threads);
  return reply;
};

export const voteThread = async (
  threadId: string,
  direction: VoteDirection
): Promise<Thread | null> => {
  const threads = await readThreads();
  const thread = threads.find((t) => t.id === threadId);
  if (!thread) return null;

  if (direction === "up") thread.upvotes++;
  else thread.downvotes++;

  await writeThreads(threads);
  return thread;
};

export const voteReply = async (
  threadId: string,
  replyId: string,
  direction: VoteDirection
): Promise<Reply | null> => {
  const threads = await readThreads();
  const thread = threads.find((t) => t.id === threadId);
  if (!thread) return null;

  const reply = thread.replies.find((r) => r.id === replyId);
  if (!reply) return null;

  if (direction === "up") reply.upvotes++;
  else reply.downvotes++;

  await writeThreads(threads);
  return reply;
};

const scoreOf = (item: { upvotes: number; downvotes: number }): number =>
  item.upvotes - item.downvotes;

const latestReplyTime = (thread: Thread): string =>
  thread.replies.length > 0
    ? thread.replies[thread.replies.length - 1].createdAt
    : thread.createdAt;

export const listThreads = async (
  sortBy: SortMode = "newest",
  search?: string
): Promise<Thread[]> => {
  let threads = await readThreads();

  if (search) {
    const query = search.toLowerCase();
    threads = threads.filter((t) => t.title.toLowerCase().includes(query));
  }

  const sorters: Record<SortMode, (a: Thread, b: Thread) => number> = {
    newest: (a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime(),
    top: (a, b) => scoreOf(b) - scoreOf(a),
    active: (a, b) =>
      new Date(latestReplyTime(b)).getTime() - new Date(latestReplyTime(a)).getTime(),
  };

  threads.sort(sorters[sortBy]);
  return threads;
};

