import { createThread, getThread, createReply, voteThread, voteReply, listThreads } from "./store";
import { renderThreadList, renderThread, renderNewThreadForm } from "./view";
import type { SortMode, VoteDirection } from "./types";

const parseBody = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text();
  return Object.fromEntries(new URLSearchParams(text));
};

export const serve = () =>
  Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url);
      const path = url.pathname;

      if (req.method === "GET" && path === "/") {
        const sort = (url.searchParams.get("sort") as SortMode) ?? "newest";
        const search = url.searchParams.get("q") ?? "";
        const threads = await listThreads(sort, search || undefined);
        const html = renderThreadList(threads, sort, search);
        return new Response(html, { headers: { "content-type": "text/html; charset=utf-8" } });
      }

      if (req.method === "GET" && path === "/new") {
        const html = renderNewThreadForm();
        return new Response(html, { headers: { "content-type": "text/html; charset=utf-8" } });
      }

      if (req.method === "GET" && path.startsWith("/thread/")) {
        const threadId = path.slice("/thread/".length);
        const thread = await getThread(threadId);
        if (!thread) return new Response("Thread not found", { status: 404 });
        const html = renderThread(thread);
        return new Response(html, { headers: { "content-type": "text/html; charset=utf-8" } });
      }

      if (req.method === "POST" && path === "/thread") {
        const body = await parseBody(req);
        const { title, author, body: content } = body;
        if (!title || !author || !content) {
          return new Response("Missing required fields", { status: 400 });
        }
        const thread = await createThread(title, content, author);
        return Response.redirect(`/thread/${thread.id}`, 303);
      }

      if (req.method === "POST" && path.startsWith("/thread/") && path.endsWith("/reply")) {
        const threadId = path.slice("/thread/".length, path.length - "/reply".length);
        const body = await parseBody(req);
        const { author, body: content, parentReplyId } = body;
        if (!author || !content) {
          return new Response("Missing required fields", { status: 400 });
        }
        await createReply(threadId, content, author, parentReplyId || undefined);
        return Response.redirect(`/thread/${threadId}`, 303);
      }

      if (req.method === "POST" && path.startsWith("/thread/") && path.endsWith("/vote")) {
        const threadId = path.slice("/thread/".length, path.length - "/vote".length);
        const body = await parseBody(req);
        const direction = body.direction as VoteDirection;
        if (!direction || !["up", "down"].includes(direction)) {
          return new Response("Invalid vote direction", { status: 400 });
        }
        await voteThread(threadId, direction);
        return Response.redirect(req.headers.get("referer") ?? "/", 303);
      }

      if (req.method === "POST" && path.includes("/reply/") && path.endsWith("/vote")) {
        const parts = path.split("/");
        const threadId = parts[2];
        const replyId = parts[4];
        const body = await parseBody(req);
        const direction = body.direction as VoteDirection;
        if (!direction || !["up", "down"].includes(direction)) {
          return new Response("Invalid vote direction", { status: 400 });
        }
        await voteReply(threadId, replyId, direction);
        return Response.redirect(req.headers.get("referer") ?? "/", 303);
      }

      return new Response("Not found", { status: 404 });
    },
  });

