import type {
  Thread,
  Reply,
  ForumData,
  CreateThreadInput,
  CreateReplyInput,
  VoteInput,
  GetThreadsParams,
  SortMode,
} from './types'

const DATA_PATH = `${import.meta.dir}/data/threads.json`

const generateId = (): string => crypto.randomUUID()

const readData = async (): Promise<ForumData> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return { threads: [] }
  return file.json()
}

const writeData = async (data: ForumData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2))
}

export const createThread = async (input: CreateThreadInput): Promise<Thread> => {
  const data = await readData()
  const now = new Date().toISOString()
  const thread: Thread = {
    id: generateId(),
    title: input.title,
    body: input.body,
    author: input.author,
    votes: [],
    score: 0,
    replies: [],
    createdAt: now,
    lastActivityAt: now,
  }
  data.threads.push(thread)
  await writeData(data)
  return thread
}

export const createReply = async (input: CreateReplyInput): Promise<Reply | null> => {
  const data = await readData()
  const thread = data.threads.find((t) => t.id === input.threadId)
  if (!thread) return null

  if (input.parentReplyId) {
    const parentReply = thread.replies.find((r) => r.id === input.parentReplyId)
    if (!parentReply) return null
    if (parentReply.parentReplyId !== null) return null // enforce one level deep
  }

  const reply: Reply = {
    id: generateId(),
    threadId: input.threadId,
    parentReplyId: input.parentReplyId ?? null,
    author: input.author,
    body: input.body,
    votes: [],
    score: 0,
    createdAt: new Date().toISOString(),
  }
  thread.replies.push(reply)
  thread.lastActivityAt = reply.createdAt
  await writeData(data)
  return reply
}

export const vote = async (input: VoteInput): Promise<boolean> => {
  const data = await readData()

  if (input.targetType === 'thread') {
    const thread = data.threads.find((t) => t.id === input.targetId)
    if (!thread) return false
    const existing = thread.votes.findIndex((v) => v.userId === input.userId)
    if (existing !== -1) {
      thread.votes[existing].value = input.value
    } else {
      thread.votes.push({ userId: input.userId, value: input.value })
    }
    thread.score = thread.votes.reduce((sum, v) => sum + v.value, 0)
  } else {
    let found = false
    for (const thread of data.threads) {
      const reply = thread.replies.find((r) => r.id === input.targetId)
      if (reply) {
        const existing = reply.votes.findIndex((v) => v.userId === input.userId)
        if (existing !== -1) {
          reply.votes[existing].value = input.value
        } else {
          reply.votes.push({ userId: input.userId, value: input.value })
        }
        reply.score = reply.votes.reduce((sum, v) => sum + v.value, 0)
        found = true
        break
      }
    }
    if (!found) return false
  }

  await writeData(data)
  return true
}

const sortThreads = (threads: Thread[], mode: SortMode): Thread[] => {
  const sorted = [...threads]
  switch (mode) {
    case 'newest':
      return sorted.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
    case 'most-upvoted':
      return sorted.sort((a, b) => b.score - a.score)
    case 'most-active':
      return sorted.sort((a, b) => new Date(b.lastActivityAt).getTime() - new Date(a.lastActivityAt).getTime())
  }
}

export const getThreads = async (params: GetThreadsParams = {}): Promise<Thread[]> => {
  const data = await readData()
  let threads = data.threads

  if (params.search) {
    const query = params.search.toLowerCase()
    threads = threads.filter((t) => t.title.toLowerCase().includes(query))
  }

  return sortThreads(threads, params.sort ?? 'newest')
}

export const getThread = async (id: string): Promise<Thread | null> => {
  const data = await readData()
  return data.threads.find((t) => t.id === id) ?? null
}

export const deleteThread = async (id: string): Promise<boolean> => {
  const data = await readData()
  const index = data.threads.findIndex((t) => t.id === id)
  if (index === -1) return false
  data.threads.splice(index, 1)
  await writeData(data)
  return true
}

