import { createThread, createReply, vote, getThreads, getThread, deleteThread } from './data'
import { renderThreadList, renderThreadDetail } from './views'
import type { SortMode, CreateThreadInput, CreateReplyInput, VoteInput } from './types'

export type RouteResult = {
  status: number
  headers?: Record<string, string>
  body: string
}

const json = (data: unknown, status = 200): RouteResult => ({
  status,
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify(data),
})

const html = (content: string, status = 200): RouteResult => ({
  status,
  headers: { 'Content-Type': 'text/html; charset=utf-8' },
  body: content,
})

const error = (message: string, status = 400): RouteResult =>
  json({ error: message }, status)

export const handleRequest = async (method: string, path: string, body?: unknown): Promise<RouteResult> => {
  // GET /threads — list threads (HTML)
  if (method === 'GET' && path === '/threads') {
    const url = new URL(path, 'http://localhost')
    const sort = (url.searchParams.get('sort') as SortMode) ?? 'newest'
    const search = url.searchParams.get('search') ?? undefined
    const threads = await getThreads({ sort, search })
    return html(renderThreadList(threads, sort, search))
  }

  // GET /threads?format=json — list threads (JSON)
  if (method === 'GET' && path.startsWith('/threads?')) {
    const url = new URL(path, 'http://localhost')
    const format = url.searchParams.get('format')
    const sort = (url.searchParams.get('sort') as SortMode) ?? 'newest'
    const search = url.searchParams.get('search') ?? undefined
    const threads = await getThreads({ sort, search })
    if (format === 'json') return json(threads)
    return html(renderThreadList(threads, sort, search))
  }

  // GET /threads/:id — single thread
  if (method === 'GET' && path.match(/^\/threads\/[\w-]+$/)) {
    const id = path.split('/')[2]
    const thread = await getThread(id)
    if (!thread) return error('Thread not found', 404)
    return html(renderThreadDetail(thread))
  }

  // GET /api/threads — list threads (JSON API)
  if (method === 'GET' && path.startsWith('/api/threads')) {
    const url = new URL(path, 'http://localhost')
    const sort = (url.searchParams.get('sort') as SortMode) ?? 'newest'
    const search = url.searchParams.get('search') ?? undefined
    const threads = await getThreads({ sort, search })
    return json(threads)
  }

  // GET /api/threads/:id — single thread (JSON API)
  if (method === 'GET' && path.match(/^\/api\/threads\/[\w-]+$/)) {
    const id = path.split('/')[3]
    const thread = await getThread(id)
    if (!thread) return error('Thread not found', 404)
    return json(thread)
  }

  // POST /api/threads — create thread
  if (method === 'POST' && path === '/api/threads') {
    const input = body as CreateThreadInput
    if (!input?.title || !input?.body || !input?.author) {
      return error('title, body, and author are required')
    }
    const thread = await createThread(input)
    return json(thread, 201)
  }

  // POST /api/threads/:id/replies — create reply
  if (method === 'POST' && path.match(/^\/api\/threads\/[\w-]+\/replies$/)) {
    const threadId = path.split('/')[3]
    const input = body as Omit<CreateReplyInput, 'threadId'>
    if (!input?.body || !input?.author) {
      return error('body and author are required')
    }
    const reply = await createReply({ ...input, threadId })
    if (!reply) return error('Thread or parent reply not found', 404)
    return json(reply, 201)
  }

  // POST /api/vote — vote on thread or reply
  if (method === 'POST' && path === '/api/vote') {
    const input = body as VoteInput
    if (!input?.targetId || !input?.targetType || !input?.userId || !input?.value) {
      return error('targetId, targetType, userId, and value are required')
    }
    if (input.value !== 1 && input.value !== -1) {
      return error('value must be 1 or -1')
    }
    const success = await vote(input)
    if (!success) return error('Target not found', 404)
    return json({ success: true })
  }

  // DELETE /api/threads/:id — delete thread
  if (method === 'DELETE' && path.match(/^\/api\/threads\/[\w-]+$/)) {
    const id = path.split('/')[3]
    const success = await deleteThread(id)
    if (!success) return error('Thread not found', 404)
    return json({ success: true })
  }

  return error('Not found', 404)
}

export { createThread, createReply, vote, getThreads, getThread, deleteThread } from './data'
export { renderThreadList, renderThreadDetail } from './views'
export { handleRequest } from './routes'
export type {
  Thread,
  Reply,
  Vote,
  SortMode,
  CreateThreadInput,
  CreateReplyInput,
  VoteInput,
  GetThreadsParams,
  ForumData,
} from './types'

import { handleRequest } from './routes'

const PORT = Number(process.env.PORT ?? 3000)

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)
    const method = req.method
    const path = url.pathname + url.search

    let body: unknown
    if (method === 'POST' || method === 'PUT') {
      try {
        body = await req.json()
      } catch {
        body = undefined
      }
    }

    // Serve root as thread list
    const routePath = path === '/' ? '/threads' : path
    const result = await handleRequest(method, routePath, body)

    return new Response(result.body, {
      status: result.status,
      headers: result.headers,
    })
  },
})

