import type { Thread, Reply, CreateThreadInput, CreateReplyInput, VoteDirection, ListThreadsOptions, ThreadSummary, SortMode } from './types'

const THREADS_PATH = './data/threads.jsonl'
const REPLIES_PATH = './data/replies.jsonl'

const generateId = (): string => crypto.randomUUID()

const readJsonl = async <T>(path: string): Promise<T[]> => {
  const file = Bun.file(path)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  return text
    .split('\n')
    .filter((line) => line.trim().length > 0)
    .map((line) => JSON.parse(line) as T)
}

const appendJsonl = async <T>(path: string, record: T): Promise<void> => {
  const file = Bun.file(path)
  const exists = await file.exists()
  const existing = exists ? await file.text() : ''
  const newLine = JSON.stringify(record) + '\n'
  await Bun.write(path, existing + newLine)
}

const writeAllJsonl = async <T>(path: string, records: T[]): Promise<void> => {
  const content = records.map((r) => JSON.stringify(r)).join('\n') + (records.length > 0 ? '\n' : '')
  await Bun.write(path, content)
}

export const createThread = async (input: CreateThreadInput): Promise<Thread> => {
  const now = new Date().toISOString()
  const thread: Thread = {
    id: generateId(),
    title: input.title,
    body: input.body,
    author: input.author,
    createdAt: now,
    upvotes: 0,
    downvotes: 0,
    lastActivityAt: now,
  }
  await appendJsonl(THREADS_PATH, thread)
  return thread
}

export const createReply = async (input: CreateReplyInput): Promise<Reply> => {
  const now = new Date().toISOString()
  const reply: Reply = {
    id: generateId(),
    threadId: input.threadId,
    parentReplyId: input.parentReplyId ?? null,
    body: input.body,
    author: input.author,
    createdAt: now,
    upvotes: 0,
    downvotes: 0,
  }

  if (input.parentReplyId) {
    const replies = await readJsonl<Reply>(REPLIES_PATH)
    const parent = replies.find((r) => r.id === input.parentReplyId)
    if (parent && parent.parentReplyId !== null) {
      throw new Error('Replies can only be nested one level deep')
    }
  }

  await appendJsonl(REPLIES_PATH, reply)

  const threads = await readJsonl<Thread>(THREADS_PATH)
  const updated = threads.map((t) =>
    t.id === input.threadId ? { ...t, lastActivityAt: now } : t,
  )
  await writeAllJsonl(THREADS_PATH, updated)

  return reply
}

export const voteThread = async (threadId: string, direction: VoteDirection): Promise<Thread> => {
  const threads = await readJsonl<Thread>(THREADS_PATH)
  const idx = threads.findIndex((t) => t.id === threadId)
  if (idx === -1) throw new Error(`Thread not found: ${threadId}`)

  const thread = threads[idx]
  const updated: Thread = direction === 'up'
    ? { ...thread, upvotes: thread.upvotes + 1 }
    : { ...thread, downvotes: thread.downvotes + 1 }

  threads[idx] = updated
  await writeAllJsonl(THREADS_PATH, threads)
  return updated
}

export const voteReply = async (replyId: string, direction: VoteDirection): Promise<Reply> => {
  const replies = await readJsonl<Reply>(REPLIES_PATH)
  const idx = replies.findIndex((r) => r.id === replyId)
  if (idx === -1) throw new Error(`Reply not found: ${replyId}`)

  const reply = replies[idx]
  const updated: Reply = direction === 'up'
    ? { ...reply, upvotes: reply.upvotes + 1 }
    : { ...reply, downvotes: reply.downvotes + 1 }

  replies[idx] = updated
  await writeAllJsonl(REPLIES_PATH, replies)
  return updated
}

export const getThread = async (threadId: string): Promise<{ thread: Thread; replies: Reply[] }> => {
  const threads = await readJsonl<Thread>(THREADS_PATH)
  const thread = threads.find((t) => t.id === threadId)
  if (!thread) throw new Error(`Thread not found: ${threadId}`)

  const allReplies = await readJsonl<Reply>(REPLIES_PATH)
  const replies = allReplies.filter((r) => r.threadId === threadId)

  return { thread, replies }
}

const sortThreads = (summaries: ThreadSummary[], mode: SortMode): ThreadSummary[] => {
  const sorted = [...summaries]
  switch (mode) {
    case 'newest':
      return sorted.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
    case 'most-upvoted':
      return sorted.sort((a, b) => b.score - a.score)
    case 'most-active':
      return sorted.sort((a, b) => new Date(b.lastActivityAt).getTime() - new Date(a.lastActivityAt).getTime())
  }
}

export const listThreads = async (options: ListThreadsOptions = {}): Promise<ThreadSummary[]> => {
  const { sort = 'newest', search } = options

  const threads = await readJsonl<Thread>(THREADS_PATH)
  const allReplies = await readJsonl<Reply>(REPLIES_PATH)

  const replyCountByThread = new Map<string, number>()
  for (const reply of allReplies) {
    replyCountByThread.set(reply.threadId, (replyCountByThread.get(reply.threadId) ?? 0) + 1)
  }

  let summaries: ThreadSummary[] = threads.map((t) => ({
    id: t.id,
    title: t.title,
    author: t.author,
    replyCount: replyCountByThread.get(t.id) ?? 0,
    score: t.upvotes - t.downvotes,
    createdAt: t.createdAt,
    lastActivityAt: t.lastActivityAt,
  }))

  if (search) {
    const query = search.toLowerCase()
    summaries = summaries.filter((s) => s.title.toLowerCase().includes(query))
  }

  return sortThreads(summaries, sort)
}

