export const renderThreadDetail = (thread: Thread, replies: Reply[]) => {
  const topLevelReplies = replies
    .filter((r) => r.parentReplyId === null)
    .sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime())

  const nestedReplies = replies.filter((r) => r.parentReplyId !== null)
  const nestedByParent = new Map<string, Reply[]>()
  for (const r of nestedReplies) {
    const existing = nestedByParent.get(r.parentReplyId!) ?? []
    existing.push(r)
    nestedByParent.set(r.parentReplyId!, existing)
  }

  const threadScore = thread.upvotes - thread.downvotes

  return h('div', { style: styles.container },
    h('button', {
      style: { ...styles.sortButton, marginBottom: '16px' },
      'p-trigger': 'click:back-to-list',
    }, '\u2190 Back to threads'),
    h('div', { style: { ...styles.threadCard, cursor: 'default' } },
      h('div', { style: { display: 'flex', gap: '12px', alignItems: 'flex-start' } },
        h('div', { style: { ...styles.voteGroup, flexDirection: 'column', alignItems: 'center' } },
          h('button', { style: styles.voteButton, 'p-trigger': `click:upvote-thread-${thread.id}` }, '\u25B2'),
          h('span', { style: { ...styles.score, color: threadScore > 0 ? '#16a34a' : threadScore < 0 ? '#dc2626' : '#64748b' } }, String(threadScore)),
          h('button', { style: styles.voteButton, 'p-trigger': `click:downvote-thread-${thread.id}` }, '\u25BC'),
        ),
        h('div', { style: { flex: '1' } },
          h('h2', { style: { ...styles.threadTitle, fontSize: '20px' } }, thread.title),
          h('div', { style: styles.threadMeta },
            h('span', {}, `by ${thread.author}`),
            h('span', {}, formatDate(thread.createdAt)),
          ),
          h('p', { style: styles.threadBody }, thread.body),
        ),
      ),
    ),
    h('div', { style: styles.replyContainer },
      h('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px' } },
        h('h3', { style: { margin: '0', fontSize: '16px' } }, `${replies.length} ${replies.length === 1 ? 'Reply' : 'Replies'}`),
        h('button', {
          style: styles.submitButton,
          'p-trigger': `click:reply-to-thread-${thread.id}`,
        }, 'Reply'),
      ),
      ...topLevelReplies.flatMap((reply) => [
        renderReplyItem(reply, false),
        ...(nestedByParent.get(reply.id) ?? [])
          .sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime())
          .map((nested) => renderReplyItem(nested, true)),
      ]),
    ),
  )
}

