export const kelvinToCelsius = (k: number): number =>
  Math.round((k - 273.15) * 10) / 10

export const kelvinToFahrenheit = (k: number): number =>
  Math.round(((k - 273.15) * 9) / 5 + 32)

export const formatTemp = (kelvin: number): string => {
  const c = kelvinToCelsius(kelvin)
  const f = kelvinToFahrenheit(kelvin)
  return `${c}\u00B0C / ${f}\u00B0F`
}

export const windDirection = (deg: number): string => {
  const directions = ['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW']
  const index = Math.round(deg / 45) % 8
  return directions[index]
}

