const generateForecastEntries = (baseTemp: number, conditions: { id: number; main: string; description: string; icon: string }[]): ForecastEntry[] => {
  const now = Math.floor(Date.now() / 1000)
  const entries: ForecastEntry[] = []

  for (let day = 0; day < 5; day++) {
    for (let hour = 0; hour < 8; hour++) {
      const dt = now + (day * 86400) + (hour * 10800)
      const hourOffset = (hour - 4) * 0.8
      const dayOffset = Math.sin(day * 0.8) * 3
      const temp = baseTemp + dayOffset + hourOffset
      const date = new Date(dt * 1000)
      const dtTxt = date.toISOString().slice(0, 19).replace('T', ' ')
      const condition = conditions[day % conditions.length]

      entries.push({
        dt,
        main: {
          temp: Math.round(temp * 100) / 100,
          feels_like: Math.round((temp - 2) * 100) / 100,
          temp_min: Math.round((temp - 1.5) * 100) / 100,
          temp_max: Math.round((temp + 1.5) * 100) / 100,
          pressure: 1013 + Math.round(Math.sin(day) * 5),
          humidity: 60 + Math.round(Math.sin(day + hour) * 15),
        },
        weather: [condition],
        clouds: { all: condition.main === 'Clear' ? 10 : 60 },
        wind: { speed: 3 + Math.round(Math.random() * 5 * 10) / 10, deg: Math.round(Math.random() * 360) },
        visibility: 10000,
        pop: condition.main === 'Rain' ? 0.7 : 0.1,
        dt_txt: dtTxt,
      })
    }
  }

  return entries
}

export const fetchCurrentWeather = (city: string): CurrentWeather => {
  const info = cityData[city] ?? defaultCity
  const conditions = weatherConditions[city] ?? defaultConditions
  const now = Math.floor(Date.now() / 1000)

  return {
    coord: { lon: info.lon, lat: info.lat },
    weather: [conditions[0]],
    main: {
      temp: info.baseTemp + 2,
      feels_like: info.baseTemp,
      temp_min: info.baseTemp - 1,
      temp_max: info.baseTemp + 4,
      pressure: 1015,
      humidity: 72,
    },
    visibility: 10000,
    wind: { speed: 4.6, deg: 230, gust: 7.2 },
    clouds: { all: conditions[0].main === 'Clear' ? 5 : 50 },
    dt: now,
    sys: { country: info.country, sunrise: now - 21600, sunset: now + 21600 },
    timezone: 0,
    name: city,
  }
}

export const fetchForecast = (city: string): ForecastResponse => {
  const info = cityData[city] ?? defaultCity
  const conditions = weatherConditions[city] ?? defaultConditions
  const entries = generateForecastEntries(info.baseTemp, conditions)

  return {
    cnt: entries.length,
    list: entries,
    city: {
      name: city,
      coord: { lat: info.lat, lon: info.lon },
      country: info.country,
      timezone: 0,
    },
  }
}

import { h } from 'plaited'
import type { DailyForecast } from './types'
import { kelvinToCelsius } from './convert'

type Point = { x: number; y: number }

const SVG_WIDTH = 600
const SVG_HEIGHT = 200
const PADDING = { top: 30, right: 40, bottom: 40, left: 50 }
const CHART_W = SVG_WIDTH - PADDING.left - PADDING.right
const CHART_H = SVG_HEIGHT - PADDING.top - PADDING.bottom

const buildPoints = (values: number[]): { points: Point[]; minVal: number; maxVal: number } => {
  const minVal = Math.min(...values) - 2
  const maxVal = Math.max(...values) + 2
  const range = maxVal - minVal || 1

  const points = values.map((v, i) => ({
    x: PADDING.left + (i / (values.length - 1)) * CHART_W,
    y: PADDING.top + CHART_H - ((v - minVal) / range) * CHART_H,
  }))

  return { points, minVal, maxVal }
}

const polylinePath = (points: Point[]): string =>
  points.map((p, i) => `${i === 0 ? 'M' : 'L'}${p.x.toFixed(1)},${p.y.toFixed(1)}`).join(' ')

const areaPath = (points: Point[]): string => {
  const line = polylinePath(points)
  const lastX = points[points.length - 1].x.toFixed(1)
  const firstX = points[0].x.toFixed(1)
  const bottom = (PADDING.top + CHART_H).toFixed(1)
  return `${line} L${lastX},${bottom} L${firstX},${bottom} Z`
}

export const renderTemperatureChart = (dailyForecasts: DailyForecast[]): ReturnType<typeof h> => {
  const highs = dailyForecasts.map((d) => kelvinToCelsius(d.tempMax))
  const lows = dailyForecasts.map((d) => kelvinToCelsius(d.tempMin))
  const allTemps = [...highs, ...lows]
  const { points: highPoints, minVal, maxVal } = buildPoints(highs)
  const { points: lowPoints } = buildPoints(lows)

  const yTicks = 5
  const range = maxVal - minVal

  return h(
    'svg',
    {
      viewBox: `0 0 ${SVG_WIDTH} ${SVG_HEIGHT}`,
      style: { width: '100%', maxWidth: '600px', height: 'auto', fontFamily: 'system-ui, sans-serif' },
    },
    // Background
    h('rect', { width: SVG_WIDTH, height: SVG_HEIGHT, fill: '#1e293b', rx: '8' }),

    // Grid lines and Y-axis labels
    ...Array.from({ length: yTicks }, (_, i) => {
      const val = minVal + (range * i) / (yTicks - 1)
      const y = PADDING.top + CHART_H - (i / (yTicks - 1)) * CHART_H
      return h(
        'g',
        {},
        h('line', {
          x1: PADDING.left,
          y1: y.toFixed(1),
          x2: (PADDING.left + CHART_W).toString(),
          y2: y.toFixed(1),
          stroke: '#334155',
          'stroke-dasharray': '4,4',
        }),
        h(
          'text',
          { x: (PADDING.left - 8).toString(), y: (y + 4).toFixed(1), fill: '#94a3b8', 'font-size': '11', 'text-anchor': 'end' },
          `${Math.round(val)}\u00B0`,
        ),
      )
    }),

    // X-axis labels
    ...dailyForecasts.map((d, i) => {
      const x = PADDING.left + (i / (dailyForecasts.length - 1)) * CHART_W
      return h(
        'text',
        { x: x.toFixed(1), y: (PADDING.top + CHART_H + 20).toString(), fill: '#94a3b8', 'font-size': '11', 'text-anchor': 'middle' },
        d.dayName,
      )
    }),

    // High temperature area
    h('path', { d: areaPath(highPoints), fill: 'rgba(251,146,60,0.15)' }),
    // Low temperature area
    h('path', { d: areaPath(lowPoints), fill: 'rgba(96,165,250,0.15)' }),

    // High temperature line
    h('path', { d: polylinePath(highPoints), fill: 'none', stroke: '#fb923c', 'stroke-width': '2.5', 'stroke-linecap': 'round', 'stroke-linejoin': 'round' }),
    // Low temperature line
    h('path', { d: polylinePath(lowPoints), fill: 'none', stroke: '#60a5fa', 'stroke-width': '2.5', 'stroke-linecap': 'round', 'stroke-linejoin': 'round' }),

    // Data points - highs
    ...highPoints.map((p, i) =>
      h(
        'g',
        {},
        h('circle', { cx: p.x.toFixed(1), cy: p.y.toFixed(1), r: '4', fill: '#fb923c', stroke: '#1e293b', 'stroke-width': '2' }),
        h(
          'text',
          { x: p.x.toFixed(1), y: (p.y - 10).toFixed(1), fill: '#fb923c', 'font-size': '10', 'text-anchor': 'middle', 'font-weight': 'bold' },
          `${highs[i]}\u00B0`,
        ),
      ),
    ),

    // Data points - lows
    ...lowPoints.map((p, i) =>
      h(
        'g',
        {},
        h('circle', { cx: p.x.toFixed(1), cy: p.y.toFixed(1), r: '4', fill: '#60a5fa', stroke: '#1e293b', 'stroke-width': '2' }),
        h(
          'text',
          { x: p.x.toFixed(1), y: (p.y + 18).toFixed(1), fill: '#60a5fa', 'font-size': '10', 'text-anchor': 'middle', 'font-weight': 'bold' },
          `${lows[i]}\u00B0`,
        ),
      ),
    ),

    // Legend
    h('circle', { cx: (PADDING.left + 10).toString(), cy: '14', r: '4', fill: '#fb923c' }),
    h('text', { x: (PADDING.left + 20).toString(), y: '18', fill: '#94a3b8', 'font-size': '11' }, 'High'),
    h('circle', { cx: (PADDING.left + 65).toString(), cy: '14', r: '4', fill: '#60a5fa' }),
    h('text', { x: (PADDING.left + 75).toString(), y: '18', fill: '#94a3b8', 'font-size': '11' }, 'Low'),
  )
}

