import { createSSR } from 'plaited'
import type { CurrentWeather, ForecastResponse, DailyForecast, DashboardData } from './types'
import { fetchCurrentWeather, fetchForecast } from './data'
import { renderDashboard } from './render'

const DAY_NAMES = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']

const aggregateDailyForecasts = (forecast: ForecastResponse): DailyForecast[] => {
  const dailyMap = new Map<string, { temps: number[]; conditions: Map<string, { count: number; condition: typeof forecast.list[0]['weather'][0] }> }>()

  for (const entry of forecast.list) {
    const date = entry.dt_txt.split(' ')[0]

    if (!dailyMap.has(date)) {
      dailyMap.set(date, { temps: [], conditions: new Map() })
    }

    const day = dailyMap.get(date)!
    day.temps.push(entry.main.temp_min, entry.main.temp_max)

    const condKey = entry.weather[0].main
    const existing = day.conditions.get(condKey)
    if (existing) {
      existing.count++
    } else {
      day.conditions.set(condKey, { count: 1, condition: entry.weather[0] })
    }
  }

  const dailyForecasts: DailyForecast[] = []

  for (const [dateStr, data] of dailyMap) {
    if (dailyForecasts.length >= 5) break

    const dateObj = new Date(dateStr)
    const dayName = DAY_NAMES[dateObj.getUTCDay()]
    const month = dateObj.getUTCMonth() + 1
    const dayNum = dateObj.getUTCDate()

    let dominantCondition = data.conditions.values().next().value!
    for (const entry of data.conditions.values()) {
      if (entry.count > dominantCondition.count) {
        dominantCondition = entry
      }
    }

    dailyForecasts.push({
      date: `${month}/${dayNum}`,
      dayName,
      tempMin: Math.min(...data.temps),
      tempMax: Math.max(...data.temps),
      condition: dominantCondition.condition,
    })
  }

  return dailyForecasts
}

export const getWeatherData = (city: string): DashboardData => {
  const current = fetchCurrentWeather(city)
  const forecast = fetchForecast(city)
  const dailyForecasts = aggregateDailyForecasts(forecast)

  return { current, forecast, dailyForecasts }
}

export const getWeatherDashboard = (city: string): string => {
  const { current, dailyForecasts } = getWeatherData(city)
  const template = renderDashboard(current, dailyForecasts)
  const ssr = createSSR()
  return ssr(template)
}

export const saveCityData = async (city: string): Promise<void> => {
  const data = getWeatherData(city)
  const filePath = `data/${city.toLowerCase().replace(/\s+/g, '-')}.json`
  await Bun.write(filePath, JSON.stringify(data, null, 2))
}

