import type { CurrentWeather, ForecastResponse, DayForecast, WeatherDashboardData } from './types'

const ICON_MAP: Record<string, string> = {
  '01d': '\u2600\uFE0F', '01n': '\uD83C\uDF11',
  '02d': '\u26C5', '02n': '\u26C5',
  '03d': '\u2601\uFE0F', '03n': '\u2601\uFE0F',
  '04d': '\u2601\uFE0F', '04n': '\u2601\uFE0F',
  '09d': '\uD83C\uDF27\uFE0F', '09n': '\uD83C\uDF27\uFE0F',
  '10d': '\uD83C\uDF26\uFE0F', '10n': '\uD83C\uDF26\uFE0F',
  '11d': '\u26C8\uFE0F', '11n': '\u26C8\uFE0F',
  '13d': '\u2744\uFE0F', '13n': '\u2744\uFE0F',
  '50d': '\uD83C\uDF2B\uFE0F', '50n': '\uD83C\uDF2B\uFE0F',
}

export const celsiusToFahrenheit = (c: number): number =>
  Math.round((c * 9) / 5 + 32)

export const getWeatherIcon = (iconCode: string): string =>
  ICON_MAP[iconCode] ?? '\u2600\uFE0F'

export const formatDate = (timestamp: number): string => {
  const date = new Date(timestamp * 1000)
  return date.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' })
}

export const getDayName = (timestamp: number): string => {
  const date = new Date(timestamp * 1000)
  return date.toLocaleDateString('en-US', { weekday: 'short' })
}

export const extractDailyForecasts = (forecast: ForecastResponse): DayForecast[] =>
  forecast.list.map((entry) => ({
    date: formatDate(entry.dt),
    dayName: getDayName(entry.dt),
    tempMin: Math.round(entry.main.temp_min),
    tempMax: Math.round(entry.main.temp_max),
    description: entry.weather[0]?.description ?? 'unknown',
    icon: entry.weather[0]?.icon ?? '01d',
  }))

export const loadSampleData = async (): Promise<WeatherDashboardData> => {
  const file = Bun.file(new URL('./data/sample-weather.json', import.meta.url).pathname)
  const raw = await file.json() as { current: CurrentWeather; forecast: ForecastResponse }
  const dailyForecasts = extractDailyForecasts(raw.forecast)
  return {
    current: raw.current,
    forecast: raw.forecast,
    dailyForecasts,
    city: raw.current.name,
  }
}

export const fetchWeather = async (
  city: string,
  apiKey?: string,
): Promise<WeatherDashboardData> => {
  if (!apiKey) {
    return loadSampleData()
  }

  const base = 'https://api.openweathermap.org/data/2.5'
  const params = `q=${encodeURIComponent(city)}&appid=${apiKey}&units=metric`

  const [currentRes, forecastRes] = await Promise.all([
    fetch(`${base}/weather?${params}`),
    fetch(`${base}/forecast?${params}`),
  ])

  if (!currentRes.ok || !forecastRes.ok) {
    throw new Error(`Failed to fetch weather for "${city}"`)
  }

  const current = (await currentRes.json()) as CurrentWeather
  const forecast = (await forecastRes.json()) as ForecastResponse

  // Extract one entry per day (noon entries)
  const dailyMap = new Map<string, ForecastResponse['list'][number]>()
  for (const entry of forecast.list) {
    const dateKey = entry.dt_txt.split(' ')[0]
    if (!dailyMap.has(dateKey) || entry.dt_txt.includes('12:00:00')) {
      dailyMap.set(dateKey, entry)
    }
  }

  const filteredForecast: ForecastResponse = {
    city: forecast.city,
    list: [...dailyMap.values()].slice(0, 5),
  }

  const dailyForecasts = extractDailyForecasts(filteredForecast)

  return { current, forecast: filteredForecast, dailyForecasts, city: current.name }
}

import type { DayForecast } from './types'

export type ChartPoint = {
  x: number
  y: number
  label: string
  value: number
}

export type ChartDimensions = {
  width: number
  height: number
  padding: { top: number; right: number; bottom: number; left: number }
}

const DEFAULT_DIMENSIONS: ChartDimensions = {
  width: 600,
  height: 200,
  padding: { top: 20, right: 30, bottom: 40, left: 50 },
}

export const buildChartPoints = (
  forecasts: DayForecast[],
  useMax = true,
  dims: ChartDimensions = DEFAULT_DIMENSIONS,
): ChartPoint[] => {
  const temps = useMax ? forecasts.map((f) => f.tempMax) : forecasts.map((f) => f.tempMin)
  const minTemp = Math.min(...temps) - 2
  const maxTemp = Math.max(...temps) + 2
  const tempRange = maxTemp - minTemp || 1

  const plotWidth = dims.width - dims.padding.left - dims.padding.right
  const plotHeight = dims.height - dims.padding.top - dims.padding.bottom

  return forecasts.map((f, i) => ({
    x: dims.padding.left + (i / Math.max(forecasts.length - 1, 1)) * plotWidth,
    y: dims.padding.top + plotHeight - ((temps[i] - minTemp) / tempRange) * plotHeight,
    label: f.dayName,
    value: temps[i],
  }))
}

export const pointsToPolyline = (points: ChartPoint[]): string =>
  points.map((p) => `${p.x},${p.y}`).join(' ')

export const buildSvgChart = (
  forecasts: DayForecast[],
  dims: ChartDimensions = DEFAULT_DIMENSIONS,
): string => {
  const maxPoints = buildChartPoints(forecasts, true, dims)
  const minPoints = buildChartPoints(forecasts, false, dims)

  const maxLine = pointsToPolyline(maxPoints)
  const minLine = pointsToPolyline(minPoints)

  const dots = (points: ChartPoint[], color: string) =>
    points
      .map(
        (p) =>
          `<circle cx="${p.x}" cy="${p.y}" r="4" fill="${color}" />` +
          `<text x="${p.x}" y="${p.y - 10}" text-anchor="middle" fill="${color}" font-size="11" font-family="system-ui, sans-serif">${p.value}\u00B0</text>`,
      )
      .join('')

  const xLabels = maxPoints
    .map(
      (p) =>
        `<text x="${p.x}" y="${dims.height - 8}" text-anchor="middle" fill="#6b7280" font-size="11" font-family="system-ui, sans-serif">${p.label}</text>`,
    )
    .join('')

  return `<svg viewBox="0 0 ${dims.width} ${dims.height}" xmlns="http://www.w3.org/2000/svg" style="width:100%;max-width:${dims.width}px;height:auto">
  <rect width="${dims.width}" height="${dims.height}" rx="8" fill="#f9fafb" />
  <polyline points="${maxLine}" fill="none" stroke="#ef4444" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" />
  <polyline points="${minLine}" fill="none" stroke="#3b82f6" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" />
  ${dots(maxPoints, '#ef4444')}
  ${dots(minPoints, '#3b82f6')}
  ${xLabels}
  <text x="${dims.padding.left - 8}" y="16" fill="#ef4444" font-size="10" font-family="system-ui, sans-serif" text-anchor="end">High</text>
  <text x="${dims.padding.left - 8}" y="28" fill="#3b82f6" font-size="10" font-family="system-ui, sans-serif" text-anchor="end">Low</text>
</svg>`
}

