import { fetchWeather } from './weather-utils'
import { renderDashboard } from './render'

const DEFAULT_CITY = 'London'

const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)

  if (url.pathname === '/api/weather') {
    const city = url.searchParams.get('city') ?? DEFAULT_CITY
    const apiKey = url.searchParams.get('apiKey') ?? undefined
    const data = await fetchWeather(city, apiKey)
    return new Response(JSON.stringify(data), {
      headers: { 'Content-Type': 'application/json' },
    })
  }

  const city = url.searchParams.get('city') ?? DEFAULT_CITY
  const apiKey = url.searchParams.get('apiKey') ?? undefined
  const data = await fetchWeather(city, apiKey)
  const html = renderDashboard(data)

  const page = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Weather Dashboard - ${data.city}</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; }
    body { margin: 0; padding: 24px; background: #f3f4f6; min-height: 100vh; }
  </style>
</head>
<body>${html}</body>
</html>`

  return new Response(page, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

export default {
  port: 3000,
  fetch: handleRequest,
}

