/** Matches OpenWeatherMap weather condition object */
export type WeatherCondition = {
  id: number
  main: string
  description: string
  icon: string
}

/** Matches OpenWeatherMap main weather data */
export type MainWeatherData = {
  temp: number
  feels_like: number
  temp_min: number
  temp_max: number
  pressure: number
  humidity: number
}

/** Matches OpenWeatherMap wind data */
export type WindData = {
  speed: number
  deg: number
  gust?: number
}

/** Matches OpenWeatherMap current weather response */
export type CurrentWeatherResponse = {
  coord: { lon: number; lat: number }
  weather: WeatherCondition[]
  main: MainWeatherData
  wind: WindData
  clouds: { all: number }
  dt: number
  sys: { country: string; sunrise: number; sunset: number }
  name: string
  cod: number
}

/** Single entry in OpenWeatherMap 5-day forecast */
export type ForecastEntry = {
  dt: number
  main: MainWeatherData
  weather: WeatherCondition[]
  wind: WindData
  clouds: { all: number }
  dt_txt: string
}

/** Matches OpenWeatherMap 5-day forecast response */
export type ForecastResponse = {
  cod: string
  cnt: number
  list: ForecastEntry[]
  city: {
    name: string
    country: string
    coord: { lon: number; lat: number }
  }
}

/** Aggregated daily forecast for display */
export type DailyForecast = {
  date: string
  dayName: string
  tempMin: number
  tempMax: number
  humidity: number
  windSpeed: number
  condition: WeatherCondition
}

/** Full weather data bundle for rendering */
export type WeatherData = {
  current: CurrentWeatherResponse
  forecast: ForecastResponse
  daily: DailyForecast[]
