import type {
  CurrentWeatherResponse,
  ForecastResponse,
  ForecastEntry,
  DailyForecast,
} from './types'

const WEATHER_CONDITIONS = [
  { id: 800, main: 'Clear', description: 'clear sky', icon: '01d' },
  { id: 801, main: 'Clouds', description: 'few clouds', icon: '02d' },
  { id: 802, main: 'Clouds', description: 'scattered clouds', icon: '03d' },
  { id: 500, main: 'Rain', description: 'light rain', icon: '10d' },
  { id: 501, main: 'Rain', description: 'moderate rain', icon: '09d' },
  { id: 601, main: 'Snow', description: 'snow', icon: '13d' },
  { id: 701, main: 'Mist', description: 'mist', icon: '50d' },
  { id: 200, main: 'Thunderstorm', description: 'thunderstorm', icon: '11d' },
] as const

/** Seed a deterministic pseudo-random number from a city name */
const seedFromCity = (city: string): number => {
  let hash = 0
  for (let i = 0; i < city.length; i++) {
    hash = (hash * 31 + city.charCodeAt(i)) | 0
  }
  return Math.abs(hash)
}

/** Simple seeded pseudo-random number generator */
const seededRandom = (seed: number): (() => number) => {
  let s = seed
  return () => {
    s = (s * 1103515245 + 12345) & 0x7fffffff
    return s / 0x7fffffff
  }
}

/** Generate placeholder current weather matching OpenWeatherMap format */
export const generateCurrentWeather = (city: string): CurrentWeatherResponse => {
  const seed = seedFromCity(city)
  const rng = seededRandom(seed)

  const conditionIndex = Math.floor(rng() * WEATHER_CONDITIONS.length)
  const baseTemp = 15 + rng() * 20 - 5 // 10-30°C range
  const now = Math.floor(Date.now() / 1000)

  return {
    coord: { lon: -0.1257 + rng() * 50, lat: 51.5085 + rng() * 30 },
    weather: [{ ...WEATHER_CONDITIONS[conditionIndex] }],
    main: {
      temp: Math.round(baseTemp * 10) / 10,
      feels_like: Math.round((baseTemp + (rng() * 4 - 2)) * 10) / 10,
      temp_min: Math.round((baseTemp - 2 - rng() * 3) * 10) / 10,
      temp_max: Math.round((baseTemp + 2 + rng() * 3) * 10) / 10,
      pressure: Math.round(1000 + rng() * 40),
      humidity: Math.round(40 + rng() * 50),
    },
    wind: {
      speed: Math.round(rng() * 15 * 10) / 10,
      deg: Math.round(rng() * 360),
      gust: Math.round(rng() * 20 * 10) / 10,
    },
    clouds: { all: Math.round(rng() * 100) },
    dt: now,
    sys: {
      country: city.length > 5 ? 'US' : 'GB',
      sunrise: now - 25000,
      sunset: now + 18000,
    },
    name: city.charAt(0).toUpperCase() + city.slice(1).toLowerCase(),
    cod: 200,
  }
}

/** Generate placeholder 5-day forecast matching OpenWeatherMap format */
export const generateForecast = (city: string): ForecastResponse => {
  const seed = seedFromCity(city)
  const rng = seededRandom(seed + 1000)

  const now = new Date()
  now.setHours(0, 0, 0, 0)
  const baseTemp = 15 + rng() * 20 - 5

  const list: ForecastEntry[] = []

  for (let day = 0; day < 5; day++) {
    const hours = [0, 3, 6, 9, 12, 15, 18, 21]
    for (const hour of hours) {
      const date = new Date(now)
      date.setDate(date.getDate() + day + 1)
      date.setHours(hour)

      const dayVariation = Math.sin((day / 5) * Math.PI) * 5
      const hourVariation = Math.sin((hour / 24) * Math.PI * 2) * 4
      const temp = baseTemp + dayVariation + hourVariation + (rng() * 3 - 1.5)
      const conditionIndex = Math.floor(rng() * WEATHER_CONDITIONS.length)

      list.push({
        dt: Math.floor(date.getTime() / 1000),
        main: {
          temp: Math.round(temp * 10) / 10,
          feels_like: Math.round((temp + rng() * 3 - 1.5) * 10) / 10,
          temp_min: Math.round((temp - 1.5) * 10) / 10,
          temp_max: Math.round((temp + 1.5) * 10) / 10,
          pressure: Math.round(1005 + rng() * 30),
          humidity: Math.round(45 + rng() * 45),
        },
        weather: [{ ...WEATHER_CONDITIONS[conditionIndex] }],
        wind: {
          speed: Math.round(rng() * 12 * 10) / 10,
          deg: Math.round(rng() * 360),
        },
        clouds: { all: Math.round(rng() * 100) },
        dt_txt: date.toISOString().replace('T', ' ').slice(0, 19),
      })
    }
  }

  return {
    cod: '200',
    cnt: list.length,
    list,
    city: {
      name: city.charAt(0).toUpperCase() + city.slice(1).toLowerCase(),
      country: city.length > 5 ? 'US' : 'GB',
      coord: { lon: -0.1257 + rng() * 50, lat: 51.5085 + rng() * 30 },
    },
  }
}

/** Aggregate 3-hour forecast entries into daily summaries */
export const aggregateDailyForecasts = (forecast: ForecastResponse): DailyForecast[] => {
  const dayMap = new Map<string, ForecastEntry[]>()

  for (const entry of forecast.list) {
    const dateKey = entry.dt_txt.split(' ')[0]
    const existing = dayMap.get(dateKey) ?? []
    existing.push(entry)
    dayMap.set(dateKey, existing)
  }

  const days: DailyForecast[] = []
  const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']

  for (const [dateKey, entries] of dayMap) {
    const date = new Date(dateKey)
    const temps = entries.map((e) => e.main.temp)
    const midday = entries.find((e) => e.dt_txt.includes('12:00')) ?? entries[Math.floor(entries.length / 2)]

    days.push({
      date: dateKey,
      dayName: dayNames[date.getDay()],
      tempMin: Math.round(Math.min(...temps) * 10) / 10,
      tempMax: Math.round(Math.max(...temps) * 10) / 10,
      humidity: Math.round(entries.reduce((sum, e) => sum + e.main.humidity, 0) / entries.length),
      windSpeed: Math.round((entries.reduce((sum, e) => sum + e.wind.speed, 0) / entries.length) * 10) / 10,
      condition: midday.weather[0],
    })
  }

  return days.slice(0, 5)
}

/** Convert Celsius to Fahrenheit */
export const celsiusToFahrenheit = (celsius: number): number =>
  Math.round((celsius * 9 / 5 + 32) * 10) / 10

/** Format temperature with both units */
export const formatTemp = (celsius: number): string =>
  `${celsius}°C / ${celsiusToFahrenheit(celsius)}°F`

/** Format temperature for compact display */
export const formatTempShort = (celsius: number): string =>
  `${Math.round(celsius)}°`

/** Get wind direction label from degrees */
export const windDirection = (deg: number): string => {
  const directions = ['N', 'NNE', 'NE', 'ENE', 'E', 'ESE', 'SE', 'SSE', 'S', 'SSW', 'SW', 'WSW', 'W', 'WNW', 'NW', 'NNW']
  const index = Math.round(deg / 22.5) % 16
  return directions[index]
}

/** Map OpenWeatherMap icon code to an emoji */
export const weatherEmoji = (icon: string): string => {
  const map: Record<string, string> = {
    '01d': '\u2600\uFE0F', '01n': '\uD83C\uDF19',
    '02d': '\u26C5', '02n': '\uD83C\uDF19',
    '03d': '\u2601\uFE0F', '03n': '\u2601\uFE0F',
    '04d': '\u2601\uFE0F', '04n': '\u2601\uFE0F',
    '09d': '\uD83C\uDF27\uFE0F', '09n': '\uD83C\uDF27\uFE0F',
    '10d': '\uD83C\uDF26\uFE0F', '10n': '\uD83C\uDF27\uFE0F',
    '11d': '\u26C8\uFE0F', '11n': '\u26C8\uFE0F',
    '13d': '\u2744\uFE0F', '13n': '\u2744\uFE0F',
    '50d': '\uD83C\uDF2B\uFE0F', '50n': '\uD83C\uDF2B\uFE0F',
  }
  return map[icon] ?? '\uD83C\uDF24\uFE0F'
}

/** Format unix timestamp to readable time */
export const formatTime = (timestamp: number): string => {
  const date = new Date(timestamp * 1000)
  return date.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' })
}

/** Format a date string (YYYY-MM-DD) to readable format */
export const formatDate = (dateStr: string): string => {
  const date = new Date(dateStr)
  return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })
}

import { h } from 'plaited'
import type { DailyForecast } from './types'
import { celsiusToFahrenheit } from './utils'

type ChartPoint = {
  x: number
  y: number
  label: string
  value: number
}

const CHART_WIDTH = 600
const CHART_HEIGHT = 200
const PADDING = { top: 30, right: 40, bottom: 40, left: 50 }

const plotWidth = CHART_WIDTH - PADDING.left - PADDING.right
const plotHeight = CHART_HEIGHT - PADDING.top - PADDING.bottom

/** Map data points to SVG coordinates */
const mapToPoints = (values: number[], labels: string[]): ChartPoint[] => {
  const min = Math.min(...values) - 2
  const max = Math.max(...values) + 2
  const range = max - min || 1

  return values.map((value, i) => ({
    x: PADDING.left + (i / (values.length - 1)) * plotWidth,
    y: PADDING.top + plotHeight - ((value - min) / range) * plotHeight,
    label: labels[i],
    value,
  }))
}

/** Build an SVG polyline path from points */
const pointsToPath = (points: ChartPoint[]): string =>
  points.map((p, i) => `${i === 0 ? 'M' : 'L'}${p.x},${p.y}`).join(' ')

/** Create a filled area path below the line */
const pointsToArea = (points: ChartPoint[]): string => {
  const linePath = pointsToPath(points)
  const lastX = points[points.length - 1].x
  const firstX = points[0].x
  const bottom = PADDING.top + plotHeight
  return `${linePath} L${lastX},${bottom} L${firstX},${bottom} Z`
}

/** Render Y-axis grid lines and labels */
const renderYAxis = (values: number[]) => {
  const min = Math.min(...values) - 2
  const max = Math.max(...values) + 2
  const range = max - min || 1
  const steps = 4
  const elements = []

  for (let i = 0; i <= steps; i++) {
    const value = min + (range * i) / steps
    const y = PADDING.top + plotHeight - (i / steps) * plotHeight

    elements.push(
      h('line', {
        x1: String(PADDING.left),
        y1: String(y),
        x2: String(PADDING.left + plotWidth),
        y2: String(y),
        stroke: '#e2e8f0',
        'stroke-width': '1',
        'stroke-dasharray': '4,4',
      })
    )
    elements.push(
      h('text', {
        x: String(PADDING.left - 8),
        y: String(y + 4),
        'text-anchor': 'end',
        fill: '#94a3b8',
        'font-size': '11',
        'font-family': 'system-ui, sans-serif',
      }, `${Math.round(value)}°`)
    )
  }

  return elements
}

/** Render the temperature trend line chart as SVG */
export const renderTemperatureChart = (daily: DailyForecast[]) => {
  const maxTemps = daily.map((d) => d.tempMax)
  const minTemps = daily.map((d) => d.tempMin)
  const labels = daily.map((d) => d.dayName)

  const maxPoints = mapToPoints(maxTemps, labels)
  const minPoints = mapToPoints(minTemps, labels)

  return h('svg', {
    viewBox: `0 0 ${CHART_WIDTH} ${CHART_HEIGHT}`,
    width: '100%',
    height: 'auto',
    style: 'max-width:600px',
    xmlns: 'http://www.w3.org/2000/svg',
  },
    // Background
    h('rect', {
      width: String(CHART_WIDTH),
      height: String(CHART_HEIGHT),
      fill: '#f8fafc',
      rx: '8',
    }),

    // Y-axis grid
    ...renderYAxis([...maxTemps, ...minTemps]),

    // High temp area fill
    h('path', {
      d: pointsToArea(maxPoints),
      fill: 'rgba(239,68,68,0.08)',
    }),

    // Low temp area fill
    h('path', {
      d: pointsToArea(minPoints),
      fill: 'rgba(59,130,246,0.08)',
    }),

    // High temp line
    h('path', {
      d: pointsToPath(maxPoints),
      fill: 'none',
      stroke: '#ef4444',
      'stroke-width': '2.5',
      'stroke-linecap': 'round',
      'stroke-linejoin': 'round',
    }),

    // Low temp line
    h('path', {
      d: pointsToPath(minPoints),
      fill: 'none',
      stroke: '#3b82f6',
      'stroke-width': '2.5',
      'stroke-linecap': 'round',
      'stroke-linejoin': 'round',
    }),

    // Data points and labels - high temps
    ...maxPoints.flatMap((p) => [
      h('circle', {
        cx: String(p.x),
        cy: String(p.y),
        r: '4',
        fill: '#ef4444',
        stroke: '#fff',
        'stroke-width': '2',
      }),
      h('text', {
        x: String(p.x),
        y: String(p.y - 10),
        'text-anchor': 'middle',
        fill: '#ef4444',
        'font-size': '10',
        'font-weight': '600',
        'font-family': 'system-ui, sans-serif',
      }, `${Math.round(p.value)}°`),
    ]),

    // Data points and labels - low temps
    ...minPoints.flatMap((p) => [
      h('circle', {
        cx: String(p.x),
        cy: String(p.y),
        r: '4',
        fill: '#3b82f6',
        stroke: '#fff',
        'stroke-width': '2',
      }),
      h('text', {
        x: String(p.x),
        y: String(p.y + 16),
        'text-anchor': 'middle',
        fill: '#3b82f6',
        'font-size': '10',
        'font-weight': '600',
        'font-family': 'system-ui, sans-serif',
      }, `${Math.round(p.value)}°`),
    ]),

    // X-axis labels
    ...maxPoints.map((p) =>
      h('text', {
        x: String(p.x),
        y: String(PADDING.top + plotHeight + 20),
        'text-anchor': 'middle',
        fill: '#64748b',
        'font-size': '12',
        'font-weight': '500',
        'font-family': 'system-ui, sans-serif',
      }, p.label)
    ),

    // Legend
    h('circle', { cx: String(CHART_WIDTH - 120), cy: '14', r: '4', fill: '#ef4444' }),
    h('text', {
      x: String(CHART_WIDTH - 112),
      y: '18',
      fill: '#64748b',
      'font-size': '11',
      'font-family': 'system-ui, sans-serif',
    }, 'High'),
    h('circle', { cx: String(CHART_WIDTH - 70), cy: '14', r: '4', fill: '#3b82f6' }),
    h('text', {
      x: String(CHART_WIDTH - 62),
      y: '18',
      fill: '#64748b',
      'font-size': '11',
      'font-family': 'system-ui, sans-serif',
    }, 'Low'),
  )
}

