import type { WeatherData } from './types'
import {
  generateCurrentWeather,
  generateForecast,
  aggregateDailyForecasts,
} from './data'
import { renderDashboard } from './render'

/** Cache file path for weather data */
const CACHE_PATH = 'data/weather-cache.json'

type CacheEntry = {
  city: string
  timestamp: number
  data: WeatherData
}

type CacheStore = {
  entries: Record<string, CacheEntry>
}

/** Read the cache from disk */
const readCache = async (): Promise<CacheStore> => {
  const file = Bun.file(CACHE_PATH)
  if (await file.exists()) {
    return file.json()
  }
  return { entries: {} }
}

/** Write cache to disk */
const writeCache = async (cache: CacheStore): Promise<void> => {
  await Bun.write(CACHE_PATH, JSON.stringify(cache, null, 2))
}

/** Fetch weather data for a city (uses placeholder data) */
export const fetchWeatherData = async (city: string): Promise<WeatherData> => {
  const normalizedCity = city.trim().toLowerCase()

  // Check cache (valid for 30 minutes)
  const cache = await readCache()
  const cached = cache.entries[normalizedCity]
  const thirtyMinutes = 30 * 60 * 1000

  if (cached && Date.now() - cached.timestamp < thirtyMinutes) {
    return cached.data
  }

  // Generate placeholder data (replace with real API call when key is available)
  const current = generateCurrentWeather(normalizedCity)
  const forecast = generateForecast(normalizedCity)
  const daily = aggregateDailyForecasts(forecast)

  const data: WeatherData = { current, forecast, daily }

  // Update cache
  cache.entries[normalizedCity] = {
    city: normalizedCity,
    timestamp: Date.now(),
    data,
  }
  await writeCache(cache)

  return data
}

/** Generate weather dashboard HTML for a city */
export const getWeatherDashboard = async (city: string): Promise<string> => {
  const data = await fetchWeatherData(city)
  return renderDashboard(data)
}

/** CLI entry point */
const main = async () => {
  const city = process.argv[2] ?? 'London'
  console.log(`Fetching weather for: ${city}`)

  const html = await getWeatherDashboard(city)
  const outputPath = `data/${city.toLowerCase().replace(/\s+/g, '-')}-dashboard.html`
  await Bun.write(outputPath, html)

  console.log(`Dashboard written to ${outputPath}`)
}

main().catch(console.error)

