export type ConversionResult = {
  value: number
  formula: string
}

// Base-unit factors: every unit maps to a base unit within its category.
// Length base: meters
const lengthToBase: Record<string, number> = {
  mm: 0.001,
  cm: 0.01,
  m: 1,
  km: 1000,
  in: 0.0254,
  ft: 0.3048,
  yd: 0.9144,
  mi: 1609.344,
}

// Weight base: grams
const weightToBase: Record<string, number> = {
  mg: 0.001,
  g: 1,
  kg: 1000,
  lb: 453.5924,
  oz: 28.3495,
}

// Volume base: milliliters
const volumeToBase: Record<string, number> = {
  ml: 1,
  l: 1000,
  gal: 3785.41,
  qt: 946.353,
  pt: 473.176,
  cup: 236.588,
  tbsp: 14.7868,
  tsp: 4.92892,
}

// Time base: seconds
const timeToBase: Record<string, number> = {
  ms: 0.001,
  s: 1,
  min: 60,
  hr: 3600,
  day: 86400,
  week: 604800,
}

const factorMaps: Record<string, Record<string, number>> = {
  length: lengthToBase,
  weight: weightToBase,
  volume: volumeToBase,
  time: timeToBase,
}

const formatNumber = (n: number): string => {
  if (Number.isInteger(n) && Math.abs(n) < 1e15) return n.toString()
  const fixed = n.toPrecision(10)
  return parseFloat(fixed).toString()
}

const convertTemperature = (value: number, from: string, to: string): ConversionResult => {
  if (from === to) return { value, formula: `${from} = ${to}` }

  const key = `${from}_${to}`
  const formulaMap: Record<string, { calc: (v: number) => number; formula: string }> = {
    C_F: { calc: (v) => v * 9 / 5 + 32, formula: '(C x 9/5) + 32 = F' },
    C_K: { calc: (v) => v + 273.15, formula: 'C + 273.15 = K' },
    F_C: { calc: (v) => (v - 32) * 5 / 9, formula: '(F - 32) x 5/9 = C' },
    F_K: { calc: (v) => (v - 32) * 5 / 9 + 273.15, formula: '(F - 32) x 5/9 + 273.15 = K' },
    K_C: { calc: (v) => v - 273.15, formula: 'K - 273.15 = C' },
    K_F: { calc: (v) => (v - 273.15) * 9 / 5 + 32, formula: '(K - 273.15) x 9/5 + 32 = F' },
  }

  const entry = formulaMap[key]
  if (!entry) return { value: NaN, formula: 'Unknown conversion' }
  return { value: entry.calc(value), formula: entry.formula }
}

const convertByFactor = (
  value: number,
  from: string,
  to: string,
  category: string,
): ConversionResult => {
  const map = factorMaps[category]
  if (!map || !map[from] || !map[to]) return { value: NaN, formula: 'Unknown conversion' }

  if (from === to) return { value, formula: `1 ${from} = 1 ${to}` }

  const factor = map[from] / map[to]
  const result = value * factor
  const formulaFactor = formatNumber(factor)
  return {
    value: result,
    formula: `1 ${from} = ${formulaFactor} ${to} → multiply by ${formulaFactor}`,
  }
}

export const convert = (
  value: number,
  from: string,
  to: string,
  category: Category,
): ConversionResult => {
  if (category === 'temperature') return convertTemperature(value, from, to)
  return convertByFactor(value, from, to, category)
}

