import { createSSR } from 'plaited'
import { renderConverter } from './render'
import { convert } from './converter'
import { categories, categoryKeys } from './units'
import type { Category } from './units'
import type { ConversionResult } from './converter'

export type ConvertRequest = {
  value: number
  from: string
  to: string
  category: Category
}

export type ConvertResponse = ConversionResult & {
  input: number
  from: string
  to: string
  category: Category
}

const defaultState = (category: Category = 'length') => ({
  category,
  value: '',
  from: categories[category].units[0].symbol,
  to: categories[category].units[1]?.symbol ?? categories[category].units[0].symbol,
})

/** Perform a unit conversion and return the result with formula. */
export const convertUnits = (req: ConvertRequest): ConvertResponse => {
  const result = convert(req.value, req.from, req.to, req.category)
  return {
    ...result,
    input: req.value,
    from: req.from,
    to: req.to,
    category: req.category,
  }
}

/** Log a conversion to the history file. */
const logConversion = async (entry: ConvertResponse): Promise<void> => {
  const line = JSON.stringify({ ...entry, timestamp: new Date().toISOString() }) + '\n'
  const file = Bun.file('data/history.jsonl')
  const existing = (await file.exists()) ? await file.text() : ''
  await Bun.write(file, existing + line)
}

/** Render the converter UI as an HTML string. */
export const renderHTML = (category: Category = 'length', value = '', from?: string, to?: string): string => {
  const cat = categories[category]
  const state = {
    category,
    value,
    from: from ?? cat.units[0].symbol,
    to: to ?? (cat.units[1]?.symbol ?? cat.units[0].symbol),
  }
  const ssr = createSSR()
  return ssr(renderConverter(state))
}

/** Main entry: HTTP handler for the converter. */
export const handler = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)

  if (req.method === 'POST' && url.pathname === '/convert') {
    const body = (await req.json()) as ConvertRequest
    const result = convertUnits(body)
    await logConversion(result)
    return new Response(JSON.stringify(result), {
      headers: { 'Content-Type': 'application/json' },
    })
  }

  const category = (url.searchParams.get('category') as Category) ?? 'length'
  const value = url.searchParams.get('value') ?? ''
  const from = url.searchParams.get('from') ?? undefined
  const to = url.searchParams.get('to') ?? undefined

  const validCategory = categoryKeys.includes(category) ? category : 'length'
  const html = renderHTML(validCategory, value, from, to)

  return new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

