export const categories: Record<Category, CategoryDef> = {
  length: { label: 'Length', baseUnit: 'm', units: lengthUnits },
  weight: { label: 'Weight', baseUnit: 'g', units: weightUnits },
  temperature: { label: 'Temperature', baseUnit: 'C', units: temperatureUnits },
  volume: { label: 'Volume', baseUnit: 'l', units: volumeUnits },
  time: { label: 'Time', baseUnit: 's', units: timeUnits },
};

export const getUnitsForCategory = (category: Category): UnitDef[] =>
  categories[category].units;

export const findUnit = (category: Category, symbol: string): UnitDef | undefined =>
  categories[category].units.find((u) => u.symbol === symbol);

export const buildFormula = (
  fromUnit: UnitDef,
  toUnit: UnitDef,
  baseUnitSymbol: string,
): string => {
  if (fromUnit.symbol === toUnit.symbol) return `${fromUnit.symbol} = ${toUnit.symbol}`;

  const toBasePart = fromUnit.symbol === baseUnitSymbol
    ? 'v'
    : `${fromUnit.formulaToBase.replace(/v/g, fromUnit.symbol)}`;

  const fromBasePart = toUnit.symbol === baseUnitSymbol
    ? `${baseUnitSymbol}`
    : `${toUnit.formulaFromBase.replace(/v/g, baseUnitSymbol)}`;

  if (fromUnit.symbol === baseUnitSymbol) {
    return `${toUnit.symbol} = ${toUnit.formulaFromBase.replace(/v/g, fromUnit.symbol)}`;
  }
  if (toUnit.symbol === baseUnitSymbol) {
    return `${toUnit.symbol} = ${fromUnit.formulaToBase.replace(/v/g, fromUnit.symbol)}`;
  }

  return `${fromUnit.symbol} -> ${baseUnitSymbol}: ${fromUnit.formulaToBase.replace(/v/g, fromUnit.symbol)}, then ${baseUnitSymbol} -> ${toUnit.symbol}: ${toUnit.formulaFromBase.replace(/v/g, baseUnitSymbol)}`;
};

export const convert = (
  value: number,
  category: Category,
  fromSymbol: string,
  toSymbol: string,
): ConversionResult => {
  const fromUnit = findUnit(category, fromSymbol);
  const toUnit = findUnit(category, toSymbol);

  if (!fromUnit || !toUnit) {
    throw new Error(`Unknown unit: ${fromSymbol} or ${toSymbol} in category ${category}`);
  }

  const baseValue = fromUnit.toBase(value);
  const outputValue = toUnit.fromBase(baseValue);

  const formula = buildFormula(fromUnit, toUnit, categories[category].baseUnit);

  return {
    inputValue: value,
    outputValue,
    fromUnit: fromSymbol,
    toUnit: toSymbol,
    formula,
    category,
  };
};

export const formatValue = (value: number): string => {
  if (Number.isInteger(value)) return value.toString();
  if (Math.abs(value) < 0.0001 || Math.abs(value) > 1e10) return value.toExponential(6);
  return parseFloat(value.toPrecision(10)).toString();
};

