import { renderConverter } from './ui.js';
import type { Category } from './converter.js';

type ConvertRequest = {
  category?: Category;
  value?: string;
  from?: string;
  to?: string;
};

const VALID_CATEGORIES: Category[] = ['length', 'weight', 'temperature', 'volume', 'time'];

const isValidCategory = (cat: string | undefined): cat is Category =>
  !!cat && VALID_CATEGORIES.includes(cat as Category);

const parseQuery = (url: URL): ConvertRequest => ({
  category: isValidCategory(url.searchParams.get('category') ?? undefined)
    ? (url.searchParams.get('category') as Category)
    : 'length',
  value: url.searchParams.get('value') ?? '1',
  from: url.searchParams.get('from') ?? undefined,
  to: url.searchParams.get('to') ?? undefined,
});

const historyPath = new URL('./data/history.jsonl', import.meta.url).pathname;

const logConversion = async (params: ConvertRequest) => {
  const entry = JSON.stringify({
    ...params,
    timestamp: new Date().toISOString(),
  });
  const file = Bun.file(historyPath);
  const existing = await file.exists() ? await file.text() : '';
  await Bun.write(historyPath, existing + entry + '\n');
};

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url);

  if (url.pathname === '/api/convert' && req.method === 'GET') {
    const { convert } = await import('./converter.js');
    const params = parseQuery(url);
    const category = params.category ?? 'length';
    const value = parseFloat(params.value ?? '1') || 0;
    const { categories: cats } = await import('./converter.js');
    const units = cats[category].units;
    const from = params.from ?? units[0].symbol;
    const to = params.to ?? units[1].symbol;

    try {
      const result = convert(value, category, from, to);
      await logConversion(params);
      return new Response(JSON.stringify(result), {
        headers: { 'Content-Type': 'application/json' },
      });
    } catch (err) {
      return new Response(
        JSON.stringify({ error: (err as Error).message }),
        { status: 400, headers: { 'Content-Type': 'application/json' } },
      );
    }
  }

  // HTML page
  const params = parseQuery(url);
  const html = renderConverter(
    params.category as Category,
    params.value,
    params.from,
    params.to,
  );

  const page = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Unit Converter</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { background: #f5f5fa; min-height: 100vh; display: flex; align-items: center; justify-content: center; padding: 20px; }
    select, input, button { font-family: inherit; }
    input:focus, select:focus { border-color: #667eea !important; }
    button:hover { opacity: 0.85; }
  </style>
</head>
<body>
  <div id="app">${html}</div>
  <script>
    const app = document.getElementById('app');

    const getState = () => {
      const params = new URLSearchParams(window.location.search);
      return {
        category: params.get('category') || 'length',
        value: params.get('value') || '1',
        from: params.get('from') || '',
        to: params.get('to') || '',
      };
    };

    const navigate = (params) => {
      const state = { ...getState(), ...params };
      const qs = new URLSearchParams(state).toString();
      window.location.search = qs;
    };

    app.addEventListener('click', (e) => {
      const btn = e.target.closest('[p-trigger*="selectCategory"]');
      if (btn) {
        navigate({ category: btn.dataset.category, from: '', to: '' });
      }
      const swap = e.target.closest('[p-trigger*="swapUnits"]');
      if (swap) {
        const state = getState();
        navigate({ from: state.to, to: state.from });
      }
    });

    app.addEventListener('change', (e) => {
      const el = e.target;
      if (el.closest('[p-trigger*="updateFromUnit"]')) navigate({ from: el.value });
      if (el.closest('[p-trigger*="updateToUnit"]')) navigate({ to: el.value });
    });

    let debounce;
    app.addEventListener('input', (e) => {
      const el = e.target;
      if (el.closest('[p-trigger*="updateValue"]')) {
        clearTimeout(debounce);
        debounce = setTimeout(() => navigate({ value: el.value }), 400);
      }
    });
  </script>
</body>
</html>`;

  return new Response(page, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  });
};

const port = parseInt(process.env.PORT ?? '3000', 10);

Bun.serve({
  port,
  fetch: handleRequest,
});

console.log(`Unit Converter running at http://localhost:${port}`);

