import { categories, type Category, type UnitDef } from './units'

export type ConversionResult = {
  inputValue: number
  outputValue: number
  fromUnit: string
  toUnit: string
  formula: string
  category: Category
}

const findUnit = (category: Category, symbol: string): UnitDef | undefined =>
  categories[category].units.find((u) => u.symbol === symbol)

const formatNumber = (n: number): string => {
  if (Number.isInteger(n) && Math.abs(n) < 1e15) return n.toString()
  const fixed = n.toPrecision(10)
  return parseFloat(fixed).toString()
}

const buildTemperatureFormula = (from: string, to: string): string => {
  const formulaMap: Record<string, string> = {
    'C->F': '(value * 9/5) + 32',
    'F->C': '(value - 32) * 5/9',
    'C->K': 'value + 273.15',
    'K->C': 'value - 273.15',
    'F->K': '(value - 32) * 5/9 + 273.15',
    'K->F': '(value - 273.15) * 9/5 + 32',
    'C->C': 'value',
    'F->F': 'value',
    'K->K': 'value',
  }
  return formulaMap[`${from}->${to}`] ?? 'value'
}

const buildLinearFormula = (
  from: UnitDef,
  to: UnitDef,
  baseUnit: string,
): string => {
  const fromFactor = from.toBase as number
  const toFactor = to.toBase as number
  const ratio = fromFactor / toFactor

  if (from.symbol === to.symbol) return 'value'
  if (from.symbol === baseUnit) return `value / ${toFactor}`
  if (to.symbol === baseUnit) return `value * ${fromFactor}`
  return `value * ${formatNumber(ratio)}`
}

export const convert = (
  category: Category,
  fromSymbol: string,
  toSymbol: string,
  value: number,
): ConversionResult | null => {
  const catDef = categories[category]
  const fromUnit = findUnit(category, fromSymbol)
  const toUnit = findUnit(category, toSymbol)
  if (!fromUnit || !toUnit) return null

  let outputValue: number
  let formula: string

  if (category === 'temperature') {
    const toBase = fromUnit.toBaseCustom!
    const fromBase = toUnit.fromBase!
    outputValue = fromBase(toBase(value))
    formula = buildTemperatureFormula(fromSymbol, toSymbol)
  } else {
    const fromFactor = fromUnit.toBase as number
    const toFactor = toUnit.toBase as number
    const baseValue = value * fromFactor
    outputValue = baseValue / toFactor
    formula = buildLinearFormula(fromUnit, toUnit, catDef.baseUnit)
  }

  return {
    inputValue: value,
    outputValue,
    fromUnit: fromSymbol,
    toUnit: toSymbol,
    formula,
    category,
  }
}

export const listCategories = (): { key: Category; label: string }[] =>
  (Object.keys(categories) as Category[]).map((key) => ({
    key,
    label: categories[key].label,
  }))

export const listUnits = (category: Category): { symbol: string; name: string }[] =>
  categories[category].units.map((u) => ({ symbol: u.symbol, name: u.name }))

