export const getDefaultUnits = (
  category: Category,
): { fromUnit: string; toUnit: string } => {
  const units = listUnits(category)
  const defaults: Record<Category, [string, string]> = {
    length: ['m', 'ft'],
    weight: ['kg', 'lb'],
    temperature: ['C', 'F'],
    volume: ['l', 'gal'],
    time: ['hr', 'min'],
  }
  const [from, to] = defaults[category] ?? [units[0].symbol, units[1]?.symbol ?? units[0].symbol]
  return { fromUnit: from, toUnit: to }
}

import { renderConverter, getDefaultUnits, type RenderParams } from './render'
import { convert, listCategories, listUnits } from './converter'
import { type Category } from './units'

export type AppState = {
  category: Category
  fromUnit: string
  toUnit: string
  value: number
}

const createInitialState = (): AppState => {
  const category: Category = 'length'
  const { fromUnit, toUnit } = getDefaultUnits(category)
  return { category, fromUnit, toUnit, value: 1 }
}

const saveConversion = async (state: AppState, result: number) => {
  const entry = {
    timestamp: new Date().toISOString(),
    category: state.category,
    from: state.fromUnit,
    to: state.toUnit,
    inputValue: state.value,
    outputValue: result,
  }
  const file = Bun.file('./data/history.jsonl')
  const existing = (await file.exists()) ? await file.text() : ''
  await Bun.write(file, existing + JSON.stringify(entry) + '\n')
}

export const handleRequest = async (
  action: string,
  payload: Record<string, string>,
  state: AppState,
): Promise<{ html: string; state: AppState }> => {
  let nextState = { ...state }

  switch (action) {
    case 'category-select': {
      const newCategory = payload.value as Category
      const { fromUnit, toUnit } = getDefaultUnits(newCategory)
      nextState = { category: newCategory, fromUnit, toUnit, value: 1 }
      break
    }
    case 'unit-change': {
      const field = payload.name as 'fromUnit' | 'toUnit'
      nextState[field] = payload.value
      break
    }
    case 'value-input': {
      const parsed = parseFloat(payload.value)
      if (!isNaN(parsed)) nextState.value = parsed
      break
    }
    case 'swap-units': {
      const { fromUnit, toUnit } = nextState
      nextState.fromUnit = toUnit
      nextState.toUnit = fromUnit
      break
    }
  }

  const result = convert(
    nextState.category,
    nextState.fromUnit,
    nextState.toUnit,
    nextState.value,
  )
  if (result) {
    await saveConversion(nextState, result.outputValue)
  }

  const html = renderConverter(nextState)
  return { html, state: nextState }
}

export const init = (): { html: string; state: AppState } => {
  const state = createInitialState()
  const html = renderConverter(state)
  return { html, state }
}

