export const getDaysInMonth = (year: number, month: number): number =>
  new Date(year, month + 1, 0).getDate();

export const getFirstDayOfMonth = (year: number, month: number): number =>
  new Date(year, month, 1).getDay();

export const formatDate = (year: number, month: number, day: number): string => {
  const m = String(month + 1).padStart(2, "0");
  const d = String(day).padStart(2, "0");
  return `${year}-${m}-${d}`;
};

export const parseDate = (dateStr: string): { year: number; month: number; day: number } => {
  const [year, month, day] = dateStr.split("-").map(Number);
  return { year, month: month - 1, day };
};

export const getTodayStr = (): string => {
  const now = new Date();
  return formatDate(now.getFullYear(), now.getMonth(), now.getDate());
};

const addDays = (dateStr: string, days: number): string => {
  const d = new Date(dateStr);
  d.setDate(d.getDate() + days);
  return formatDate(d.getFullYear(), d.getMonth(), d.getDate());
};

const addMonths = (dateStr: string, months: number): string => {
  const d = new Date(dateStr);
  d.setMonth(d.getMonth() + months);
  return formatDate(d.getFullYear(), d.getMonth(), d.getDate());
};

const isRecurrenceMatch = (eventDate: string, targetDate: string, recurrence: Recurrence): boolean => {
  if (recurrence === "none") return eventDate === targetDate;
  if (targetDate < eventDate) return false;

  const event = new Date(eventDate);
  const target = new Date(targetDate);

  if (recurrence === "daily") return true;

  if (recurrence === "weekly") {
    return event.getDay() === target.getDay();
  }

  if (recurrence === "monthly") {
    return event.getDate() === target.getDate();
  }

  return false;
};

export const getEventsOnDate = (events: CalendarEvent[], dateStr: string): CalendarEvent[] =>
  events.filter((evt) => isRecurrenceMatch(evt.date, dateStr, evt.recurrence));

export const getCategoriesOnDate = (events: CalendarEvent[], dateStr: string): EventCategory[] => {
  const matched = getEventsOnDate(events, dateStr);
  return [...new Set(matched.map((e) => e.category))];
};

export const sortEventsByTime = (events: CalendarEvent[]): CalendarEvent[] =>
  [...events].sort((a, b) => a.startTime.localeCompare(b.startTime));

export const filterByCategory = (events: CalendarEvent[], category: EventCategory): CalendarEvent[] =>
  events.filter((e) => e.category === category);

export const filterByDateRange = (events: CalendarEvent[], start: string, end: string): CalendarEvent[] =>
  events.filter((e) => e.date >= start && e.date <= end);

export const buildMonthGrid = (year: number, month: number, events: CalendarEvent[]): DayCell[] => {
  const daysInMonth = getDaysInMonth(year, month);
  const firstDay = getFirstDayOfMonth(year, month);
  const today = getTodayStr();
  const cells: DayCell[] = [];

  // Previous month padding
  const prevMonth = month === 0 ? 11 : month - 1;
  const prevYear = month === 0 ? year - 1 : year;
  const daysInPrevMonth = getDaysInMonth(prevYear, prevMonth);

  for (let i = firstDay - 1; i >= 0; i--) {
    const day = daysInPrevMonth - i;
    const date = formatDate(prevYear, prevMonth, day);
    cells.push({
      date,
      dayNumber: day,
      isCurrentMonth: false,
      isToday: date === today,
      eventCategories: getCategoriesOnDate(events, date),
    });
  }

  // Current month days
  for (let day = 1; day <= daysInMonth; day++) {
    const date = formatDate(year, month, day);
    cells.push({
      date,
      dayNumber: day,
      isCurrentMonth: true,
      isToday: date === today,
      eventCategories: getCategoriesOnDate(events, date),
    });
  }

  // Next month padding to fill 6 rows
  const remaining = 42 - cells.length;
  const nextMonth = month === 11 ? 0 : month + 1;
  const nextYear = month === 11 ? year + 1 : year;

  for (let day = 1; day <= remaining; day++) {
    const date = formatDate(nextYear, nextMonth, day);
    cells.push({
      date,
      dayNumber: day,
      isCurrentMonth: false,
      isToday: date === today,
      eventCategories: getCategoriesOnDate(events, date),
    });
  }

  return cells;
};

export const getMonthName = (month: number): string => {
  const names = [
    "January", "February", "March", "April", "May", "June",
    "July", "August", "September", "October", "November", "December",
  ];
  return names[month];
};

export const formatTime12h = (time24: string): string => {
  const [h, m] = time24.split(":").map(Number);
  const period = h >= 12 ? "PM" : "AM";
  const hour = h % 12 || 12;
  return `${hour}:${String(m).padStart(2, "0")} ${period}`;
};

