export const createEvent = async (input: CreateEventInput): Promise<CalendarEvent> => {
  const events = await loadEvents();
  const newEvent: CalendarEvent = {
    id: generateId(),
    ...input,
  };
  events.push(newEvent);
  await saveEvents(events);
  return newEvent;
};

export const updateEvent = async (input: UpdateEventInput): Promise<CalendarEvent | null> => {
  const events = await loadEvents();
  const index = events.findIndex((e) => e.id === input.id);
  if (index === -1) return null;

  const updated: CalendarEvent = { ...events[index], ...input };
  events[index] = updated;
  await saveEvents(events);
  return updated;
};

export const deleteEvent = async (id: string): Promise<boolean> => {
  const events = await loadEvents();
  const index = events.findIndex((e) => e.id === id);
  if (index === -1) return false;

  events.splice(index, 1);
  await saveEvents(events);
  return true;
};

export const getEventById = async (id: string): Promise<CalendarEvent | null> => {
  const events = await loadEvents();
  return events.find((e) => e.id === id) ?? null;
};

export const getAllEvents = async (): Promise<CalendarEvent[]> => {
  return loadEvents();
};

export const getEventsForDate = async (dateStr: string): Promise<CalendarEvent[]> => {
  const events = await loadEvents();
  return sortEventsByTime(getEventsOnDate(events, dateStr));
};

export const getEventsByCategory = async (category: EventCategory): Promise<CalendarEvent[]> => {
  const events = await loadEvents();
  return filterByCategory(events, category);
};

export const getEventsInRange = async (start: string, end: string): Promise<CalendarEvent[]> => {
  const events = await loadEvents();
  return filterByDateRange(events, start, end);
};

