import type { CalendarEvent, EventInput } from './types'

const DATA_PATH = `${import.meta.dir}/data/events.json`

const generateId = (): string => crypto.randomUUID()

export const loadEvents = async (): Promise<CalendarEvent[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text.trim() ? JSON.parse(text) : []
}

const saveEvents = async (events: CalendarEvent[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(events, null, 2))
}

export const createEvent = async (input: EventInput): Promise<CalendarEvent> => {
  const events = await loadEvents()
  const event: CalendarEvent = { id: generateId(), ...input }
  events.push(event)
  await saveEvents(events)
  return event
}

export const updateEvent = async (
  id: string,
  updates: Partial<EventInput>,
): Promise<CalendarEvent | null> => {
  const events = await loadEvents()
  const idx = events.findIndex((e) => e.id === id)
  if (idx === -1) return null
  events[idx] = { ...events[idx], ...updates }
  await saveEvents(events)
  return events[idx]
}

export const deleteEvent = async (id: string): Promise<boolean> => {
  const events = await loadEvents()
  const filtered = events.filter((e) => e.id !== id)
  if (filtered.length === events.length) return false
  await saveEvents(filtered)
  return true
}

export const getEventById = async (id: string): Promise<CalendarEvent | null> => {
  const events = await loadEvents()
  return events.find((e) => e.id === id) ?? null
}

export const getEventsForDate = async (dateStr: string): Promise<CalendarEvent[]> => {
  const events = await loadEvents()
  const target = new Date(dateStr + 'T00:00:00')
  const matched: CalendarEvent[] = []

  for (const event of events) {
    if (occursOnDate(event, target)) {
      matched.push(event)
    }
  }

  return matched.sort((a, b) => a.startTime.localeCompare(b.startTime))
}

const occursOnDate = (event: CalendarEvent, target: Date): boolean => {
  const eventDate = new Date(event.date + 'T00:00:00')

  if (target < eventDate) return false

  if (event.recurrence === 'none') {
    return event.date === formatDate(target)
  }

  if (event.recurrence === 'daily') {
    return true
  }

  if (event.recurrence === 'weekly') {
    return eventDate.getDay() === target.getDay()
  }

  if (event.recurrence === 'monthly') {
    return eventDate.getDate() === target.getDate()
  }

  return false
}

export const formatDate = (d: Date): string => {
  const y = d.getFullYear()
  const m = String(d.getMonth() + 1).padStart(2, '0')
  const day = String(d.getDate()).padStart(2, '0')
  return `${y}-${m}-${day}`
}

import type { DayCell } from './types'
import { getEventsForDate, formatDate } from './events'

export const getMonthGrid = async (year: number, month: number): Promise<DayCell[][]> => {
  const firstDay = new Date(year, month, 1)
  const startDow = firstDay.getDay() // 0=Sun
  const daysInMonth = new Date(year, month + 1, 0).getDate()

  const today = new Date()
  const todayStr = formatDate(today)

  // Build flat list of day cells including leading/trailing days
  const cells: DayCell[] = []

  // Previous month trailing days
  const prevMonthDays = new Date(year, month, 0).getDate()
  for (let i = startDow - 1; i >= 0; i--) {
    const day = prevMonthDays - i
    const d = new Date(year, month - 1, day)
    const dateStr = formatDate(d)
    cells.push({
      day,
      date: dateStr,
      isCurrentMonth: false,
      isToday: dateStr === todayStr,
      events: await getEventsForDate(dateStr),
    })
  }

  // Current month days
  for (let day = 1; day <= daysInMonth; day++) {
    const d = new Date(year, month, day)
    const dateStr = formatDate(d)
    cells.push({
      day,
      date: dateStr,
      isCurrentMonth: true,
      isToday: dateStr === todayStr,
      events: await getEventsForDate(dateStr),
    })
  }

  // Next month leading days to fill grid
  const remaining = 7 - (cells.length % 7)
  if (remaining < 7) {
    for (let day = 1; day <= remaining; day++) {
      const d = new Date(year, month + 1, day)
      const dateStr = formatDate(d)
      cells.push({
        day,
        date: dateStr,
        isCurrentMonth: false,
        isToday: dateStr === todayStr,
        events: await getEventsForDate(dateStr),
      })
    }
  }

  // Chunk into weeks
  const weeks: DayCell[][] = []
  for (let i = 0; i < cells.length; i += 7) {
    weeks.push(cells.slice(i, i + 7))
  }

  return weeks
}

