const renderDayCell = (cell: DayCell) => {
  const cellStyle = {
    ...styles.dayCell,
    ...(cell.isCurrentMonth ? {} : styles.dayCellMuted),
    ...(cell.isToday ? styles.dayCellToday : {}),
  }

  const dayLabel = cell.isToday
    ? h('span', { style: styleStr(styles.todayBadge) }, String(cell.day))
    : h('span', {}, String(cell.day))

  const maxVisible = 2
  const visible = cell.events.slice(0, maxVisible)
  const overflow = cell.events.length - maxVisible

  return h(
    'div',
    {
      style: styleStr(cellStyle),
      'p-trigger': `click:selectDay`,
      'data-date': cell.date,
