import type { CalendarEvent, CreateEventInput, UpdateEventInput, Recurrence } from './types.ts'

const DATA_PATH = new URL('./data/events.jsonl', import.meta.url).pathname

const generateId = (): string => crypto.randomUUID()

const readAllEvents = async (): Promise<CalendarEvent[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  if (!text.trim()) return []
  return text
    .trim()
    .split('\n')
    .map((line) => JSON.parse(line) as CalendarEvent)
}

const writeAllEvents = async (events: CalendarEvent[]): Promise<void> => {
  const content = events.map((e) => JSON.stringify(e)).join('\n')
  await Bun.write(DATA_PATH, content ? content + '\n' : '')
}

export const createEvent = async (input: CreateEventInput): Promise<CalendarEvent> => {
  const now = new Date().toISOString()
  const event: CalendarEvent = {
    id: generateId(),
    title: input.title,
    date: input.date,
    startTime: input.startTime,
    endTime: input.endTime,
    description: input.description ?? '',
    category: input.category ?? 'personal',
    recurrence: input.recurrence ?? 'none',
    createdAt: now,
    updatedAt: now,
  }
  const events = await readAllEvents()
  events.push(event)
  await writeAllEvents(events)
  return event
}

export const updateEvent = async (
  id: string,
  input: UpdateEventInput
): Promise<CalendarEvent | null> => {
  const events = await readAllEvents()
  const idx = events.findIndex((e) => e.id === id)
  if (idx === -1) return null
  const updated: CalendarEvent = {
    ...events[idx],
    ...input,
    updatedAt: new Date().toISOString(),
  }
  events[idx] = updated
  await writeAllEvents(events)
  return updated
}

export const deleteEvent = async (id: string): Promise<boolean> => {
  const events = await readAllEvents()
  const filtered = events.filter((e) => e.id !== id)
  if (filtered.length === events.length) return false
  await writeAllEvents(filtered)
  return true
}

export const getEventById = async (id: string): Promise<CalendarEvent | null> => {
  const events = await readAllEvents()
  return events.find((e) => e.id === id) ?? null
}

export const getAllEvents = readAllEvents

const matchesRecurrence = (event: CalendarEvent, targetDate: string): boolean => {
  const eventDate = new Date(event.date + 'T00:00:00')
  const target = new Date(targetDate + 'T00:00:00')

  if (target < eventDate) return false
  if (event.date === targetDate) return true
  if (event.recurrence === 'none') return false

  const diffMs = target.getTime() - eventDate.getTime()
  const diffDays = Math.round(diffMs / (1000 * 60 * 60 * 24))

  switch (event.recurrence) {
    case 'daily':
      return diffDays >= 0
    case 'weekly':
      return diffDays >= 0 && diffDays % 7 === 0
    case 'monthly':
      return (
        target.getDate() === eventDate.getDate() &&
        (target.getFullYear() > eventDate.getFullYear() ||
          (target.getFullYear() === eventDate.getFullYear() &&
            target.getMonth() >= eventDate.getMonth()))
      )
    default:
      return false
  }
}

export const getEventsForDate = async (date: string): Promise<CalendarEvent[]> => {
  const events = await readAllEvents()
  return events
    .filter((e) => matchesRecurrence(e, date))
    .sort((a, b) => a.startTime.localeCompare(b.startTime))
}

export const getEventsForMonth = async (
  year: number,
  month: number
): Promise<Map<string, CalendarEvent[]>> => {
  const events = await readAllEvents()
  const result = new Map<string, CalendarEvent[]>()

  const daysInMonth = new Date(year, month + 1, 0).getDate()

  for (let day = 1; day <= daysInMonth; day++) {
    const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`
    const dayEvents = events
      .filter((e) => matchesRecurrence(e, dateStr))
      .sort((a, b) => a.startTime.localeCompare(b.startTime))
    if (dayEvents.length > 0) {
      result.set(dateStr, dayEvents)
    }
  }

  return result
}

import type { DayCell, MonthGrid, CalendarEvent } from './types.ts'
import { getEventsForMonth } from './events.ts'

const MONTH_NAMES = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December',
]

const formatDate = (year: number, month: number, day: number): string =>
  `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`

const getTodayStr = (): string => {
  const now = new Date()
  return formatDate(now.getFullYear(), now.getMonth(), now.getDate())
}

export const getMonthView = async (year: number, month: number): Promise<MonthGrid> => {
  const eventsByDate = await getEventsForMonth(year, month)
  const today = getTodayStr()

  const firstDayOfMonth = new Date(year, month, 1).getDay() // 0=Sun
  const daysInMonth = new Date(year, month + 1, 0).getDate()
  const daysInPrevMonth = new Date(year, month, 0).getDate()

  const cells: DayCell[] = []

  // Previous month padding
  const prevMonth = month === 0 ? 11 : month - 1
  const prevYear = month === 0 ? year - 1 : year
  for (let i = firstDayOfMonth - 1; i >= 0; i--) {
    const day = daysInPrevMonth - i
    const date = formatDate(prevYear, prevMonth, day)
    cells.push({
      date,
      day,
      isCurrentMonth: false,
      isToday: date === today,
      events: eventsByDate.get(date) ?? [],
    })
  }

  // Current month days
  for (let day = 1; day <= daysInMonth; day++) {
    const date = formatDate(year, month, day)
    cells.push({
      date,
      day,
      isCurrentMonth: true,
      isToday: date === today,
      events: eventsByDate.get(date) ?? [],
    })
  }

  // Next month padding to complete the last week
  const remaining = 7 - (cells.length % 7)
  if (remaining < 7) {
    const nextMonth = month === 11 ? 0 : month + 1
    const nextYear = month === 11 ? year + 1 : year
    for (let day = 1; day <= remaining; day++) {
      const date = formatDate(nextYear, nextMonth, day)
      cells.push({
        date,
        day,
        isCurrentMonth: false,
        isToday: date === today,
        events: eventsByDate.get(date) ?? [],
      })
    }
  }

  // Split into weeks
  const weeks: DayCell[][] = []
  for (let i = 0; i < cells.length; i += 7) {
    weeks.push(cells.slice(i, i + 7))
  }

  return {
    year,
    month,
    monthName: MONTH_NAMES[month],
    weeks,
  }
}

export const navigateMonth = (year: number, month: number, direction: 1 | -1): { year: number; month: number } => {
  const newMonth = month + direction
  if (newMonth < 0) return { year: year - 1, month: 11 }
  if (newMonth > 11) return { year: year + 1, month: 0 }
  return { year, month: newMonth }
}

