const styleToString = (style: Record<string, string | number>): string =>
  Object.entries(style)
    .map(([key, value]) => {
      const cssKey = key.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)
      return `${cssKey}: ${typeof value === 'number' ? `${value}px` : value}`
    })
    .join('; ')

const renderEventDots = (events: CalendarEvent[]) => {
  const categories = [...new Set(events.map((e) => e.category))]
  return h(
    'div',
    { style: 'display: flex; flex-wrap: wrap; gap: 2px;' },
    ...categories.map((cat) =>
      h('span', {
        style: styleToString({
          ...styles.eventDot,
          background: CATEGORY_COLORS[cat],
        }),
      })
    )
  )
}

const renderEventChips = (events: CalendarEvent[]) => {
  const visible = events.slice(0, 3)
  const remaining = events.length - 3
  return h(
    Fragment,
    {},
    ...visible.map((event) =>
      h(
        'span',
        {
          style: styleToString({
            ...styles.eventChip,
            background: CATEGORY_BG_COLORS[event.category],
            color: CATEGORY_COLORS[event.category],
          }),
        },
        event.title
      )
    ),
    ...(remaining > 0
      ? [
          h(
            'span',
            {
              style: 'font-size: 11px; color: #6b7280; padding: 2px 6px;',
            },
            `+${remaining} more`
          ),
        ]
      : [])
  )
}

const renderDayCell = (cell: DayCell) => {
  const cellStyle = {
    ...styles.dayCell,
    ...(cell.isCurrentMonth ? {} : styles.dayCellMuted),
    ...(cell.isToday ? styles.dayCellToday : {}),
  }

  const dayNumberContent = cell.isToday
    ? h('div', { style: styleToString(styles.dayNumberToday) }, String(cell.day))
    : h('div', { style: styleToString(styles.dayNumber) }, String(cell.day))

  return h(
    'div',
    {
      style: styleToString(cellStyle),
      'p-trigger': `click:selectDate`,
      'data-date': cell.date,
    },
    dayNumberContent,
    ...(cell.events.length > 0
      ? [renderEventDots(cell.events), renderEventChips(cell.events)]
      : [])
  )
}

