export const renderDayView = (date: string, events: CalendarEvent[]) => {
  const dateObj = new Date(date + 'T00:00:00')
  const formatted = dateObj.toLocaleDateString('en-US', {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  })

  const recurrenceLabel = (r: Recurrence): string => {
    if (r === 'none') return ''
    return `Repeats ${r}`
  }

  const eventCards = events.map((event) =>
    h(
      'div',
      { style: styleToString(styles.eventCard) },
      h('div', {
        style: styleToString({
          ...styles.eventColorBar,
          background: CATEGORY_COLORS[event.category],
        }),
      }),
      h(
        'div',
        { style: styleToString(styles.eventContent) },
        h(
          'div',
          { style: styleToString(styles.eventTitle) },
          event.title,
          ...(event.recurrence !== 'none'
            ? [
                h(
                  'span',
                  { style: styleToString(styles.recurrenceBadge) },
                  recurrenceLabel(event.recurrence)
                ),
              ]
            : [])
        ),
        h(
          'div',
          { style: styleToString(styles.eventTime) },
          `${event.startTime} \u2013 ${event.endTime}`
        ),
        ...(event.description
          ? [h('div', { style: styleToString(styles.eventDesc) }, event.description)]
          : []),
        h(
          'span',
          {
            style: styleToString({
              ...styles.eventCategory,
              background: CATEGORY_BG_COLORS[event.category],
              color: CATEGORY_COLORS[event.category],
            }),
          },
          event.category
        )
      ),
      h(
        'div',
        { style: styleToString(styles.eventActions) },
        h(
          'button',
          {
            style: styleToString(styles.actionBtn),
            'p-trigger': 'click:editEvent',
            'data-event-id': event.id,
          },
          'Edit'
        ),
        h(
          'button',
          {
            style: styleToString(styles.deleteBtn),
            'p-trigger': 'click:deleteEvent',
            'data-event-id': event.id,
          },
          'Delete'
        )
      )
    )
  )

  return h(
    'div',
    { style: styleToString(styles.dayView) },
    h('h3', { style: styleToString(styles.dayViewTitle) }, formatted),
    ...(events.length > 0
      ? eventCards
      : [h('div', { style: styleToString(styles.emptyDay) }, 'No events scheduled for this day')])
  )
}

