export const renderCalendarPage = async (
  grid: MonthGrid,
  selectedDate?: string,
  dayEvents?: CalendarEvent[],
  editingEvent?: CalendarEvent
) => {
  const ssr = createSSR()
  const content = h(
    Fragment,
    {},
    renderMonthGrid(grid),
    h(
      'div',
      { style: styleToString(styles.container) },
      ...(selectedDate && dayEvents
        ? [
            renderDayView(selectedDate, dayEvents),
            renderEventForm(editingEvent),
          ]
        : [renderEventForm(editingEvent)])
    )
  )
  return ssr(content)
}

import { getMonthView, navigateMonth } from './calendar.ts'
import { createEvent, updateEvent, deleteEvent, getEventsForDate, getEventById } from './events.ts'
import { renderCalendarPage } from './ui.ts'
import type { CreateEventInput, UpdateEventInput, EventCategory, Recurrence } from './types.ts'

const parseFormData = async (req: Request): Promise<Record<string, string>> => {
  const formData = await req.formData()
  const result: Record<string, string> = {}
  formData.forEach((value, key) => {
    result[key] = value.toString()
  })
  return result
}

const htmlResponse = (html: string): Response =>
  new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

export const serve = () => {
  const now = new Date()
  let currentYear = now.getFullYear()
  let currentMonth = now.getMonth()

  return Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url)
      const { pathname } = url

      // GET / — render calendar page
      if (req.method === 'GET' && pathname === '/') {
        const year = Number(url.searchParams.get('year')) || currentYear
        const month = Number(url.searchParams.get('month') ?? currentMonth)
        const selectedDate = url.searchParams.get('date') ?? undefined
        const editId = url.searchParams.get('edit') ?? undefined

        const grid = await getMonthView(year, month)
        const dayEvents = selectedDate ? await getEventsForDate(selectedDate) : undefined
        const editingEvent = editId ? (await getEventById(editId)) ?? undefined : undefined

        const html = await renderCalendarPage(grid, selectedDate, dayEvents, editingEvent)
        return htmlResponse(`<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Calendar</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { background: #f3f4f6; min-height: 100vh; }
  </style>
</head>
<body>${html}</body>
</html>`)
      }

      // POST /events — create event
      if (req.method === 'POST' && pathname === '/events') {
        const data = await parseFormData(req)
        const input: CreateEventInput = {
          title: data.title,
          date: data.date,
          startTime: data.startTime,
          endTime: data.endTime,
          description: data.description,
          category: (data.category as EventCategory) || 'personal',
          recurrence: (data.recurrence as Recurrence) || 'none',
        }
        const event = await createEvent(input)
        // Redirect back to the calendar with the event's date selected
        return Response.redirect(`/?date=${event.date}&month=${new Date(event.date).getMonth()}&year=${new Date(event.date).getFullYear()}`, 303)
      }

      // POST /events/:id/update — update event
      if (req.method === 'POST' && pathname.match(/^\/events\/[^/]+\/update$/)) {
        const id = pathname.split('/')[2]
        const data = await parseFormData(req)
        const input: UpdateEventInput = {}
        if (data.title) input.title = data.title
        if (data.date) input.date = data.date
        if (data.startTime) input.startTime = data.startTime
        if (data.endTime) input.endTime = data.endTime
        if (data.description !== undefined) input.description = data.description
        if (data.category) input.category = data.category as EventCategory
        if (data.recurrence) input.recurrence = data.recurrence as Recurrence
        const event = await updateEvent(id, input)
        if (!event) return jsonResponse({ error: 'Event not found' }, 404)
        return Response.redirect(`/?date=${event.date}&month=${new Date(event.date).getMonth()}&year=${new Date(event.date).getFullYear()}`, 303)
      }

      // POST /events/:id/delete — delete event
      if (req.method === 'POST' && pathname.match(/^\/events\/[^/]+\/delete$/)) {
        const id = pathname.split('/')[2]
        const deleted = await deleteEvent(id)
        if (!deleted) return jsonResponse({ error: 'Event not found' }, 404)
        return Response.redirect('/', 303)
      }

      // GET /api/events?date=YYYY-MM-DD — JSON API for day events
      if (req.method === 'GET' && pathname === '/api/events') {
        const date = url.searchParams.get('date')
        if (!date) return jsonResponse({ error: 'date parameter required' }, 400)
        const events = await getEventsForDate(date)
        return jsonResponse(events)
      }

      // GET /api/events/:id — JSON API for single event
      if (req.method === 'GET' && pathname.match(/^\/api\/events\/[^/]+$/)) {
        const id = pathname.split('/')[2]
        const event = await getEventById(id)
        if (!event) return jsonResponse({ error: 'Event not found' }, 404)
        return jsonResponse(event)
      }

      return jsonResponse({ error: 'Not found' }, 404)
    },
  })
}

