import type { CategoryColor, MarkerCategory } from './types';

export const CATEGORY_COLORS: CategoryColor[] = [
  { name: 'default', hex: '#2196F3', label: 'Default' },
  { name: 'food', hex: '#FF9800', label: 'Food' },
  { name: 'transport', hex: '#4CAF50', label: 'Transport' },
  { name: 'health', hex: '#F44336', label: 'Health' },
  { name: 'education', hex: '#9C27B0', label: 'Education' },
  { name: 'shopping', hex: '#FFEB3B', label: 'Shopping' },
];

export const getCategoryColor = (category: MarkerCategory): string => {
  const found = CATEGORY_COLORS.find((c) => c.name === category);
  return found?.hex ?? '#2196F3';
};

export const getCategoryLabel = (category: MarkerCategory): string => {
  const found = CATEGORY_COLORS.find((c) => c.name === category);
  return found?.label ?? 'Default';
};

import type { MapMarker, MapCircle, MarkerCategory } from './types';

const MARKERS_PATH = './data/markers.json';
const CIRCLES_PATH = './data/circles.json';

const generateId = (): string => crypto.randomUUID();

// --- Markers ---

export const loadMarkers = async (): Promise<MapMarker[]> => {
  const file = Bun.file(MARKERS_PATH);
  if (!(await file.exists())) return [];
  const text = await file.text();
  return JSON.parse(text) as MapMarker[];
};

export const saveMarkers = async (markers: MapMarker[]): Promise<void> => {
  await Bun.write(MARKERS_PATH, JSON.stringify(markers, null, 2));
};

export const addMarker = async (params: {
  title: string;
  description: string;
  lat: number;
  lng: number;
  category?: MarkerCategory;
}): Promise<MapMarker> => {
  const markers = await loadMarkers();
  const marker: MapMarker = {
    id: generateId(),
    title: params.title,
    description: params.description,
    lat: params.lat,
    lng: params.lng,
    category: params.category ?? 'default',
    createdAt: new Date().toISOString(),
  };
  markers.push(marker);
  await saveMarkers(markers);
  return marker;
};

export const removeMarker = async (id: string): Promise<boolean> => {
  const markers = await loadMarkers();
  const filtered = markers.filter((m) => m.id !== id);
  if (filtered.length === markers.length) return false;
  await saveMarkers(filtered);
  return true;
};

export const getMarkersByCategory = async (
  category: MarkerCategory
): Promise<MapMarker[]> => {
  const markers = await loadMarkers();
  return markers.filter((m) => m.category === category);
};

// --- Circles ---

export const loadCircles = async (): Promise<MapCircle[]> => {
  const file = Bun.file(CIRCLES_PATH);
  if (!(await file.exists())) return [];
  const text = await file.text();
  return JSON.parse(text) as MapCircle[];
};

export const saveCircles = async (circles: MapCircle[]): Promise<void> => {
  await Bun.write(CIRCLES_PATH, JSON.stringify(circles, null, 2));
};

export const addCircle = async (params: {
  lat: number;
  lng: number;
  radius: number;
  color?: string;
  label?: string;
}): Promise<MapCircle> => {
  const circles = await loadCircles();
  const circle: MapCircle = {
    id: generateId(),
    lat: params.lat,
    lng: params.lng,
    radius: params.radius,
    color: params.color ?? '#2196F3',
    label: params.label ?? '',
    createdAt: new Date().toISOString(),
  };
  circles.push(circle);
  await saveCircles(circles);
  return circle;
};

export const removeCircle = async (id: string): Promise<boolean> => {
  const circles = await loadCircles();
  const filtered = circles.filter((c) => c.id !== id);
  if (filtered.length === circles.length) return false;
  await saveCircles(filtered);
  return true;
};

