const styleToString = (style: Record<string, string | number>): string =>
  Object.entries(style)
    .map(([key, value]) => {
      const cssKey = key.replace(/([A-Z])/g, '-$1').toLowerCase();
      return `${cssKey}: ${typeof value === 'number' ? `${value}px` : value}`;
    })
    .join('; ');

const renderSidebarMarkers = (markers: MapMarker[]): string => {
  const grouped = new Map<MarkerCategory, MapMarker[]>();
  for (const marker of markers) {
    const list = grouped.get(marker.category) ?? [];
    list.push(marker);
    grouped.set(marker.category, list);
  }

  if (markers.length === 0) {
    return '<p style="padding: 16px; color: #6c757d; text-align: center; font-size: 14px;">No markers yet. Add one below or click the map.</p>';
  }

  let html = '';
  for (const cat of CATEGORY_COLORS) {
    const catMarkers = grouped.get(cat.name);
    if (!catMarkers || catMarkers.length === 0) continue;

    html += `<div style="${styleToString(styles.categoryGroup)}">`;
    html += `<div style="${styleToString(styles.categoryHeader)}">`;
    html += `<span style="${styleToString({ ...styles.categoryDot, backgroundColor: cat.hex })}"></span>`;
    html += `${cat.label} (${catMarkers.length})`;
    html += `</div>`;

    for (const m of catMarkers) {
      html += `<div style="${styleToString(styles.markerItem)}" `;
      html += `onclick="flyToMarker(${m.lat}, ${m.lng})" `;
      html += `onmouseover="this.style.boxShadow='0 2px 8px rgba(0,0,0,0.12)'" `;
      html += `onmouseout="this.style.boxShadow='none'">`;
      html += `<p style="${styleToString(styles.markerTitle)}">${escapeHtml(m.title)}</p>`;
      if (m.description) {
        html += `<p style="${styleToString(styles.markerDesc)}">${escapeHtml(m.description)}</p>`;
      }
      html += `<p style="${styleToString(styles.markerCoords)}">${m.lat.toFixed(5)}, ${m.lng.toFixed(5)}</p>`;
      html += `</div>`;
    }
    html += `</div>`;
  }
  return html;
};

const escapeHtml = (str: string): string =>
  str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');

export const renderMapPage = (markers: MapMarker[], circles: MapCircle[]): string => {
  const markersJson = JSON.stringify(markers);
  const circlesJson = JSON.stringify(circles);
  const categoryColorsJson = JSON.stringify(CATEGORY_COLORS);

  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Interactive Map</title>
  <link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css" />
  <script src="https://unpkg.com/leaflet@1.9.4/dist/leaflet.js"><\/script>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    html, body { height: 100%; overflow: hidden; }
    #map { width: 100%; height: 100%; }
    .custom-marker {
