    .popup-title { font-weight: 600; font-size: 15px; margin-bottom: 4px; }
    .popup-desc { color: #555; font-size: 13px; }
    .popup-category { display: inline-block; padding: 2px 8px; border-radius: 10px; font-size: 11px; color: #fff; margin-top: 6px; }
  </style>
</head>
<body>
  <div style="${styleToString(styles.container)}">
    <div style="${styleToString(styles.sidebar)}">
      <div style="${styleToString(styles.sidebarHeader)}">
        <h2 style="${styleToString(styles.sidebarTitle)}">Interactive Map</h2>
        <form id="searchForm" style="${styleToString(styles.searchForm)}" onsubmit="handleSearch(event)">
          <input
            id="searchInput"
            type="text"
            placeholder="Search location..."
            style="${styleToString(styles.searchInput)}"
          />
          <button type="submit" style="${styleToString(styles.searchButton)}">Go</button>
        </form>
        <div style="${styleToString(styles.filterRow)}" id="filterRow">
          <span
            style="${styleToString({ ...styles.filterChip, ...styles.filterChipActive, backgroundColor: '#495057' })}"
            onclick="filterCategory('all')"
            data-filter="all"
            class="filter-chip active"
          >All</span>
          ${CATEGORY_COLORS.map(
            (c) =>
              `<span
                style="${styleToString(styles.filterChip)}"
                onclick="filterCategory('${c.name}')"
                data-filter="${c.name}"
                class="filter-chip"
              >${c.label}</span>`
          ).join('')}
        </div>
      </div>
      <div style="${styleToString(styles.markerList)}" id="markerList">
        ${renderSidebarMarkers(markers)}
      </div>
      <div style="${styleToString(styles.addPanel)}">
        <p style="${styleToString(styles.addPanelTitle)}">Add Marker</p>
        <form id="addMarkerForm" onsubmit="handleAddMarker(event)">
          <div style="${styleToString(styles.formGroup)}">
            <label style="${styleToString(styles.formLabel)}">Title</label>
            <input name="title" required style="${styleToString(styles.formInput)}" placeholder="Marker title" />
          </div>
          <div style="${styleToString(styles.formGroup)}">
            <label style="${styleToString(styles.formLabel)}">Description</label>
            <input name="description" style="${styleToString(styles.formInput)}" placeholder="Optional description" />
          </div>
          <div style="${styleToString(styles.formRow)}">
            <div style="${styleToString(styles.formRowHalf)}">
              <label style="${styleToString(styles.formLabel)}">Lat</label>
              <input name="lat" type="number" step="any" required style="${styleToString(styles.formInput)}" placeholder="51.505" />
            </div>
            <div style="${styleToString(styles.formRowHalf)}">
              <label style="${styleToString(styles.formLabel)}">Lng</label>
              <input name="lng" type="number" step="any" required style="${styleToString(styles.formInput)}" placeholder="-0.09" />
            </div>
          </div>
          <div style="${styleToString(styles.formGroup)}">
            <label style="${styleToString(styles.formLabel)}">Category</label>
            <select name="category" style="${styleToString(styles.formSelect)}">
              ${CATEGORY_COLORS.map((c) => `<option value="${c.name}">${c.label}</option>`).join('')}
            </select>
          </div>
          <button type="submit" style="${styleToString(styles.submitButton)}">Add Marker</button>
        </form>
      </div>
    </div>
    <div style="${styleToString(styles.mapContainer)}">
      <div id="map"></div>
    </div>
  </div>

  <script>
    const markersData = ${markersJson};
    const circlesData = ${circlesJson};
    const categoryColors = ${categoryColorsJson};

    let map;
    let leafletMarkers = [];
    let leafletCircles = [];
    let activeFilter = 'all';

    const getCatColor = (cat) => {
      const found = categoryColors.find(c => c.name === cat);
      return found ? found.hex : '#2196F3';
    };

    const createColorIcon = (color) => {
      return L.divIcon({
        className: '',
        html: '<div class="custom-marker" style="background-color: ' + color + ';"></div>',
        iconSize: [24, 24],
        iconAnchor: [12, 24],
        popupAnchor: [0, -24],
      });
    };

    const initMap = () => {
      map = L.map('map').setView([51.505, -0.09], 13);
      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors',
        maxZoom: 19,
      }).addTo(map);

      map.on('click', (e) => {
        const form = document.getElementById('addMarkerForm');
        form.lat.value = e.latlng.lat.toFixed(6);
        form.lng.value = e.latlng.lng.toFixed(6);
      });

      renderMarkers(markersData);
      renderCircles(circlesData);

      if (markersData.length > 0) {
        const bounds = L.latLngBounds(markersData.map(m => [m.lat, m.lng]));
        map.fitBounds(bounds, { padding: [50, 50] });
      }
    };

    const renderMarkers = (markers) => {
      leafletMarkers.forEach(lm => map.removeLayer(lm));
      leafletMarkers = [];

      const filtered = activeFilter === 'all'
        ? markers
        : markers.filter(m => m.category === activeFilter);

      filtered.forEach(m => {
        const color = getCatColor(m.category);
        const icon = createColorIcon(color);
        const lm = L.marker([m.lat, m.lng], { icon })
          .addTo(map)
          .bindPopup(
            '<div class="popup-title">' + escapeHtml(m.title) + '</div>' +
            (m.description ? '<div class="popup-desc">' + escapeHtml(m.description) + '</div>' : '') +
            '<span class="popup-category" style="background-color: ' + color + ';">' +
            m.category + '</span>'
          );
        leafletMarkers.push(lm);
      });
    };

    const renderCircles = (circles) => {
      leafletCircles.forEach(lc => map.removeLayer(lc));
      leafletCircles = [];

      circles.forEach(c => {
        const lc = L.circle([c.lat, c.lng], {
          radius: c.radius,
          color: c.color,
          fillColor: c.color,
          fillOpacity: 0.15,
          weight: 2,
        }).addTo(map);
        if (c.label) lc.bindPopup(escapeHtml(c.label));
        leafletCircles.push(lc);
      });
    };

    const escapeHtml = (str) =>
      str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
         .replace(/"/g, '&quot;').replace(/'/g, '&#039;');

    const flyToMarker = (lat, lng) => {
      map.flyTo([lat, lng], 16, { duration: 0.8 });
      leafletMarkers.forEach(lm => {
        const pos = lm.getLatLng();
        if (Math.abs(pos.lat - lat) < 0.0001 && Math.abs(pos.lng - lng) < 0.0001) {
          lm.openPopup();
        }
      });
    };

    const filterCategory = (category) => {
      activeFilter = category;
      document.querySelectorAll('.filter-chip').forEach(chip => {
        const filter = chip.dataset.filter;
        if (filter === category) {
          chip.style.backgroundColor = filter === 'all' ? '#495057' : getCatColor(filter);
          chip.style.color = '#fff';
          chip.style.borderColor = 'transparent';
        } else {
          chip.style.backgroundColor = '#fff';
          chip.style.color = '#212529';
          chip.style.borderColor = '#dee2e6';
        }
      });
      renderMarkers(markersData);
      updateSidebar();
    };

    const updateSidebar = () => {
      const filtered = activeFilter === 'all'
        ? markersData
        : markersData.filter(m => m.category === activeFilter);
      fetch('/api/sidebar?filter=' + activeFilter)
        .then(r => r.text())
        .then(html => {
          document.getElementById('markerList').innerHTML = html;
        })
        .catch(() => {});
    };

    const handleSearch = async (e) => {
      e.preventDefault();
      const query = document.getElementById('searchInput').value.trim();
      if (!query) return;
      try {
        const res = await fetch(
          'https://nominatim.openstreetmap.org/search?format=json&q=' +
          encodeURIComponent(query) + '&limit=1'
        );
        const results = await res.json();
        if (results.length > 0) {
          const { lat, lon } = results[0];
          map.flyTo([parseFloat(lat), parseFloat(lon)], 15, { duration: 1.2 });
        } else {
          alert('Location not found');
        }
      } catch {
        alert('Search failed. Please try again.');
      }
    };

    const handleAddMarker = async (e) => {
      e.preventDefault();
      const form = e.target;
      const data = {
        title: form.title.value,
        description: form.description.value,
        lat: parseFloat(form.lat.value),
        lng: parseFloat(form.lng.value),
        category: form.category.value,
      };

      try {
        const res = await fetch('/api/markers', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(data),
        });
        if (res.ok) {
          const marker = await res.json();
          markersData.push(marker);
          renderMarkers(markersData);
          updateSidebar();
          form.reset();
          map.flyTo([marker.lat, marker.lng], 15, { duration: 0.8 });
        }
      } catch {
        alert('Failed to add marker');
      }
    };

    document.addEventListener('DOMContentLoaded', initMap);
  <\/script>
</body>
</html>`;
};

export const renderSidebarHtml = (markers: MapMarker[], filter: string): string => {
  const filtered =
    filter === 'all'
      ? markers
      : markers.filter((m) => m.category === filter);
  return renderSidebarMarkers(filtered);
};

import {
  loadMarkers,
  loadCircles,
  addMarker,
  removeMarker,
  addCircle,
  removeCircle,
} from './map-data';
import { renderMapPage, renderSidebarHtml } from './map-render';
import type { MarkerCategory } from './types';

const PORT = 3000;

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  });

const htmlResponse = (html: string, status = 200): Response =>
  new Response(html, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  });

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url);
    const { pathname } = url;

    // --- Page ---
    if (pathname === '/' && req.method === 'GET') {
      const [markers, circles] = await Promise.all([
        loadMarkers(),
        loadCircles(),
      ]);
      return htmlResponse(renderMapPage(markers, circles));
    }

    // --- Sidebar partial ---
    if (pathname === '/api/sidebar' && req.method === 'GET') {
      const filter = url.searchParams.get('filter') ?? 'all';
      const markers = await loadMarkers();
      return htmlResponse(renderSidebarHtml(markers, filter));
    }

    // --- Markers CRUD ---
    if (pathname === '/api/markers') {
      if (req.method === 'GET') {
        const markers = await loadMarkers();
        return jsonResponse(markers);
      }

      if (req.method === 'POST') {
        const body = await req.json() as {
          title: string;
          description?: string;
          lat: number;
          lng: number;
          category?: MarkerCategory;
        };

        if (!body.title || body.lat == null || body.lng == null) {
          return jsonResponse({ error: 'title, lat, and lng are required' }, 400);
        }

        const marker = await addMarker({
          title: body.title,
          description: body.description ?? '',
          lat: body.lat,
          lng: body.lng,
          category: body.category,
        });
        return jsonResponse(marker, 201);
      }

      if (req.method === 'DELETE') {
        const id = url.searchParams.get('id');
        if (!id) return jsonResponse({ error: 'id is required' }, 400);
        const removed = await removeMarker(id);
        return removed
          ? jsonResponse({ success: true })
          : jsonResponse({ error: 'marker not found' }, 404);
      }
    }

    // --- Circles CRUD ---
    if (pathname === '/api/circles') {
      if (req.method === 'GET') {
        const circles = await loadCircles();
        return jsonResponse(circles);
      }

      if (req.method === 'POST') {
        const body = await req.json() as {
          lat: number;
          lng: number;
          radius: number;
          color?: string;
          label?: string;
        };

        if (body.lat == null || body.lng == null || body.radius == null) {
          return jsonResponse({ error: 'lat, lng, and radius are required' }, 400);
        }

        const circle = await addCircle({
          lat: body.lat,
          lng: body.lng,
          radius: body.radius,
          color: body.color,
          label: body.label,
        });
        return jsonResponse(circle, 201);
      }

      if (req.method === 'DELETE') {
        const id = url.searchParams.get('id');
        if (!id) return jsonResponse({ error: 'id is required' }, 400);
        const removed = await removeCircle(id);
        return removed
          ? jsonResponse({ success: true })
          : jsonResponse({ error: 'circle not found' }, 404);
      }
    }

    return jsonResponse({ error: 'not found' }, 404);
  },
});

