          ),
        ),
      ),
      h('div', { id: 'map', style: styleToString(styles.mapContainer) }),
      h(
        'script',
        {},
        `
        const markersData = ${JSON.stringify(markers)};
        const circlesData = ${JSON.stringify(circles)};
        const categoriesData = ${JSON.stringify(categories)};
        const categoryMap = {};
        categoriesData.forEach(c => categoryMap[c.id] = c);

        const map = L.map('map').setView([40.7128, -74.006], 12);
        L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
          attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>',
          maxZoom: 19,
        }).addTo(map);

        const markerLayer = L.layerGroup().addTo(map);
        const circleLayer = L.layerGroup().addTo(map);
        const leafletMarkers = {};

        const createIcon = (color) => {
          const svg = \`<svg xmlns="http://www.w3.org/2000/svg" width="25" height="41" viewBox="0 0 25 41">
            <path d="M12.5 0C5.6 0 0 5.6 0 12.5c0 9.4 12.5 28.5 12.5 28.5S25 21.9 25 12.5C25 5.6 19.4 0 12.5 0z" fill="\${color}"/>
            <circle cx="12.5" cy="12.5" r="5" fill="white"/>
          </svg>\`;
          return L.icon({
            iconUrl: 'data:image/svg+xml;base64,' + btoa(svg),
            iconSize: [25, 41],
            iconAnchor: [12, 41],
            popupAnchor: [0, -35],
          });
        };

        const addMarkerToMap = (marker) => {
          const cat = categoryMap[marker.categoryId];
          const color = cat ? cat.color : '#2196F3';
          const icon = createIcon(color);
          const lm = L.marker([marker.position.lat, marker.position.lng], { icon })
            .bindPopup('<h3>' + marker.title + '</h3><p>' + marker.description + '</p>')
            .addTo(markerLayer);
          leafletMarkers[marker.id] = lm;
        };

        markersData.forEach(addMarkerToMap);

        circlesData.forEach(c => {
          L.circle([c.center.lat, c.center.lng], {
            radius: c.radius,
            color: c.color,
            fillColor: c.color,
            fillOpacity: c.fillOpacity,
          }).bindPopup('<h3>' + c.label + '</h3>').addTo(circleLayer);
        });

        let activeCategory = 'all';

        const filterCategory = (catId, el) => {
          activeCategory = catId;
          document.querySelectorAll('.cat-chip').forEach(c => c.classList.remove('active'));
          el.classList.add('active');
          document.querySelectorAll('.marker-item').forEach(item => {
            if (catId === 'all' || item.dataset.category === catId) {
              item.style.display = 'flex';
            } else {
              item.style.display = 'none';
            }
          });
          markerLayer.clearLayers();
          markersData.forEach(m => {
            if (catId === 'all' || m.categoryId === catId) {
              addMarkerToMap(m);
            }
          });
        };

        const centerOnMarker = (id) => {
          const lm = leafletMarkers[id];
          if (lm) {
            map.setView(lm.getLatLng(), 15);
            lm.openPopup();
          }
        };

        map.on('click', (e) => {
          document.getElementById('marker-lat').value = e.latlng.lat.toFixed(6);
          document.getElementById('marker-lng').value = e.latlng.lng.toFixed(6);
        });

        const addMarker = async () => {
          const title = document.getElementById('marker-title').value.trim();
          const desc = document.getElementById('marker-desc').value.trim();
          const catId = document.getElementById('marker-category').value;
          const lat = parseFloat(document.getElementById('marker-lat').value);
          const lng = parseFloat(document.getElementById('marker-lng').value);
          if (!title || isNaN(lat) || isNaN(lng)) {
            alert('Please enter a title and click the map to set position.');
            return;
          }
          const res = await fetch('/api/markers', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ position: { lat, lng }, title, description: desc, categoryId: catId }),
          });
          if (res.ok) location.reload();
        };

        const deleteMarker = async (id) => {
          const res = await fetch('/api/markers/' + id, { method: 'DELETE' });
          if (res.ok) location.reload();
        };

        let searchTimeout;
        const searchInput = document.getElementById('search-input');
        const searchResults = document.getElementById('search-results');

        searchInput.addEventListener('input', () => {
          clearTimeout(searchTimeout);
          const q = searchInput.value.trim();
          if (q.length < 2) {
            searchResults.classList.remove('visible');
            return;
          }
          searchTimeout = setTimeout(async () => {
            const res = await fetch('/api/search?q=' + encodeURIComponent(q));
            const data = await res.json();
            searchResults.innerHTML = '';
            if (data.length > 0) {
              searchResults.classList.add('visible');
              data.forEach(r => {
                const li = document.createElement('li');
                li.className = 'search-result';
                li.style.cssText = 'padding:6px 8px;font-size:12px;cursor:pointer;border-radius:4px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;';
                li.textContent = r.displayName;
                li.onclick = () => {
                  map.setView([parseFloat(r.lat), parseFloat(r.lon)], 14);
                  searchResults.classList.remove('visible');
                  searchInput.value = r.displayName;
                };
                searchResults.appendChild(li);
              });
            } else {
              searchResults.classList.remove('visible');
            }
          }, 400);
        });
        `,
      ),
    ),
  );

  const ssr = createSSR();
  return '<!DOCTYPE html>' + ssr(template);
};

import { getMarkers, getCircles, getCategories, addMarker, removeMarker, addCircle, removeCircle, addCategory } from './store';
import { searchLocation } from './search';
import { renderPage } from './render';
import type { AddMarkerPayload, AddCirclePayload, AddCategoryPayload } from './types';

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  });

const htmlResponse = (html: string): Response =>
  new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  });

const extractId = (pathname: string, prefix: string): string | null => {
  const match = pathname.match(new RegExp(`^${prefix}/([^/]+)$`));
  return match ? match[1] : null;
};

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url);
  const { pathname } = url;
  const method = req.method;

  // Serve the main page
  if (pathname === '/' && method === 'GET') {
    const [markers, circles, categories] = await Promise.all([
      getMarkers(),
      getCircles(),
      getCategories(),
    ]);
    const html = renderPage(markers, circles, categories);
    return htmlResponse(html);
  }

  // Markers API
  if (pathname === '/api/markers' && method === 'GET') {
    return jsonResponse(await getMarkers());
  }

  if (pathname === '/api/markers' && method === 'POST') {
    const body = (await req.json()) as AddMarkerPayload;
    const marker = await addMarker(body);
    return jsonResponse(marker, 201);
  }

  const markerId = extractId(pathname, '/api/markers');
  if (markerId && method === 'DELETE') {
    const removed = await removeMarker(markerId);
    return removed
      ? jsonResponse({ success: true })
      : jsonResponse({ error: 'Marker not found' }, 404);
  }

  // Circles API
  if (pathname === '/api/circles' && method === 'GET') {
    return jsonResponse(await getCircles());
  }

  if (pathname === '/api/circles' && method === 'POST') {
    const body = (await req.json()) as AddCirclePayload;
    const circle = await addCircle(body);
    return jsonResponse(circle, 201);
  }

  const circleId = extractId(pathname, '/api/circles');
  if (circleId && method === 'DELETE') {
    const removed = await removeCircle(circleId);
    return removed
      ? jsonResponse({ success: true })
      : jsonResponse({ error: 'Circle not found' }, 404);
  }

  // Categories API
  if (pathname === '/api/categories' && method === 'GET') {
    return jsonResponse(await getCategories());
  }

  if (pathname === '/api/categories' && method === 'POST') {
    const body = (await req.json()) as AddCategoryPayload;
    const category = await addCategory(body);
    return jsonResponse(category, 201);
  }

  // Search API
  if (pathname === '/api/search' && method === 'GET') {
    const query = url.searchParams.get('q') ?? '';
    if (query.length < 2) return jsonResponse([]);
    const results = await searchLocation(query);
    return jsonResponse(results);
  }

  return jsonResponse({ error: 'Not found' }, 404);
};

const PORT = Number(process.env.PORT) || 3000;

Bun.serve({
  port: PORT,
  fetch: handleRequest,
});

console.log(`Interactive Map running at http://localhost:${PORT}`);

