import type { MapData, MapMarker, MapCircle, MarkerCategory } from './types';

const DATA_PATH = `${import.meta.dir}/data/markers.json`;

const loadData = async (): Promise<MapData> => {
  const file = Bun.file(DATA_PATH);
  const text = await file.text();
  return JSON.parse(text) as MapData;
};

const saveData = async (data: MapData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2));
};

const generateId = (): string =>
  `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;

export const getMarkers = async (): Promise<MapMarker[]> => {
  const data = await loadData();
  return data.markers;
};

export const addMarker = async (
  marker: Omit<MapMarker, 'id' | 'createdAt'>
): Promise<MapMarker> => {
  const data = await loadData();
  const newMarker: MapMarker = {
    ...marker,
    id: generateId(),
    createdAt: new Date().toISOString(),
  };
  data.markers.push(newMarker);
  await saveData(data);
  return newMarker;
};

export const removeMarker = async (id: string): Promise<boolean> => {
  const data = await loadData();
  const idx = data.markers.findIndex((m) => m.id === id);
  if (idx === -1) return false;
  data.markers.splice(idx, 1);
  await saveData(data);
  return true;
};

export const getCircles = async (): Promise<MapCircle[]> => {
  const data = await loadData();
  return data.circles;
};

export const addCircle = async (
  circle: Omit<MapCircle, 'id' | 'createdAt'>
): Promise<MapCircle> => {
  const data = await loadData();
  const newCircle: MapCircle = {
    ...circle,
    id: generateId(),
    createdAt: new Date().toISOString(),
  };
  data.circles.push(newCircle);
  await saveData(data);
  return newCircle;
};

export const removeCircle = async (id: string): Promise<boolean> => {
  const data = await loadData();
  const idx = data.circles.findIndex((c) => c.id === id);
  if (idx === -1) return false;
  data.circles.splice(idx, 1);
  await saveData(data);
  return true;
};

export const getCategories = async (): Promise<MarkerCategory[]> => {
  const data = await loadData();
  return data.categories;
};

export const addCategory = async (
  category: Omit<MarkerCategory, 'id'>
): Promise<MarkerCategory> => {
  const data = await loadData();
  const newCategory: MarkerCategory = {
    ...category,
    id: generateId(),
  };
  data.categories.push(newCategory);
  await saveData(data);
  return newCategory;
};

export const getAllData = async (): Promise<MapData> => {
  return loadData();
};

import type { SearchResult } from './types';

const NOMINATIM_URL = 'https://nominatim.openstreetmap.org/search';

export const searchLocation = async (query: string): Promise<SearchResult[]> => {
  const params = new URLSearchParams({
    q: query,
    format: 'json',
    limit: '5',
    addressdetails: '0',
  });

  const response = await fetch(`${NOMINATIM_URL}?${params}`, {
    headers: {
      'User-Agent': 'interactive-map-modnet/1.0',
    },
  });

  if (!response.ok) {
    return [];
  }

  const results = (await response.json()) as Array<{
    lat: string;
    lon: string;
    display_name: string;
  }>;

  return results.map((r) => ({
    lat: parseFloat(r.lat),
    lng: parseFloat(r.lon),
    displayName: r.display_name,
  }));
};

