            return;
          }
          searchTimeout = setTimeout(async () => {
            const res = await fetch('/api/search?q=' + encodeURIComponent(query));
            const results = await res.json();
            const container = document.getElementById('search-results');
            container.innerHTML = '';
            if (results.length === 0) {
              container.style.display = 'none';
              return;
            }
            results.forEach(r => {
              const div = document.createElement('div');
              div.className = 'search-result-item';
              div.textContent = r.displayName;
              div.onclick = () => {
                map.setView([r.lat, r.lng], 13);
                container.style.display = 'none';
                document.getElementById('search-input').value = r.displayName;
              };
              container.appendChild(div);
            });
            container.style.display = 'block';
          }, 400);
        };

        const handleSearchKey = (e) => {
          if (e.key === 'Escape') {
            document.getElementById('search-results').style.display = 'none';
          }
        };

        const openAddMarkerModal = () => {
          const center = map.getCenter();
          document.getElementById('marker-lat').value = center.lat.toFixed(4);
          document.getElementById('marker-lng').value = center.lng.toFixed(4);
          document.getElementById('marker-modal').classList.add('active');
        };

        const openAddCircleModal = () => {
          const center = map.getCenter();
          document.getElementById('circle-lat').value = center.lat.toFixed(4);
          document.getElementById('circle-lng').value = center.lng.toFixed(4);
          document.getElementById('circle-modal').classList.add('active');
        };

        const closeModals = () => {
          document.querySelectorAll('.modal-overlay').forEach(m => m.classList.remove('active'));
        };

        const submitMarker = async () => {
          const body = {
            title: document.getElementById('marker-title').value,
            description: document.getElementById('marker-desc').value,
            categoryId: document.getElementById('marker-category').value,
            lat: parseFloat(document.getElementById('marker-lat').value),
            lng: parseFloat(document.getElementById('marker-lng').value),
          };
          if (!body.title) return alert('Title is required');
          const res = await fetch('/api/markers', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body),
          });
          if (res.ok) location.reload();
        };

        const submitCircle = async () => {
          const body = {
            label: document.getElementById('circle-label').value,
            lat: parseFloat(document.getElementById('circle-lat').value),
            lng: parseFloat(document.getElementById('circle-lng').value),
            radius: parseFloat(document.getElementById('circle-radius').value),
            color: document.getElementById('circle-color').value,
          };
          if (!body.label) return alert('Label is required');
          const res = await fetch('/api/circles', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body),
          });
          if (res.ok) location.reload();
        };

        const toggleSidebar = () => {
          document.getElementById('sidebar').classList.toggle('open');
        };

        // Click on map to place marker
        map.on('contextmenu', (e) => {
          document.getElementById('marker-lat').value = e.latlng.lat.toFixed(4);
          document.getElementById('marker-lng').value = e.latlng.lng.toFixed(4);
          document.getElementById('marker-modal').classList.add('active');
        });
      `),
    ),
  );

  return ssr(template);
};

import {
  getMarkers,
  addMarker,
  removeMarker,
  getCircles,
  addCircle,
  removeCircle,
  getCategories,
  addCategory,
  getAllData,
} from './store';
import { searchLocation } from './search';
import { renderPage } from './render';

const PORT = 3000;

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  });

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url);
    const path = url.pathname;
    const method = req.method;

    // Serve the map page
    if (path === '/' && method === 'GET') {
      const data = await getAllData();
      const html = renderPage(data);
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      });
    }

    // Markers API
    if (path === '/api/markers' && method === 'GET') {
      return jsonResponse(await getMarkers());
    }

    if (path === '/api/markers' && method === 'POST') {
      const body = await req.json();
      const { title, description, lat, lng, categoryId } = body as {
        title: string;
        description: string;
        lat: number;
        lng: number;
        categoryId: string;
      };
      if (!title || lat == null || lng == null) {
        return jsonResponse({ error: 'title, lat, lng are required' }, 400);
      }
      const marker = await addMarker({
        title,
        description: description || '',
        lat,
        lng,
        categoryId: categoryId || 'custom',
      });
      return jsonResponse(marker, 201);
    }

    if (path.startsWith('/api/markers/') && method === 'DELETE') {
      const id = path.slice('/api/markers/'.length);
      const removed = await removeMarker(id);
      return removed
        ? jsonResponse({ ok: true })
        : jsonResponse({ error: 'not found' }, 404);
    }

    // Circles API
    if (path === '/api/circles' && method === 'GET') {
      return jsonResponse(await getCircles());
    }

    if (path === '/api/circles' && method === 'POST') {
      const body = await req.json();
      const { label, lat, lng, radius, color } = body as {
        label: string;
        lat: number;
        lng: number;
        radius: number;
        color: string;
      };
      if (!label || lat == null || lng == null || !radius) {
        return jsonResponse({ error: 'label, lat, lng, radius are required' }, 400);
      }
      const circle = await addCircle({
        label,
        lat,
        lng,
        radius,
        color: color || '#3388ff',
      });
      return jsonResponse(circle, 201);
    }

    if (path.startsWith('/api/circles/') && method === 'DELETE') {
      const id = path.slice('/api/circles/'.length);
      const removed = await removeCircle(id);
      return removed
        ? jsonResponse({ ok: true })
        : jsonResponse({ error: 'not found' }, 404);
    }

    // Categories API
    if (path === '/api/categories' && method === 'GET') {
      return jsonResponse(await getCategories());
    }

    if (path === '/api/categories' && method === 'POST') {
      const body = await req.json();
      const { name, color } = body as { name: string; color: string };
      if (!name || !color) {
        return jsonResponse({ error: 'name and color are required' }, 400);
      }
      const category = await addCategory({ name, color });
      return jsonResponse(category, 201);
    }

    // Search API
    if (path === '/api/search' && method === 'GET') {
      const query = url.searchParams.get('q') || '';
      if (!query.trim()) {
        return jsonResponse([]);
      }
      const results = await searchLocation(query);
      return jsonResponse(results);
    }

    return jsonResponse({ error: 'not found' }, 404);
  },
});

