export type ChartType = 'bar' | 'line' | 'pie'

export type FieldInfo = {
  name: string
  type: 'numeric' | 'categorical'
  values: (string | number)[]
}

export type DetectedFields = {
  numeric: FieldInfo[]
  categorical: FieldInfo[]
}

export type AxisConfig = {
  label?: string
  ticks?: number
}

export type ChartOptions = {
  type: ChartType
  title?: string
  xAxis?: AxisConfig
  yAxis?: AxisConfig
  xField?: string
  yField?: string
  labelField?: string
  valueField?: string
  colors?: string[]
  width?: number
  height?: number
}

export type ChartResult = {
  svg: string
  fields: FieldInfo[]
  warnings: string[]
}

export type ChartData = {
  labels: string[]
  values: number[]
}

export type TokenType = 'key' | 'string' | 'number' | 'boolean' | 'null' | 'punctuation' | 'whitespace'

export type Token = {
  type: TokenType
  value: string
}

export type EditorOptions = {
  width?: number
  height?: number
  theme?: 'light' | 'dark'
}

export const DEFAULT_PALETTE = [
  '#4e79a7',
  '#f28e2b',
  '#e15759',
  '#76b7b2',
  '#59a14f',
  '#edc948',
  '#b07aa1',
  '#ff9da7',
  '#9c755f',
  '#bab0ac',
] as const

export const getColor = (index: number, palette?: string[]): string => {
  const p = palette ?? DEFAULT_PALETTE
  return p[index % p.length]
}

export const hexToRgb = (hex: string): { r: number; g: number; b: number } | null => {
  const match = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex)
  if (!match) return null
  return {
    r: parseInt(match[1], 16),
    g: parseInt(match[2], 16),
    b: parseInt(match[3], 16),
  }
}

export const lighten = (hex: string, amount: number): string => {
  const rgb = hexToRgb(hex)
  if (!rgb) return hex
  const r = Math.min(255, Math.round(rgb.r + (255 - rgb.r) * amount))
  const g = Math.min(255, Math.round(rgb.g + (255 - rgb.g) * amount))
  const b = Math.min(255, Math.round(rgb.b + (255 - rgb.b) * amount))
  return `#${r.toString(16).padStart(2, '0')}${g.toString(16).padStart(2, '0')}${b.toString(16).padStart(2, '0')}`
}

import type { FieldInfo, DetectedFields } from './types'

const isNumeric = (value: unknown): boolean => {
  if (typeof value === 'number') return !isNaN(value)
  if (typeof value === 'string') {
    const trimmed = value.trim()
    if (trimmed === '') return false
    return !isNaN(Number(trimmed))
  }
  return false
}

export const detectFields = (data: Record<string, unknown>[]): DetectedFields => {
  if (data.length === 0) return { numeric: [], categorical: [] }

  const allKeys = [...new Set(data.flatMap(Object.keys))]
  const numeric: FieldInfo[] = []
  const categorical: FieldInfo[] = []

  for (const key of allKeys) {
    const values = data.map((row) => row[key])
    const nonNull = values.filter((v) => v !== null && v !== undefined)

    if (nonNull.length === 0) continue

    const numericCount = nonNull.filter(isNumeric).length
    const numericRatio = numericCount / nonNull.length

    if (numericRatio >= 0.8) {
      numeric.push({
        name: key,
        type: 'numeric',
        values: nonNull.map((v) => (typeof v === 'number' ? v : Number(v))),
      })
    } else {
      categorical.push({
        name: key,
        type: 'categorical',
        values: nonNull.map(String),
      })
    }
  }

  return { numeric, categorical }
}

export const pickFields = (
  detected: DetectedFields,
  xField?: string,
  yField?: string,
): { x: FieldInfo | null; y: FieldInfo | null } => {
  const all = [...detected.categorical, ...detected.numeric]
  const x = xField ? all.find((f) => f.name === xField) ?? null : detected.categorical[0] ?? null
  const y = yField
    ? detected.numeric.find((f) => f.name === yField) ?? null
    : detected.numeric[0] ?? null

  return { x, y }
}

export const pickPieFields = (
  detected: DetectedFields,
  labelField?: string,
  valueField?: string,
): { label: FieldInfo | null; value: FieldInfo | null } => {
  const all = [...detected.categorical, ...detected.numeric]
  const label = labelField
    ? all.find((f) => f.name === labelField) ?? null
    : detected.categorical[0] ?? null
  const value = valueField
    ? detected.numeric.find((f) => f.name === valueField) ?? null
    : detected.numeric[0] ?? null

  return { label, value }
}

import { h } from 'plaited'
import type { ChartOptions, ChartData } from './types'
import { getColor } from './colors'

const TAU = 2 * Math.PI

const describeArc = (cx: number, cy: number, r: number, startAngle: number, endAngle: number): string => {
  const start = { x: cx + r * Math.cos(startAngle), y: cy + r * Math.sin(startAngle) }
  const end = { x: cx + r * Math.cos(endAngle), y: cy + r * Math.sin(endAngle) }
  const largeArc = endAngle - startAngle > Math.PI ? 1 : 0
  return `M ${cx} ${cy} L ${start.x} ${start.y} A ${r} ${r} 0 ${largeArc} 1 ${end.x} ${end.y} Z`
}

export const renderPieChart = (data: ChartData, options: ChartOptions) => {
  const { labels, values } = data
  const width = options.width ?? 600
  const height = options.height ?? 400
  const palette = options.colors?.length ? options.colors : undefined

  const total = values.reduce((sum, v) => sum + v, 0)
  if (total === 0) {
    return h(
      'svg',
      { xmlns: 'http://www.w3.org/2000/svg', viewBox: `0 0 ${width} ${height}`, width: String(width), height: String(height) },
      h('rect', { width: String(width), height: String(height), fill: '#ffffff' }),
      h('text', { x: String(width / 2), y: String(height / 2), 'text-anchor': 'middle', 'font-size': '14', fill: '#999' }, 'No data'),
    )
  }

  const legendW = 160
  const chartArea = width - legendW
  const cx = chartArea / 2
  const cy = height / 2 + (options.title ? 10 : 0)
  const r = Math.min(chartArea, height - (options.title ? 80 : 40)) / 2 - 10

  let currentAngle = -Math.PI / 2

  const slices = values.map((value, i) => {
    const sliceAngle = (value / total) * TAU
    const startAngle = currentAngle
    const endAngle = currentAngle + sliceAngle
    currentAngle = endAngle
    const color = getColor(i, palette)

    if (values.length === 1) {
      return h('circle', { cx: String(cx), cy: String(cy), r: String(r), fill: color })
    }

    const midAngle = startAngle + sliceAngle / 2
    const labelR = r * 0.65
    const labelX = cx + labelR * Math.cos(midAngle)
    const labelY = cy + labelR * Math.sin(midAngle)
    const pct = Math.round((value / total) * 100)

    return h(
      'g',
      {},
      h('path', {
        d: describeArc(cx, cy, r, startAngle, endAngle),
        fill: color,
        stroke: '#ffffff',
        'stroke-width': '2',
      }),
      pct >= 5
        ? h(
            'text',
            {
              x: String(labelX),
              y: String(labelY + 4),
              'text-anchor': 'middle',
              'font-size': '11',
              'font-weight': '600',
              'font-family': 'system-ui, sans-serif',
              fill: '#ffffff',
            },
            `${pct}%`,
          )
        : null,
    )
  })

  const legendItems = labels.map((label, i) => {
    const y = 60 + i * 24
    const color = getColor(i, palette)
    const truncLabel = label.length > 16 ? label.slice(0, 15) + '\u2026' : label
    return h(
      'g',
      {},
      h('rect', {
        x: String(chartArea + 10),
        y: String(y),
        width: '14',
        height: '14',
        rx: '2',
        fill: color,
      }),
      h(
        'text',
        {
          x: String(chartArea + 30),
          y: String(y + 12),
          'font-size': '12',
          'font-family': 'system-ui, sans-serif',
          fill: '#444',
        },
        `${truncLabel} (${values[i]})`,
      ),
    )
  })

  const title = options.title
    ? h(
        'text',
        {
          x: String(chartArea / 2),
          y: '28',
          'text-anchor': 'middle',
          'font-size': '16',
          'font-weight': '600',
          'font-family': 'system-ui, sans-serif',
          fill: '#222',
        },
        options.title,
      )
    : null

  return h(
    'svg',
    {
      xmlns: 'http://www.w3.org/2000/svg',
      viewBox: `0 0 ${width} ${height}`,
      width: String(width),
      height: String(height),
    },
    h('rect', { width: String(width), height: String(height), fill: '#ffffff' }),
    title,
    h('g', {}, ...slices),
    h('g', {}, ...legendItems),
  )
}

import { h } from 'plaited'
import type { Token, TokenType, EditorOptions } from './types'

const TOKEN_COLORS: Record<TokenType, { light: string; dark: string }> = {
  key: { light: '#881280', dark: '#c792ea' },
  string: { light: '#1a6b39', dark: '#c3e88d' },
  number: { light: '#1750eb', dark: '#f78c6c' },
  boolean: { light: '#7c4dff', dark: '#89ddff' },
  null: { light: '#7c4dff', dark: '#89ddff' },
  punctuation: { light: '#666666', dark: '#89ddff' },
  whitespace: { light: '', dark: '' },
}

export const tokenize = (json: string): Token[] => {
  const tokens: Token[] = []
  let i = 0

  while (i < json.length) {
    if (/\s/.test(json[i])) {
      let ws = ''
      while (i < json.length && /\s/.test(json[i])) ws += json[i++]
      tokens.push({ type: 'whitespace', value: ws })
      continue
    }

    if (json[i] === '"') {
      let str = '"'
      i++
      while (i < json.length && json[i] !== '"') {
        if (json[i] === '\\') {
          str += json[i++]
        }
        if (i < json.length) str += json[i++]
      }
      if (i < json.length) {
        str += '"'
        i++
      }

      let j = i
      while (j < json.length && /\s/.test(json[j])) j++
      const isKey = j < json.length && json[j] === ':'
      tokens.push({ type: isKey ? 'key' : 'string', value: str })
      continue
    }

    if (json[i] === '-' || (json[i] >= '0' && json[i] <= '9')) {
      let num = ''
      while (i < json.length && /[-\d.eE+]/.test(json[i])) num += json[i++]
      tokens.push({ type: 'number', value: num })
      continue
    }

    if (json.startsWith('true', i)) {
      tokens.push({ type: 'boolean', value: 'true' })
      i += 4
      continue
    }
    if (json.startsWith('false', i)) {
      tokens.push({ type: 'boolean', value: 'false' })
      i += 5
      continue
    }
    if (json.startsWith('null', i)) {
      tokens.push({ type: 'null', value: 'null' })
      i += 4
      continue
    }

    tokens.push({ type: 'punctuation', value: json[i] })
    i++
  }

  return tokens
}

const highlightTokens = (tokens: Token[], theme: 'light' | 'dark') =>
  tokens.map((token) => {
    if (token.type === 'whitespace') return token.value
    const color = TOKEN_COLORS[token.type][theme]
    if (!color) return token.value
    return h(
      'span',
      { style: `color:${color}${token.type === 'key' ? ';font-weight:600' : ''}` },
      token.value,
    )
  })

export const renderEditor = (json: string, options?: EditorOptions) => {
  const width = options?.width ?? 560
  const height = options?.height ?? 300
  const theme = options?.theme ?? 'light'

  const bgColor = theme === 'dark' ? '#1e1e1e' : '#fafafa'
  const textColor = theme === 'dark' ? '#d4d4d4' : '#333333'
  const borderColor = theme === 'dark' ? '#444' : '#ddd'

  const tokens = tokenize(json)
  const highlighted = highlightTokens(tokens, theme)

  const containerStyle = [
    `position:relative`,
    `width:${width}px`,
    `height:${height}px`,
    `border:1px solid ${borderColor}`,
    `border-radius:6px`,
    `overflow:hidden`,
    `font-family:'SF Mono',Monaco,Consolas,monospace`,
    `font-size:13px`,
    `line-height:1.5`,
  ].join(';')

  const sharedTextStyle = [
    `position:absolute`,
    `top:0`,
    `left:0`,
    `width:100%`,
    `height:100%`,
    `padding:12px`,
    `margin:0`,
    `border:none`,
    `font:inherit`,
    `line-height:inherit`,
    `white-space:pre-wrap`,
    `word-wrap:break-word`,
    `overflow:auto`,
    `box-sizing:border-box`,
  ].join(';')

  return h(
    'div',
    { style: containerStyle, 'p-target': 'json-editor' },
    h(
      'pre',
      {
        style: `${sharedTextStyle};background:${bgColor};color:${textColor};pointer-events:none`,
        'aria-hidden': 'true',
      },
      h('code', {}, ...highlighted),
    ),
    h('textarea', {
      style: `${sharedTextStyle};background:transparent;color:transparent;caret-color:${textColor};resize:none;outline:none`,
      'p-trigger': JSON.stringify({ input: 'jsonInput', change: 'jsonChange' }),
      spellcheck: 'false',
      autocomplete: 'off',
      autocorrect: 'off',
      autocapitalize: 'off',
      'data-gramm': 'false',
      value: json,
    }),
  )
}

import { createSSR } from 'plaited'
import { detectFields, pickFields, pickPieFields } from './detect'
import { renderBarChart } from './bar-chart'
import { renderLineChart } from './line-chart'
import { renderPieChart } from './pie-chart'
import type { ChartOptions, ChartResult, ChartData } from './types'

const ssr = createSSR()

const extractChartData = (
  data: Record<string, unknown>[],
  options: ChartOptions,
): { chartData: ChartData; warnings: string[] } => {
  const detected = detectFields(data)
  const warnings: string[] = []

  if (options.type === 'pie') {
    const { label, value } = pickPieFields(
      detected,
      options.labelField ?? options.xField,
      options.valueField ?? options.yField,
    )

    if (!value) {
      warnings.push('No numeric field found for pie chart values')
      return { chartData: { labels: [], values: [] }, warnings }
    }

    const labels = label ? label.values.map(String) : value.values.map((_, i) => `Item ${i + 1}`)
    const values = value.values.map(Number)

    return { chartData: { labels, values }, warnings }
  }

  const { x, y } = pickFields(detected, options.xField, options.yField)

  if (!y) {
    warnings.push('No numeric field found for chart values')
    return { chartData: { labels: [], values: [] }, warnings }
  }

  if (!x) {
    warnings.push('No categorical field found; using row indices as labels')
  }

  const labels = x ? x.values.map(String) : y.values.map((_, i) => String(i + 1))
  const values = y.values.map(Number)

  return { chartData: { labels, values }, warnings }
}

export const generateChart = (
  data: Record<string, unknown>[],
  options: ChartOptions,
): ChartResult => {
  const detected = detectFields(data)
  const allFields = [...detected.numeric, ...detected.categorical]

  if (data.length === 0) {
    return { svg: '', fields: allFields, warnings: ['Input data is empty'] }
  }

  const { chartData, warnings } = extractChartData(data, options)

  if (chartData.labels.length === 0) {
    return { svg: '', fields: allFields, warnings }
  }

  let template: ReturnType<typeof renderBarChart>

  switch (options.type) {
    case 'bar':
      template = renderBarChart(chartData, options)
      break
    case 'line':
      template = renderLineChart(chartData, options)
      break
    case 'pie':
      template = renderPieChart(chartData, options)
      break
  }

  const svg = ssr(template)

  return { svg: String(svg), fields: allFields, warnings }
}

export const toSVG = (
  data: Record<string, unknown>[],
  options: ChartOptions,
): string => {
  const { svg } = generateChart(data, options)
  return `<?xml version="1.0" encoding="UTF-8"?>\n${svg}`
}

export const saveSVG = async (
  data: Record<string, unknown>[],
  options: ChartOptions,
  path: string,
): Promise<void> => {
  const content = toSVG(data, options)
  await Bun.write(path, content)
}

{
  "name": "@node/chart-generator",
  "version": "1.0.0",
  "description": "Generate bar, line, and pie charts from JSON data with auto field detection",
  "main": "src/index.ts",
  "dependencies": {
    "@aspect/plaited": "^0.1.0"
  },
  "modnet": {
    "contentType": "data-viz",
    "structure": "form",
    "mechanics": ["chart", "filter"],
    "boundary": "all",
    "scale": 2
  }
}

export type ChartType = 'bar' | 'line' | 'pie';

export type FieldType = 'numeric' | 'categorical';

export type FieldInfo = {
  name: string;
  type: FieldType;
};

export type ChartConfig = {
  type: ChartType;
  title: string;
  xLabel: string;
  yLabel: string;
  categoryField: string;
  valueFields: string[];
  colors: string[];
  width: number;
  height: number;
};

export type DataRow = Record<string, string | number>;

export type DetectedSchema = {
  fields: FieldInfo[];
  numericFields: string[];
  categoricalFields: string[];
};

export const DEFAULT_COLORS: string[] = [
  '#4e79a7', '#f28e2b', '#e15759', '#76b7b2',
  '#59a14f', '#edc948', '#b07aa1', '#ff9da7',
  '#9c755f', '#bab0ac',
];

export const CHART_PADDING = {
  top: 60,
  right: 30,
  bottom: 60,
  left: 70,
} as const;

import { type DataRow, type DetectedSchema, type FieldInfo } from './types';

export const detectSchema = (data: DataRow[]): DetectedSchema => {
  if (data.length === 0) {
    return { fields: [], numericFields: [], categoricalFields: [] };
  }

  const keys = Object.keys(data[0]);
  const fields: FieldInfo[] = keys.map((name) => {
    const isNumeric = data.every((row) => {
      const val = row[name];
      if (val === null || val === undefined || val === '') return true;
      return typeof val === 'number' || !isNaN(Number(val));
    });

    const hasAtLeastOneValue = data.some((row) => {
      const val = row[name];
      return val !== null && val !== undefined && val !== '';
    });

    return {
      name,
      type: isNumeric && hasAtLeastOneValue ? 'numeric' : 'categorical',
    };
  });

  return {
    fields,
    numericFields: fields.filter((f) => f.type === 'numeric').map((f) => f.name),
    categoricalFields: fields.filter((f) => f.type === 'categorical').map((f) => f.name),
  };
};

export const parseData = (input: string): DataRow[] => {
  const parsed = JSON.parse(input);
  if (!Array.isArray(parsed)) {
    throw new Error('Data must be a JSON array');
  }
  if (parsed.length === 0) {
    throw new Error('Data array must not be empty');
  }
  if (typeof parsed[0] !== 'object' || parsed[0] === null) {
    throw new Error('Each item must be an object');
  }
  return parsed as DataRow[];
};

import { h } from '@aspect/plaited';
import { type ChartConfig, type DataRow, CHART_PADDING } from '../types';

const computeNiceMax = (max: number): number => {
  if (max <= 0) return 10;
  const magnitude = Math.pow(10, Math.floor(Math.log10(max)));
  const normalized = max / magnitude;
  const niceValues = [1, 1.5, 2, 2.5, 3, 4, 5, 6, 8, 10];
  const nice = niceValues.find((v) => v >= normalized) ?? 10;
  return nice * magnitude;
};

export const renderBarChart = (data: DataRow[], config: ChartConfig): string => {
  const { width, height, title, xLabel, yLabel, categoryField, valueFields, colors } = config;
  const pad = CHART_PADDING;
  const plotW = width - pad.left - pad.right;
  const plotH = height - pad.top - pad.bottom;

  const categories = data.map((row) => String(row[categoryField] ?? ''));
  const allValues = data.flatMap((row) => valueFields.map((f) => Number(row[f]) || 0));
  const maxVal = computeNiceMax(Math.max(...allValues, 0));

  const groupCount = categories.length;
  const barCount = valueFields.length;
  const groupWidth = plotW / groupCount;
  const barGap = 4;
  const barWidth = (groupWidth - barGap * (barCount + 1)) / barCount;

  const gridLines = 5;
  const gridStep = maxVal / gridLines;

  const gridElements = Array.from({ length: gridLines + 1 }, (_, i) => {
    const val = gridStep * i;
    const y = pad.top + plotH - (val / maxVal) * plotH;
    return h('g', {},
      h('line', {
        x1: String(pad.left),
        y1: String(y),
        x2: String(width - pad.right),
        y2: String(y),
        stroke: '#e0e0e0',
        'stroke-width': '1',
      }),
      h('text', {
        x: String(pad.left - 8),
        y: String(y + 4),
        'text-anchor': 'end',
        'font-size': '11',
        fill: '#666',
      }, String(Math.round(val))),
    );
  });

  const barGroups = categories.map((cat, gi) => {
    const bars = valueFields.map((field, bi) => {
      const val = Number(data[gi][field]) || 0;
      const barH = (val / maxVal) * plotH;
      const x = pad.left + gi * groupWidth + barGap * (bi + 1) + bi * barWidth;
      const y = pad.top + plotH - barH;
      return h('g', {},
        h('rect', {
          x: String(x),
          y: String(y),
          width: String(Math.max(barWidth, 1)),
          height: String(barH),
          fill: colors[bi % colors.length],
          rx: '2',
        }),
        h('title', {}, `${field}: ${val}`),
      );
    });

    const labelX = pad.left + gi * groupWidth + groupWidth / 2;
    const labelY = pad.top + plotH + 18;

    return h('g', {},
      ...bars,
      h('text', {
        x: String(labelX),
        y: String(labelY),
        'text-anchor': 'middle',
        'font-size': '11',
        fill: '#666',
      }, cat),
    );
  });

  const legend = valueFields.length > 1
    ? valueFields.map((field, i) =>
        h('g', { transform: `translate(${pad.left + i * 120}, ${height - 12})` },
          h('rect', { x: '0', y: '-8', width: '12', height: '12', fill: colors[i % colors.length], rx: '2' }),
          h('text', { x: '16', y: '2', 'font-size': '11', fill: '#444' }, field),
        ),
      )
    : [];

  const svg = h('svg', {
    xmlns: 'http://www.w3.org/2000/svg',
    viewBox: `0 0 ${width} ${height}`,
    width: String(width),
    height: String(height),
    style: 'background: #fff; font-family: system-ui, sans-serif;',
  },
    // Title
    title ? h('text', {
      x: String(width / 2),
      y: '28',
      'text-anchor': 'middle',
      'font-size': '16',
      'font-weight': 'bold',
      fill: '#333',
    }, title) : h('g', {}),
    // Y axis label
    yLabel ? h('text', {
      x: '0',
      y: '0',
      transform: `translate(16, ${pad.top + plotH / 2}) rotate(-90)`,
      'text-anchor': 'middle',
      'font-size': '12',
      fill: '#555',
    }, yLabel) : h('g', {}),
    // X axis label
    xLabel ? h('text', {
      x: String(pad.left + plotW / 2),
      y: String(height - 30),
      'text-anchor': 'middle',
      'font-size': '12',
      fill: '#555',
    }, xLabel) : h('g', {}),
    // Axes
    h('line', {
      x1: String(pad.left),
      y1: String(pad.top),
      x2: String(pad.left),
      y2: String(pad.top + plotH),
      stroke: '#999',
      'stroke-width': '1',
    }),
    h('line', {
      x1: String(pad.left),
      y1: String(pad.top + plotH),
      x2: String(width - pad.right),
      y2: String(pad.top + plotH),
      stroke: '#999',
      'stroke-width': '1',
    }),
    // Grid + bars + legend
    ...gridElements,
    ...barGroups,
    ...legend,
  );

  return svg as unknown as string;
};

import { h } from '@aspect/plaited';
import { type ChartConfig, type DataRow, CHART_PADDING } from '../types';

const computeNiceMax = (max: number): number => {
  if (max <= 0) return 10;
  const magnitude = Math.pow(10, Math.floor(Math.log10(max)));
  const normalized = max / magnitude;
  const niceValues = [1, 1.5, 2, 2.5, 3, 4, 5, 6, 8, 10];
  const nice = niceValues.find((v) => v >= normalized) ?? 10;
  return nice * magnitude;
};

export const renderLineChart = (data: DataRow[], config: ChartConfig): string => {
  const { width, height, title, xLabel, yLabel, categoryField, valueFields, colors } = config;
  const pad = CHART_PADDING;
  const plotW = width - pad.left - pad.right;
  const plotH = height - pad.top - pad.bottom;

  const categories = data.map((row) => String(row[categoryField] ?? ''));
  const allValues = data.flatMap((row) => valueFields.map((f) => Number(row[f]) || 0));
  const maxVal = computeNiceMax(Math.max(...allValues, 0));

  const gridLines = 5;
  const gridStep = maxVal / gridLines;

  const gridElements = Array.from({ length: gridLines + 1 }, (_, i) => {
    const val = gridStep * i;
    const y = pad.top + plotH - (val / maxVal) * plotH;
    return h('g', {},
      h('line', {
        x1: String(pad.left),
        y1: String(y),
        x2: String(width - pad.right),
        y2: String(y),
        stroke: '#e0e0e0',
        'stroke-width': '1',
      }),
      h('text', {
        x: String(pad.left - 8),
        y: String(y + 4),
        'text-anchor': 'end',
        'font-size': '11',
        fill: '#666',
      }, String(Math.round(val))),
    );
  });

  const xLabels = categories.map((cat, i) => {
    const x = pad.left + (i / Math.max(categories.length - 1, 1)) * plotW;
    return h('text', {
      x: String(x),
      y: String(pad.top + plotH + 18),
      'text-anchor': 'middle',
      'font-size': '11',
      fill: '#666',
    }, cat);
  });

  const lines = valueFields.map((field, fi) => {
    const points = data.map((row, i) => {
      const x = pad.left + (i / Math.max(data.length - 1, 1)) * plotW;
      const val = Number(row[field]) || 0;
      const y = pad.top + plotH - (val / maxVal) * plotH;
      return { x, y, val };
    });

    const pathData = points
      .map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`)
      .join(' ');

    const color = colors[fi % colors.length];

    const dots = points.map((p) =>
      h('g', {},
        h('circle', {
          cx: String(p.x),
          cy: String(p.y),
          r: '4',
          fill: color,
          stroke: '#fff',
          'stroke-width': '2',
        }),
        h('title', {}, `${field}: ${p.val}`),
      ),
    );

    return h('g', {},
      h('path', {
        d: pathData,
        fill: 'none',
        stroke: color,
        'stroke-width': '2.5',
        'stroke-linejoin': 'round',
        'stroke-linecap': 'round',
      }),
      ...dots,
    );
  });

  const legend = valueFields.length > 1
    ? valueFields.map((field, i) =>
        h('g', { transform: `translate(${pad.left + i * 120}, ${height - 12})` },
          h('rect', { x: '0', y: '-8', width: '12', height: '12', fill: colors[i % colors.length], rx: '2' }),
          h('text', { x: '16', y: '2', 'font-size': '11', fill: '#444' }, field),
        ),
      )
    : [];

  const svg = h('svg', {
    xmlns: 'http://www.w3.org/2000/svg',
    viewBox: `0 0 ${width} ${height}`,
    width: String(width),
    height: String(height),
    style: 'background: #fff; font-family: system-ui, sans-serif;',
  },
    title ? h('text', {
      x: String(width / 2),
      y: '28',
      'text-anchor': 'middle',
      'font-size': '16',
      'font-weight': 'bold',
      fill: '#333',
    }, title) : h('g', {}),
    yLabel ? h('text', {
      x: '0',
      y: '0',
      transform: `translate(16, ${pad.top + plotH / 2}) rotate(-90)`,
      'text-anchor': 'middle',
      'font-size': '12',
      fill: '#555',
    }, yLabel) : h('g', {}),
    xLabel ? h('text', {
      x: String(pad.left + plotW / 2),
      y: String(height - 30),
      'text-anchor': 'middle',
      'font-size': '12',
      fill: '#555',
    }, xLabel) : h('g', {}),
    h('line', {
      x1: String(pad.left),
      y1: String(pad.top),
      x2: String(pad.left),
      y2: String(pad.top + plotH),
      stroke: '#999',
      'stroke-width': '1',
    }),
    h('line', {
      x1: String(pad.left),
      y1: String(pad.top + plotH),
      x2: String(width - pad.right),
      y2: String(pad.top + plotH),
      stroke: '#999',
      'stroke-width': '1',
    }),
    ...gridElements,
    ...xLabels,
    ...lines,
    ...legend,
  );

  return svg as unknown as string;
};

import { h } from '@aspect/plaited';
import { type ChartConfig, type DataRow } from '../types';

const polarToCartesian = (cx: number, cy: number, r: number, angleDeg: number) => {
  const rad = ((angleDeg - 90) * Math.PI) / 180;
  return {
    x: cx + r * Math.cos(rad),
    y: cy + r * Math.sin(rad),
  };
};

const describeArc = (cx: number, cy: number, r: number, startAngle: number, endAngle: number): string => {
  const sweep = endAngle - startAngle;
  if (sweep >= 359.99) {
    const mid = startAngle + sweep / 2;
    const s1 = polarToCartesian(cx, cy, r, startAngle);
    const m = polarToCartesian(cx, cy, r, mid);
    const e = polarToCartesian(cx, cy, r, endAngle - 0.01);
    return [
      `M ${s1.x} ${s1.y}`,
      `A ${r} ${r} 0 0 1 ${m.x} ${m.y}`,
      `A ${r} ${r} 0 0 1 ${e.x} ${e.y}`,
      'Z',
    ].join(' ');
  }

  const start = polarToCartesian(cx, cy, r, startAngle);
  const end = polarToCartesian(cx, cy, r, endAngle);
  const largeArc = sweep > 180 ? 1 : 0;

  return [
    `M ${cx} ${cy}`,
    `L ${start.x} ${start.y}`,
    `A ${r} ${r} 0 ${largeArc} 1 ${end.x} ${end.y}`,
    'Z',
  ].join(' ');
};

export const renderPieChart = (data: DataRow[], config: ChartConfig): string => {
  const { width, height, title, categoryField, valueFields, colors } = config;

  const valueField = valueFields[0];
  if (!valueField) {
    return h('svg', { xmlns: 'http://www.w3.org/2000/svg', width: String(width), height: String(height) },
      h('text', { x: '50%', y: '50%', 'text-anchor': 'middle', fill: '#999' }, 'No numeric field selected'),
    ) as unknown as string;
  }

  const slices = data.map((row) => ({
    label: String(row[categoryField] ?? ''),
    value: Math.max(0, Number(row[valueField]) || 0),
  }));

  const total = slices.reduce((sum, s) => sum + s.value, 0);
  if (total === 0) {
    return h('svg', { xmlns: 'http://www.w3.org/2000/svg', width: String(width), height: String(height) },
      h('text', { x: '50%', y: '50%', 'text-anchor': 'middle', fill: '#999' }, 'All values are zero'),
    ) as unknown as string;
  }

  const cx = width / 2;
  const cy = height / 2 + (title ? 10 : 0);
  const radius = Math.min(width, height) / 2 - 60;

  let currentAngle = 0;
  const paths = slices.map((slice, i) => {
    const sweep = (slice.value / total) * 360;
    const path = describeArc(cx, cy, radius, currentAngle, currentAngle + sweep);
    const midAngle = currentAngle + sweep / 2;
    const labelPos = polarToCartesian(cx, cy, radius + 20, midAngle);
    const pct = ((slice.value / total) * 100).toFixed(1);

    const el = h('g', {},
      h('path', {
        d: path,
        fill: colors[i % colors.length],
        stroke: '#fff',
        'stroke-width': '2',
      }),
      h('title', {}, `${slice.label}: ${slice.value} (${pct}%)`),
      sweep > 15
        ? h('text', {
            x: String(labelPos.x),
            y: String(labelPos.y),
            'text-anchor': midAngle > 180 ? 'end' : 'start',
            'font-size': '11',
            fill: '#444',
          }, `${slice.label} (${pct}%)`)
        : h('g', {}),
    );

    currentAngle += sweep;
    return el;
  });

  const legendY = cy + radius + 40;
  const legendItems = slices.map((slice, i) =>
    h('g', { transform: `translate(${pad(i, slices.length, width)}, ${legendY})` },
      h('rect', { x: '0', y: '-8', width: '10', height: '10', fill: colors[i % colors.length], rx: '2' }),
      h('text', { x: '14', y: '1', 'font-size': '10', fill: '#444' }, slice.label),
    ),
  );

  const svg = h('svg', {
    xmlns: 'http://www.w3.org/2000/svg',
    viewBox: `0 0 ${width} ${height}`,
    width: String(width),
    height: String(height),
    style: 'background: #fff; font-family: system-ui, sans-serif;',
  },
    title ? h('text', {
      x: String(width / 2),
      y: '28',
      'text-anchor': 'middle',
      'font-size': '16',
      'font-weight': 'bold',
      fill: '#333',
    }, title) : h('g', {}),
    ...paths,
    ...legendItems,
  );

  return svg as unknown as string;
};

const pad = (index: number, total: number, width: number): number => {
  const itemWidth = 80;
  const totalWidth = total * itemWidth;
  const startX = (width - totalWidth) / 2;
  return startX + index * itemWidth;
};

