import { h } from '@aspect/plaited';

type TokenType = 'key' | 'string' | 'number' | 'boolean' | 'null' | 'brace' | 'comma';

type Token = {
  type: TokenType;
  value: string;
};

const tokenize = (json: string): Token[] => {
  const tokens: Token[] = [];
  const re = /("(?:\\.|[^"\\])*")\s*:|("(?:\\.|[^"\\])*")|(-?\d+(?:\.\d+)?(?:[eE][+-]?\d+)?)|(\btrue\b|\bfalse\b)|(\bnull\b)|([[\]{}])|([,:])/g;
  let match: RegExpExecArray | null;

  while ((match = re.exec(json)) !== null) {
    if (match[1]) {
      tokens.push({ type: 'key', value: match[1] });
      tokens.push({ type: 'comma', value: ':' });
    } else if (match[2]) {
      tokens.push({ type: 'string', value: match[2] });
    } else if (match[3]) {
      tokens.push({ type: 'number', value: match[3] });
    } else if (match[4]) {
      tokens.push({ type: 'boolean', value: match[4] });
    } else if (match[5]) {
      tokens.push({ type: 'null', value: match[5] });
    } else if (match[6]) {
      tokens.push({ type: 'brace', value: match[6] });
    } else if (match[7]) {
      tokens.push({ type: 'comma', value: match[7] });
    }
  }

  return tokens;
};

const colorMap: Record<TokenType, string> = {
  key: '#9cdcfe',
  string: '#ce9178',
  number: '#b5cea8',
  boolean: '#569cd6',
  null: '#569cd6',
  brace: '#d4d4d4',
  comma: '#d4d4d4',
};

export const highlightJson = (json: string): string => {
  const tokens = tokenize(json);
  const spans = tokens.map((token) =>
    h('span', { style: `color: ${colorMap[token.type]}` }, token.value),
  );

  return h('pre', {
    style: [
      'background: #1e1e1e',
      'color: #d4d4d4',
      'padding: 16px',
      'border-radius: 6px',
      'font-family: "SF Mono", Menlo, monospace',
      'font-size: 13px',
      'line-height: 1.5',
      'overflow-x: auto',
      'white-space: pre-wrap',
      'word-wrap: break-word',
      'margin: 0',
    ].join('; '),
  }, ...spans) as unknown as string;
};

export const renderJsonEditor = (currentValue: string, error?: string): string => {
  const preview = (() => {
    try {
      const formatted = JSON.stringify(JSON.parse(currentValue), null, 2);
      return highlightJson(formatted);
    } catch {
      return h('pre', {
        style: 'background: #1e1e1e; color: #d4d4d4; padding: 16px; border-radius: 6px; font-family: monospace; font-size: 13px; margin: 0;',
      }, currentValue) as unknown as string;
    }
  })();

  return h('div', { class: 'json-editor' },
    h('div', {
      style: 'display: flex; justify-content: space-between; align-items: center; margin-bottom: 8px;',
    },
      h('label', {
        style: 'font-weight: 600; font-size: 14px; color: #333;',
      }, 'JSON Data Input'),
    ),
    h('textarea', {
      name: 'data',
      'p-target': 'json-input',
      'p-trigger': 'input',
      rows: '12',
