    error
      ? h('div', {
          style: 'color: #e15759; font-size: 12px; margin-top: 4px; padding: 6px 10px; background: #fef2f2; border-radius: 4px;',
        }, error)
      : h('span', {}),
    h('details', { style: 'margin-top: 8px;' },
