import { renderJsonEditor } from './editor';

const chartRenderers: Record<ChartType, typeof renderBarChart> = {
  bar: renderBarChart,
  line: renderLineChart,
  pie: renderPieChart,
};

export const renderPage = (params: {
  jsonInput: string;
  chartType: ChartType;
  title: string;
  xLabel: string;
  yLabel: string;
  colors: string;
  selectedCategory?: string;
  selectedValues?: string[];
  error?: string;
}): string => {
  const { jsonInput, chartType, title, xLabel, yLabel, colors, error } = params;

  let chartSvg = '';
  let detectedFields = '';
  let svgDownload = '';

  try {
    const data = parseData(jsonInput);
    const schema = detectSchema(data);

    const categoryField = params.selectedCategory || schema.categoricalFields[0] || schema.fields[0]?.name || '';
    const valueFields = params.selectedValues?.length
      ? params.selectedValues
      : schema.numericFields.length
        ? schema.numericFields
        : [schema.fields[1]?.name || ''];

    const colorList = colors
      ? colors.split(',').map((c) => c.trim()).filter(Boolean)
      : DEFAULT_COLORS;

    const config: ChartConfig = {
      type: chartType,
      title,
      xLabel,
      yLabel,
      categoryField,
      valueFields: chartType === 'pie' ? [valueFields[0]] : valueFields,
      colors: colorList,
