import { type ChartType, DEFAULT_COLORS } from './types';
import { parseData, detectSchema } from './detect';
import { renderBarChart, renderLineChart, renderPieChart } from './charts';
import { renderPage } from './render';

const sampleData = await Bun.file('data/sample.json').text();

const chartRenderers = {
  bar: renderBarChart,
  line: renderLineChart,
  pie: renderPieChart,
} as const;

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url);

    if (url.pathname === '/' && req.method === 'GET') {
      const html = renderPage({
        jsonInput: sampleData,
        chartType: 'bar',
        title: '',
        xLabel: '',
        yLabel: '',
        colors: '',
      });
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      });
    }

    if (url.pathname === '/' && req.method === 'POST') {
      const formData = await req.formData();
      const jsonInput = formData.get('data') as string || sampleData;
      const chartType = (formData.get('chartType') as ChartType) || 'bar';
      const title = (formData.get('title') as string) || '';
      const xLabel = (formData.get('xLabel') as string) || '';
      const yLabel = (formData.get('yLabel') as string) || '';
      const colors = (formData.get('colors') as string) || '';
      const selectedCategory = (formData.get('selectedCategory') as string) || undefined;
      const selectedValuesRaw = formData.getAll('selectedValues') as string[];

      let error: string | undefined;
      try {
        parseData(jsonInput);
      } catch (e) {
        error = e instanceof Error ? e.message : 'Invalid JSON';
      }

      const html = renderPage({
        jsonInput,
        chartType,
        title,
        xLabel,
        yLabel,
        colors,
        selectedCategory,
        selectedValues: selectedValuesRaw.length ? selectedValuesRaw : undefined,
        error,
      });

      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      });
    }

    if (url.pathname === '/api/download') {
      const dataParam = url.searchParams.get('data');
      const chartType = (url.searchParams.get('type') as ChartType) || 'bar';
      const title = url.searchParams.get('title') || '';
      const xLabel = url.searchParams.get('xLabel') || '';
      const yLabel = url.searchParams.get('yLabel') || '';
      const colorsParam = url.searchParams.get('colors') || '';
      const categoryField = url.searchParams.get('categoryField') || '';
      const valueFieldsParam = url.searchParams.get('valueFields') || '';

      // For download, re-read from the last saved state or use a cookie/session
      // For simplicity, we re-parse from stored data
      const jsonInput = dataParam || sampleData;
      const data = parseData(jsonInput);
      const schema = detectSchema(data);

      const colorList = colorsParam
        ? colorsParam.split(',').map((c) => c.trim()).filter(Boolean)
        : DEFAULT_COLORS;

      const catField = categoryField || schema.categoricalFields[0] || schema.fields[0]?.name || '';
      const valFields = valueFieldsParam
        ? valueFieldsParam.split(',').filter(Boolean)
        : schema.numericFields;

      const renderer = chartRenderers[chartType] || renderBarChart;
      const svg = renderer(data, {
        type: chartType,
        title,
        xLabel,
        yLabel,
        categoryField: catField,
        valueFields: chartType === 'pie' ? [valFields[0]] : valFields,
        colors: colorList,
        width: 700,
        height: 420,
      });

      return new Response(svg, {
        headers: {
          'Content-Type': 'image/svg+xml',
          'Content-Disposition': `attachment; filename="chart-${chartType}.svg"`,
        },
      });
    }

    if (url.pathname === '/api/generate' && req.method === 'POST') {
      const body = await req.json() as {
        data: string;
        chartType?: ChartType;
        title?: string;
        xLabel?: string;
        yLabel?: string;
        colors?: string[];
        categoryField?: string;
        valueFields?: string[];
      };

      const data = parseData(body.data);
      const schema = detectSchema(data);
      const chartType = body.chartType || 'bar';
      const colorList = body.colors?.length ? body.colors : DEFAULT_COLORS;
      const catField = body.categoryField || schema.categoricalFields[0] || schema.fields[0]?.name || '';
      const valFields = body.valueFields?.length ? body.valueFields : schema.numericFields;

      const renderer = chartRenderers[chartType] || renderBarChart;
      const svg = renderer(data, {
        type: chartType,
        title: body.title || '',
        xLabel: body.xLabel || '',
        yLabel: body.yLabel || '',
        categoryField: catField,
        valueFields: chartType === 'pie' ? [valFields[0]] : valFields,
        colors: colorList,
        width: 700,
        height: 420,
      });

      return new Response(JSON.stringify({ svg, schema }), {
        headers: { 'Content-Type': 'application/json' },
      });
    }

    if (url.pathname === '/api/detect' && req.method === 'POST') {
      const body = await req.json() as { data: string };
      const data = parseData(body.data);
      const schema = detectSchema(data);
      return new Response(JSON.stringify(schema), {
        headers: { 'Content-Type': 'application/json' },
      });
    }

    return new Response('Not Found', { status: 404 });
  },
});

