import type { DetectedSchema, FieldInfo, FieldType } from './types'

const isNumeric = (value: unknown): boolean => {
  if (typeof value === 'number') return true
  if (typeof value === 'string') {
    const trimmed = value.trim()
    return trimmed !== '' && !isNaN(Number(trimmed))
  }
  return false
}

const detectFieldType = (values: unknown[]): FieldType => {
  const nonNull = values.filter((v) => v !== null && v !== undefined && v !== '')
  if (nonNull.length === 0) return 'categorical'
  const numericCount = nonNull.filter(isNumeric).length
  return numericCount / nonNull.length >= 0.8 ? 'numeric' : 'categorical'
}

export const detectSchema = (data: Record<string, unknown>[]): DetectedSchema => {
  if (data.length === 0) {
    return { fields: [], numericFields: [], categoricalFields: [], rowCount: 0 }
  }

  const keys = new Set<string>()
  for (const row of data) {
    for (const key of Object.keys(row)) {
      keys.add(key)
    }
  }

  const fields: FieldInfo[] = []
  const numericFields: string[] = []
  const categoricalFields: string[] = []

  for (const key of keys) {
    const values = data.map((row) => row[key] as string | number)
    const type = detectFieldType(values)
    fields.push({ name: key, type, values })

    if (type === 'numeric') {
      numericFields.push(key)
    } else {
      categoricalFields.push(key)
    }
  }

  return { fields, numericFields, categoricalFields, rowCount: data.length }
}

export const resolveConfig = (
  schema: DetectedSchema,
  categoryField?: string,
  valueFields?: string[],
): { category: string; values: string[] } => {
  const category = categoryField
    ?? schema.categoricalFields[0]
    ?? schema.numericFields[0]
    ?? schema.fields[0]?.name
    ?? 'index'

  const values = valueFields?.length
    ? valueFields
    : schema.numericFields.filter((f) => f !== category)

  return { category, values: values.length > 0 ? values : schema.numericFields.slice(0, 1) }
}

import type { ChartDimensions } from './types'
import { DEFAULT_WIDTH, DEFAULT_HEIGHT, DEFAULT_PADDING } from './types'

export const createDimensions = (
  width = DEFAULT_WIDTH,
  height = DEFAULT_HEIGHT,
  padding = DEFAULT_PADDING,
): ChartDimensions => ({
  width,
  height,
  padding,
  plotWidth: width - padding.left - padding.right,
  plotHeight: height - padding.top - padding.bottom,
  plotX: padding.left,
  plotY: padding.top,
})

export const linearScale = (
  value: number,
  domainMin: number,
  domainMax: number,
  rangeMin: number,
  rangeMax: number,
): number => {
  if (domainMax === domainMin) return (rangeMin + rangeMax) / 2
  return rangeMin + ((value - domainMin) / (domainMax - domainMin)) * (rangeMax - rangeMin)
}

export const niceMax = (max: number): number => {
  if (max === 0) return 1
  const magnitude = Math.pow(10, Math.floor(Math.log10(Math.abs(max))))
  const normalized = max / magnitude
  const nice = normalized <= 1 ? 1 : normalized <= 2 ? 2 : normalized <= 5 ? 5 : 10
  return nice * magnitude
}

export const generateTicks = (min: number, max: number, count = 5): number[] => {
  const nMax = niceMax(max)
  const step = nMax / count
  const ticks: number[] = []
  for (let i = 0; i <= count; i++) {
    ticks.push(Math.round((min + step * i) * 100) / 100)
  }
  return ticks
}

export const formatNumber = (n: number): string => {
  if (Math.abs(n) >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`
  if (Math.abs(n) >= 1_000) return `${(n / 1_000).toFixed(1)}K`
  return n % 1 === 0 ? n.toString() : n.toFixed(2)
}

import { h } from 'plaited/template'
import type { ChartConfig, DetectedSchema, ChartDimensions } from '../types'
import { DEFAULT_COLORS } from '../types'
import { createDimensions, linearScale, niceMax, generateTicks, formatNumber } from '../scale'
import { resolveConfig } from '../detect'

export const renderBarChart = (
  data: Record<string, unknown>[],
  schema: DetectedSchema,
  config: ChartConfig,
): string => {
  const dim = createDimensions(config.width, config.height)
  const { category, values } = resolveConfig(schema, config.categoryField, config.valueFields)
  const colors = config.colors ?? DEFAULT_COLORS
  const categories = data.map((row, i) => String(row[category] ?? i))

  const allValues = values.flatMap((field) =>
    data.map((row) => Number(row[field]) || 0),
  )
  const maxVal = niceMax(Math.max(...allValues, 0))
  const ticks = generateTicks(0, maxVal)

  const groupWidth = dim.plotWidth / categories.length
  const barWidth = (groupWidth * 0.7) / values.length
  const barGap = groupWidth * 0.3

  const gridLines = ticks.map((tick) => {
    const y = dim.plotY + dim.plotHeight - linearScale(tick, 0, maxVal, 0, dim.plotHeight)
    return h('g', {},
      h('line', {
        x1: String(dim.plotX),
        y1: String(y),
        x2: String(dim.plotX + dim.plotWidth),
        y2: String(y),
        stroke: '#e0e0e0',
        'stroke-width': '1',
      }),
      h('text', {
        x: String(dim.plotX - 10),
        y: String(y + 4),
        'text-anchor': 'end',
        'font-size': '12',
        fill: '#666',
      }, formatNumber(tick)),
    )
  })

  const bars = categories.flatMap((cat, catIdx) =>
    values.map((field, fieldIdx) => {
      const val = Number(data[catIdx]?.[field]) || 0
      const barHeight = linearScale(val, 0, maxVal, 0, dim.plotHeight)
      const x = dim.plotX + catIdx * groupWidth + barGap / 2 + fieldIdx * barWidth
      const y = dim.plotY + dim.plotHeight - barHeight
      const color = colors[fieldIdx % colors.length]

      return h('g', {},
        h('rect', {
          x: String(x),
          y: String(y),
          width: String(barWidth),
          height: String(barHeight),
          fill: color,
          rx: '2',
        }),
        barHeight > 20
          ? h('text', {
              x: String(x + barWidth / 2),
              y: String(y + barHeight / 2 + 4),
              'text-anchor': 'middle',
              'font-size': '11',
              fill: '#fff',
              'font-weight': 'bold',
            }, formatNumber(val))
          : h('text', {
              x: String(x + barWidth / 2),
              y: String(y - 5),
              'text-anchor': 'middle',
              'font-size': '11',
              fill: '#333',
            }, formatNumber(val)),
      )
    }),
  )

  const categoryLabels = categories.map((cat, i) =>
    h('text', {
      x: String(dim.plotX + i * groupWidth + groupWidth / 2),
      y: String(dim.plotY + dim.plotHeight + 20),
      'text-anchor': 'middle',
      'font-size': '12',
      fill: '#333',
    }, cat),
  )

  const legend = values.length > 1
    ? values.map((field, i) =>
        h('g', { transform: `translate(${dim.plotX + i * 120}, ${dim.height - 20})` },
          h('rect', {
            x: '0', y: '-10', width: '14', height: '14',
            fill: colors[i % colors.length], rx: '2',
          }),
          h('text', {
            x: '20', y: '2', 'font-size': '12', fill: '#333',
          }, field),
        ),
      )
    : []

  return h('svg', {
    xmlns: 'http://www.w3.org/2000/svg',
    viewBox: `0 0 ${dim.width} ${dim.height}`,
    width: String(dim.width),
    height: String(dim.height),
    style: 'font-family: system-ui, -apple-system, sans-serif; background: #fff;',
  },
    config.title
      ? h('text', {
          x: String(dim.width / 2),
          y: '30',
          'text-anchor': 'middle',
          'font-size': '18',
          'font-weight': 'bold',
          fill: '#1a1a1a',
        }, config.title)
      : '',
    h('line', {
      x1: String(dim.plotX),
      y1: String(dim.plotY + dim.plotHeight),
      x2: String(dim.plotX + dim.plotWidth),
      y2: String(dim.plotY + dim.plotHeight),
      stroke: '#333',
      'stroke-width': '1',
    }),
    h('line', {
      x1: String(dim.plotX),
      y1: String(dim.plotY),
      x2: String(dim.plotX),
      y2: String(dim.plotY + dim.plotHeight),
      stroke: '#333',
      'stroke-width': '1',
    }),
    ...gridLines,
    ...bars,
    ...categoryLabels,
    config.xLabel
      ? h('text', {
          x: String(dim.plotX + dim.plotWidth / 2),
          y: String(dim.height - 40),
          'text-anchor': 'middle',
          'font-size': '14',
          fill: '#333',
        }, config.xLabel)
      : '',
    config.yLabel
      ? h('text', {
          x: '20',
          y: String(dim.plotY + dim.plotHeight / 2),
          'text-anchor': 'middle',
          'font-size': '14',
          fill: '#333',
          transform: `rotate(-90, 20, ${dim.plotY + dim.plotHeight / 2})`,
        }, config.yLabel)
      : '',
    ...legend,
  ) as string
}

import { h } from 'plaited/template'
import type { ChartConfig, DetectedSchema } from '../types'
import { DEFAULT_COLORS } from '../types'
import { createDimensions, linearScale, niceMax, generateTicks, formatNumber } from '../scale'
import { resolveConfig } from '../detect'

export const renderLineChart = (
  data: Record<string, unknown>[],
  schema: DetectedSchema,
  config: ChartConfig,
): string => {
  const dim = createDimensions(config.width, config.height)
  const { category, values } = resolveConfig(schema, config.categoryField, config.valueFields)
  const colors = config.colors ?? DEFAULT_COLORS
  const categories = data.map((row, i) => String(row[category] ?? i))

  const allValues = values.flatMap((field) =>
    data.map((row) => Number(row[field]) || 0),
  )
  const maxVal = niceMax(Math.max(...allValues, 0))
  const ticks = generateTicks(0, maxVal)

  const gridLines = ticks.map((tick) => {
    const y = dim.plotY + dim.plotHeight - linearScale(tick, 0, maxVal, 0, dim.plotHeight)
    return h('g', {},
      h('line', {
        x1: String(dim.plotX),
        y1: String(y),
        x2: String(dim.plotX + dim.plotWidth),
        y2: String(y),
        stroke: '#e0e0e0',
        'stroke-width': '1',
        'stroke-dasharray': '4,4',
      }),
      h('text', {
        x: String(dim.plotX - 10),
        y: String(y + 4),
        'text-anchor': 'end',
        'font-size': '12',
        fill: '#666',
      }, formatNumber(tick)),
    )
  })

  const lines = values.map((field, fieldIdx) => {
    const color = colors[fieldIdx % colors.length]
    const points = data.map((row, i) => {
      const val = Number(row[field]) || 0
      const x = dim.plotX + (i / Math.max(data.length - 1, 1)) * dim.plotWidth
      const y = dim.plotY + dim.plotHeight - linearScale(val, 0, maxVal, 0, dim.plotHeight)
      return { x, y, val }
    })

    const pathD = points
      .map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`)
      .join(' ')

    return h('g', {},
      h('path', {
        d: pathD,
        fill: 'none',
        stroke: color,
        'stroke-width': '2.5',
        'stroke-linejoin': 'round',
        'stroke-linecap': 'round',
      }),
      ...points.map((p) =>
        h('circle', {
          cx: String(p.x),
          cy: String(p.y),
          r: '4',
          fill: '#fff',
          stroke: color,
          'stroke-width': '2',
        }),
      ),
      ...points.map((p) =>
        h('text', {
          x: String(p.x),
          y: String(p.y - 12),
          'text-anchor': 'middle',
          'font-size': '11',
          fill: '#333',
        }, formatNumber(p.val)),
      ),
    )
  })

  const categoryLabels = categories.map((cat, i) => {
    const x = dim.plotX + (i / Math.max(categories.length - 1, 1)) * dim.plotWidth
    return h('text', {
      x: String(x),
      y: String(dim.plotY + dim.plotHeight + 20),
      'text-anchor': 'middle',
      'font-size': '12',
      fill: '#333',
    }, cat)
  })

  const legend = values.length > 1
    ? values.map((field, i) =>
        h('g', { transform: `translate(${dim.plotX + i * 120}, ${dim.height - 20})` },
          h('line', {
            x1: '0', y1: '-3', x2: '14', y2: '-3',
            stroke: colors[i % colors.length],
            'stroke-width': '3',
          }),
          h('circle', {
            cx: '7', cy: '-3', r: '3',
            fill: colors[i % colors.length],
          }),
          h('text', {
            x: '20', y: '2', 'font-size': '12', fill: '#333',
          }, field),
        ),
      )
    : []

  return h('svg', {
    xmlns: 'http://www.w3.org/2000/svg',
    viewBox: `0 0 ${dim.width} ${dim.height}`,
    width: String(dim.width),
    height: String(dim.height),
    style: 'font-family: system-ui, -apple-system, sans-serif; background: #fff;',
  },
    config.title
      ? h('text', {
          x: String(dim.width / 2),
          y: '30',
          'text-anchor': 'middle',
          'font-size': '18',
          'font-weight': 'bold',
          fill: '#1a1a1a',
        }, config.title)
      : '',
    h('line', {
      x1: String(dim.plotX),
      y1: String(dim.plotY + dim.plotHeight),
      x2: String(dim.plotX + dim.plotWidth),
      y2: String(dim.plotY + dim.plotHeight),
      stroke: '#333',
      'stroke-width': '1',
    }),
    h('line', {
      x1: String(dim.plotX),
      y1: String(dim.plotY),
      x2: String(dim.plotX),
      y2: String(dim.plotY + dim.plotHeight),
      stroke: '#333',
      'stroke-width': '1',
    }),
    ...gridLines,
    ...lines,
    ...categoryLabels,
    config.xLabel
      ? h('text', {
          x: String(dim.plotX + dim.plotWidth / 2),
          y: String(dim.height - 40),
          'text-anchor': 'middle',
          'font-size': '14',
          fill: '#333',
        }, config.xLabel)
      : '',
    config.yLabel
      ? h('text', {
          x: '20',
          y: String(dim.plotY + dim.plotHeight / 2),
          'text-anchor': 'middle',
          'font-size': '14',
          fill: '#333',
          transform: `rotate(-90, 20, ${dim.plotY + dim.plotHeight / 2})`,
        }, config.yLabel)
      : '',
    ...legend,
  ) as string
}

import { h } from 'plaited/template'
import type { ChartConfig, DetectedSchema } from '../types'
import { DEFAULT_COLORS } from '../types'
import { createDimensions } from '../scale'
import { resolveConfig } from '../detect'
import { formatNumber } from '../scale'

const describeArc = (
  cx: number,
  cy: number,
  radius: number,
  startAngle: number,
  endAngle: number,
): string => {
  const start = polarToCartesian(cx, cy, radius, endAngle)
  const end = polarToCartesian(cx, cy, radius, startAngle)
  const largeArc = endAngle - startAngle > Math.PI ? 1 : 0

  return [
    `M ${cx} ${cy}`,
    `L ${start.x} ${start.y}`,
    `A ${radius} ${radius} 0 ${largeArc} 0 ${end.x} ${end.y}`,
    'Z',
  ].join(' ')
}

const polarToCartesian = (
  cx: number,
  cy: number,
  radius: number,
  angle: number,
): { x: number; y: number } => ({
  x: cx + radius * Math.cos(angle),
  y: cy + radius * Math.sin(angle),
})

export const renderPieChart = (
  data: Record<string, unknown>[],
  schema: DetectedSchema,
  config: ChartConfig,
): string => {
  const dim = createDimensions(config.width, config.height)
  const { category, values } = resolveConfig(schema, config.categoryField, config.valueFields)
  const colors = config.colors ?? DEFAULT_COLORS
  const valueField = values[0]

  if (!valueField) return '<svg></svg>'

  const categories = data.map((row, i) => String(row[category] ?? i))
  const rawValues = data.map((row) => Math.abs(Number(row[valueField]) || 0))
  const total = rawValues.reduce((sum, v) => sum + v, 0)

  if (total === 0) return '<svg></svg>'

  const cx = dim.width / 2
  const cy = dim.plotY + dim.plotHeight / 2
  const radius = Math.min(dim.plotWidth, dim.plotHeight) / 2 - 20

  let currentAngle = -Math.PI / 2
  const slices = rawValues.map((val, i) => {
    const sliceAngle = (val / total) * Math.PI * 2
    const startAngle = currentAngle
    const endAngle = currentAngle + sliceAngle
    const midAngle = startAngle + sliceAngle / 2
    currentAngle = endAngle

    const color = colors[i % colors.length]
    const percentage = ((val / total) * 100).toFixed(1)

    const labelRadius = radius * 0.65
    const labelPos = polarToCartesian(cx, cy, labelRadius, midAngle)

    const outerLabelRadius = radius + 24
    const outerPos = polarToCartesian(cx, cy, outerLabelRadius, midAngle)

    const isFullCircle = rawValues.length === 1

    const path = isFullCircle
      ? h('circle', {
          cx: String(cx),
          cy: String(cy),
          r: String(radius),
          fill: color,
          stroke: '#fff',
          'stroke-width': '2',
        })
      : h('path', {
          d: describeArc(cx, cy, radius, startAngle, endAngle),
          fill: color,
          stroke: '#fff',
          'stroke-width': '2',
        })

    const showInnerLabel = sliceAngle > 0.3

    return h('g', {},
      path,
      showInnerLabel
        ? h('text', {
            x: String(labelPos.x),
            y: String(labelPos.y + 4),
            'text-anchor': 'middle',
            'font-size': '13',
            'font-weight': 'bold',
            fill: '#fff',
          }, `${percentage}%`)
        : '',
      h('text', {
        x: String(outerPos.x),
        y: String(outerPos.y + 4),
        'text-anchor': midAngle > Math.PI / 2 && midAngle < (3 * Math.PI) / 2 ? 'end' : 'start',
        'font-size': '12',
        fill: '#333',
      }, categories[i]),
    )
  })

  const legendY = dim.plotY + dim.plotHeight + 20
  const legend = categories.map((cat, i) =>
    h('g', { transform: `translate(${dim.plotX + (i % 4) * 180}, ${legendY + Math.floor(i / 4) * 22})` },
      h('rect', {
        x: '0', y: '-10', width: '14', height: '14',
        fill: colors[i % colors.length], rx: '2',
      }),
      h('text', {
        x: '20', y: '2', 'font-size': '12', fill: '#333',
      }, `${cat}: ${formatNumber(rawValues[i])}`),
    ),
  )

  return h('svg', {
    xmlns: 'http://www.w3.org/2000/svg',
    viewBox: `0 0 ${dim.width} ${dim.height + Math.ceil(categories.length / 4) * 22}`,
    width: String(dim.width),
    height: String(dim.height + Math.ceil(categories.length / 4) * 22),
    style: 'font-family: system-ui, -apple-system, sans-serif; background: #fff;',
  },
    config.title
      ? h('text', {
          x: String(dim.width / 2),
          y: '30',
          'text-anchor': 'middle',
          'font-size': '18',
          'font-weight': 'bold',
          fill: '#1a1a1a',
        }, config.title)
      : '',
    ...slices,
    ...legend,
  ) as string
}

import { h } from 'plaited/template'

type TokenType = 'key' | 'string' | 'number' | 'boolean' | 'null' | 'punctuation'

type Token = {
  type: TokenType
  value: string
}

const tokenize = (json: string): Token[] => {
  const tokens: Token[] = []
  const regex =
    /("(?:\\.|[^"\\])*")\s*:|("(?:\\.|[^"\\])*")|(-?\d+(?:\.\d+)?(?:[eE][+-]?\d+)?)|(\btrue\b|\bfalse\b)|(\bnull\b)|([\[\]{}:,])|(\s+)/g

  let match: RegExpExecArray | null
  while ((match = regex.exec(json)) !== null) {
    if (match[1]) {
      tokens.push({ type: 'key', value: match[1] })
      const colonIdx = match[0].indexOf(':')
      if (colonIdx !== -1) {
        tokens.push({ type: 'punctuation', value: ':' })
      }
    } else if (match[2]) {
      tokens.push({ type: 'string', value: match[2] })
    } else if (match[3]) {
      tokens.push({ type: 'number', value: match[3] })
    } else if (match[4]) {
      tokens.push({ type: 'boolean', value: match[4] })
    } else if (match[5]) {
      tokens.push({ type: 'null', value: match[5] })
    } else if (match[6]) {
      tokens.push({ type: 'punctuation', value: match[6] })
    }
  }
  return tokens
}

const TOKEN_COLORS: Record<TokenType, string> = {
  key: '#0550ae',
  string: '#0a3069',
  number: '#0550ae',
  boolean: '#cf222e',
  null: '#cf222e',
  punctuation: '#57606a',
}

export const highlightJson = (json: string): string => {
  const tokens = tokenize(json)
  const formatted = JSON.stringify(JSON.parse(json), null, 2)
  const formattedTokens = tokenize(formatted)

  const spans = formattedTokens.map((token) =>
    h('span', { style: `color: ${TOKEN_COLORS[token.type]};` }, token.value),
  )

  return h('pre', {
    style: [
      'margin: 0',
      'padding: 16px',
      'background: #f6f8fa',
      'border: 1px solid #d0d7de',
      'border-radius: 6px',
      'font-family: "SF Mono", "Fira Code", "Consolas", monospace',
      'font-size: 13px',
      'line-height: 1.5',
      'overflow-x: auto',
      'white-space: pre',
      'tab-size: 2',
    ].join('; '),
  }, ...spans) as string
}

export const renderEditor = (json: string, error?: string): string => {
  const editorStyles = [
    'width: 100%',
    'min-height: 300px',
    'padding: 16px',
    'font-family: "SF Mono", "Fira Code", "Consolas", monospace',
    'font-size: 13px',
    'line-height: 1.5',
    'border: 1px solid #d0d7de',
    'border-radius: 6px',
    'background: #f6f8fa',
    'color: #1f2328',
    'resize: vertical',
    'tab-size: 2',
  ].join('; ')

  const errorBanner = error
    ? h('div', {
        style: [
          'padding: 8px 12px',
          'background: #ffebe9',
          'border: 1px solid #ff818266',
          'border-radius: 6px',
          'color: #cf222e',
          'font-size: 13px',
          'margin-bottom: 8px',
        ].join('; '),
      }, error)
    : ''

  return h('div', { class: 'json-editor' },
    h('label', {
      style: 'display: block; font-weight: 600; margin-bottom: 8px; color: #1f2328;',
    }, 'JSON Data Input'),
    errorBanner,
    h('textarea', {
      'p-trigger': 'input:onJsonInput',
      'p-target': 'json-editor',
      style: editorStyles,
      spellcheck: 'false',
      placeholder: '[{"category": "A", "value": 10}, ...]',
    }, json),
    h('div', {
      style: 'margin-top: 12px;',
    },
      h('strong', { style: 'font-size: 13px; color: #57606a;' }, 'Preview:'),
      (() => {
        try {
          return highlightJson(json)
        } catch {
          return h('pre', {
            style: 'padding: 16px; background: #f6f8fa; border-radius: 6px; color: #57606a;',
          }, 'Enter valid JSON to see highlighted preview')
        }
      })(),
    ),
  ) as string
}

export const validateJson = (raw: string): { valid: boolean; data?: Record<string, unknown>[]; error?: string } => {
  try {
    const parsed = JSON.parse(raw)
    if (!Array.isArray(parsed)) {
      return { valid: false, error: 'Input must be a JSON array of objects' }
    }
    if (parsed.length === 0) {
      return { valid: false, error: 'Array must contain at least one object' }
    }
    if (!parsed.every((item: unknown) => typeof item === 'object' && item !== null && !Array.isArray(item))) {
      return { valid: false, error: 'Every element in the array must be an object' }
    }
    return { valid: true, data: parsed as Record<string, unknown>[] }
  } catch (e) {
    return { valid: false, error: `Invalid JSON: ${(e as Error).message}` }
  }
}

import { h } from 'plaited/template'
import type { ChartConfig, ChartType, RenderResult } from './types'
import { detectSchema } from './detect'
import { renderBarChart } from './charts/bar'
import { renderLineChart } from './charts/line'
import { renderPieChart } from './charts/pie'
import { renderEditor, validateJson } from './editor'

const chartRenderers: Record<ChartType, (
  data: Record<string, unknown>[],
  schema: ReturnType<typeof detectSchema>,
  config: ChartConfig,
) => string> = {
  bar: renderBarChart,
  line: renderLineChart,
  pie: renderPieChart,
}

export const generateChart = (
  data: Record<string, unknown>[],
  config: ChartConfig,
): RenderResult => {
  const schema = detectSchema(data)
  const renderer = chartRenderers[config.type]
  const svg = renderer(data, schema, config)
  return { svg, config, schema }
}

export const generateChartFromJson = (
  jsonString: string,
  config: ChartConfig,
): RenderResult & { error?: string } => {
  const validation = validateJson(jsonString)
  if (!validation.valid || !validation.data) {
    return {
      svg: '',
      config,
      schema: { fields: [], numericFields: [], categoricalFields: [], rowCount: 0 },
      error: validation.error,
    }
  }
  return generateChart(validation.data, config)
}

export const renderChartPage = (
  jsonString: string,
  config: ChartConfig,
): string => {
  const validation = validateJson(jsonString)
  const schema = validation.data ? detectSchema(validation.data) : null

  const chartSvg = validation.valid && validation.data
    ? chartRenderers[config.type](validation.data, detectSchema(validation.data), config)
    : ''

  const chartTypeButtons = (['bar', 'line', 'pie'] as const).map((type) =>
    h('button', {
      'p-trigger': `click:onChartType:${type}`,
      style: [
        'padding: 8px 20px',
        'border: 1px solid #d0d7de',
        `background: ${config.type === type ? '#0969da' : '#fff'}`,
        `color: ${config.type === type ? '#fff' : '#1f2328'}`,
        'border-radius: 6px',
        'font-size: 14px',
        'font-weight: 500',
        'cursor: pointer',
      ].join('; '),
    }, type.charAt(0).toUpperCase() + type.slice(1)),
  )

  const fieldSelector = schema
    ? h('div', { style: 'display: flex; gap: 16px; flex-wrap: wrap;' },
        h('div', {},
          h('label', { style: 'display: block; font-size: 13px; color: #57606a; margin-bottom: 4px;' }, 'Category field'),
          h('select', {
            'p-trigger': 'change:onCategoryChange',
            style: 'padding: 6px 12px; border: 1px solid #d0d7de; border-radius: 6px; font-size: 14px;',
          },
            ...schema.categoricalFields.map((f) =>
              h('option', {
                value: f,
                ...(f === config.categoryField ? { selected: 'selected' } : {}),
              }, f),
            ),
          ),
        ),
        h('div', {},
          h('label', { style: 'display: block; font-size: 13px; color: #57606a; margin-bottom: 4px;' }, 'Value fields'),
          ...schema.numericFields.map((f) =>
            h('label', { style: 'display: flex; align-items: center; gap: 4px; font-size: 13px;' },
              h('input', {
                type: 'checkbox',
                value: f,
                checked: config.valueFields?.includes(f) || !config.valueFields ? 'checked' : undefined,
                'p-trigger': 'change:onValueFieldToggle',
              }),
              f,
            ),
          ),
        ),
      )
    : ''

  const inputSection = h('div', { style: 'padding: 16px;' },
    h('input', {
      type: 'text',
      value: config.title ?? '',
      placeholder: 'Chart title',
      'p-trigger': 'input:onTitleChange',
      style: 'width: 100%; padding: 8px 12px; border: 1px solid #d0d7de; border-radius: 6px; font-size: 14px; margin-bottom: 12px;',
    }),
    h('div', { style: 'display: flex; gap: 12px; margin-bottom: 16px;' },
      h('input', {
        type: 'text',
        value: config.xLabel ?? '',
        placeholder: 'X-axis label',
        'p-trigger': 'input:onXLabelChange',
        style: 'flex: 1; padding: 8px 12px; border: 1px solid #d0d7de; border-radius: 6px; font-size: 14px;',
      }),
      h('input', {
        type: 'text',
        value: config.yLabel ?? '',
        placeholder: 'Y-axis label',
        'p-trigger': 'input:onYLabelChange',
        style: 'flex: 1; padding: 8px 12px; border: 1px solid #d0d7de; border-radius: 6px; font-size: 14px;',
      }),
    ),
  )

  return h('div', {
    style: 'max-width: 960px; margin: 0 auto; font-family: system-ui, -apple-system, sans-serif;',
  },
    h('h1', {
      style: 'font-size: 24px; font-weight: 700; color: #1f2328; margin-bottom: 24px;',
    }, 'Chart Generator'),
    h('div', {
      style: 'background: #fff; border: 1px solid #d0d7de; border-radius: 8px; margin-bottom: 24px;',
    },
      h('div', { style: 'padding: 16px; border-bottom: 1px solid #d0d7de;' },
        renderEditor(jsonString, validation.error),
      ),
      inputSection,
      h('div', { style: 'padding: 16px; border-top: 1px solid #d0d7de;' },
        h('div', { style: 'display: flex; gap: 8px; margin-bottom: 16px;' }, ...chartTypeButtons),
        fieldSelector,
      ),
    ),
    validation.valid
      ? h('div', {
          style: 'background: #fff; border: 1px solid #d0d7de; border-radius: 8px; padding: 24px;',
        },
          h('div', { 'p-target': 'chart-output', style: 'text-align: center;' }, chartSvg),
          h('div', { style: 'text-align: center; margin-top: 16px;' },
            h('button', {
              'p-trigger': 'click:onDownloadSvg',
              style: [
                'padding: 8px 20px',
                'background: #2da44e',
                'color: #fff',
                'border: none',
                'border-radius: 6px',
                'font-size: 14px',
                'font-weight: 500',
                'cursor: pointer',
              ].join('; '),
            }, 'Download SVG'),
          ),
        )
      : '',
  ) as string
}

import { createSSR } from 'plaited/server'
import type { ChartConfig, ChartType, RenderResult } from './types'
import { detectSchema } from './detect'
import { generateChart, generateChartFromJson, renderChartPage } from './render'
import { validateJson, highlightJson } from './editor'
import { renderBarChart } from './charts/bar'
import { renderLineChart } from './charts/line'
import { renderPieChart } from './charts/pie'

const loadSampleData = async (): Promise<string> => {
  const file = Bun.file('./data/sample.json')
  return await file.text()
}

const saveSvg = async (svg: string, filename: string): Promise<string> => {
  const path = `./data/${filename}`
  await Bun.write(path, svg)
  return path
}

export const createChartGenerator = () => {
  let currentJson = ''
  let currentConfig: ChartConfig = { type: 'bar' }

  const init = async (): Promise<void> => {
    currentJson = await loadSampleData()
  }

  const setData = (jsonString: string): { valid: boolean; error?: string } => {
    const validation = validateJson(jsonString)
    if (validation.valid) {
      currentJson = jsonString
    }
    return { valid: validation.valid, error: validation.error }
  }

  const setConfig = (config: Partial<ChartConfig>): void => {
    currentConfig = { ...currentConfig, ...config }
  }

  const setChartType = (type: ChartType): void => {
    currentConfig.type = type
  }

  const render = (): RenderResult & { error?: string } => {
    return generateChartFromJson(currentJson, currentConfig)
  }

  const renderPage = (): string => {
    return renderChartPage(currentJson, currentConfig)
  }

  const downloadSvg = async (filename = 'chart.svg'): Promise<string> => {
    const result = render()
    if (result.error) throw new Error(result.error)
    return saveSvg(result.svg, filename)
  }

  const getSchema = () => {
    const validation = validateJson(currentJson)
    if (!validation.data) return null
    return detectSchema(validation.data)
  }

  return {
    init,
    setData,
    setConfig,
    setChartType,
    render,
    renderPage,
    downloadSvg,
    getSchema,
  }
}

// Serve the chart generator as an HTTP endpoint
export const serve = () => {
  const generator = createChartGenerator()

  return Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url)

      if (url.pathname === '/' && req.method === 'GET') {
        await generator.init()
        const html = createSSR(generator.renderPage())
        return new Response(html, {
          headers: { 'content-type': 'text/html; charset=utf-8' },
        })
      }

      if (url.pathname === '/api/chart' && req.method === 'POST') {
        const body = await req.json() as { data: string; config: ChartConfig }
        const result = generateChartFromJson(
          typeof body.data === 'string' ? body.data : JSON.stringify(body.data),
          body.config,
        )

        if (result.error) {
          return Response.json({ error: result.error }, { status: 400 })
        }

        return Response.json({
          svg: result.svg,
          schema: result.schema,
        })
      }

      if (url.pathname === '/api/chart.svg' && req.method === 'POST') {
        const body = await req.json() as { data: string; config: ChartConfig }
        const result = generateChartFromJson(
          typeof body.data === 'string' ? body.data : JSON.stringify(body.data),
          body.config,
        )

        if (result.error) {
          return new Response(result.error, { status: 400 })
        }

        return new Response(result.svg, {
          headers: {
            'content-type': 'image/svg+xml',
            'content-disposition': 'attachment; filename="chart.svg"',
          },
        })
      }

      if (url.pathname === '/api/detect' && req.method === 'POST') {
        const body = await req.json() as { data: string }
        const validation = validateJson(
          typeof body.data === 'string' ? body.data : JSON.stringify(body.data),
        )
        if (!validation.valid || !validation.data) {
          return Response.json({ error: validation.error }, { status: 400 })
        }
        return Response.json(detectSchema(validation.data))
      }

      if (url.pathname === '/api/highlight' && req.method === 'POST') {
        const body = await req.json() as { json: string }
        try {
          const html = highlightJson(body.json)
          return new Response(html, {
            headers: { 'content-type': 'text/html; charset=utf-8' },
          })
        } catch (e) {
          return Response.json({ error: (e as Error).message }, { status: 400 })
        }
      }

      return new Response('Not found', { status: 404 })
    },
  })
}

