  dateAdded: string;
};

export type SortMode = 'date' | 'alpha';

export type GalleryFilters = {
  search?: string;
  tag?: string;
  sort?: SortMode;
};

import type { Project, GalleryFilters, SortMode } from './types';

const DATA_PATH = `${import.meta.dir}/data/projects.json`;

const readProjects = async (): Promise<Project[]> => {
  const file = Bun.file(DATA_PATH);
  const text = await file.text();
  return JSON.parse(text) as Project[];
};

const writeProjects = async (projects: Project[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(projects, null, 2));
};

const sortProjects = (projects: Project[], mode: SortMode): Project[] => {
  const sorted = [...projects];
  if (mode === 'alpha') {
    sorted.sort((a, b) => a.title.localeCompare(b.title));
  } else {
    sorted.sort((a, b) => new Date(b.dateAdded).getTime() - new Date(a.dateAdded).getTime());
  }
  return sorted;
};

const filterByTag = (projects: Project[], tag: string): Project[] => {
  if (!tag) return projects;
  const lower = tag.toLowerCase();
  return projects.filter((p) => p.tags.some((t) => t.toLowerCase() === lower));
};

const filterBySearch = (projects: Project[], query: string): Project[] => {
  if (!query) return projects;
  const lower = query.toLowerCase();
  return projects.filter((p) => p.title.toLowerCase().includes(lower));
};

export const getProjects = async (filters: GalleryFilters = {}): Promise<Project[]> => {
  const { search = '', tag = '', sort = 'date' } = filters;
  let projects = await readProjects();
  projects = filterByTag(projects, tag);
  projects = filterBySearch(projects, search);
  projects = sortProjects(projects, sort);
  return projects;
};

export const getProjectById = async (id: string): Promise<Project | undefined> => {
  const projects = await readProjects();
  return projects.find((p) => p.id === id);
};

export const getAllTags = async (): Promise<string[]> => {
  const projects = await readProjects();
  const tagSet = new Set<string>();
  for (const p of projects) {
    for (const t of p.tags) {
      tagSet.add(t);
    }
  }
  return [...tagSet].sort();
};

export const addProject = async (project: Project): Promise<void> => {
  const projects = await readProjects();
  projects.push(project);
  await writeProjects(projects);
};

export const removeProject = async (id: string): Promise<boolean> => {
  const projects = await readProjects();
  const idx = projects.findIndex((p) => p.id === id);
  if (idx === -1) return false;
  projects.splice(idx, 1);
  await writeProjects(projects);
  return true;
};

