type RouteResult = {
  status: number;
  headers: Record<string, string>;
  body: string;
};

const htmlHeaders = { 'Content-Type': 'text/html; charset=utf-8' };
const jsonHeaders = { 'Content-Type': 'application/json' };

const parseFilters = (url: URL): GalleryFilters => ({
  search: url.searchParams.get('search') ?? '',
  tag: url.searchParams.get('tag') ?? '',
  sort: (url.searchParams.get('sort') as SortMode) ?? 'date',
});

const wrapHtml = (body: string, title: string): string => `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>${title}</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; }
    body { margin: 0; background: #fafbfc; }
    img { max-width: 100%; }
    button { font-family: inherit; }
    a:hover { opacity: 0.85; }
    article:hover { box-shadow: 0 8px 24px rgba(0,0,0,0.1); transform: translateY(-2px); }
  </style>
</head>
<body>${body}</body>
</html>`;

export const handleRequest = async (req: Request): Promise<RouteResult> => {
  const url = new URL(req.url);
  const path = url.pathname;

  // API: list projects as JSON
  if (path === '/api/projects' && req.method === 'GET') {
    const filters = parseFilters(url);
    const projects = await getProjects(filters);
    return { status: 200, headers: jsonHeaders, body: JSON.stringify(projects) };
  }

  // API: list all tags
  if (path === '/api/tags' && req.method === 'GET') {
    const tags = await getAllTags();
    return { status: 200, headers: jsonHeaders, body: JSON.stringify(tags) };
  }

  // API: single project as JSON
  const apiMatch = path.match(/^\/api\/projects\/([^/]+)$/);
  if (apiMatch && req.method === 'GET') {
    const project = await getProjectById(apiMatch[1]);
    if (!project) {
      return { status: 404, headers: jsonHeaders, body: JSON.stringify({ error: 'Not found' }) };
    }
    return { status: 200, headers: jsonHeaders, body: JSON.stringify(project) };
  }

  // HTML: project detail page
  const detailMatch = path.match(/^\/projects\/([^/]+)$/);
  if (detailMatch) {
    const imageIndex = parseInt(url.searchParams.get('img') ?? '0', 10);
    const html = await renderDetail(detailMatch[1], imageIndex);
    if (!html) {
      return { status: 404, headers: htmlHeaders, body: wrapHtml('<p>Project not found.</p>', 'Not Found') };
    }
    const project = await getProjectById(detailMatch[1]);
    const title = project ? `${project.title} — Portfolio` : 'Portfolio';
    return { status: 200, headers: htmlHeaders, body: wrapHtml(html, title) };
  }

  // HTML: gallery index
  if (path === '/' || path === '/gallery') {
    const filters = parseFilters(url);
    const html = await renderGallery(filters);
    return { status: 200, headers: htmlHeaders, body: wrapHtml(html, 'Portfolio Gallery') };
  }

  return { status: 404, headers: htmlHeaders, body: wrapHtml('<p>Page not found.</p>', '404') };
};

// Start server when run directly
if (import.meta.main) {
  const port = parseInt(Bun.env.PORT ?? '3000', 10);

  Bun.serve({
    port,
    fetch: async (req) => {
      const result = await handleRequest(req);
      return new Response(result.body, {
        status: result.status,
        headers: result.headers,
      });
    },
  });

  console.log(`Portfolio gallery running at http://localhost:${port}`);
}

