import type { Project, ProjectFilter, SortOption } from './types'

const DATA_PATH = `${import.meta.dir}/data/projects.json`

const readProjects = async (): Promise<Project[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  return file.json()
}

const writeProjects = async (projects: Project[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(projects, null, 2))
}

const sortProjects = (projects: Project[], sort: SortOption): Project[] => {
  const sorted = [...projects]
  switch (sort) {
    case 'date-desc':
      return sorted.sort((a, b) => new Date(b.dateAdded).getTime() - new Date(a.dateAdded).getTime())
    case 'date-asc':
      return sorted.sort((a, b) => new Date(a.dateAdded).getTime() - new Date(b.dateAdded).getTime())
    case 'alpha-asc':
      return sorted.sort((a, b) => a.title.localeCompare(b.title))
    case 'alpha-desc':
      return sorted.sort((a, b) => b.title.localeCompare(a.title))
    default:
      return sorted
  }
}

export const getProjects = async (filter?: ProjectFilter): Promise<Project[]> => {
  let projects = await readProjects()

  if (filter?.tag) {
    const tag = filter.tag.toLowerCase()
    projects = projects.filter((p) => p.tags.some((t) => t.toLowerCase() === tag))
  }

  if (filter?.query) {
    const q = filter.query.toLowerCase()
    projects = projects.filter((p) => p.title.toLowerCase().includes(q))
  }

  const sort = filter?.sort ?? 'date-desc'
  return sortProjects(projects, sort)
}

export const getProjectById = async (id: string): Promise<Project | undefined> => {
  const projects = await readProjects()
  return projects.find((p) => p.id === id)
}

export const addProject = async (project: Omit<Project, 'id'>): Promise<Project> => {
  const projects = await readProjects()
  const id = project.title
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/(^-|-$)/g, '')
  const newProject: Project = { ...project, id }
  projects.push(newProject)
  await writeProjects(projects)
  return newProject
}

export const updateProject = async (id: string, updates: Partial<Project>): Promise<Project | null> => {
  const projects = await readProjects()
  const index = projects.findIndex((p) => p.id === id)
  if (index === -1) return null
  projects[index] = { ...projects[index], ...updates, id }
  await writeProjects(projects)
  return projects[index]
}

export const deleteProject = async (id: string): Promise<boolean> => {
  const projects = await readProjects()
  const index = projects.findIndex((p) => p.id === id)
  if (index === -1) return false
  projects.splice(index, 1)
  await writeProjects(projects)
  return true
}

export const getAllTags = async (): Promise<string[]> => {
  const projects = await readProjects()
  const tagSet = new Set<string>()
  for (const p of projects) {
    for (const t of p.tags) {
      tagSet.add(t)
    }
  }
  return [...tagSet].sort()
}

