export const renderDocument = (body: string, title: string): string => `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${title}</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #f8f9fa; }
    article:hover { transform: translateY(-4px); box-shadow: 0 8px 24px rgba(0,0,0,0.12) !important; }
    img { transition: opacity 0.3s; }
    button:hover { opacity: 0.85; }
    select:focus, input:focus { border-color: #4361ee !important; box-shadow: 0 0 0 3px rgba(67,97,238,0.15); }
    @media (max-width: 640px) {
      h1 { font-size: 1.8rem !important; }
    }
  </style>
</head>
<body>${body}
<script>
  // Lightbox functionality
  document.addEventListener('click', (e) => {
    const target = e.target;
    const lightbox = document.querySelector('[p-target="lightbox"]');
    const lightboxImg = document.querySelector('[p-target="lightbox-img"]');
    if (!lightbox || !lightboxImg) return;

    const trigger = target.closest('[p-trigger]');
    if (!trigger) return;
    const action = trigger.getAttribute('p-trigger');

    if (action === 'click:open-lightbox') {
      e.stopPropagation();
      lightboxImg.src = target.src;
      lightbox.dataset.currentIndex = target.dataset.index || '0';
      lightbox.style.display = 'flex';
    }

    if (action === 'click:close-lightbox') {
      lightbox.style.display = 'none';
    }

    if (action === 'click:lightbox-prev' || action === 'click:lightbox-next') {
      e.stopPropagation();
      const images = [...document.querySelectorAll('[p-target="carousel-track"] img')];
      let idx = parseInt(lightbox.dataset.currentIndex || '0', 10);
      idx = action.includes('prev') ? (idx - 1 + images.length) % images.length : (idx + 1) % images.length;
      lightboxImg.src = images[idx].src;
      lightbox.dataset.currentIndex = String(idx);
    }

    if (action && action.startsWith('click:carousel-goto:')) {
      const idx = parseInt(action.split(':')[2], 10);
      const track = document.querySelector('[p-target="carousel-track"]');
      if (track) {
        const img = track.children[idx];
        if (img) img.scrollIntoView({ behavior: 'smooth', inline: 'start', block: 'nearest' });
      }
    }
  });
</script>
</body>
</html>`

import { getProjects, getProjectById, addProject, updateProject, deleteProject, getAllTags } from './data'
import { renderGallery, renderDetail, renderDocument } from './render'
import type { ProjectFilter, SortOption, Project } from './types'

const parseFilter = (url: URL): ProjectFilter => ({
  tag: url.searchParams.get('tag') ?? undefined,
  query: url.searchParams.get('q') ?? undefined,
  sort: (url.searchParams.get('sort') as SortOption) ?? 'date-desc',
})

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (body: string, status = 200) =>
  new Response(body, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,

  fetch: async (req) => {
    const url = new URL(req.url)
    const { pathname } = url
    const method = req.method

    // --- HTML routes ---

    if (method === 'GET' && pathname === '/') {
      const filter = parseFilter(url)
      const [projects, tags] = await Promise.all([getProjects(filter), getAllTags()])
      const body = renderGallery(projects, tags, filter.tag ?? '', filter.query ?? '', filter.sort ?? 'date-desc')
      return htmlResponse(renderDocument(body, 'Portfolio Gallery'))
    }

    const projectDetailMatch = pathname.match(/^\/project\/([a-z0-9-]+)$/)
    if (method === 'GET' && projectDetailMatch) {
      const project = await getProjectById(projectDetailMatch[1])
      if (!project) return htmlResponse(renderDocument('<p>Project not found.</p>', 'Not Found'), 404)
      const body = renderDetail(project)
      return htmlResponse(renderDocument(body, `${project.title} — Portfolio`))
    }

    // --- API routes ---

    if (method === 'GET' && pathname === '/api/projects') {
      const filter = parseFilter(url)
      const projects = await getProjects(filter)
      return jsonResponse(projects)
    }

    if (method === 'GET' && pathname.startsWith('/api/projects/')) {
      const id = pathname.replace('/api/projects/', '')
      const project = await getProjectById(id)
      if (!project) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse(project)
    }

    if (method === 'POST' && pathname === '/api/projects') {
      const body = (await req.json()) as Omit<Project, 'id'>
      const project = await addProject(body)
      return jsonResponse(project, 201)
    }

    if (method === 'PUT' && pathname.startsWith('/api/projects/')) {
      const id = pathname.replace('/api/projects/', '')
      const body = (await req.json()) as Partial<Project>
      const updated = await updateProject(id, body)
      if (!updated) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse(updated)
    }

    if (method === 'DELETE' && pathname.startsWith('/api/projects/')) {
      const id = pathname.replace('/api/projects/', '')
      const deleted = await deleteProject(id)
      if (!deleted) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse({ ok: true })
    }

    if (method === 'GET' && pathname === '/api/tags') {
      const tags = await getAllTags()
      return jsonResponse(tags)
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
})

