};

export type SortOption = 'date-desc' | 'date-asc' | 'alpha-asc' | 'alpha-desc';

export type GalleryState = {
  projects: Project[];
  activeTag: string | null;
  searchQuery: string;
  sortBy: SortOption;
  selectedProjectId: string | null;
  lightboxIndex: number;
};

import type { Project, SortOption } from './types';

export const filterByTag = (projects: Project[], tag: string): Project[] =>
  projects.filter((p) => p.tags.some((t) => t.toLowerCase() === tag.toLowerCase()));

export const searchByTitle = (projects: Project[], query: string): Project[] => {
  const q = query.toLowerCase().trim();
  if (!q) return projects;
  return projects.filter((p) => p.title.toLowerCase().includes(q));
};

export const sortProjects = (projects: Project[], option: SortOption): Project[] => {
  const sorted = [...projects];
  switch (option) {
    case 'date-desc':
      return sorted.sort((a, b) => new Date(b.dateAdded).getTime() - new Date(a.dateAdded).getTime());
    case 'date-asc':
      return sorted.sort((a, b) => new Date(a.dateAdded).getTime() - new Date(b.dateAdded).getTime());
    case 'alpha-asc':
      return sorted.sort((a, b) => a.title.localeCompare(b.title));
    case 'alpha-desc':
      return sorted.sort((a, b) => b.title.localeCompare(a.title));
  }
};

export const getAllTags = (projects: Project[]): string[] => {
  const tagSet = new Set<string>();
  for (const p of projects) {
    for (const t of p.tags) {
      tagSet.add(t);
    }
  }
  return [...tagSet].sort();
};

export const applyFilters = (
  projects: Project[],
  tag: string | null,
  query: string,
  sort: SortOption
): Project[] => {
  let result = projects;
  if (tag) result = filterByTag(result, tag);
  if (query) result = searchByTitle(result, query);
  return sortProjects(result, sort);
};

