  sortBy: 'date-desc',
  selectedProjectId: null,
  lightboxIndex: 0,
});

export const setTag = (state: GalleryState, tag: string | null): GalleryState => ({
  ...state,
  activeTag: tag,
});

export const setSearch = (state: GalleryState, query: string): GalleryState => ({
  ...state,
  searchQuery: query,
});

export const setSort = (state: GalleryState, sortBy: SortOption): GalleryState => ({
  ...state,
  sortBy,
});

export const selectProject = (state: GalleryState, id: string | null): GalleryState => ({
  ...state,
  selectedProjectId: id,
  lightboxIndex: 0,
});

export const setLightboxIndex = (state: GalleryState, index: number): GalleryState => ({
  ...state,
  lightboxIndex: index,
});

export const nextImage = (state: GalleryState): GalleryState => {
  const project = state.projects.find((p) => p.id === state.selectedProjectId);
  if (!project) return state;
  const total = project.images.length;
  return {
    ...state,
    lightboxIndex: (state.lightboxIndex + 1) % total,
  };
};

export const prevImage = (state: GalleryState): GalleryState => {
  const project = state.projects.find((p) => p.id === state.selectedProjectId);
  if (!project) return state;
  const total = project.images.length;
  return {
    ...state,
    lightboxIndex: (state.lightboxIndex - 1 + total) % total,
  };
};

import { createSSR } from '@plaited/template';
import type { Project, SortOption } from './types';
import { applyFilters } from './filters';
import { renderGallery } from './gallery';
import { renderDetailView } from './detail';
import { createStore, setTag, setSearch, setSort, selectProject, nextImage, prevImage, setLightboxIndex } from './store';

const loadProjects = async (): Promise<Project[]> => {
  const file = Bun.file(new URL('./data/projects.json', import.meta.url).pathname);
  const text = await file.text();
  return JSON.parse(text) as Project[];
};

const renderPage = (
  projects: Project[],
  tag: string | null,
  query: string,
  sortBy: SortOption,
  selectedId: string | null,
  lightboxIndex: number
): string => {
  const filtered = applyFilters(projects, tag, query, sortBy);
  const galleryTemplate = renderGallery(projects, filtered, tag, sortBy);

  let detailHtml = '';
  if (selectedId) {
    const project = projects.find((p) => p.id === selectedId);
    if (project) {
      const detailTemplate = renderDetailView(project, lightboxIndex);
      detailHtml = createSSR(detailTemplate);
    }
  }

  const galleryHtml = createSSR(galleryTemplate);

  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Portfolio Gallery</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #f8f9fa; min-height: 100vh; }
    article:hover { box-shadow: 0 8px 25px rgba(0,0,0,0.1); transform: translateY(-2px); }
    a:hover { opacity: 0.85; }
    input:focus { border-color: #4f46e5; }
    @media (max-width: 640px) {
      [style*="grid-template-columns"] { grid-template-columns: 1fr !important; }
      [style*="min-width:240px"] { min-width: 100% !important; }
    }
  </style>
</head>
<body>
  ${galleryHtml}
  ${detailHtml}
</body>
</html>`;
};

export const serve = async () => {
  const projects = await loadProjects();

  return Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url);

      if (url.pathname === '/' || url.pathname === '/gallery') {
        const tag = url.searchParams.get('tag') ?? null;
        const query = url.searchParams.get('q') ?? '';
        const sortBy = (url.searchParams.get('sort') as SortOption) ?? 'date-desc';
        const selectedId = url.searchParams.get('project') ?? null;
        const lightboxIndex = parseInt(url.searchParams.get('img') ?? '0', 10);

        const html = renderPage(projects, tag, query, sortBy, selectedId, lightboxIndex);
        return new Response(html, {
          headers: { 'Content-Type': 'text/html; charset=utf-8' },
        });
      }

      if (url.pathname === '/api/projects') {
        const tag = url.searchParams.get('tag') ?? null;
        const query = url.searchParams.get('q') ?? '';
        const sortBy = (url.searchParams.get('sort') as SortOption) ?? 'date-desc';
        const filtered = applyFilters(projects, tag, query, sortBy);
        return Response.json(filtered);
      }

      if (url.pathname.startsWith('/api/projects/')) {
        const id = url.pathname.split('/').pop();
        const project = projects.find((p) => p.id === id);
        if (!project) {
          return Response.json({ error: 'Project not found' }, { status: 404 });
        }
        return Response.json(project);
      }

      return new Response('Not Found', { status: 404 });
    },
  });
};

