// Color type definitions and conversion utilities

export type RGB = { r: number; g: number; b: number }
export type HSL = { h: number; s: number; l: number }
export type ColorValue = {
  hex: string
  rgb: RGB
  hsl: HSL
}

export const hexToRgb = (hex: string): RGB => {
  const cleaned = hex.replace(/^#/, '')
  const full =
    cleaned.length === 3
      ? cleaned
          .split('')
          .map((c) => c + c)
          .join('')
      : cleaned
  const num = parseInt(full, 16)
  return {
    r: (num >> 16) & 255,
    g: (num >> 8) & 255,
    b: num & 255,
  }
}

export const rgbToHex = (rgb: RGB): string => {
  const toHex = (n: number) =>
    Math.round(Math.min(255, Math.max(0, n)))
      .toString(16)
      .padStart(2, '0')
  return `#${toHex(rgb.r)}${toHex(rgb.g)}${toHex(rgb.b)}`
}

export const rgbToHsl = (rgb: RGB): HSL => {
  const r = rgb.r / 255
  const g = rgb.g / 255
  const b = rgb.b / 255
  const max = Math.max(r, g, b)
  const min = Math.min(r, g, b)
  const l = (max + min) / 2
  if (max === min) return { h: 0, s: 0, l: Math.round(l * 100) }
  const d = max - min
  const s = l > 0.5 ? d / (2 - max - min) : d / (max + min)
  let h = 0
  if (max === r) h = ((g - b) / d + (g < b ? 6 : 0)) / 6
  else if (max === g) h = ((b - r) / d + 2) / 6
  else h = ((r - g) / d + 4) / 6
  return {
    h: Math.round(h * 360),
    s: Math.round(s * 100),
    l: Math.round(l * 100),
  }
}

export const hslToRgb = (hsl: HSL): RGB => {
  const h = hsl.h / 360
  const s = hsl.s / 100
  const l = hsl.l / 100
  if (s === 0) {
    const v = Math.round(l * 255)
    return { r: v, g: v, b: v }
  }
  const hue2rgb = (p: number, q: number, t: number): number => {
    const tt = t < 0 ? t + 1 : t > 1 ? t - 1 : t
    if (tt < 1 / 6) return p + (q - p) * 6 * tt
    if (tt < 1 / 2) return q
    if (tt < 2 / 3) return p + (q - p) * (2 / 3 - tt) * 6
    return p
  }
  const q = l < 0.5 ? l * (1 + s) : l + s - l * s
  const p = 2 * l - q
  return {
    r: Math.round(hue2rgb(p, q, h + 1 / 3) * 255),
    g: Math.round(hue2rgb(p, q, h) * 255),
    b: Math.round(hue2rgb(p, q, h - 1 / 3) * 255),
  }
}

export const toColorValue = (hex: string): ColorValue => {
  const rgb = hexToRgb(hex)
  const hsl = rgbToHsl(rgb)
  return { hex: rgbToHex(rgb), rgb, hsl }
}

export const hslToColorValue = (hsl: HSL): ColorValue => {
  const normalizedH = ((hsl.h % 360) + 360) % 360
  const normalizedHsl = { ...hsl, h: normalizedH }
  const rgb = hslToRgb(normalizedHsl)
  return { hex: rgbToHex(rgb), rgb, hsl: normalizedHsl }
}

export const isValidHex = (hex: string): boolean =>
  /^#?([0-9a-fA-F]{3}|[0-9a-fA-F]{6})$/.test(hex)

export const formatRgb = (rgb: RGB): string => `rgb(${rgb.r}, ${rgb.g}, ${rgb.b})`

export const formatHsl = (hsl: HSL): string => `hsl(${hsl.h}, ${hsl.s}%, ${hsl.l}%)`

// Color harmony generation using color theory rules

import { type ColorValue, type HSL, hslToColorValue, toColorValue, rgbToHsl, hexToRgb } from './color'

export type HarmonyMode =
  | 'complementary'
  | 'analogous'
  | 'triadic'
  | 'split-complementary'
  | 'tetradic'

export type Palette = {
  mode: HarmonyMode
  base: ColorValue
  colors: ColorValue[]
}

const shiftHue = (hsl: HSL, degrees: number): HSL => ({
  ...hsl,
  h: (hsl.h + degrees) % 360,
})

const generateComplementary = (baseHsl: HSL): ColorValue[] => [
  hslToColorValue(baseHsl),
  hslToColorValue(shiftHue(baseHsl, 180)),
]

const generateAnalogous = (baseHsl: HSL): ColorValue[] => [
  hslToColorValue(shiftHue(baseHsl, -30)),
  hslToColorValue(baseHsl),
  hslToColorValue(shiftHue(baseHsl, 30)),
]

const generateTriadic = (baseHsl: HSL): ColorValue[] => [
  hslToColorValue(baseHsl),
  hslToColorValue(shiftHue(baseHsl, 120)),
  hslToColorValue(shiftHue(baseHsl, 240)),
]

const generateSplitComplementary = (baseHsl: HSL): ColorValue[] => [
  hslToColorValue(baseHsl),
  hslToColorValue(shiftHue(baseHsl, 150)),
  hslToColorValue(shiftHue(baseHsl, 210)),
]

const generateTetradic = (baseHsl: HSL): ColorValue[] => [
  hslToColorValue(baseHsl),
  hslToColorValue(shiftHue(baseHsl, 90)),
  hslToColorValue(shiftHue(baseHsl, 180)),
  hslToColorValue(shiftHue(baseHsl, 270)),
]

const generators: Record<HarmonyMode, (hsl: HSL) => ColorValue[]> = {
  complementary: generateComplementary,
  analogous: generateAnalogous,
  triadic: generateTriadic,
  'split-complementary': generateSplitComplementary,
  tetradic: generateTetradic,
}

export const generatePalette = (baseHex: string, mode: HarmonyMode): Palette => {
  const base = toColorValue(baseHex)
  const baseHsl = rgbToHsl(hexToRgb(baseHex))
  const colors = generators[mode](baseHsl)
  return { mode, base, colors }
}

export const HARMONY_MODES: { value: HarmonyMode; label: string; description: string }[] = [
  { value: 'complementary', label: 'Complementary', description: 'Two colors opposite on the wheel (180deg)' },
  { value: 'analogous', label: 'Analogous', description: 'Three adjacent colors (30deg apart)' },
  { value: 'triadic', label: 'Triadic', description: 'Three evenly spaced colors (120deg apart)' },
  {
    value: 'split-complementary',
    label: 'Split-Complementary',
    description: 'Base + two colors flanking its complement',
  },
  { value: 'tetradic', label: 'Tetradic', description: 'Four colors in a rectangle (90deg apart)' },
]

// WCAG contrast ratio calculation and compliance checking

import type { RGB } from './color'

export type WcagLevel = 'AAA' | 'AA' | 'Fail'

export type ContrastResult = {
  ratio: number
  ratioText: string
  normalText: { aa: boolean; aaa: boolean; level: WcagLevel }
  largeText: { aa: boolean; aaa: boolean; level: WcagLevel }
}

const srgbToLinear = (channel: number): number => {
  const c = channel / 255
  return c <= 0.04045 ? c / 12.92 : Math.pow((c + 0.055) / 1.055, 2.4)
}

export const relativeLuminance = (rgb: RGB): number =>
  0.2126 * srgbToLinear(rgb.r) + 0.7152 * srgbToLinear(rgb.g) + 0.0722 * srgbToLinear(rgb.b)

export const contrastRatio = (rgb1: RGB, rgb2: RGB): number => {
  const l1 = relativeLuminance(rgb1)
  const l2 = relativeLuminance(rgb2)
  const lighter = Math.max(l1, l2)
  const darker = Math.min(l1, l2)
  return (lighter + 0.05) / (darker + 0.05)
}

const wcagLevel = (ratio: number, aaThreshold: number, aaaThreshold: number): WcagLevel => {
  if (ratio >= aaaThreshold) return 'AAA'
  if (ratio >= aaThreshold) return 'AA'
  return 'Fail'
}

export const checkContrast = (rgb1: RGB, rgb2: RGB): ContrastResult => {
  const ratio = contrastRatio(rgb1, rgb2)
  return {
    ratio,
    ratioText: `${ratio.toFixed(2)}:1`,
    normalText: {
      aa: ratio >= 4.5,
      aaa: ratio >= 7,
      level: wcagLevel(ratio, 4.5, 7),
    },
    largeText: {
      aa: ratio >= 3,
      aaa: ratio >= 4.5,
      level: wcagLevel(ratio, 3, 4.5),
    },
  }
}

// Palette persistence using Bun file APIs

import type { Palette } from './harmony'

type SavedPalette = Palette & {
  id: string
  name: string
  createdAt: string
}

const DATA_PATH = new URL('../data/palettes.json', import.meta.url).pathname

export const loadPalettes = async (): Promise<SavedPalette[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return JSON.parse(text) as SavedPalette[]
}

export const savePalette = async (palette: Palette, name: string): Promise<SavedPalette> => {
  const palettes = await loadPalettes()
  const saved: SavedPalette = {
    ...palette,
    id: crypto.randomUUID(),
    name,
    createdAt: new Date().toISOString(),
  }
  palettes.push(saved)
  await Bun.write(DATA_PATH, JSON.stringify(palettes, null, 2))
  return saved
}

export const deletePalette = async (id: string): Promise<void> => {
  const palettes = await loadPalettes()
  const filtered = palettes.filter((p) => p.id !== id)
  await Bun.write(DATA_PATH, JSON.stringify(filtered, null, 2))
}

