export const renderPage = (
  palette: Palette,
  selectedIndices: [number, number] | null,
  contrastHtml: string | null,
): string => {
  const { ssr, sheet } = createSSR()
  return ssr(
    h(
      'html',
      { lang: 'en' },
      h(
        'head',
        {},
        h('meta', { charset: 'UTF-8' }),
        h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1.0' }),
        h('title', {}, 'Color Palette Generator'),
        h('style', {}, sheet()),
      ),
      h(
        'body',
        { style: 'margin: 0' },
        h(
          'div',
          { style: styleToString(styles.container) },
          h('h1', { style: styleToString(styles.title) }, 'Color Palette Generator'),
          renderInputSection(palette.base.hex) as unknown as ReturnType<typeof h>,
          renderModeSelector(palette.mode) as unknown as ReturnType<typeof h>,
          h(
            'div',
            { style: styleToString(styles.swatchGrid), 'p-target': 'swatch-grid' },
            ...palette.colors.map((color, i) => {
              const isSelected = selectedIndices
                ? selectedIndices[0] === i || selectedIndices[1] === i
                : false
              return renderColorSwatch(color, i, isSelected) as unknown as ReturnType<typeof h>
            }),
          ),
          h(
            'div',
            { style: styleToString(styles.hint) },
            'Click a swatch to select it for contrast checking. Click color values to copy.',
          ),
          contrastHtml
            ? (contrastHtml as unknown as ReturnType<typeof h>)
            : (h(
                'div',
                {
                  style: styleToString(styles.contrastSection),
                  'p-target': 'contrast-checker',
                },
                h(
                  'div',
                  { style: styleToString(styles.contrastTitle) },
                  'Contrast Checker',
                ),
                h(
                  'p',
                  { style: styleToString({ color: '#666', fontSize: '14px' }) },
                  'Select two swatches above to compare their contrast ratio.',
                ),
              ) as unknown as ReturnType<typeof h>),
          h('div', {
            style: styleToString({ ...styles.copyToast, opacity: '0', pointerEvents: 'none' }),
            'p-target': 'copy-toast',
          }),
        ),
        h(
          'script',
          {},
          `
          document.addEventListener('click', async (e) => {
            const copyEl = e.target.closest('[data-value]');
            if (copyEl) {
              const value = copyEl.dataset.value;
              try {
                await navigator.clipboard.writeText(value);
                const toast = document.querySelector('[p-target="copy-toast"]');
                if (toast) {
                  toast.textContent = 'Copied: ' + value;
                  toast.style.opacity = '1';
                  toast.style.pointerEvents = 'auto';
                  setTimeout(() => {
                    toast.style.opacity = '0';
                    toast.style.pointerEvents = 'none';
                  }, 1500);
                }
              } catch {}
            }
          });

          const selected = [];
          document.querySelectorAll('[p-trigger="select-color:click"]').forEach(el => {
            el.addEventListener('click', (e) => {
              if (e.target.closest('[data-value]')) return;
              const idx = parseInt(el.dataset.index);
              const existing = selected.indexOf(idx);
              if (existing >= 0) {
                selected.splice(existing, 1);
                el.style.borderColor = 'transparent';
              } else {
                if (selected.length >= 2) {
                  const removed = selected.shift();
                  const removedEl = document.querySelector('[data-index="' + removed + '"]');
                  if (removedEl) removedEl.style.borderColor = 'transparent';
                }
                selected.push(idx);
                el.style.borderColor = '#e94560';
              }
              if (selected.length === 2) {
                window.location.href = '?base=' + encodeURIComponent(document.querySelector('[p-target="hex-field"]').value) +
                  '&mode=' + encodeURIComponent(document.querySelector('[p-trigger="change-mode:click"][style*="e94560"]').dataset.mode) +
                  '&sel=' + selected.join(',');
              }
            });
          });

          document.querySelectorAll('[p-trigger="change-mode:click"]').forEach(btn => {
            btn.addEventListener('click', () => {
              const mode = btn.dataset.mode;
              const base = document.querySelector('[p-target="hex-field"]').value;
              window.location.href = '?base=' + encodeURIComponent(base) + '&mode=' + encodeURIComponent(mode);
            });
          });

          const colorPicker = document.querySelector('[p-trigger="color-pick:input"]');
          const hexField = document.querySelector('[p-target="hex-field"]');
          if (colorPicker) {
            colorPicker.addEventListener('input', (e) => {
              const mode = document.querySelector('[p-trigger="change-mode:click"][style*="e94560"]').dataset.mode;
              window.location.href = '?base=' + encodeURIComponent(e.target.value) + '&mode=' + encodeURIComponent(mode);
            });
          }
          if (hexField) {
            let debounce;
            hexField.addEventListener('input', (e) => {
              clearTimeout(debounce);
              debounce = setTimeout(() => {
                const val = e.target.value;
                if (/^#[0-9a-fA-F]{6}$/.test(val)) {
                  const mode = document.querySelector('[p-trigger="change-mode:click"][style*="e94560"]').dataset.mode;
                  window.location.href = '?base=' + encodeURIComponent(val) + '&mode=' + encodeURIComponent(mode);
                }
              }, 600);
            });
          }
          `,
        ),
      ),
    ),
  )
}

