    const url = new URL(req.url)

    // API: save palette
    if (url.pathname === '/api/save' && req.method === 'POST') {
      const body = (await req.json()) as { base: string; mode: string; name: string }
      if (!isValidHex(body.base) || !isHarmonyMode(body.mode)) {
        return new Response(JSON.stringify({ error: 'Invalid parameters' }), {
          status: 400,
          headers: { 'Content-Type': 'application/json' },
        })
      }
      const palette = generatePalette(body.base, body.mode)
      const saved = await savePalette(palette, body.name || 'Untitled')
      return new Response(JSON.stringify(saved), {
        headers: { 'Content-Type': 'application/json' },
      })
    }

    // API: list saved palettes
    if (url.pathname === '/api/palettes' && req.method === 'GET') {
      const palettes = await loadPalettes()
      return new Response(JSON.stringify(palettes), {
        headers: { 'Content-Type': 'application/json' },
      })
    }

    // API: delete palette
    if (url.pathname.startsWith('/api/palettes/') && req.method === 'DELETE') {
      const id = url.pathname.split('/').pop() ?? ''
      await deletePalette(id)
      return new Response(JSON.stringify({ ok: true }), {
        headers: { 'Content-Type': 'application/json' },
      })
    }

    // API: contrast check
    if (url.pathname === '/api/contrast' && req.method === 'GET') {
      const hex1 = url.searchParams.get('c1') ?? ''
      const hex2 = url.searchParams.get('c2') ?? ''
      if (!isValidHex(hex1) || !isValidHex(hex2)) {
        return new Response(JSON.stringify({ error: 'Invalid hex colors' }), {
          status: 400,
          headers: { 'Content-Type': 'application/json' },
        })
      }
      const color1 = toColorValue(hex1)
      const color2 = toColorValue(hex2)
      const result = checkContrast(color1.rgb, color2.rgb)
      return new Response(JSON.stringify({ color1, color2, ...result }), {
        headers: { 'Content-Type': 'application/json' },
      })
    }

    // Main page
    const baseHex = url.searchParams.get('base') ?? DEFAULT_BASE
    const modeParam = url.searchParams.get('mode') ?? DEFAULT_MODE
    const selParam = url.searchParams.get('sel')

    const base = isValidHex(baseHex) ? baseHex : DEFAULT_BASE
    const mode = isHarmonyMode(modeParam) ? modeParam : DEFAULT_MODE

    const palette = generatePalette(base, mode)

    let selectedIndices: [number, number] | null = null
    let contrastHtml: string | null = null

    if (selParam) {
      const parts = selParam.split(',').map(Number)
      if (
        parts.length === 2 &&
        parts.every((i) => !isNaN(i) && i >= 0 && i < palette.colors.length)
      ) {
        selectedIndices = [parts[0], parts[1]]
        const c1 = palette.colors[parts[0]]
        const c2 = palette.colors[parts[1]]
        const result = checkContrast(c1.rgb, c2.rgb)
        contrastHtml = renderContrastChecker(c1, c2, result)
      }
    }

    const html = renderPage(palette, selectedIndices, contrastHtml)

    return new Response(html, {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  },
})

