import type { RGB, HSL, ColorValue } from './color.types'

const clamp = (val: number, min: number, max: number): number =>
  Math.min(max, Math.max(min, val))

const roundTo = (val: number, decimals: number): number => {
  const factor = 10 ** decimals
  return Math.round(val * factor) / factor
}

export const hexToRgb = (hex: string): RGB => {
  const cleaned = hex.replace(/^#/, '')
  const full =
    cleaned.length === 3
      ? cleaned
          .split('')
          .map((c) => c + c)
          .join('')
      : cleaned
  const num = parseInt(full, 16)
  return {
    r: (num >> 16) & 255,
    g: (num >> 8) & 255,
    b: num & 255,
  }
}

export const rgbToHex = (rgb: RGB): string => {
  const toHex = (c: number) =>
    clamp(Math.round(c), 0, 255).toString(16).padStart(2, '0')
  return `#${toHex(rgb.r)}${toHex(rgb.g)}${toHex(rgb.b)}`
}

export const rgbToHsl = (rgb: RGB): HSL => {
  const r = rgb.r / 255
  const g = rgb.g / 255
  const b = rgb.b / 255
  const max = Math.max(r, g, b)
  const min = Math.min(r, g, b)
  const l = (max + min) / 2
  if (max === min) {
    return { h: 0, s: 0, l: roundTo(l * 100, 1) }
  }
  const d = max - min
  const s = l > 0.5 ? d / (2 - max - min) : d / (max + min)
  let h = 0
  if (max === r) h = ((g - b) / d + (g < b ? 6 : 0)) / 6
  else if (max === g) h = ((b - r) / d + 2) / 6
  else h = ((r - g) / d + 4) / 6
  return {
    h: roundTo(h * 360, 1),
    s: roundTo(s * 100, 1),
    l: roundTo(l * 100, 1),
  }
}

export const hslToRgb = (hsl: HSL): RGB => {
  const h = hsl.h / 360
  const s = hsl.s / 100
  const l = hsl.l / 100
  if (s === 0) {
    const v = Math.round(l * 255)
    return { r: v, g: v, b: v }
  }
  const hue2rgb = (p: number, q: number, t: number): number => {
    let tt = t
    if (tt < 0) tt += 1
    if (tt > 1) tt -= 1
    if (tt < 1 / 6) return p + (q - p) * 6 * tt
    if (tt < 1 / 2) return q
    if (tt < 2 / 3) return p + (q - p) * (2 / 3 - tt) * 6
    return p
  }
  const q = l < 0.5 ? l * (1 + s) : l + s - l * s
  const p = 2 * l - q
  return {
    r: Math.round(hue2rgb(p, q, h + 1 / 3) * 255),
    g: Math.round(hue2rgb(p, q, h) * 255),
    b: Math.round(hue2rgb(p, q, h - 1 / 3) * 255),
  }
}

export const normalizeHue = (h: number): number => ((h % 360) + 360) % 360

export const toColorValue = (hex: string): ColorValue => {
  const rgb = hexToRgb(hex)
  const hsl = rgbToHsl(rgb)
  return { hex: rgbToHex(rgb), rgb, hsl }
}

export const fromHsl = (hsl: HSL): ColorValue => {
  const rgb = hslToRgb(hsl)
  return { hex: rgbToHex(rgb), rgb, hsl: { ...hsl, h: normalizeHue(hsl.h) } }
}

export const isValidHex = (hex: string): boolean =>
  /^#?([0-9A-Fa-f]{3}|[0-9A-Fa-f]{6})$/.test(hex)

export const formatRgb = (rgb: RGB): string =>
  `rgb(${rgb.r}, ${rgb.g}, ${rgb.b})`

export const formatHsl = (hsl: HSL): string =>
  `hsl(${hsl.h}°, ${hsl.s}%, ${hsl.l}%)`

import type { HarmonyMode, PaletteEntry, Palette, ColorValue } from './color.types'
import { toColorValue, fromHsl, normalizeHue } from './color-utils'

const shiftHue = (base: ColorValue, degrees: number): ColorValue =>
  fromHsl({
    h: normalizeHue(base.hsl.h + degrees),
    s: base.hsl.s,
    l: base.hsl.l,
  })

const makeEntry = (color: ColorValue, label: string): PaletteEntry => ({
  color,
  label,
})

const complementary = (base: ColorValue): PaletteEntry[] => [
  makeEntry(base, 'Base'),
  makeEntry(shiftHue(base, 180), 'Complement'),
]

const analogous = (base: ColorValue): PaletteEntry[] => [
  makeEntry(shiftHue(base, -30), 'Analogous -30°'),
  makeEntry(base, 'Base'),
  makeEntry(shiftHue(base, 30), 'Analogous +30°'),
]

const triadic = (base: ColorValue): PaletteEntry[] => [
  makeEntry(base, 'Base'),
  makeEntry(shiftHue(base, 120), 'Triad 120°'),
  makeEntry(shiftHue(base, 240), 'Triad 240°'),
]

const splitComplementary = (base: ColorValue): PaletteEntry[] => [
  makeEntry(base, 'Base'),
  makeEntry(shiftHue(base, 150), 'Split 150°'),
  makeEntry(shiftHue(base, 210), 'Split 210°'),
]

const tetradic = (base: ColorValue): PaletteEntry[] => [
  makeEntry(base, 'Base'),
  makeEntry(shiftHue(base, 60), 'Tetrad 60°'),
  makeEntry(shiftHue(base, 180), 'Tetrad 180°'),
  makeEntry(shiftHue(base, 240), 'Tetrad 240°'),
]

const generators: Record<HarmonyMode, (base: ColorValue) => PaletteEntry[]> = {
  complementary,
  analogous,
  triadic,
  'split-complementary': splitComplementary,
  tetradic,
}

export const generatePalette = (baseHex: string, mode: HarmonyMode): Palette => {
  const baseColor = toColorValue(baseHex)
  const colors = generators[mode](baseColor)
  return { baseColor, mode, colors }
}

export const HARMONY_MODES: { value: HarmonyMode; label: string }[] = [
  { value: 'complementary', label: 'Complementary' },
  { value: 'analogous', label: 'Analogous' },
  { value: 'triadic', label: 'Triadic' },
  { value: 'split-complementary', label: 'Split-Complementary' },
  { value: 'tetradic', label: 'Tetradic' },
]

import type { RGB, ColorValue, ContrastResult, ContrastPair, WCAGLevel } from './color.types'

const linearize = (channel: number): number => {
  const s = channel / 255
  return s <= 0.03928 ? s / 12.92 : ((s + 0.055) / 1.055) ** 2.4
}

export const relativeLuminance = (rgb: RGB): number =>
  0.2126 * linearize(rgb.r) + 0.7152 * linearize(rgb.g) + 0.0722 * linearize(rgb.b)

export const contrastRatio = (color1: RGB, color2: RGB): number => {
  const l1 = relativeLuminance(color1)
  const l2 = relativeLuminance(color2)
  const lighter = Math.max(l1, l2)
  const darker = Math.min(l1, l2)
  return Math.round(((lighter + 0.05) / (darker + 0.05)) * 100) / 100
}

const classifyNormalText = (ratio: number): WCAGLevel => {
  if (ratio >= 7) return 'AAA'
  if (ratio >= 4.5) return 'AA'
  return 'Fail'
}

const classifyLargeText = (ratio: number): WCAGLevel => {
  if (ratio >= 4.5) return 'AAA'
  if (ratio >= 3) return 'AA'
  return 'Fail'
}

export const checkContrast = (color1: ColorValue, color2: ColorValue): ContrastResult => {
  const ratio = contrastRatio(color1.rgb, color2.rgb)
  return {
    ratio,
    normalText: classifyNormalText(ratio),
    largeText: classifyLargeText(ratio),
  }
}

export const checkAllPairs = (colors: ColorValue[]): ContrastPair[] => {
  const pairs: ContrastPair[] = []
  for (let i = 0; i < colors.length; i++) {
    for (let j = i + 1; j < colors.length; j++) {
      pairs.push({
        color1: colors[i],
        color2: colors[j],
        contrast: checkContrast(colors[i], colors[j]),
      })
    }
  }
  return pairs
}

import type { SavedPalette, HarmonyMode } from './color.types'

const DATA_PATH = './data/palettes.jsonl'

export const savePalette = async (baseHex: string, mode: HarmonyMode): Promise<SavedPalette> => {
  const entry: SavedPalette = {
    id: crypto.randomUUID(),
    createdAt: new Date().toISOString(),
    baseHex,
    mode,
  }
  const line = JSON.stringify(entry) + '\n'
  const file = Bun.file(DATA_PATH)
  const existing = (await file.exists()) ? await file.text() : ''
  await Bun.write(DATA_PATH, existing + line)
  return entry
}

export const loadPalettes = async (): Promise<SavedPalette[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text
    .trim()
    .split('\n')
    .filter((line) => line.length > 0)
    .map((line) => JSON.parse(line) as SavedPalette)
}

export const deletePalette = async (id: string): Promise<boolean> => {
  const palettes = await loadPalettes()
  const filtered = palettes.filter((p) => p.id !== id)
  if (filtered.length === palettes.length) return false
  const content = filtered.map((p) => JSON.stringify(p)).join('\n') + (filtered.length ? '\n' : '')
  await Bun.write(DATA_PATH, content)
  return true
}

