          ),
          ...contrastPairs.slice(0, 3).map(renderContrastPreview),
        ),
      ),

      h('script', {}, `
        document.querySelectorAll('[data-value]').forEach(btn => {
          btn.addEventListener('click', async (e) => {
            e.preventDefault();
            const val = btn.getAttribute('data-value');
            try {
              await navigator.clipboard.writeText(val);
              const orig = btn.textContent;
              btn.textContent = 'Copied!';
              setTimeout(() => { btn.textContent = orig; }, 1200);
            } catch {
              const ta = document.createElement('textarea');
              ta.value = val;
              document.body.appendChild(ta);
              ta.select();
              document.execCommand('copy');
              document.body.removeChild(ta);
              const orig = btn.textContent;
              btn.textContent = 'Copied!';
              setTimeout(() => { btn.textContent = orig; }, 1200);
            }
          });
        });

        const picker = document.getElementById('picker');
        const hex = document.getElementById('hex');
        if (picker && hex) {
          picker.addEventListener('input', () => { hex.value = picker.value.toUpperCase(); });
          hex.addEventListener('input', () => {
            const v = hex.value;
            if (/^#[0-9A-Fa-f]{6}$/.test(v)) picker.value = v;
          });
        }
      `),
    ),
  )

  const ssr = createSSR()
  return ssr(tree)
}

import type { HarmonyMode } from './color.types'
import { isValidHex, toColorValue } from './color-utils'
import { generatePalette, HARMONY_MODES } from './harmony'
import { checkAllPairs } from './contrast'
import { renderPalettePage } from './render'
import { savePalette } from './storage'

const DEFAULT_COLOR = '#3a86ff'
const DEFAULT_MODE: HarmonyMode = 'complementary'

const parseRequest = (url: URL): { color: string; mode: HarmonyMode } => {
  const rawColor = url.searchParams.get('color') ?? DEFAULT_COLOR
  const color = rawColor.startsWith('#') ? rawColor : `#${rawColor}`
  const rawMode = url.searchParams.get('mode') ?? DEFAULT_MODE
  const mode = HARMONY_MODES.some((m) => m.value === rawMode)
    ? (rawMode as HarmonyMode)
    : DEFAULT_MODE
  return {
    color: isValidHex(color) ? color : DEFAULT_COLOR,
    mode,
  }
}

const handleGenerate = (color: string, mode: HarmonyMode): string => {
  const palette = generatePalette(color, mode)
  const colorValues = palette.colors.map((c) => c.color)
  const contrastPairs = checkAllPairs(colorValues)
  return renderPalettePage(palette, contrastPairs)
}

const handleApi = async (url: URL): Promise<Response> => {
  const { color, mode } = parseRequest(url)
  const palette = generatePalette(color, mode)
  const colorValues = palette.colors.map((c) => c.color)
  const contrastPairs = checkAllPairs(colorValues)

  return Response.json({
    palette: {
      baseColor: palette.baseColor,
      mode: palette.mode,
      colors: palette.colors,
    },
    contrast: contrastPairs.map((p) => ({
      pair: [p.color1.hex, p.color2.hex],
      ratio: p.contrast.ratio,
      normalText: p.contrast.normalText,
      largeText: p.contrast.largeText,
    })),
  })
}

const handleSave = async (url: URL): Promise<Response> => {
  const { color, mode } = parseRequest(url)
  const saved = await savePalette(color, mode)
  return Response.json(saved)
}

export const serve = () => {
  const port = Number(process.env.PORT) || 3000

  Bun.serve({
    port,
    fetch: async (req) => {
      const url = new URL(req.url)

      if (url.pathname === '/api/palette') {
        return handleApi(url)
      }

      if (url.pathname === '/api/save' && req.method === 'POST') {
        return handleSave(url)
      }

      const { color, mode } = parseRequest(url)
      const html = handleGenerate(color, mode)
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    },
  })

  console.log(`Color Palette Generator running at http://localhost:${port}`)
}

