export type RGB = { r: number; g: number; b: number }
export type HSL = { h: number; s: number; l: number }

export const hexToRgb = (hex: string): RGB => {
  const cleaned = hex.replace(/^#/, '')
  const full =
    cleaned.length === 3
      ? cleaned
          .split('')
          .map((c) => c + c)
          .join('')
      : cleaned
  const num = parseInt(full, 16)
  return {
    r: (num >> 16) & 255,
    g: (num >> 8) & 255,
    b: num & 255,
  }
}

export const rgbToHex = (rgb: RGB): string => {
  const toHex = (n: number) =>
    Math.round(Math.max(0, Math.min(255, n)))
      .toString(16)
      .padStart(2, '0')
  return `#${toHex(rgb.r)}${toHex(rgb.g)}${toHex(rgb.b)}`
}

export const rgbToHsl = (rgb: RGB): HSL => {
  const r = rgb.r / 255
  const g = rgb.g / 255
  const b = rgb.b / 255
  const max = Math.max(r, g, b)
  const min = Math.min(r, g, b)
  const l = (max + min) / 2
  if (max === min) return { h: 0, s: 0, l: Math.round(l * 100) }
  const d = max - min
  const s = l > 0.5 ? d / (2 - max - min) : d / (max + min)
  let h = 0
  if (max === r) h = ((g - b) / d + (g < b ? 6 : 0)) / 6
  else if (max === g) h = ((b - r) / d + 2) / 6
  else h = ((r - g) / d + 4) / 6
  return {
    h: Math.round(h * 360),
    s: Math.round(s * 100),
    l: Math.round(l * 100),
  }
}

export const hslToRgb = (hsl: HSL): RGB => {
  const h = hsl.h / 360
  const s = hsl.s / 100
  const l = hsl.l / 100
  if (s === 0) {
    const v = Math.round(l * 255)
    return { r: v, g: v, b: v }
  }
  const hue2rgb = (p: number, q: number, t: number): number => {
    const tt = t < 0 ? t + 1 : t > 1 ? t - 1 : t
    if (tt < 1 / 6) return p + (q - p) * 6 * tt
    if (tt < 1 / 2) return q
    if (tt < 2 / 3) return p + (q - p) * (2 / 3 - tt) * 6
    return p
  }
  const q = l < 0.5 ? l * (1 + s) : l + s - l * s
  const p = 2 * l - q
  return {
    r: Math.round(hue2rgb(p, q, h + 1 / 3) * 255),
    g: Math.round(hue2rgb(p, q, h) * 255),
    b: Math.round(hue2rgb(p, q, h - 1 / 3) * 255),
  }
}

export const hslToHex = (hsl: HSL): string => rgbToHex(hslToRgb(hsl))

export const hexToHsl = (hex: string): HSL => rgbToHsl(hexToRgb(hex))

export const isValidHex = (hex: string): boolean =>
  /^#?([0-9a-fA-F]{3}|[0-9a-fA-F]{6})$/.test(hex)

export const normalizeHex = (hex: string): string => {
  const cleaned = hex.replace(/^#/, '')
  const full =
    cleaned.length === 3
      ? cleaned
          .split('')
          .map((c) => c + c)
          .join('')
      : cleaned
  return `#${full.toLowerCase()}`
}

export const formatRgb = (rgb: RGB): string => `rgb(${rgb.r}, ${rgb.g}, ${rgb.b})`

export const formatHsl = (hsl: HSL): string => `hsl(${hsl.h}, ${hsl.s}%, ${hsl.l}%)`

export const perceivedLightness = (rgb: RGB): number => {
  const rsrgb = rgb.r / 255
  const gsrgb = rgb.g / 255
  const bsrgb = rgb.b / 255
  const rlin = rsrgb <= 0.03928 ? rsrgb / 12.92 : Math.pow((rsrgb + 0.055) / 1.055, 2.4)
  const glin = gsrgb <= 0.03928 ? gsrgb / 12.92 : Math.pow((gsrgb + 0.055) / 1.055, 2.4)
  const blin = bsrgb <= 0.03928 ? bsrgb / 12.92 : Math.pow((bsrgb + 0.055) / 1.055, 2.4)
  return 0.2126 * rlin + 0.7152 * glin + 0.0722 * blin
}

import { hexToRgb, perceivedLightness } from './color-utils'

export type WCAGLevel = 'AAA' | 'AA' | 'Fail'

export type ContrastResult = {
  ratio: number
  ratioText: string
  normalText: { level: WCAGLevel; passes: boolean }
  largeText: { level: WCAGLevel; passes: boolean }
}

export const calculateContrastRatio = (hex1: string, hex2: string): number => {
  const lum1 = perceivedLightness(hexToRgb(hex1))
  const lum2 = perceivedLightness(hexToRgb(hex2))
  const lighter = Math.max(lum1, lum2)
  const darker = Math.min(lum1, lum2)
  return (lighter + 0.05) / (darker + 0.05)
}

const getNormalTextLevel = (ratio: number): { level: WCAGLevel; passes: boolean } => {
  if (ratio >= 7) return { level: 'AAA', passes: true }
  if (ratio >= 4.5) return { level: 'AA', passes: true }
  return { level: 'Fail', passes: false }
}

const getLargeTextLevel = (ratio: number): { level: WCAGLevel; passes: boolean } => {
  if (ratio >= 4.5) return { level: 'AAA', passes: true }
  if (ratio >= 3) return { level: 'AA', passes: true }
  return { level: 'Fail', passes: false }
}

export const checkContrast = (hex1: string, hex2: string): ContrastResult => {
  const ratio = calculateContrastRatio(hex1, hex2)
  return {
    ratio,
    ratioText: `${ratio.toFixed(2)}:1`,
    normalText: getNormalTextLevel(ratio),
    largeText: getLargeTextLevel(ratio),
  }
}

