    renderContrastResult(result, fg, bg)
  )
}

export type RenderOptions = {
  baseColor: string
  harmony: HarmonyType
  fgIndex?: number
  bgIndex?: number
}

export const renderPalette = (options: RenderOptions): string => {
  const { baseColor, harmony, fgIndex = 0, bgIndex = 1 } = options
  const palette = generatePalette(baseColor, harmony)

  const template = h(
    'div',
    { style: styleToString(styles.container) },
    h('h1', { style: styleToString(styles.heading) }, 'Color Palette Generator'),
    h(
      'p',
      { style: styleToString(styles.subtitle) },
      'Generate harmonious palettes using color theory'
    ),
    h(
      'div',
      { style: styleToString(styles.inputSection) },
      h('input', {
        type: 'color',
        value: normalizeHex(baseColor),
        style: styleToString(styles.colorPicker),
        'p-trigger': 'set-color:input',
        'p-target': 'color-picker',
      }),
      h('input', {
        type: 'text',
        value: normalizeHex(baseColor),
        placeholder: '#3A86FF',
        style: styleToString(styles.hexInput),
        'p-trigger': 'set-color:change',
        'p-target': 'hex-input',
      })
    ),
    h(
      'div',
      { style: styleToString(styles.harmonyTabs) },
      ...allHarmonyTypes.map((ht) =>
        h(
          'button',
          {
            style: styleToString(ht === harmony ? styles.tabActive : styles.tab),
            'p-trigger': 'set-harmony:click',
            'data-harmony': ht,
            title: harmonyDescriptions[ht],
          },
          ht
            .split('-')
            .map((w) => w[0].toUpperCase() + w.slice(1))
            .join(' ')
        )
      )
    ),
    h(
      'div',
      { style: styleToString(styles.paletteGrid) },
      ...palette.colors.map((color, i) => renderSwatchCard(color, i))
    ),
    renderContrastSection(palette.colors, fgIndex, bgIndex)
  )

  const ssr = createSSR()
  return ssr(template)
}

import { isValidHex, normalizeHex } from './color-utils'
import { generatePalette, allHarmonyTypes, harmonyDescriptions } from './palette-generator'
import type { HarmonyType, Palette, PaletteColor } from './palette-generator'
import { checkContrast, calculateContrastRatio } from './contrast-checker'
import type { ContrastResult, WCAGLevel } from './contrast-checker'
import { renderPalette } from './render'
import type { RenderOptions } from './render'

export type PaletteState = {
  baseColor: string
  harmony: HarmonyType
  fgIndex: number
  bgIndex: number
}

const DATA_PATH = './data/saved-palettes.json'

const defaultState: PaletteState = {
  baseColor: '#3a86ff',
  harmony: 'complementary',
  fgIndex: 0,
  bgIndex: 1,
}

export const createPaletteState = (partial?: Partial<PaletteState>): PaletteState => ({
  ...defaultState,
  ...partial,
})

export const setBaseColor = (state: PaletteState, hex: string): PaletteState => {
  if (!isValidHex(hex)) return state
  return { ...state, baseColor: normalizeHex(hex) }
}

export const setHarmony = (state: PaletteState, harmony: HarmonyType): PaletteState => {
  if (!allHarmonyTypes.includes(harmony)) return state
  return { ...state, harmony, fgIndex: 0, bgIndex: 1 }
}

export const setContrastPair = (
  state: PaletteState,
  fgIndex: number,
  bgIndex: number
): PaletteState => ({
  ...state,
  fgIndex,
  bgIndex,
})

export const getPalette = (state: PaletteState): Palette =>
  generatePalette(state.baseColor, state.harmony)

export const getContrastResult = (state: PaletteState): ContrastResult => {
  const palette = getPalette(state)
  const fg = palette.colors[state.fgIndex]?.hex ?? '#000000'
  const bg = palette.colors[state.bgIndex]?.hex ?? '#ffffff'
  return checkContrast(fg, bg)
}

export const render = (state: PaletteState): string =>
  renderPalette({
    baseColor: state.baseColor,
    harmony: state.harmony,
    fgIndex: state.fgIndex,
    bgIndex: state.bgIndex,
  })

type SavedPalette = {
  id: string
  name: string
  state: PaletteState
  createdAt: string
}

export const savePalette = async (state: PaletteState, name: string): Promise<SavedPalette> => {
  const file = Bun.file(DATA_PATH)
  const existing: SavedPalette[] = (await file.exists()) ? await file.json() : []
  const entry: SavedPalette = {
    id: crypto.randomUUID(),
    name,
    state,
    createdAt: new Date().toISOString(),
  }
  existing.push(entry)
  await Bun.write(DATA_PATH, JSON.stringify(existing, null, 2))
  return entry
}

export const loadPalettes = async (): Promise<SavedPalette[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  return file.json()
}

export const deletePalette = async (id: string): Promise<boolean> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return false
  const existing: SavedPalette[] = await file.json()
  const filtered = existing.filter((p) => p.id !== id)
  if (filtered.length === existing.length) return false
  await Bun.write(DATA_PATH, JSON.stringify(filtered, null, 2))
  return true
}

