export type ToolbarAction =
  | 'h1' | 'h2' | 'h3'
  | 'bold' | 'italic'
  | 'link' | 'image'
  | 'code' | 'codeblock'
  | 'ul' | 'ol'
  | 'blockquote'
  | 'hr'
  | 'table';

/**
 * Lightweight markdown-to-HTML renderer supporting standard syntax:
 * headings, bold, italic, links, images, code blocks, lists,
 * blockquotes, horizontal rules, and GFM-style tables.
 */

const escapeHtml = (text: string): string =>
  text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');

const renderInline = (text: string): string => {
  let result = text;
  // images (before links so ![...](...) isn't consumed by link rule)
  result = result.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '<img src="$2" alt="$1" />');
  // links
  result = result.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');
  // bold+italic
  result = result.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>');
  // bold
  result = result.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
  // italic
  result = result.replace(/\*(.+?)\*/g, '<em>$1</em>');
  // inline code
  result = result.replace(/`([^`]+)`/g, '<code>$1</code>');
  return result;
};

type BlockToken =
  | { type: 'heading'; level: number; text: string }
  | { type: 'hr' }
  | { type: 'codeblock'; lang: string; code: string }
  | { type: 'table'; headers: string[]; alignments: ('left' | 'center' | 'right' | null)[]; rows: string[][] }
  | { type: 'blockquote'; lines: string[] }
  | { type: 'ul'; items: string[] }
  | { type: 'ol'; items: string[] }
  | { type: 'paragraph'; text: string }
  | { type: 'blank' };

const tokenize = (src: string): BlockToken[] => {
  const lines = src.split('\n');
  const tokens: BlockToken[] = [];
  let i = 0;

  while (i < lines.length) {
    const line = lines[i];

    // blank line
    if (line.trim() === '') {
      tokens.push({ type: 'blank' });
      i++;
      continue;
    }

    // fenced code block
    const fenceMatch = line.match(/^```(\w*)/);
    if (fenceMatch) {
      const lang = fenceMatch[1] ?? '';
      const codeLines: string[] = [];
      i++;
      while (i < lines.length && !lines[i].startsWith('```')) {
        codeLines.push(lines[i]);
        i++;
      }
      i++; // skip closing fence
      tokens.push({ type: 'codeblock', lang, code: codeLines.join('\n') });
      continue;
    }

    // heading
    const headingMatch = line.match(/^(#{1,6})\s+(.+)/);
    if (headingMatch) {
      tokens.push({ type: 'heading', level: headingMatch[1].length, text: headingMatch[2] });
      i++;
      continue;
    }

    // horizontal rule
    if (/^(\*{3,}|-{3,}|_{3,})\s*$/.test(line)) {
      tokens.push({ type: 'hr' });
      i++;
      continue;
    }

    // table (need at least header + separator)
    if (i + 1 < lines.length && line.includes('|') && /^\|?[\s-:|]+\|?$/.test(lines[i + 1])) {
      const parseRow = (row: string): string[] =>
        row.replace(/^\|/, '').replace(/\|$/, '').split('|').map(c => c.trim());
      const headers = parseRow(line);
      const sepCells = parseRow(lines[i + 1]);
      const alignments = sepCells.map((c): 'left' | 'center' | 'right' | null => {
        const left = c.startsWith(':');
        const right = c.endsWith(':');
        if (left && right) return 'center';
        if (right) return 'right';
        if (left) return 'left';
        return null;
      });
      i += 2;
      const rows: string[][] = [];
      while (i < lines.length && lines[i].includes('|') && lines[i].trim() !== '') {
        rows.push(parseRow(lines[i]));
        i++;
      }
      tokens.push({ type: 'table', headers, alignments, rows });
      continue;
    }

    // blockquote
    if (line.startsWith('>')) {
      const bqLines: string[] = [];
      while (i < lines.length && (lines[i].startsWith('>') || (lines[i].trim() !== '' && bqLines.length > 0 && !lines[i].startsWith('#')))) {
        if (lines[i].startsWith('>')) {
          bqLines.push(lines[i].replace(/^>\s?/, ''));
        } else {
          bqLines.push(lines[i]);
        }
        i++;
      }
      tokens.push({ type: 'blockquote', lines: bqLines });
      continue;
    }

    // unordered list
    if (/^[\s]*[-*+]\s+/.test(line)) {
      const items: string[] = [];
      while (i < lines.length && /^[\s]*[-*+]\s+/.test(lines[i])) {
        items.push(lines[i].replace(/^[\s]*[-*+]\s+/, ''));
        i++;
      }
      tokens.push({ type: 'ul', items });
      continue;
    }

    // ordered list
    if (/^[\s]*\d+\.\s+/.test(line)) {
      const items: string[] = [];
      while (i < lines.length && /^[\s]*\d+\.\s+/.test(lines[i])) {
        items.push(lines[i].replace(/^[\s]*\d+\.\s+/, ''));
        i++;
      }
      tokens.push({ type: 'ol', items });
      continue;
    }

    // paragraph — collect contiguous non-empty lines
    const paraLines: string[] = [];
    while (i < lines.length && lines[i].trim() !== '' && !lines[i].startsWith('#') && !lines[i].startsWith('>') && !lines[i].startsWith('```') && !/^(\*{3,}|-{3,}|_{3,})\s*$/.test(lines[i]) && !/^[\s]*[-*+]\s+/.test(lines[i]) && !/^[\s]*\d+\.\s+/.test(lines[i])) {
      paraLines.push(lines[i]);
      i++;
    }
    if (paraLines.length > 0) {
      tokens.push({ type: 'paragraph', text: paraLines.join('\n') });
    }
  }

  return tokens;
};

const renderTokens = (tokens: BlockToken[]): string => {
  const parts: string[] = [];

  for (const token of tokens) {
    switch (token.type) {
      case 'blank':
        break;
      case 'heading':
        parts.push(`<h${token.level}>${renderInline(escapeHtml(token.text))}</h${token.level}>`);
        break;
      case 'hr':
        parts.push('<hr />');
        break;
      case 'codeblock':
        parts.push(`<pre><code${token.lang ? ` class="language-${escapeHtml(token.lang)}"` : ''}>${escapeHtml(token.code)}</code></pre>`);
        break;
      case 'blockquote': {
        const inner = renderMarkdown(token.lines.join('\n'));
        parts.push(`<blockquote>${inner}</blockquote>`);
        break;
      }
      case 'ul':
        parts.push(`<ul>${token.items.map(item => `<li>${renderInline(escapeHtml(item))}</li>`).join('')}</ul>`);
        break;
      case 'ol':
        parts.push(`<ol>${token.items.map(item => `<li>${renderInline(escapeHtml(item))}</li>`).join('')}</ol>`);
        break;
      case 'table': {
        const thRow = token.headers.map((h, idx) => {
          const align = token.alignments[idx];
          const style = align ? ` style="text-align:${align}"` : '';
          return `<th${style}>${renderInline(escapeHtml(h))}</th>`;
        }).join('');
        const bodyRows = token.rows.map(row => {
          const cells = row.map((cell, idx) => {
            const align = token.alignments[idx];
            const style = align ? ` style="text-align:${align}"` : '';
            return `<td${style}>${renderInline(escapeHtml(cell))}</td>`;
          }).join('');
          return `<tr>${cells}</tr>`;
        }).join('');
        parts.push(`<table><thead><tr>${thRow}</tr></thead><tbody>${bodyRows}</tbody></table>`);
        break;
      }
      case 'paragraph':
        parts.push(`<p>${renderInline(escapeHtml(token.text))}</p>`);
        break;
    }
  }

  return parts.join('\n');
};

export const renderMarkdown = (src: string): string => {
  const tokens = tokenize(src);
  return renderTokens(tokens);
};

import type { Document, DocumentMeta } from './types';

const DATA_PATH = `${import.meta.dir}/data/documents.json`;

const readAll = async (): Promise<Document[]> => {
  const file = Bun.file(DATA_PATH);
  const exists = await file.exists();
  if (!exists) return [];
  const text = await file.text();
  if (!text.trim()) return [];
  return JSON.parse(text) as Document[];
};

const writeAll = async (docs: Document[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(docs, null, 2));
};

const generateId = (): string =>
  `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;

export const listDocuments = async (): Promise<DocumentMeta[]> => {
  const docs = await readAll();
  return docs.map(({ id, title, createdAt, updatedAt }) => ({
    id,
    title,
    createdAt,
    updatedAt,
  }));
};

export const getDocument = async (id: string): Promise<Document | null> => {
  const docs = await readAll();
  return docs.find(d => d.id === id) ?? null;
};

export const createDocument = async (title: string, content: string): Promise<Document> => {
  const docs = await readAll();
  const now = new Date().toISOString();
  const doc: Document = {
    id: generateId(),
    title,
    content,
    createdAt: now,
    updatedAt: now,
  };
  docs.push(doc);
  await writeAll(docs);
  return doc;
};

export const updateDocument = async (
  id: string,
  updates: { title?: string; content?: string },
): Promise<Document | null> => {
  const docs = await readAll();
  const idx = docs.findIndex(d => d.id === id);
  if (idx === -1) return null;
  const doc = docs[idx];
  if (updates.title !== undefined) doc.title = updates.title;
  if (updates.content !== undefined) doc.content = updates.content;
  doc.updatedAt = new Date().toISOString();
  docs[idx] = doc;
  await writeAll(docs);
  return doc;
};

export const deleteDocument = async (id: string): Promise<boolean> => {
  const docs = await readAll();
  const idx = docs.findIndex(d => d.id === id);
  if (idx === -1) return false;
  docs.splice(idx, 1);
  await writeAll(docs);
  return true;
};

