/**
 * Client-side script for the markdown editor.
 * Handles live preview rendering, toolbar actions, save/load, and document management.
 */

type ToolbarAction =
  | 'h1' | 'h2' | 'h3'
  | 'bold' | 'italic'
  | 'link' | 'image'
  | 'code' | 'codeblock'
  | 'ul' | 'ol'
  | 'blockquote'
  | 'hr'
  | 'table';

const editor = document.getElementById('editor') as HTMLTextAreaElement;
const preview = document.getElementById('preview') as HTMLDivElement;
const docTitle = document.getElementById('doc-title') as HTMLInputElement;

let currentDocId: string | null = null;
let debounceTimer: ReturnType<typeof setTimeout> | null = null;

const updatePreview = async () => {
  const content = editor.value;
  const res = await fetch('/api/render', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ content }),
  });
  const { html } = await res.json();
  preview.innerHTML = html;
};

const debouncedPreview = () => {
  if (debounceTimer) clearTimeout(debounceTimer);
  debounceTimer = setTimeout(updatePreview, 150);
};

const insertAtCursor = (before: string, after: string = '', placeholder: string = '') => {
  const start = editor.selectionStart;
  const end = editor.selectionEnd;
  const selected = editor.value.substring(start, end);
  const text = selected || placeholder;
  const replacement = `${before}${text}${after}`;
  editor.setRangeText(replacement, start, end, 'select');
  editor.focus();
  if (!selected && placeholder) {
    editor.selectionStart = start + before.length;
    editor.selectionEnd = start + before.length + placeholder.length;
  }
  debouncedPreview();
};

const toolbarActions: Record<ToolbarAction, () => void> = {
  h1: () => insertAtCursor('# ', '', 'Heading 1'),
  h2: () => insertAtCursor('## ', '', 'Heading 2'),
  h3: () => insertAtCursor('### ', '', 'Heading 3'),
  bold: () => insertAtCursor('**', '**', 'bold text'),
  italic: () => insertAtCursor('*', '*', 'italic text'),
  link: () => insertAtCursor('[', '](https://)', 'link text'),
  image: () => insertAtCursor('![', '](https://image-url)', 'alt text'),
  code: () => insertAtCursor('`', '`', 'code'),
  codeblock: () => insertAtCursor('```\n', '\n```', 'code here'),
  ul: () => insertAtCursor('- ', '', 'list item'),
  ol: () => insertAtCursor('1. ', '', 'list item'),
  blockquote: () => insertAtCursor('> ', '', 'quote'),
  hr: () => insertAtCursor('\n---\n'),
  table: () => insertAtCursor(
    '| Header 1 | Header 2 | Header 3 |\n| -------- | -------- | -------- |\n| Cell 1   | Cell 2   | Cell 3   |\n',
  ),
};

const handleSave = async () => {
  const title = docTitle.value.trim() || 'Untitled';
  const content = editor.value;

  if (currentDocId) {
    await fetch(`/api/documents/${currentDocId}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ title, content }),
    });
  } else {
    const res = await fetch('/api/documents', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ title, content }),
    });
    const doc = await res.json();
    currentDocId = doc.id;
  }
};

const handleLoad = async () => {
  const res = await fetch('/api/documents');
  const documents = await res.json();
  const modal = document.createElement('div');
  modal.id = 'doc-modal';
  modal.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.6);display:flex;align-items:center;justify-content:center;z-index:1000';
  const inner = document.createElement('div');
  inner.style.cssText = 'background:#16213e;border-radius:8px;padding:24px;min-width:400px;max-height:60vh;overflow:auto';
  inner.innerHTML = `<h3 style="margin:0 0 16px;color:#e94560">Saved Documents</h3>`;

  if (documents.length === 0) {
    inner.innerHTML += '<p style="color:#888">No saved documents yet.</p>';
  } else {
    for (const doc of documents) {
      const item = document.createElement('div');
      item.style.cssText = 'display:flex;justify-content:space-between;align-items:center;padding:8px 12px;border-bottom:1px solid #0f3460;cursor:pointer';
      item.innerHTML = `
        <div>
          <strong style="color:#e0e0e0">${doc.title || 'Untitled'}</strong><br>
          <small style="color:#888">${new Date(doc.updatedAt).toLocaleString()}</small>
        </div>
      `;
      const delBtn = document.createElement('button');
      delBtn.textContent = '✕';
      delBtn.style.cssText = 'padding:4px 10px;border:none;border-radius:4px;background:#e94560;color:#fff;cursor:pointer;font-size:13px';
      delBtn.onclick = async (e) => {
        e.stopPropagation();
        await fetch(`/api/documents/${doc.id}`, { method: 'DELETE' });
        item.remove();
      };
      item.appendChild(delBtn);
      item.onclick = async () => {
        const docRes = await fetch(`/api/documents/${doc.id}`);
        const fullDoc = await docRes.json();
        editor.value = fullDoc.content;
        docTitle.value = fullDoc.title;
        currentDocId = fullDoc.id;
        modal.remove();
        updatePreview();
      };
      inner.appendChild(item);
    }
  }

  const closeBtn = document.createElement('button');
  closeBtn.textContent = 'Close';
  closeBtn.style.cssText = 'padding:6px 14px;border:none;border-radius:4px;background:#0f3460;color:#e0e0e0;cursor:pointer;font-size:13px;font-weight:600;margin-top:16px';
  closeBtn.onclick = () => modal.remove();
  inner.appendChild(closeBtn);
  modal.appendChild(inner);
  modal.onclick = (e) => { if (e.target === modal) modal.remove(); };
  document.body.appendChild(modal);
};

const handleNew = () => {
  editor.value = '';
  docTitle.value = '';
  currentDocId = null;
  updatePreview();
};

// Event listeners
editor.addEventListener('input', debouncedPreview);

document.addEventListener('click', (e) => {
  const target = e.target as HTMLElement;
  const trigger = target.getAttribute('p-trigger');
  if (!trigger) return;

  if (trigger === 'save') return void handleSave();
  if (trigger === 'load') return void handleLoad();
  if (trigger === 'new') return void handleNew();

  if (trigger.startsWith('toolbar:')) {
    const action = trigger.replace('toolbar:', '') as ToolbarAction;
    toolbarActions[action]?.();
  }
});

// Keyboard shortcuts
editor.addEventListener('keydown', (e) => {
  if ((e.metaKey || e.ctrlKey) && e.key === 'b') {
    e.preventDefault();
    toolbarActions.bold();
  }
  if ((e.metaKey || e.ctrlKey) && e.key === 'i') {
    e.preventDefault();
    toolbarActions.italic();
  }
  if ((e.metaKey || e.ctrlKey) && e.key === 's') {
    e.preventDefault();
    handleSave();
  }
});

// Tab key support for indentation
editor.addEventListener('keydown', (e) => {
  if (e.key === 'Tab') {
    e.preventDefault();
    insertAtCursor('  ', '', '');
  }
});

// Initial preview
updatePreview();

import { renderMarkdown } from './markdown';
import { listDocuments, getDocument, createDocument, updateDocument, deleteDocument } from './store';
import { renderEditorPage, previewStyles } from './ui';
import { createSSR } from 'plaited';

const CLIENT_PATH = `${import.meta.dir}/client.ts`;

const defaultContent = `# Welcome to Markdown Editor

Start typing your **markdown** here and see the *live preview* on the right.

## Features

- **Bold** and *italic* text
- [Links](https://example.com) and images
- Code blocks with syntax highlighting
- Lists, blockquotes, tables, and more

### Code Example

\`\`\`typescript
const greeting = (name: string): string => {
  return \`Hello, \${name}!\`;
};
\`\`\`

> This is a blockquote. It can span multiple lines and supports **inline formatting**.

| Feature       | Supported |
| ------------- | --------- |
| Headings      | ✓         |
| Bold/Italic   | ✓         |
| Links         | ✓         |
| Code Blocks   | ✓         |
| Tables        | ✓         |
| Lists         | ✓         |

---

Happy writing!
`;

const buildHtmlPage = (bodyHtml: string, previewHtml: string): string => `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Markdown Editor</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    html, body { height: 100%; overflow: hidden; }
    ${previewStyles}
  </style>
</head>
<body>
  ${bodyHtml}
  <script>
    // Inject initial preview HTML before client script loads
    document.addEventListener('DOMContentLoaded', () => {
      const preview = document.getElementById('preview');
      if (preview) preview.innerHTML = ${JSON.stringify(previewHtml)};
    });
  </script>
  <script src="/client.js" defer></script>
</body>
</html>`;

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  });

const serve = Bun.serve({
  port: Number(process.env.PORT) || 3000,

  fetch: async (req) => {
    const url = new URL(req.url);
    const { pathname } = url;

    // Serve client JS bundle
    if (pathname === '/client.js') {
      const result = await Bun.build({
        entrypoints: [CLIENT_PATH],
        minify: true,
      });
      const blob = result.outputs[0];
      return new Response(blob, {
        headers: { 'Content-Type': 'application/javascript' },
      });
    }

    // API: Render markdown
    if (pathname === '/api/render' && req.method === 'POST') {
      const { content } = await req.json() as { content: string };
      const html = renderMarkdown(content ?? '');
      return jsonResponse({ html });
    }

    // API: List documents
    if (pathname === '/api/documents' && req.method === 'GET') {
      const docs = await listDocuments();
      return jsonResponse(docs);
    }

    // API: Get document
    const docMatch = pathname.match(/^\/api\/documents\/(.+)$/);
    if (docMatch && req.method === 'GET') {
      const doc = await getDocument(docMatch[1]);
      if (!doc) return jsonResponse({ error: 'Not found' }, 404);
      return jsonResponse(doc);
    }

    // API: Create document
    if (pathname === '/api/documents' && req.method === 'POST') {
      const { title, content } = await req.json() as { title: string; content: string };
      const doc = await createDocument(title, content);
      return jsonResponse(doc, 201);
    }

    // API: Update document
    if (docMatch && req.method === 'PUT') {
      const updates = await req.json() as { title?: string; content?: string };
      const doc = await updateDocument(docMatch[1], updates);
      if (!doc) return jsonResponse({ error: 'Not found' }, 404);
      return jsonResponse(doc);
    }

    // API: Delete document
    if (docMatch && req.method === 'DELETE') {
      const ok = await deleteDocument(docMatch[1]);
      if (!ok) return jsonResponse({ error: 'Not found' }, 404);
      return jsonResponse({ ok: true });
    }

    // Main page
    if (pathname === '/' || pathname === '') {
      const ssr = createSSR();
      const bodyHtml = ssr(renderEditorPage(defaultContent, '', ''));
      const previewHtml = renderMarkdown(defaultContent);
      const html = buildHtmlPage(bodyHtml, previewHtml);
      return new Response(html, {
        headers: { 'Content-Type': 'text/html' },
      });
    }

    return new Response('Not found', { status: 404 });
  },
});

