type TokenType =
  | 'heading'
  | 'blockquote'
  | 'code_block'
  | 'hr'
  | 'table'
  | 'ul'
  | 'ol'
  | 'paragraph';

type Token = {
  type: TokenType;
  content: string;
  level?: number;
  rows?: string[][];
  header?: string[];
  alignments?: ('left' | 'center' | 'right' | null)[];
};

const escapeHtml = (str: string): string =>
  str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');

const parseInline = (text: string): string => {
  let result = text;

  // Images (before links so ![...](...) isn't caught by link regex)
  result = result.replace(
    /!\[([^\]]*)\]\(([^)]+)\)/g,
    '<img src="$2" alt="$1" />'
  );

  // Links
  result = result.replace(
    /\[([^\]]+)\]\(([^)]+)\)/g,
    '<a href="$2">$1</a>'
  );

  // Bold + italic
  result = result.replace(
    /\*\*\*(.+?)\*\*\*/g,
    '<strong><em>$1</em></strong>'
  );

  // Bold
  result = result.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
  result = result.replace(/__(.+?)__/g, '<strong>$1</strong>');

  // Italic
  result = result.replace(/\*(.+?)\*/g, '<em>$1</em>');
  result = result.replace(/_(.+?)_/g, '<em>$1</em>');

  // Strikethrough
  result = result.replace(/~~(.+?)~~/g, '<del>$1</del>');

  // Inline code
  result = result.replace(/`([^`]+)`/g, '<code>$1</code>');

  return result;
};

const tokenize = (markdown: string): Token[] => {
  const lines = markdown.split('\n');
  const tokens: Token[] = [];
  let i = 0;

  while (i < lines.length) {
    const line = lines[i];

    // Empty line
    if (line.trim() === '') {
      i++;
      continue;
    }

    // Fenced code block
    if (line.trim().startsWith('```')) {
      const lang = line.trim().slice(3).trim();
      const codeLines: string[] = [];
      i++;
      while (i < lines.length && !lines[i].trim().startsWith('```')) {
        codeLines.push(lines[i]);
        i++;
      }
      i++; // skip closing ```
      tokens.push({
        type: 'code_block',
        content: codeLines.join('\n'),
        level: 0,
      });
      continue;
    }

    // Heading
    const headingMatch = line.match(/^(#{1,6})\s+(.+)$/);
    if (headingMatch) {
      tokens.push({
        type: 'heading',
        level: headingMatch[1].length,
        content: headingMatch[2],
      });
      i++;
      continue;
    }

    // Horizontal rule
    if (/^([-*_])\s*\1\s*\1[\s\1]*$/.test(line.trim())) {
      tokens.push({ type: 'hr', content: '' });
      i++;
      continue;
    }

    // Table
    if (
      i + 1 < lines.length &&
      line.includes('|') &&
      /^\s*\|?\s*:?-+:?\s*(\|\s*:?-+:?\s*)*\|?\s*$/.test(lines[i + 1])
    ) {
      const parseRow = (row: string): string[] =>
        row
          .replace(/^\|/, '')
          .replace(/\|$/, '')
          .split('|')
          .map((c) => c.trim());

      const header = parseRow(line);
      const separatorCells = parseRow(lines[i + 1]);
      const alignments = separatorCells.map((cell) => {
        const left = cell.startsWith(':');
        const right = cell.endsWith(':');
        if (left && right) return 'center' as const;
        if (right) return 'right' as const;
        if (left) return 'left' as const;
        return null;
      });

      i += 2;
      const rows: string[][] = [];
      while (i < lines.length && lines[i].includes('|') && lines[i].trim() !== '') {
        rows.push(parseRow(lines[i]));
        i++;
      }

      tokens.push({
        type: 'table',
        content: '',
        header,
        rows,
        alignments,
      });
      continue;
    }

    // Blockquote
    if (line.startsWith('>')) {
      const bqLines: string[] = [];
      while (i < lines.length && lines[i].startsWith('>')) {
        bqLines.push(lines[i].replace(/^>\s?/, ''));
        i++;
      }
      tokens.push({ type: 'blockquote', content: bqLines.join('\n') });
      continue;
    }

    // Unordered list
    if (/^\s*[-*+]\s+/.test(line)) {
      const items: string[] = [];
      while (i < lines.length && /^\s*[-*+]\s+/.test(lines[i])) {
        items.push(lines[i].replace(/^\s*[-*+]\s+/, ''));
        i++;
      }
      tokens.push({ type: 'ul', content: items.join('\n') });
      continue;
    }

    // Ordered list
    if (/^\s*\d+\.\s+/.test(line)) {
      const items: string[] = [];
      while (i < lines.length && /^\s*\d+\.\s+/.test(lines[i])) {
        items.push(lines[i].replace(/^\s*\d+\.\s+/, ''));
        i++;
      }
      tokens.push({ type: 'ol', content: items.join('\n') });
      continue;
    }

    // Paragraph
    const paraLines: string[] = [];
    while (
      i < lines.length &&
      lines[i].trim() !== '' &&
      !lines[i].startsWith('#') &&
      !lines[i].startsWith('>') &&
      !lines[i].startsWith('```') &&
      !/^\s*[-*+]\s+/.test(lines[i]) &&
      !/^\s*\d+\.\s+/.test(lines[i]) &&
      !/^([-*_])\s*\1\s*\1[\s\1]*$/.test(lines[i].trim())
    ) {
      paraLines.push(lines[i]);
      i++;
    }
    if (paraLines.length > 0) {
      tokens.push({ type: 'paragraph', content: paraLines.join('\n') });
    }
  }

  return tokens;
};

const renderToken = (token: Token): string => {
  switch (token.type) {
    case 'heading': {
      const tag = `h${token.level}`;
      return `<${tag}>${parseInline(escapeHtml(token.content))}</${tag}>`;
    }
    case 'blockquote':
      return `<blockquote>${parseMarkdown(token.content)}</blockquote>`;
    case 'code_block':
      return `<pre><code>${escapeHtml(token.content)}</code></pre>`;
    case 'hr':
      return '<hr />';
    case 'table': {
      const alignAttr = (idx: number): string => {
        const a = token.alignments?.[idx];
        return a ? ` style="text-align:${a}"` : '';
      };
      const headerHtml = token.header!
        .map((h, idx) => `<th${alignAttr(idx)}>${parseInline(escapeHtml(h))}</th>`)
        .join('');
      const rowsHtml = token.rows!
        .map(
          (row) =>
            '<tr>' +
            row
              .map(
                (cell, idx) =>
                  `<td${alignAttr(idx)}>${parseInline(escapeHtml(cell))}</td>`
              )
              .join('') +
            '</tr>'
        )
        .join('');
      return `<table><thead><tr>${headerHtml}</tr></thead><tbody>${rowsHtml}</tbody></table>`;
    }
    case 'ul': {
      const items = token.content
        .split('\n')
        .map((item) => `<li>${parseInline(escapeHtml(item))}</li>`)
        .join('');
      return `<ul>${items}</ul>`;
    }
    case 'ol': {
      const items = token.content
        .split('\n')
        .map((item) => `<li>${parseInline(escapeHtml(item))}</li>`)
        .join('');
      return `<ol>${items}</ol>`;
    }
    case 'paragraph':
      return `<p>${parseInline(escapeHtml(token.content))}</p>`;
  }
};

export const parseMarkdown = (markdown: string): string => {
  const tokens = tokenize(markdown);
  return tokens.map(renderToken).join('\n');
};

import { join } from 'path';

const DATA_DIR = join(import.meta.dir, '..', 'data');
const DOCS_FILE = join(DATA_DIR, 'documents.json');

export type Document = {
  id: string;
  title: string;
  content: string;
  createdAt: string;
  updatedAt: string;
};

const generateId = (): string =>
  `doc_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;

const readDocuments = async (): Promise<Document[]> => {
  const file = Bun.file(DOCS_FILE);
  if (!(await file.exists())) {
    return [];
  }
  const text = await file.text();
  return text.trim() ? JSON.parse(text) : [];
};

const writeDocuments = async (docs: Document[]): Promise<void> => {
  await Bun.write(DOCS_FILE, JSON.stringify(docs, null, 2));
};

export const listDocuments = async (): Promise<Document[]> => {
  const docs = await readDocuments();
  return docs.sort(
    (a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime()
  );
};

export const getDocument = async (id: string): Promise<Document | null> => {
  const docs = await readDocuments();
  return docs.find((d) => d.id === id) ?? null;
};

export const saveDocument = async (
  title: string,
  content: string
): Promise<Document> => {
  const docs = await readDocuments();
  const now = new Date().toISOString();
  const doc: Document = {
    id: generateId(),
    title,
    content,
    createdAt: now,
    updatedAt: now,
  };
  docs.push(doc);
  await writeDocuments(docs);
  return doc;
};

export const updateDocument = async (
  id: string,
  updates: { title?: string; content?: string }
): Promise<Document | null> => {
  const docs = await readDocuments();
  const idx = docs.findIndex((d) => d.id === id);
  if (idx === -1) return null;
  const doc = docs[idx];
  if (updates.title !== undefined) doc.title = updates.title;
  if (updates.content !== undefined) doc.content = updates.content;
  doc.updatedAt = new Date().toISOString();
  await writeDocuments(docs);
  return doc;
};

export const deleteDocument = async (id: string): Promise<boolean> => {
  const docs = await readDocuments();
  const filtered = docs.filter((d) => d.id !== id);
  if (filtered.length === docs.length) return false;
  await writeDocuments(filtered);
  return true;
};

