const styleToString = (obj: Record<string, string | number>): string =>
  Object.entries(obj)
    .map(([k, v]) => {
      const prop = k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`);
      return `${prop}:${v}`;
    })
    .join(';');

export const renderEditor = (
  content: string,
  documents: Document[],
  currentDoc?: Document | null
): string => {
  const previewHtml = parseMarkdown(content);

  const toolbarButtons = toolbarItems
    .map(
      (item) =>
        `<button style="${styleToString(styles.toolbarBtn)}" ` +
        `data-prefix="${encodeURIComponent(item.prefix)}" ` +
        `data-suffix="${encodeURIComponent(item.suffix)}" ` +
        `data-block="${item.block ?? false}" ` +
        `class="toolbar-btn" title="${item.label}">${item.label}</button>`
    )
    .join('');

  const docOptions = documents
    .map(
      (doc) =>
        `<option value="${doc.id}" ${currentDoc?.id === doc.id ? 'selected' : ''}>${doc.title}</option>`
    )
    .join('');

  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
