    .toolbar-btn:hover { background-color: #e0e0e0 !important; }
    #save-btn:hover { background-color: #1d4ed8 !important; }
    #delete-btn:hover { background-color: #b91c1c !important; }
  </style>
</head>
<body>
  <div style="${styleToString(styles.root)}" id="app">
    <div style="${styleToString(styles.header)}">
      <span style="${styleToString(styles.headerTitle)}">Markdown Editor</span>
      <div style="${styleToString(styles.headerControls)}">
        <select id="doc-select" style="${styleToString(styles.docSelect)}">
          <option value="">-- Load Document --</option>
          ${docOptions}
        </select>
        <button id="delete-btn" style="${styleToString(styles.deleteBtn)}">Delete</button>
        <input id="title-input" type="text" placeholder="Document title..."
          style="${styleToString(styles.titleInput)}"
          value="${currentDoc ? currentDoc.title.replace(/"/g, '&quot;') : ''}" />
        <button id="save-btn" style="${styleToString(styles.saveBtn)}">Save</button>
      </div>
    </div>
    <div style="${styleToString(styles.toolbar)}">
      ${toolbarButtons}
    </div>
    <div style="${styleToString(styles.splitPane)}">
      <div style="${styleToString(styles.editorPane)}">
        <textarea id="editor" style="${styleToString(styles.textarea)}"
          placeholder="Type your markdown here..."
          spellcheck="false">${content.replace(/</g, '&lt;').replace(/>/g, '&gt;')}</textarea>
      </div>
      <div style="${styleToString(styles.previewPane)}">
        <div id="preview" class="preview" style="${styleToString(styles.previewContent)}">${previewHtml}</div>
      </div>
    </div>
  </div>
  <script>
    const editor = document.getElementById('editor');
    const preview = document.getElementById('preview');
    const titleInput = document.getElementById('title-input');
    const saveBtn = document.getElementById('save-btn');
    const docSelect = document.getElementById('doc-select');
    const deleteBtn = document.getElementById('delete-btn');
    let currentDocId = ${currentDoc ? `'${currentDoc.id}'` : 'null'};

    // Live preview via server-side parsing
    let debounceTimer;
    editor.addEventListener('input', () => {
      clearTimeout(debounceTimer);
      debounceTimer = setTimeout(async () => {
        const res = await fetch('/api/preview', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ content: editor.value }),
        });
        if (res.ok) {
          const data = await res.json();
          preview.innerHTML = data.html;
        }
      }, 150);
    });

    // Toolbar
    document.querySelectorAll('.toolbar-btn').forEach(btn => {
      btn.addEventListener('click', () => {
        const prefix = decodeURIComponent(btn.dataset.prefix);
        const suffix = decodeURIComponent(btn.dataset.suffix);
        const start = editor.selectionStart;
        const end = editor.selectionEnd;
        const selected = editor.value.substring(start, end);
        const replacement = prefix + (selected || 'text') + suffix;
        editor.setRangeText(replacement, start, end, 'select');
        editor.focus();
        editor.dispatchEvent(new Event('input'));
      });
    });

    // Save
    saveBtn.addEventListener('click', async () => {
      const title = titleInput.value.trim() || 'Untitled';
      const content = editor.value;
      const url = currentDocId ? '/api/documents/' + currentDocId : '/api/documents';
      const method = currentDocId ? 'PUT' : 'POST';
      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ title, content }),
      });
      if (res.ok) {
        const doc = await res.json();
        currentDocId = doc.id;
        window.location.reload();
      }
    });

    // Load
    docSelect.addEventListener('change', () => {
      const id = docSelect.value;
      if (id) {
        window.location.href = '/?doc=' + id;
      }
    });

    // Delete
    deleteBtn.addEventListener('click', async () => {
      if (!currentDocId) return;
      if (!confirm('Delete this document?')) return;
      await fetch('/api/documents/' + currentDocId, { method: 'DELETE' });
      window.location.href = '/';
    });
  </script>
</body>
</html>`;
};

