const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  });

const htmlResponse = (html: string): Response =>
  new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  });

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,

  fetch: async (req) => {
    const url = new URL(req.url);
    const { pathname } = url;
    const method = req.method;

    // Main editor page
    if (pathname === '/' && method === 'GET') {
      const docId = url.searchParams.get('doc');
      const documents = await listDocuments();
      let content = DEFAULT_CONTENT;
      let currentDoc = null;

      if (docId) {
        currentDoc = await getDocument(docId);
        if (currentDoc) {
          content = currentDoc.content;
        }
      }

      const html = renderEditor(content, documents, currentDoc);
      return htmlResponse(html);
    }

    // Preview endpoint (live preview)
    if (pathname === '/api/preview' && method === 'POST') {
      const body = (await req.json()) as { content: string };
      const html = parseMarkdown(body.content);
      return jsonResponse({ html });
    }

    // List documents
    if (pathname === '/api/documents' && method === 'GET') {
      const docs = await listDocuments();
      return jsonResponse(docs);
    }

    // Save new document
    if (pathname === '/api/documents' && method === 'POST') {
      const body = (await req.json()) as { title: string; content: string };
      const doc = await saveDocument(body.title, body.content);
      return jsonResponse(doc, 201);
    }

    // Document by ID routes
    const docMatch = pathname.match(/^\/api\/documents\/(.+)$/);
    if (docMatch) {
      const id = docMatch[1];

      if (method === 'GET') {
        const doc = await getDocument(id);
        if (!doc) return jsonResponse({ error: 'Not found' }, 404);
        return jsonResponse(doc);
      }

      if (method === 'PUT') {
        const body = (await req.json()) as { title?: string; content?: string };
        const doc = await updateDocument(id, body);
        if (!doc) return jsonResponse({ error: 'Not found' }, 404);
        return jsonResponse(doc);
      }

      if (method === 'DELETE') {
        const deleted = await deleteDocument(id);
        if (!deleted) return jsonResponse({ error: 'Not found' }, 404);
        return jsonResponse({ success: true });
      }
    }

    return jsonResponse({ error: 'Not found' }, 404);
  },
});

