const escapeHtml = (text: string): string =>
  text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')

const renderInline = (text: string): string => {
  let result = text
  // Images (must come before links)
  result = result.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '<img src="$2" alt="$1" />')
  // Links
  result = result.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>')
  // Bold + italic
  result = result.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>')
  // Bold
  result = result.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
  // Italic
  result = result.replace(/\*(.+?)\*/g, '<em>$1</em>')
  // Inline code
  result = result.replace(/`([^`]+)`/g, '<code>$1</code>')
  // Strikethrough
  result = result.replace(/~~(.+?)~~/g, '<del>$1</del>')
  return result
}

const renderTable = (lines: string[]): string => {
  const rows = lines.map(line =>
    line
      .replace(/^\|/, '')
      .replace(/\|$/, '')
      .split('|')
      .map(cell => cell.trim())
  )
  if (rows.length < 2) return lines.map(l => `<p>${renderInline(l)}</p>`).join('\n')

  const headers = rows[0]
  const bodyRows = rows.slice(2) // skip separator row

  const headerHtml = headers.map(h => `<th>${renderInline(h)}</th>`).join('')
  const bodyHtml = bodyRows
    .map(row => `<tr>${row.map(cell => `<td>${renderInline(cell)}</td>`).join('')}</tr>`)
    .join('\n')

  return `<table>\n<thead><tr>${headerHtml}</tr></thead>\n<tbody>\n${bodyHtml}\n</tbody>\n</table>`
}

export const renderMarkdown = (markdown: string): string => {
  const lines = markdown.split('\n')
  const output: string[] = []
  let i = 0

  while (i < lines.length) {
    const line = lines[i]

    // Fenced code block
    if (line.startsWith('```')) {
      const lang = line.slice(3).trim()
      const codeLines: string[] = []
      i++
      while (i < lines.length && !lines[i].startsWith('```')) {
        codeLines.push(escapeHtml(lines[i]))
        i++
      }
      const langAttr = lang ? ` class="language-${escapeHtml(lang)}"` : ''
      output.push(`<pre><code${langAttr}>${codeLines.join('\n')}</code></pre>`)
      i++
      continue
    }

    // Table (lines starting with |)
    if (line.startsWith('|')) {
      const tableLines: string[] = []
      while (i < lines.length && lines[i].startsWith('|')) {
        tableLines.push(lines[i])
        i++
      }
      output.push(renderTable(tableLines))
      continue
    }

    // Horizontal rule
    if (/^(-{3,}|\*{3,}|_{3,})\s*$/.test(line)) {
      output.push('<hr />')
      i++
      continue
    }

    // Headings
    const headingMatch = line.match(/^(#{1,6})\s+(.+)$/)
    if (headingMatch) {
      const level = headingMatch[1].length
      output.push(`<h${level}>${renderInline(headingMatch[2])}</h${level}>`)
      i++
      continue
    }

    // Blockquote
    if (line.startsWith('> ')) {
      const quoteLines: string[] = []
      while (i < lines.length && lines[i].startsWith('> ')) {
        quoteLines.push(lines[i].slice(2))
        i++
      }
      output.push(`<blockquote><p>${renderInline(quoteLines.join(' '))}</p></blockquote>`)
      continue
    }

    // Unordered list
    if (/^[-*+]\s+/.test(line)) {
      const items: string[] = []
      while (i < lines.length && /^[-*+]\s+/.test(lines[i])) {
        items.push(lines[i].replace(/^[-*+]\s+/, ''))
        i++
      }
      output.push(`<ul>\n${items.map(item => `<li>${renderInline(item)}</li>`).join('\n')}\n</ul>`)
      continue
    }

    // Ordered list
    if (/^\d+\.\s+/.test(line)) {
      const items: string[] = []
      while (i < lines.length && /^\d+\.\s+/.test(lines[i])) {
        items.push(lines[i].replace(/^\d+\.\s+/, ''))
        i++
      }
      output.push(`<ol>\n${items.map(item => `<li>${renderInline(item)}</li>`).join('\n')}\n</ol>`)
      continue
    }

    // Empty line
    if (line.trim() === '') {
      i++
      continue
    }

    // Paragraph
    const paraLines: string[] = []
    while (i < lines.length && lines[i].trim() !== '' && !lines[i].startsWith('#') && !lines[i].startsWith('```') && !lines[i].startsWith('|') && !lines[i].startsWith('> ') && !/^[-*+]\s+/.test(lines[i]) && !/^\d+\.\s+/.test(lines[i]) && !/^(-{3,}|\*{3,}|_{3,})\s*$/.test(lines[i])) {
      paraLines.push(lines[i])
      i++
    }
    if (paraLines.length > 0) {
      output.push(`<p>${renderInline(paraLines.join(' '))}</p>`)
    }
  }

  return output.join('\n')
}

import type { Document, DocumentList } from './types'

const DATA_PATH = `${import.meta.dir}/data/documents.json`

const readDocuments = async (): Promise<DocumentList> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  return JSON.parse(text) as DocumentList
}

const writeDocuments = async (docs: DocumentList): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(docs, null, 2))
}

const generateId = (): string =>
  `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`

export const listDocuments = async (): Promise<DocumentList> => {
  const docs = await readDocuments()
  return docs.sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime())
}

export const getDocument = async (id: string): Promise<Document | undefined> => {
  const docs = await readDocuments()
  return docs.find(d => d.id === id)
}

export const saveDocument = async (title: string, content: string): Promise<Document> => {
  const docs = await readDocuments()
  const now = new Date().toISOString()
  const doc: Document = {
    id: generateId(),
    title,
    content,
    createdAt: now,
    updatedAt: now,
  }
  docs.push(doc)
  await writeDocuments(docs)
  return doc
}

export const updateDocument = async (
  id: string,
  title: string,
  content: string
): Promise<Document | undefined> => {
  const docs = await readDocuments()
  const idx = docs.findIndex(d => d.id === id)
  if (idx === -1) return undefined
  docs[idx] = {
    ...docs[idx],
    title,
    content,
    updatedAt: new Date().toISOString(),
  }
  await writeDocuments(docs)
  return docs[idx]
}

export const deleteDocument = async (id: string): Promise<boolean> => {
  const docs = await readDocuments()
  const idx = docs.findIndex(d => d.id === id)
  if (idx === -1) return false
  docs.splice(idx, 1)
  await writeDocuments(docs)
  return true
}

