<script>
  let currentDocId = null;
  let debounceTimer = null;
  const editor = document.getElementById('editor');
  const preview = document.getElementById('preview');
  const titleInput = document.getElementById('doc-title');
  const status = document.getElementById('status');

  const setStatus = (msg) => {
    status.textContent = msg;
    setTimeout(() => { status.textContent = ''; }, 2000);
  };

  const updatePreview = async () => {
    const res = await fetch('/api/render', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ markdown: editor.value }),
    });
    const json = await res.json();
    if (json.ok) preview.innerHTML = json.data;
  };

  editor.addEventListener('input', () => {
    clearTimeout(debounceTimer);
    debounceTimer = setTimeout(updatePreview, 150);
  });

  const saveDoc = async () => {
    const title = titleInput.value.trim() || 'Untitled';
    const content = editor.value;
    let res;
    if (currentDocId) {
      res = await fetch('/api/documents/' + currentDocId, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ title, content }),
      });
    } else {
      res = await fetch('/api/documents', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ title, content }),
      });
    }
    const json = await res.json();
    if (json.ok) {
      currentDocId = json.data.id;
      setStatus('Saved');
    }
  };

  const newDoc = () => {
    currentDocId = null;
    editor.value = '';
    titleInput.value = '';
    preview.innerHTML = '';
    setStatus('New document');
  };

  const loadDoc = async (id) => {
    const res = await fetch('/api/documents/' + id);
    const json = await res.json();
    if (json.ok) {
      currentDocId = json.data.id;
      editor.value = json.data.content;
      titleInput.value = json.data.title;
      updatePreview();
      toggleSidebar();
      setStatus('Loaded');
    }
  };

  const deleteDoc = async (id) => {
    if (!confirm('Delete this document?')) return;
    await fetch('/api/documents/' + id, { method: 'DELETE' });
    loadDocList();
    if (currentDocId === id) newDoc();
  };

  const loadDocList = async () => {
    const res = await fetch('/api/documents');
    const json = await res.json();
    const list = document.getElementById('doc-list');
    if (!json.ok || json.data.length === 0) {
      list.innerHTML = '<p style="color:#888;text-align:center;padding:24px;">No saved documents yet.</p>';
      return;
    }
    list.innerHTML = json.data.map(doc =>
      '<div style="padding:10px 12px;border-radius:4px;cursor:pointer;margin-bottom:4px;border:1px solid #eee;display:flex;justify-content:space-between;align-items:center;">' +
        '<div onclick="loadDoc(\\'' + doc.id + '\\')"  style="flex:1;">' +
          '<div style="font-weight:600;font-size:14px;">' + escapeHTML(doc.title || 'Untitled') + '</div>' +
          '<div style="font-size:11px;color:#888;">Updated: ' + new Date(doc.updatedAt).toLocaleString() + '</div>' +
        '</div>' +
        '<button onclick="deleteDoc(\\'' + doc.id + '\\')" style="border:1px solid #ddd;background:#fff;border-radius:3px;padding:4px 8px;cursor:pointer;font-size:12px;color:#e55;">Del</button>' +
      '</div>'
    ).join('');
  };

  const escapeHTML = (s) => s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

  const toggleSidebar = () => {
    const sb = document.getElementById('sidebar');
    const ov = document.getElementById('overlay');
    const visible = sb.style.display === 'flex';
    sb.style.display = visible ? 'none' : 'flex';
    ov.style.display = visible ? 'none' : 'block';
    if (!visible) loadDocList();
  };

  // Toolbar actions
  const insertText = (before, after = '', placeholder = '') => {
    const start = editor.selectionStart;
    const end = editor.selectionEnd;
    const selected = editor.value.substring(start, end) || placeholder;
    const replacement = before + selected + after;
    editor.value = editor.value.substring(0, start) + replacement + editor.value.substring(end);
    editor.selectionStart = start + before.length;
    editor.selectionEnd = start + before.length + selected.length;
    editor.focus();
    updatePreview();
  };

  document.querySelector('[data-action="h1"]')?.addEventListener('click', () => insertText('# ', '', 'Heading'));
  document.querySelector('[data-action="h2"]')?.addEventListener('click', () => insertText('## ', '', 'Heading'));
  document.querySelector('[data-action="h3"]')?.addEventListener('click', () => insertText('### ', '', 'Heading'));
  document.querySelector('[data-action="bold"]')?.addEventListener('click', () => insertText('**', '**', 'bold text'));
  document.querySelector('[data-action="italic"]')?.addEventListener('click', () => insertText('*', '*', 'italic text'));
  document.querySelector('[data-action="strikethrough"]')?.addEventListener('click', () => insertText('~~', '~~', 'text'));
  document.querySelector('[data-action="link"]')?.addEventListener('click', () => insertText('[', '](url)', 'link text'));
  document.querySelector('[data-action="image"]')?.addEventListener('click', () => insertText('![', '](url)', 'alt text'));
  document.querySelector('[data-action="code"]')?.addEventListener('click', () => insertText('\`', '\`', 'code'));
  document.querySelector('[data-action="codeblock"]')?.addEventListener('click', () => insertText('\`\`\`\\n', '\\n\`\`\`', 'code'));
  document.querySelector('[data-action="ul"]')?.addEventListener('click', () => insertText('- ', '', 'list item'));
  document.querySelector('[data-action="ol"]')?.addEventListener('click', () => insertText('1. ', '', 'list item'));
  document.querySelector('[data-action="blockquote"]')?.addEventListener('click', () => insertText('> ', '', 'quote'));
  document.querySelector('[data-action="hr"]')?.addEventListener('click', () => insertText('\\n---\\n'));
  document.querySelector('[data-action="table"]')?.addEventListener('click', () => insertText('| Column 1 | Column 2 | Column 3 |\\n|----------|----------|----------|\\n| Cell 1   | Cell 2   | Cell 3   |\\n'));

  // Keyboard shortcut
  editor.addEventListener('keydown', (e) => {
    if ((e.ctrlKey || e.metaKey) && e.key === 's') {
      e.preventDefault();
      saveDoc();
    }
    if ((e.ctrlKey || e.metaKey) && e.key === 'b') {
      e.preventDefault();
      insertText('**', '**', 'bold text');
    }
    if ((e.ctrlKey || e.metaKey) && e.key === 'i') {
      e.preventDefault();
      insertText('*', '*', 'italic text');
    }
  });

  // Tab support in editor
  editor.addEventListener('keydown', (e) => {
    if (e.key === 'Tab') {
      e.preventDefault();
      const start = editor.selectionStart;
      editor.value = editor.value.substring(0, start) + '  ' + editor.value.substring(editor.selectionEnd);
      editor.selectionStart = editor.selectionEnd = start + 2;
    }
  });

  // Initial preview render
  if (editor.value) updatePreview();
</script>
</body>
</html>`
}

const escapeAttr = (s: string): string =>
  s.replace(/&/g, '&amp;').replace(/"/g, '&quot;').replace(/</g, '&lt;').replace(/>/g, '&gt;')

const escapeHtmlContent = (s: string): string =>
  s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')

import { renderMarkdown } from './markdown'
import { listDocuments, getDocument, saveDocument, updateDocument, deleteDocument } from './store'
import { renderPage } from './ui'
import type { ApiResponse, SaveRequest, RenderRequest } from './types'

const jsonResponse = <T>(data: ApiResponse<T>, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string): Response =>
  new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const parseBody = async <T>(req: Request): Promise<T | null> => {
  try {
    return (await req.json()) as T
  } catch {
    return null
  }
}

const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const { pathname } = url
  const method = req.method

  // Serve the editor UI
  if (pathname === '/' && method === 'GET') {
    const html = renderPage()
    return htmlResponse(html)
  }

  // Render markdown to HTML
  if (pathname === '/api/render' && method === 'POST') {
    const body = await parseBody<RenderRequest>(req)
    if (!body?.markdown && body?.markdown !== '') {
      return jsonResponse({ ok: false, error: 'Missing markdown field' }, 400)
    }
    const html = renderMarkdown(body.markdown)
    return jsonResponse({ ok: true, data: html })
  }

  // List all documents
  if (pathname === '/api/documents' && method === 'GET') {
    const docs = await listDocuments()
    return jsonResponse({ ok: true, data: docs })
  }

  // Get a specific document
  const docMatch = pathname.match(/^\/api\/documents\/([^/]+)$/)
  if (docMatch && method === 'GET') {
    const doc = await getDocument(docMatch[1])
    if (!doc) return jsonResponse({ ok: false, error: 'Document not found' }, 404)
    return jsonResponse({ ok: true, data: doc })
  }

  // Create a new document
  if (pathname === '/api/documents' && method === 'POST') {
    const body = await parseBody<SaveRequest>(req)
    if (!body) return jsonResponse({ ok: false, error: 'Invalid request body' }, 400)
    const title = body.title?.trim() || 'Untitled'
    const content = body.content ?? ''
    const doc = await saveDocument(title, content)
    return jsonResponse({ ok: true, data: doc }, 201)
  }

  // Update a document
  if (docMatch && method === 'PUT') {
    const body = await parseBody<SaveRequest>(req)
    if (!body) return jsonResponse({ ok: false, error: 'Invalid request body' }, 400)
    const doc = await updateDocument(docMatch[1], body.title?.trim() || 'Untitled', body.content ?? '')
    if (!doc) return jsonResponse({ ok: false, error: 'Document not found' }, 404)
    return jsonResponse({ ok: true, data: doc })
  }

  // Delete a document
  if (docMatch && method === 'DELETE') {
    const deleted = await deleteDocument(docMatch[1])
    if (!deleted) return jsonResponse({ ok: false, error: 'Document not found' }, 404)
    return jsonResponse({ ok: true })
  }

  return jsonResponse({ ok: false, error: 'Not found' }, 404)
}

export default {
  port: 3000,
  fetch: handleRequest,
}

