input.content:
{
  "name": "@node/drawing-canvas",
  "version": "1.0.0",
  "description": "A freehand drawing canvas with shapes, layers, undo/redo, and PNG export",
  "main": "index.ts",
  "modnet": {
    "contentType": "art",
    "structure": "object",
    "mechanics": ["track"],
    "boundary": "all",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export type ToolType = 'freehand' | 'rectangle' | 'circle' | 'line' | 'eraser'

export type Point = {
  x: number
  y: number
}

export type DrawAction = {
  type: ToolType
  points: Point[]
  color: string
  size: number
  layerId: string
}

export type Layer = {
  id: string
  name: string
  visible: boolean
  opacity: number
  actions: DrawAction[]
  thumbnailDataUrl?: string
}

export type CanvasState = {
  width: number
  height: number
  layers: Layer[]
  activeLayerId: string
  activeTool: ToolType
  activeColor: string
  brushSize: number
  undoStack: DrawAction[][]
  redoStack: DrawAction[][]
}

export type DrawingFile = {
  version: string
  state: Omit<CanvasState, 'undoStack' | 'redoStack'>
  createdAt: string
  updatedAt: string
}

export type CanvasEvent =
  | { type: 'pointerdown'; point: Point }
  | { type: 'pointermove'; point: Point }
  | { type: 'pointerup'; point: Point }
  | { type: 'tool-select'; tool: ToolType }
  | { type: 'color-change'; color: string }
  | { type: 'brush-size'; size: number }
  | { type: 'undo' }
  | { type: 'redo' }
  | { type: 'clear' }
  | { type: 'add-layer' }
  | { type: 'remove-layer'; layerId: string }
  | { type: 'select-layer'; layerId: string }
  | { type: 'toggle-layer-visibility'; layerId: string }
  | { type: 'save-png' }
  | { type: 'load-png'; dataUrl: string }

import type { CanvasState, DrawAction, Layer, ToolType } from './types'

const generateId = (): string => crypto.randomUUID()

export const createLayer = (name: string): Layer => ({
  id: generateId(),
  name,
  visible: true,
  opacity: 1,
  actions: [],
})

export const createInitialState = (width = 800, height = 600): CanvasState => {
  const baseLayer = createLayer('Background')
  return {
    width,
    height,
    layers: [baseLayer],
    activeLayerId: baseLayer.id,
    activeTool: 'freehand',
    activeColor: '#000000',
    brushSize: 4,
    undoStack: [],
    redoStack: [],
  }
}

export const getActiveLayer = (state: CanvasState): Layer | undefined =>
  state.layers.find((l) => l.id === state.activeLayerId)

export const addActionToLayer = (
  state: CanvasState,
  action: DrawAction
): CanvasState => {
  const layerIndex = state.layers.findIndex((l) => l.id === state.activeLayerId)
  if (layerIndex === -1) return state

  const layer = state.layers[layerIndex]
  const updatedLayer: Layer = {
    ...layer,
    actions: [...layer.actions, action],
  }
  const updatedLayers = [...state.layers]
  updatedLayers[layerIndex] = updatedLayer

  const undoSnapshot = state.layers.flatMap((l) => l.actions)

  return {
    ...state,
    layers: updatedLayers,
    undoStack: [...state.undoStack, undoSnapshot],
    redoStack: [],
  }
}

export const undo = (state: CanvasState): CanvasState => {
  if (state.undoStack.length === 0) return state

  const currentSnapshot = state.layers.flatMap((l) => l.actions)
  const previousSnapshot = state.undoStack[state.undoStack.length - 1]

  const restoredLayers = restoreLayersFromSnapshot(state.layers, previousSnapshot)

  return {
    ...state,
    layers: restoredLayers,
    undoStack: state.undoStack.slice(0, -1),
    redoStack: [...state.redoStack, currentSnapshot],
  }
}

export const redo = (state: CanvasState): CanvasState => {
  if (state.redoStack.length === 0) return state

  const currentSnapshot = state.layers.flatMap((l) => l.actions)
  const nextSnapshot = state.redoStack[state.redoStack.length - 1]

  const restoredLayers = restoreLayersFromSnapshot(state.layers, nextSnapshot)

  return {
    ...state,
    layers: restoredLayers,
    undoStack: [...state.undoStack, currentSnapshot],
    redoStack: state.redoStack.slice(0, -1),
  }
}

const restoreLayersFromSnapshot = (
  layers: Layer[],
  snapshot: DrawAction[]
): Layer[] =>
  layers.map((layer) => ({
    ...layer,
    actions: snapshot.filter((a) => a.layerId === layer.id),
  }))

export const clearCanvas = (state: CanvasState): CanvasState => {
  const currentSnapshot = state.layers.flatMap((l) => l.actions)
  if (currentSnapshot.length === 0) return state

  return {
    ...state,
    layers: state.layers.map((l) => ({ ...l, actions: [] })),
    undoStack: [...state.undoStack, currentSnapshot],
    redoStack: [],
  }
}

export const addLayer = (state: CanvasState): CanvasState => {
  const newLayer = createLayer(`Layer ${state.layers.length + 1}`)
  return {
    ...state,
    layers: [...state.layers, newLayer],
    activeLayerId: newLayer.id,
  }
}

export const removeLayer = (state: CanvasState, layerId: string): CanvasState => {
  if (state.layers.length <= 1) return state

  const filtered = state.layers.filter((l) => l.id !== layerId)
  const activeLayerId =
    state.activeLayerId === layerId ? filtered[filtered.length - 1].id : state.activeLayerId

  return {
    ...state,
    layers: filtered,
    activeLayerId,
  }
}

export const toggleLayerVisibility = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  layers: state.layers.map((l) =>
    l.id === layerId ? { ...l, visible: !l.visible } : l
  ),
})

export const setActiveTool = (state: CanvasState, tool: ToolType): CanvasState => ({
  ...state,
  activeTool: tool,
})

export const setActiveColor = (state: CanvasState, color: string): CanvasState => ({
  ...state,
  activeColor: color,
})

export const setBrushSize = (state: CanvasState, size: number): CanvasState => ({
  ...state,
  brushSize: Math.max(1, Math.min(100, size)),
})

import type { CanvasState, DrawAction, Layer, Point } from './types'

export const renderAction = (
  ctx: CanvasRenderingContext2D,
  action: DrawAction
): void => {
  ctx.save()

  if (action.type === 'eraser') {
    ctx.globalCompositeOperation = 'destination-out'
  } else {
    ctx.globalCompositeOperation = 'source-over'
    ctx.strokeStyle = action.color
    ctx.fillStyle = action.color
  }

  ctx.lineWidth = action.size
  ctx.lineCap = 'round'
  ctx.lineJoin = 'round'

  switch (action.type) {
    case 'freehand':
    case 'eraser':
      renderFreehand(ctx, action.points, action.size)
      break
    case 'rectangle':
      renderRectangle(ctx, action.points)
      break
    case 'circle':
      renderCircle(ctx, action.points)
      break
    case 'line':
      renderLine(ctx, action.points)
      break
  }

  ctx.restore()
}

const renderFreehand = (
  ctx: CanvasRenderingContext2D,
  points: Point[],
  size: number
): void => {
  if (points.length === 0) return

  if (points.length === 1) {
    ctx.beginPath()
    ctx.arc(points[0].x, points[0].y, size / 2, 0, Math.PI * 2)
    ctx.fill()
    return
  }

  ctx.beginPath()
  ctx.moveTo(points[0].x, points[0].y)

  for (let i = 1; i < points.length - 1; i++) {
    const midX = (points[i].x + points[i + 1].x) / 2
    const midY = (points[i].y + points[i + 1].y) / 2
    ctx.quadraticCurveTo(points[i].x, points[i].y, midX, midY)
  }

  const last = points[points.length - 1]
  ctx.lineTo(last.x, last.y)
  ctx.stroke()
}

const renderRectangle = (ctx: CanvasRenderingContext2D, points: Point[]): void => {
  if (points.length < 2) return
  const start = points[0]
  const end = points[points.length - 1]
  const w = end.x - start.x
  const h = end.y - start.y
  ctx.strokeRect(start.x, start.y, w, h)
}

const renderCircle = (ctx: CanvasRenderingContext2D, points: Point[]): void => {
  if (points.length < 2) return
  const start = points[0]
  const end = points[points.length - 1]
  const rx = Math.abs(end.x - start.x) / 2
  const ry = Math.abs(end.y - start.y) / 2
  const cx = (start.x + end.x) / 2
  const cy = (start.y + end.y) / 2
  ctx.beginPath()
  ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2)
  ctx.stroke()
}

const renderLine = (ctx: CanvasRenderingContext2D, points: Point[]): void => {
  if (points.length < 2) return
  const start = points[0]
  const end = points[points.length - 1]
  ctx.beginPath()
  ctx.moveTo(start.x, start.y)
  ctx.lineTo(end.x, end.y)
  ctx.stroke()
}

export const renderLayer = (
  ctx: CanvasRenderingContext2D,
  layer: Layer,
  width: number,
  height: number
): void => {
  if (!layer.visible) return

  ctx.save()
  ctx.globalAlpha = layer.opacity

  for (const action of layer.actions) {
    renderAction(ctx, action)
  }

  ctx.restore()
}

export const renderFullCanvas = (
  ctx: CanvasRenderingContext2D,
  state: CanvasState
): void => {
  ctx.clearRect(0, 0, state.width, state.height)

  ctx.fillStyle = '#ffffff'
  ctx.fillRect(0, 0, state.width, state.height)

  for (const layer of state.layers) {
    renderLayer(ctx, layer, state.width, state.height)
  }
}

export const renderLayerThumbnail = (
  sourceCtx: CanvasRenderingContext2D,
  layer: Layer,
  thumbWidth: number,
  thumbHeight: number,
  canvasWidth: number,
  canvasHeight: number
): string => {
  const offscreen = new OffscreenCanvas(thumbWidth, thumbHeight)
  const thumbCtx = offscreen.getContext('2d')
  if (!thumbCtx) return ''

  thumbCtx.fillStyle = '#f0f0f0'
  thumbCtx.fillRect(0, 0, thumbWidth, thumbHeight)

  const scaleX = thumbWidth / canvasWidth
  const scaleY = thumbHeight / canvasHeight
  thumbCtx.scale(scaleX, scaleY)

  for (const action of layer.actions) {
    renderAction(thumbCtx as unknown as CanvasRenderingContext2D, action)
  }

  return offscreen.convertToBlob
    ? '' // will be handled async
    : ''
}

import type { CanvasState, DrawAction, Point, ToolType } from './types'

export type ActiveDraw = {
  action: DrawAction
  startPoint: Point
}

export const startDraw = (
  state: CanvasState,
  point: Point
): ActiveDraw => ({
  action: {
    type: state.activeTool,
    points: [point],
    color: state.activeTool === 'eraser' ? '#000000' : state.activeColor,
    size: state.brushSize,
    layerId: state.activeLayerId,
  },
  startPoint: point,
})

export const continueDraw = (
  activeDraw: ActiveDraw,
  point: Point,
  tool: ToolType
): ActiveDraw => {
  if (tool === 'freehand' || tool === 'eraser') {
    return {
      ...activeDraw,
      action: {
        ...activeDraw.action,
        points: [...activeDraw.action.points, point],
      },
    }
  }

  // For shapes, keep only start and current point
  return {
    ...activeDraw,
    action: {
      ...activeDraw.action,
      points: [activeDraw.startPoint, point],
    },
  }
}

export const finishDraw = (activeDraw: ActiveDraw, point: Point): DrawAction => ({
  ...activeDraw.action,
  points:
    activeDraw.action.type === 'freehand' || activeDraw.action.type === 'eraser'
      ? [...activeDraw.action.points, point]
      : [activeDraw.startPoint, point],
})

import type { CanvasState, DrawingFile } from './types'

const DATA_DIR = './data'

export const stateToDrawingFile = (state: CanvasState): DrawingFile => ({
  version: '1.0.0',
  state: {
    width: state.width,
    height: state.height,
    layers: state.layers,
    activeLayerId: state.activeLayerId,
    activeTool: state.activeTool,
    activeColor: state.activeColor,
    brushSize: state.brushSize,
  },
  createdAt: new Date().toISOString(),
  updatedAt: new Date().toISOString(),
})

export const drawingFileToState = (file: DrawingFile): CanvasState => ({
  ...file.state,
  undoStack: [],
  redoStack: [],
})

export const saveDrawingData = async (
  state: CanvasState,
  filename: string
): Promise<void> => {
  const file = stateToDrawingFile(state)
  const path = `${DATA_DIR}/${filename}.json`
  await Bun.write(path, JSON.stringify(file, null, 2))
}

export const loadDrawingData = async (
  filename: string
): Promise<CanvasState | null> => {
  const path = `${DATA_DIR}/${filename}.json`
  const file = Bun.file(path)
  if (!(await file.exists())) return null
  const data = (await file.json()) as DrawingFile
  return drawingFileToState(data)
}

export const listDrawings = async (): Promise<string[]> => {
  const glob = new Bun.Glob('*.json')
  const files: string[] = []
  for await (const entry of glob.scan({ cwd: DATA_DIR })) {
    files.push(entry.replace(/\.json$/, ''))
  }
  return files
}

export const canvasToDataUrl = (canvas: HTMLCanvasElement): string =>
  canvas.toDataURL('image/png')

export const savePng = (canvas: HTMLCanvasElement, filename: string): void => {
  const link = document.createElement('a')
  link.download = `${filename}.png`
  link.href = canvasToDataUrl(canvas)
  link.click()
}

export const loadPngToCanvas = (
  ctx: CanvasRenderingContext2D,
  dataUrl: string
): Promise<void> =>
  new Promise((resolve, reject) => {
    const img = new Image()
    img.onload = () => {
      ctx.drawImage(img, 0, 0)
      resolve()
    }
    img.onerror = reject
    img.src = dataUrl
  })

