import { h, createSSR } from 'plaited'
import type { CanvasState, CanvasEvent, ToolType, Point } from './types'
import {
  createInitialState,
  addActionToLayer,
  undo,
  redo,
  clearCanvas,
  addLayer,
  removeLayer,
  toggleLayerVisibility,
  setActiveTool,
  setActiveColor,
  setBrushSize,
} from './canvas-state'
import { renderFullCanvas, renderAction } from './canvas-renderer'
import { startDraw, continueDraw, finishDraw, type ActiveDraw } from './canvas-tools'
import { saveDrawingData, loadDrawingData, savePng, loadPngToCanvas } from './save-load'
import { renderApp } from './canvas-ui'

export type DrawingCanvas = {
  state: CanvasState
  activeDraw: ActiveDraw | null
  dispatch: (event: CanvasEvent) => void
  getCanvas: () => HTMLCanvasElement | null
  getContext: () => CanvasRenderingContext2D | null
  render: () => void
  mount: (container: HTMLElement) => void
}

export const createDrawingCanvas = (
  width = 800,
  height = 600
): DrawingCanvas => {
  let state = createInitialState(width, height)
  let activeDraw: ActiveDraw | null = null
  let canvasEl: HTMLCanvasElement | null = null
  let ctx: CanvasRenderingContext2D | null = null
  let containerEl: HTMLElement | null = null

  const getCanvas = (): HTMLCanvasElement | null => canvasEl
  const getContext = (): CanvasRenderingContext2D | null => ctx

  const redrawCanvas = (): void => {
    if (!ctx) return
    renderFullCanvas(ctx, state)
  }

  const updateThumbnails = (): void => {
    if (!containerEl) return
    for (const layer of state.layers) {
      const thumbCanvas = containerEl.querySelector(
        `[p-target="thumb-${layer.id}"]`
      ) as HTMLCanvasElement | null
      if (!thumbCanvas) continue

      const thumbCtx = thumbCanvas.getContext('2d')
      if (!thumbCtx) continue

      thumbCtx.clearRect(0, 0, 40, 30)
      thumbCtx.fillStyle = '#f0f0f0'
      thumbCtx.fillRect(0, 0, 40, 30)

      const scaleX = 40 / state.width
      const scaleY = 30 / state.height
      thumbCtx.save()
      thumbCtx.scale(scaleX, scaleY)
      for (const action of layer.actions) {
        renderAction(thumbCtx, action)
      }
      thumbCtx.restore()
    }
  }

  const render = (): void => {
    if (!containerEl) return
    const ssr = createSSR()
    const html = ssr.render(renderApp(state))
    containerEl.innerHTML = html
    bindCanvas()
    bindEvents()
    redrawCanvas()
    requestAnimationFrame(updateThumbnails)
  }

  const bindCanvas = (): void => {
    if (!containerEl) return
    canvasEl = containerEl.querySelector('[p-target="main-canvas"]') as HTMLCanvasElement
    if (canvasEl) {
      ctx = canvasEl.getContext('2d')
    }
  }

  const getPointFromEvent = (e: PointerEvent): Point => {
    if (!canvasEl) return { x: 0, y: 0 }
    const rect = canvasEl.getBoundingClientRect()
    return {
      x: e.clientX - rect.left,
      y: e.clientY - rect.top,
    }
  }

  const bindEvents = (): void => {
    if (!containerEl || !canvasEl) return

    canvasEl.addEventListener('pointerdown', (e: PointerEvent) => {
      const point = getPointFromEvent(e)
      activeDraw = startDraw(state, point)
      canvasEl?.setPointerCapture(e.pointerId)
    })

    canvasEl.addEventListener('pointermove', (e: PointerEvent) => {
      if (!activeDraw || !ctx) return
      const point = getPointFromEvent(e)
      activeDraw = continueDraw(activeDraw, point, state.activeTool)

      redrawCanvas()
      renderAction(ctx, activeDraw.action)
    })

    canvasEl.addEventListener('pointerup', (e: PointerEvent) => {
      if (!activeDraw) return
      const point = getPointFromEvent(e)
      const finalAction = finishDraw(activeDraw, point)
      state = addActionToLayer(state, finalAction)
      activeDraw = null
      redrawCanvas()
      requestAnimationFrame(updateThumbnails)
    })

    // Tool buttons
    containerEl.querySelectorAll('[p-trigger^="tool-select:"]').forEach((el) => {
      el.addEventListener('click', () => {
        const trigger = el.getAttribute('p-trigger') ?? ''
        const tool = trigger.split(':')[1] as ToolType
        dispatch({ type: 'tool-select', tool })
      })
    })

    // Color swatches
    containerEl.querySelectorAll('[p-trigger^="color-change:"]').forEach((el) => {
      el.addEventListener('click', () => {
        const trigger = el.getAttribute('p-trigger') ?? ''
        const color = trigger.split(':')[1]
        dispatch({ type: 'color-change', color })
      })
    })

    // Color input
    const colorInput = containerEl.querySelector('[p-trigger="color-input"]') as HTMLInputElement
    if (colorInput) {
      colorInput.addEventListener('input', () => {
        dispatch({ type: 'color-change', color: colorInput.value })
      })
    }

    // Brush size
    const brushRange = containerEl.querySelector('[p-trigger="brush-size"]') as HTMLInputElement
    if (brushRange) {
      brushRange.addEventListener('input', () => {
        dispatch({ type: 'brush-size', size: Number(brushRange.value) })
      })
    }

    // Action buttons
    const bindAction = (trigger: string, handler: () => void): void => {
      const el = containerEl?.querySelector(`[p-trigger="${trigger}"]`)
      if (el) el.addEventListener('click', handler)
    }

    bindAction('undo', () => dispatch({ type: 'undo' }))
    bindAction('redo', () => dispatch({ type: 'redo' }))
    bindAction('clear', () => dispatch({ type: 'clear' }))
    bindAction('save-png', () => {
      if (canvasEl) savePng(canvasEl, `drawing-${Date.now()}`)
    })
    bindAction('load-png', () => {
      const input = document.createElement('input')
      input.type = 'file'
      input.accept = 'image/png'
      input.onchange = () => {
        const file = input.files?.[0]
        if (!file) return
        const reader = new FileReader()
        reader.onload = () => {
          const dataUrl = reader.result as string
          dispatch({ type: 'load-png', dataUrl })
        }
        reader.readAsDataURL(file)
      }
      input.click()
    })

    // Layer buttons
    bindAction('add-layer', () => dispatch({ type: 'add-layer' }))

    containerEl.querySelectorAll('[p-trigger^="select-layer:"]').forEach((el) => {
      el.addEventListener('click', (e) => {
        if ((e.target as HTMLElement).closest('[p-trigger^="toggle-visibility"]')) return
        if ((e.target as HTMLElement).closest('[p-trigger^="remove-layer"]')) return
        const trigger = el.getAttribute('p-trigger') ?? ''
        const layerId = trigger.split(':')[1]
        dispatch({ type: 'select-layer', layerId })
      })
    })

    containerEl.querySelectorAll('[p-trigger^="toggle-visibility:"]').forEach((el) => {
      el.addEventListener('click', () => {
        const trigger = el.getAttribute('p-trigger') ?? ''
        const layerId = trigger.split(':')[1]
        dispatch({ type: 'toggle-layer-visibility', layerId })
      })
    })

    containerEl.querySelectorAll('[p-trigger^="remove-layer:"]').forEach((el) => {
      el.addEventListener('click', () => {
        const trigger = el.getAttribute('p-trigger') ?? ''
        const layerId = trigger.split(':')[1]
        dispatch({ type: 'remove-layer', layerId })
      })
    })

    // Keyboard shortcuts
    document.addEventListener('keydown', (e: KeyboardEvent) => {
      if (e.ctrlKey || e.metaKey) {
        if (e.key === 'z' && !e.shiftKey) {
          e.preventDefault()
          dispatch({ type: 'undo' })
        }
        if (e.key === 'z' && e.shiftKey) {
          e.preventDefault()
          dispatch({ type: 'redo' })
        }
        if (e.key === 'y') {
          e.preventDefault()
          dispatch({ type: 'redo' })
        }
      }
    })
  }

  const dispatch = (event: CanvasEvent): void => {
    switch (event.type) {
      case 'tool-select':
        state = setActiveTool(state, event.tool)
        render()
        break
      case 'color-change':
        state = setActiveColor(state, event.color)
        render()
        break
      case 'brush-size':
        state = setBrushSize(state, event.size)
        render()
        break
      case 'undo':
        state = undo(state)
        render()
        break
      case 'redo':
        state = redo(state)
        render()
        break
      case 'clear':
        state = clearCanvas(state)
        render()
        break
      case 'add-layer':
        state = addLayer(state)
        render()
        break
      case 'remove-layer':
        state = removeLayer(state, event.layerId)
        render()
        break
      case 'select-layer':
        state = { ...state, activeLayerId: event.layerId }
        render()
        break
      case 'toggle-layer-visibility':
        state = toggleLayerVisibility(state, event.layerId)
        render()
        break
      case 'load-png':
        if (ctx) {
          loadPngToCanvas(ctx, event.dataUrl).then(() => {
            redrawCanvas()
          })
        }
        break
      default:
        break
    }
  }

  const mount = (container: HTMLElement): void => {
    containerEl = container
    render()
  }

  return {
    get state() { return state },
    get activeDraw() { return activeDraw },
    dispatch,
    getCanvas,
    getContext,
    render,
    mount,
  }
}

// Server-side rendering entry point
export const renderDrawingCanvasSSR = (width = 800, height = 600): string => {
  const state = createInitialState(width, height)
  const ssr = createSSR()
  return ssr.render(renderApp(state))
}

