export type ToolKind = 'freehand' | 'rectangle' | 'circle' | 'line' | 'eraser';

export type Point = {
  x: number;
  y: number;
};

export type DrawAction = {
  tool: ToolKind;
  color: string;
  size: number;
  points: Point[];
  layerId: string;
};

export type Layer = {
  id: string;
  name: string;
  visible: boolean;
  actions: DrawAction[];
};

export type CanvasState = {
  layers: Layer[];
  activeLayerId: string;
  undoStack: DrawAction[][];
  redoStack: DrawAction[][];
  width: number;
  height: number;
};

export type SavedDrawing = {
  id: string;
  name: string;
  createdAt: string;
  state: CanvasState;
};

import type { CanvasState, DrawAction, Layer } from './types';

const generateId = (): string => crypto.randomUUID();

export const createLayer = (name: string): Layer => ({
  id: generateId(),
  name,
  visible: true,
  actions: [],
});

export const createInitialState = (width = 800, height = 600): CanvasState => {
  const baseLayer = createLayer('Background');
  return {
    layers: [baseLayer],
    activeLayerId: baseLayer.id,
    undoStack: [],
    redoStack: [],
    width,
    height,
  };
};

export const addLayer = (state: CanvasState, name: string): CanvasState => {
  const layer = createLayer(name);
  return {
    ...state,
    layers: [...state.layers, layer],
    activeLayerId: layer.id,
  };
};

export const removeLayer = (state: CanvasState, layerId: string): CanvasState => {
  if (state.layers.length <= 1) return state;
  const remaining = state.layers.filter((l) => l.id !== layerId);
  const activeLayerId = state.activeLayerId === layerId
    ? remaining[remaining.length - 1].id
    : state.activeLayerId;
  return { ...state, layers: remaining, activeLayerId };
};

export const toggleLayerVisibility = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  layers: state.layers.map((l) =>
    l.id === layerId ? { ...l, visible: !l.visible } : l
  ),
});

export const setActiveLayer = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  activeLayerId: layerId,
});

export const addAction = (state: CanvasState, action: DrawAction): CanvasState => {
  const snapshotActions = state.layers.map((l) => [...l.actions]);
  const undoEntry = state.layers.flatMap((l) => l.actions);
  return {
    ...state,
    layers: state.layers.map((l) =>
      l.id === action.layerId ? { ...l, actions: [...l.actions, action] } : l
    ),
    undoStack: [...state.undoStack, undoEntry],
    redoStack: [],
  };
};

export const undo = (state: CanvasState): CanvasState => {
  if (state.undoStack.length === 0) return state;
  const currentActions = state.layers.flatMap((l) => l.actions);
  const previousActions = state.undoStack[state.undoStack.length - 1];

  const layerActionsMap = new Map<string, DrawAction[]>();
  state.layers.forEach((l) => layerActionsMap.set(l.id, []));
  previousActions.forEach((a) => {
    const existing = layerActionsMap.get(a.layerId) ?? [];
    existing.push(a);
    layerActionsMap.set(a.layerId, existing);
  });

  return {
    ...state,
    layers: state.layers.map((l) => ({
      ...l,
      actions: layerActionsMap.get(l.id) ?? [],
    })),
    undoStack: state.undoStack.slice(0, -1),
    redoStack: [...state.redoStack, currentActions],
  };
};

export const redo = (state: CanvasState): CanvasState => {
  if (state.redoStack.length === 0) return state;
  const currentActions = state.layers.flatMap((l) => l.actions);
  const nextActions = state.redoStack[state.redoStack.length - 1];

  const layerActionsMap = new Map<string, DrawAction[]>();
  state.layers.forEach((l) => layerActionsMap.set(l.id, []));
  nextActions.forEach((a) => {
    const existing = layerActionsMap.get(a.layerId) ?? [];
    existing.push(a);
    layerActionsMap.set(a.layerId, existing);
  });

  return {
    ...state,
    layers: state.layers.map((l) => ({
      ...l,
      actions: layerActionsMap.get(l.id) ?? [],
    })),
    undoStack: [...state.undoStack, currentActions],
    redoStack: state.redoStack.slice(0, -1),
  };
};

export const clearActiveLayer = (state: CanvasState): CanvasState => {
  const currentActions = state.layers.flatMap((l) => l.actions);
  return {
    ...state,
    layers: state.layers.map((l) =>
      l.id === state.activeLayerId ? { ...l, actions: [] } : l
    ),
    undoStack: [...state.undoStack, currentActions],
    redoStack: [],
  };
};

export const moveLayer = (state: CanvasState, layerId: string, direction: 'up' | 'down'): CanvasState => {
  const idx = state.layers.findIndex((l) => l.id === layerId);
  if (idx === -1) return state;
  const newIdx = direction === 'up' ? idx + 1 : idx - 1;
  if (newIdx < 0 || newIdx >= state.layers.length) return state;
  const layers = [...state.layers];
  [layers[idx], layers[newIdx]] = [layers[newIdx], layers[idx]];
  return { ...state, layers };
};

