const getClientScript = (initialState: CanvasState): string => `
(function() {
  const state = ${JSON.stringify(initialState)};
  let currentTool = 'freehand';
  let currentColor = '#000000';
  let brushSize = 3;
  let isDrawing = false;
  let startPoint = null;
  let currentPoints = [];

  const interactionCanvas = document.getElementById('interaction-layer');
  const interactionCtx = interactionCanvas.getContext('2d');

  const getLayerCanvas = (layerId) => document.getElementById('layer-' + layerId);
  const getLayerCtx = (layerId) => { const c = getLayerCanvas(layerId); return c ? c.getContext('2d') : null; };

  const getActiveCtx = () => getLayerCtx(state.activeLayerId);
  const getActiveCanvas = () => getLayerCanvas(state.activeLayerId);

  // Redraw a layer from its actions
  const redrawLayer = (layer) => {
    const ctx = getLayerCtx(layer.id);
    if (!ctx) return;
    ctx.clearRect(0, 0, state.width, state.height);
    layer.actions.forEach((action) => drawAction(ctx, action));
    updateThumb(layer.id);
  };

  const redrawAll = () => state.layers.forEach(redrawLayer);

  const drawAction = (ctx, action) => {
    ctx.lineWidth = action.size;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    if (action.tool === 'eraser') {
      ctx.globalCompositeOperation = 'destination-out';
      ctx.strokeStyle = 'rgba(0,0,0,1)';
    } else {
      ctx.globalCompositeOperation = 'source-over';
      ctx.strokeStyle = action.color;
    }

    if (action.tool === 'freehand' || action.tool === 'eraser') {
      ctx.beginPath();
      if (action.points.length === 1) {
        ctx.arc(action.points[0].x, action.points[0].y, action.size / 2, 0, Math.PI * 2);
        ctx.fillStyle = action.tool === 'eraser' ? 'rgba(0,0,0,1)' : action.color;
        ctx.fill();
      } else {
        ctx.moveTo(action.points[0].x, action.points[0].y);
        for (let i = 1; i < action.points.length; i++) {
          ctx.lineTo(action.points[i].x, action.points[i].y);
        }
        ctx.stroke();
      }
    } else if (action.tool === 'rectangle') {
      const p0 = action.points[0];
      const p1 = action.points[action.points.length - 1];
      ctx.beginPath();
      ctx.strokeRect(p0.x, p0.y, p1.x - p0.x, p1.y - p0.y);
    } else if (action.tool === 'circle') {
      const p0 = action.points[0];
      const p1 = action.points[action.points.length - 1];
      const rx = Math.abs(p1.x - p0.x) / 2;
      const ry = Math.abs(p1.y - p0.y) / 2;
      const cx = (p0.x + p1.x) / 2;
      const cy = (p0.y + p1.y) / 2;
      ctx.beginPath();
      ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2);
      ctx.stroke();
    } else if (action.tool === 'line') {
      const p0 = action.points[0];
      const p1 = action.points[action.points.length - 1];
      ctx.beginPath();
      ctx.moveTo(p0.x, p0.y);
      ctx.lineTo(p1.x, p1.y);
      ctx.stroke();
    }

    ctx.globalCompositeOperation = 'source-over';
  };

  // Preview shape while dragging
  const drawPreview = (tool, start, end) => {
    interactionCtx.clearRect(0, 0, state.width, state.height);
    interactionCtx.lineWidth = brushSize;
    interactionCtx.lineCap = 'round';
    interactionCtx.strokeStyle = currentColor;

    if (tool === 'rectangle') {
      interactionCtx.beginPath();
      interactionCtx.strokeRect(start.x, start.y, end.x - start.x, end.y - start.y);
    } else if (tool === 'circle') {
      const rx = Math.abs(end.x - start.x) / 2;
      const ry = Math.abs(end.y - start.y) / 2;
      const cx = (start.x + end.x) / 2;
      const cy = (start.y + end.y) / 2;
      interactionCtx.beginPath();
      interactionCtx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2);
      interactionCtx.stroke();
    } else if (tool === 'line') {
      interactionCtx.beginPath();
      interactionCtx.moveTo(start.x, start.y);
      interactionCtx.lineTo(end.x, end.y);
      interactionCtx.stroke();
    }
  };

  const getPos = (e) => {
    const rect = interactionCanvas.getBoundingClientRect();
    return { x: e.clientX - rect.left, y: e.clientY - rect.top };
  };

  // Save action to state
  const commitAction = (action) => {
    const layer = state.layers.find(l => l.id === action.layerId);
    if (!layer) return;
    const allActions = state.layers.flatMap(l => [...l.actions]);
    state.undoStack.push(allActions);
    state.redoStack = [];
    layer.actions.push(action);
    redrawLayer(layer);
  };

  // Mouse events
  interactionCanvas.addEventListener('pointerdown', (e) => {
    isDrawing = true;
    const pos = getPos(e);
    startPoint = pos;
    currentPoints = [pos];
    interactionCanvas.setPointerCapture(e.pointerId);
  });

  interactionCanvas.addEventListener('pointermove', (e) => {
    if (!isDrawing) return;
    const pos = getPos(e);
    currentPoints.push(pos);

    if (currentTool === 'freehand' || currentTool === 'eraser') {
      const ctx = getActiveCtx();
      if (!ctx) return;
      ctx.lineWidth = brushSize;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      if (currentTool === 'eraser') {
        ctx.globalCompositeOperation = 'destination-out';
        ctx.strokeStyle = 'rgba(0,0,0,1)';
      } else {
        ctx.globalCompositeOperation = 'source-over';
        ctx.strokeStyle = currentColor;
      }
      const len = currentPoints.length;
      ctx.beginPath();
      ctx.moveTo(currentPoints[len - 2].x, currentPoints[len - 2].y);
      ctx.lineTo(currentPoints[len - 1].x, currentPoints[len - 1].y);
      ctx.stroke();
      ctx.globalCompositeOperation = 'source-over';
    } else {
      drawPreview(currentTool, startPoint, pos);
    }
  });

  interactionCanvas.addEventListener('pointerup', (e) => {
    if (!isDrawing) return;
    isDrawing = false;
    interactionCtx.clearRect(0, 0, state.width, state.height);

    const action = {
      tool: currentTool,
      color: currentTool === 'eraser' ? '#000000' : currentColor,
      size: brushSize,
      points: currentPoints,
      layerId: state.activeLayerId,
    };

    // Redraw the full layer from scratch to keep state consistent
    const layer = state.layers.find(l => l.id === state.activeLayerId);
    if (!layer) return;
    const allActions = state.layers.flatMap(l => [...l.actions]);
    state.undoStack.push(allActions);
    state.redoStack = [];
    layer.actions.push(action);
    redrawLayer(layer);

    currentPoints = [];
    startPoint = null;
  });

  // Toolbar event delegation
  document.addEventListener('click', (e) => {
    const btn = e.target.closest('[p-trigger]');
    if (!btn) return;
    const trigger = btn.getAttribute('p-trigger');
    if (!trigger) return;
    const [, action] = trigger.split(':');

    switch (action) {
      case 'selectTool': {
        currentTool = btn.dataset.tool;
        document.querySelectorAll('.tool-btn').forEach(b => {
          b.style.cssText = b.dataset.tool === currentTool
            ? '${styleToStr(styles.toolBtnActive)}'
            : '${styleToStr(styles.toolBtn)}';
        });
        break;
      }
      case 'undo': {
        if (state.undoStack.length === 0) break;
        const current = state.layers.flatMap(l => [...l.actions]);
        const prev = state.undoStack.pop();
        state.redoStack.push(current);
        // Distribute actions back to layers
        state.layers.forEach(l => l.actions = []);
        prev.forEach(a => {
          const layer = state.layers.find(l => l.id === a.layerId);
          if (layer) layer.actions.push(a);
        });
        redrawAll();
        break;
      }
      case 'redo': {
        if (state.redoStack.length === 0) break;
        const current2 = state.layers.flatMap(l => [...l.actions]);
        const next = state.redoStack.pop();
        state.undoStack.push(current2);
        state.layers.forEach(l => l.actions = []);
        next.forEach(a => {
          const layer = state.layers.find(l => l.id === a.layerId);
          if (layer) layer.actions.push(a);
        });
        redrawAll();
        break;
      }
      case 'clearCanvas': {
        const current3 = state.layers.flatMap(l => [...l.actions]);
        state.undoStack.push(current3);
        state.redoStack = [];
        const activeLayer = state.layers.find(l => l.id === state.activeLayerId);
        if (activeLayer) {
          activeLayer.actions = [];
          redrawLayer(activeLayer);
        }
        break;
      }
      case 'addLayer': {
        const id = crypto.randomUUID();
        const name = 'Layer ' + (state.layers.length + 1);
        state.layers.push({ id, name, visible: true, actions: [] });
        state.activeLayerId = id;
        rebuildLayersUI();
        rebuildCanvasStack();
        break;
      }
      case 'selectLayer': {
        const layerId = btn.dataset.layerId || btn.closest('[data-layer-id]')?.dataset.layerId;
        if (layerId && !btn.closest('[p-trigger="click:toggleVisibility"]') && !btn.closest('[p-trigger="click:removeLayer"]')) {
          state.activeLayerId = layerId;
          rebuildLayersUI();
        }
        break;
      }
      case 'toggleVisibility': {
        const lid = btn.dataset.layerId;
        const layer = state.layers.find(l => l.id === lid);
        if (layer) {
          layer.visible = !layer.visible;
          const canvas = getLayerCanvas(lid);
          if (canvas) canvas.style.display = layer.visible ? '' : 'none';
          rebuildLayersUI();
        }
        break;
      }
      case 'removeLayer': {
        if (state.layers.length <= 1) break;
        const rid = btn.dataset.layerId;
        state.layers = state.layers.filter(l => l.id !== rid);
        if (state.activeLayerId === rid) {
          state.activeLayerId = state.layers[state.layers.length - 1].id;
        }
        rebuildLayersUI();
        rebuildCanvasStack();
        break;
      }
      case 'moveLayerUp': {
        const idx = state.layers.findIndex(l => l.id === state.activeLayerId);
        if (idx < state.layers.length - 1) {
          [state.layers[idx], state.layers[idx + 1]] = [state.layers[idx + 1], state.layers[idx]];
          rebuildLayersUI();
          rebuildCanvasStack();
        }
        break;
      }
      case 'moveLayerDown': {
        const idx2 = state.layers.findIndex(l => l.id === state.activeLayerId);
        if (idx2 > 0) {
          [state.layers[idx2], state.layers[idx2 - 1]] = [state.layers[idx2 - 1], state.layers[idx2]];
          rebuildLayersUI();
          rebuildCanvasStack();
        }
        break;
      }
      case 'savePng': {
        const offscreen = document.createElement('canvas');
        offscreen.width = state.width;
        offscreen.height = state.height;
        const offCtx = offscreen.getContext('2d');
        offCtx.fillStyle = '#ffffff';
        offCtx.fillRect(0, 0, state.width, state.height);
        state.layers.forEach(layer => {
          if (!layer.visible) return;
          const lc = getLayerCanvas(layer.id);
          if (lc) offCtx.drawImage(lc, 0, 0);
        });
        const link = document.createElement('a');
        link.download = 'drawing.png';
        link.href = offscreen.toDataURL('image/png');
        link.click();
        break;
      }
    }
  });

  // Input events
  document.addEventListener('input', (e) => {
    const trigger = e.target.getAttribute('p-trigger');
    if (!trigger) return;
    const [, action] = trigger.split(':');
    if (action === 'changeColor') {
      currentColor = e.target.value;
    } else if (action === 'changeBrushSize') {
      brushSize = parseInt(e.target.value, 10);
      document.getElementById('brush-size-label').textContent = String(brushSize);
    }
  });

  // File load
  document.addEventListener('change', (e) => {
    const trigger = e.target.getAttribute('p-trigger');
    if (!trigger) return;
    const [, action] = trigger.split(':');
    if (action === 'loadPng') {
      const file = e.target.files[0];
      if (!file) return;
      const img = new Image();
      img.onload = () => {
        const ctx = getActiveCtx();
        if (ctx) {
          const allActions = state.layers.flatMap(l => [...l.actions]);
          state.undoStack.push(allActions);
          state.redoStack = [];
          ctx.drawImage(img, 0, 0, state.width, state.height);
          // Store as a special action
          const activeLayer = state.layers.find(l => l.id === state.activeLayerId);
          if (activeLayer) updateThumb(activeLayer.id);
        }
        URL.revokeObjectURL(img.src);
      };
      img.src = URL.createObjectURL(file);
    }
  });

  // Thumbnails
  const updateThumb = (layerId) => {
    const thumb = document.querySelector('[data-thumb-for="' + layerId + '"]');
    const source = getLayerCanvas(layerId);
    if (!thumb || !source) return;
    const tCtx = thumb.getContext('2d');
    tCtx.clearRect(0, 0, 32, 24);
    tCtx.drawImage(source, 0, 0, 32, 24);
  };

  // Rebuild layers panel
  const rebuildLayersUI = () => {
    const panel = document.getElementById('layers-panel');
    panel.innerHTML = '';
    state.layers.forEach((layer) => {
      const div = document.createElement('div');
      div.style.cssText = layer.id === state.activeLayerId
        ? '${styleToStr(styles.layerItemActive)}'
        : '${styleToStr(styles.layerItem)}';
      div.dataset.layerId = layer.id;
      div.setAttribute('p-trigger', 'click:selectLayer');

      const thumb = document.createElement('canvas');
      thumb.width = 32; thumb.height = 24;
      thumb.dataset.thumbFor = layer.id;
      thumb.style.cssText = '${styleToStr(styles.layerThumb)}';
      div.appendChild(thumb);

      const name = document.createElement('span');
      name.style.cssText = 'flex:1;' + (!layer.visible ? 'opacity:0.4' : '');
      name.textContent = layer.name;
      div.appendChild(name);

      const visBtn = document.createElement('button');
      visBtn.style.cssText = 'background:none;border:none;color:#e0e0e0;cursor:pointer;font-size:14px;padding:2px';
      visBtn.setAttribute('p-trigger', 'click:toggleVisibility');
      visBtn.dataset.layerId = layer.id;
      visBtn.textContent = layer.visible ? '\u{1F441}' : '\u{1F441}\u{200D}\u{1F5E8}';
      div.appendChild(visBtn);

      if (state.layers.length > 1) {
        const delBtn = document.createElement('button');
        delBtn.style.cssText = 'background:none;border:none;color:#e94560;cursor:pointer;font-size:12px;padding:2px';
        delBtn.setAttribute('p-trigger', 'click:removeLayer');
        delBtn.dataset.layerId = layer.id;
        delBtn.textContent = '\u2715';
        div.appendChild(delBtn);
      }

      panel.appendChild(div);
      updateThumb(layer.id);
    });
  };

  // Rebuild canvas stack
  const rebuildCanvasStack = () => {
    const container = interactionCanvas.parentElement;
    // Remove old layer canvases
    container.querySelectorAll('.drawing-layer').forEach(c => c.remove());
    // Add in order
    state.layers.forEach((layer, i) => {
      const canvas = document.createElement('canvas');
      canvas.id = 'layer-' + layer.id;
      canvas.className = 'drawing-layer';
      canvas.dataset.layerId = layer.id;
      canvas.width = state.width;
      canvas.height = state.height;
      canvas.style.cssText = '${styleToStr(styles.canvas)};position:' + (i === 0 ? 'relative' : 'absolute') + ';top:0;left:0;' + (!layer.visible ? 'display:none' : '');
      container.insertBefore(canvas, interactionCanvas);
      redrawLayer(layer);
    });
  };

  // Keyboard shortcuts
  document.addEventListener('keydown', (e) => {
    if ((e.ctrlKey || e.metaKey) && e.key === 'z' && !e.shiftKey) {
      e.preventDefault();
      document.querySelector('[p-trigger="click:undo"]')?.click();
    }
    if ((e.ctrlKey || e.metaKey) && (e.key === 'y' || (e.shiftKey && e.key === 'z'))) {
      e.preventDefault();
      document.querySelector('[p-trigger="click:redo"]')?.click();
    }
  });
})();
`;

import { createInitialState } from './canvas-state';
import { renderPage } from './render';
import type { CanvasState, SavedDrawing } from './types';

const DATA_DIR = new URL('../data/', import.meta.url).pathname;
const DRAWINGS_FILE = `${DATA_DIR}drawings.jsonl`;

const ensureDataDir = async () => {
  try {
    await Bun.file(DRAWINGS_FILE).text();
  } catch {
    await Bun.write(DRAWINGS_FILE, '');
  }
};

const saveDrawing = async (drawing: SavedDrawing) => {
  const existing = await loadDrawings();
  existing.push(drawing);
  const content = existing.map((d) => JSON.stringify(d)).join('\n');
  await Bun.write(DRAWINGS_FILE, content);
};

const loadDrawings = async (): Promise<SavedDrawing[]> => {
  try {
    const text = await Bun.file(DRAWINGS_FILE).text();
    if (!text.trim()) return [];
    return text.trim().split('\n').map((line) => JSON.parse(line));
  } catch {
    return [];
  }
};

export const startServer = (port = 3000) => {
  let canvasState = createInitialState();

  const server = Bun.serve({
    port,
    fetch: async (req) => {
      const url = new URL(req.url);

      if (url.pathname === '/' && req.method === 'GET') {
        const html = renderPage(canvasState);
        return new Response(html, {
          headers: { 'Content-Type': 'text/html; charset=utf-8' },
        });
      }

      if (url.pathname === '/api/state' && req.method === 'GET') {
        return Response.json(canvasState);
      }

      if (url.pathname === '/api/state' && req.method === 'POST') {
        const body = await req.json() as CanvasState;
        canvasState = body;
        return Response.json({ ok: true });
      }

      if (url.pathname === '/api/save' && req.method === 'POST') {
        const body = await req.json() as { name: string };
        const drawing: SavedDrawing = {
          id: crypto.randomUUID(),
          name: body.name || 'Untitled',
          createdAt: new Date().toISOString(),
          state: canvasState,
        };
        await saveDrawing(drawing);
        return Response.json({ id: drawing.id });
      }

      if (url.pathname === '/api/drawings' && req.method === 'GET') {
        const drawings = await loadDrawings();
        return Response.json(drawings.map((d) => ({ id: d.id, name: d.name, createdAt: d.createdAt })));
      }

      if (url.pathname.startsWith('/api/drawings/') && req.method === 'GET') {
        const id = url.pathname.split('/').pop();
        const drawings = await loadDrawings();
        const drawing = drawings.find((d) => d.id === id);
        if (!drawing) return new Response('Not found', { status: 404 });
        canvasState = drawing.state;
        return Response.json(drawing);
      }

      return new Response('Not found', { status: 404 });
    },
  });

  ensureDataDir();
  console.log(`Drawing Canvas running at http://localhost:${port}`);
  return server;
};

export { startServer } from './server';
export { createInitialState, addLayer, removeLayer, toggleLayerVisibility, setActiveLayer, addAction, undo, redo, clearActiveLayer, moveLayer } from './canvas-state';
export { renderPage } from './render';
export type { ToolKind, Point, DrawAction, Layer, CanvasState, SavedDrawing } from './types';

// Auto-start if run directly
const isMain = import.meta.url === `file://${process.argv[1]}` || import.meta.main;
if (isMain) {
  const port = parseInt(process.env.PORT || '3000', 10);
  const { startServer } = await import('./server');
  startServer(port);
}

{
  "name": "@node/drawing-canvas",
  "version": "1.0.0",
  "description": "A freehand and shape drawing canvas with layers, undo/redo, and PNG export",
  "main": "src/index.ts",
  "modnet": {
    "contentType": "design",
    "structure": "object",
    "mechanics": ["track"],
    "boundary": "all",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export type Tool = 'freehand' | 'rect' | 'circle' | 'line' | 'eraser'

export type LayerMeta = {
  id: number
  name: string
  visible: boolean
}

export type DrawingMeta = {
  id: string
  name: string
  width: number
  height: number
  layers: LayerMeta[]
  createdAt: string
  updatedAt: string
}

export type SaveRequest = {
  name: string
  imageData: string
  width: number
  height: number
}

export type DrawingListItem = {
  id: string
  name: string
  updatedAt: string
}

export type CanvasConfig = {
  width: number
  height: number
  maxUndo: number
  maxLayers: number
}

export const DEFAULT_CONFIG: CanvasConfig = {
  width: 800,
  height: 600,
  maxUndo: 50,
  maxLayers: 10,
}

import type { DrawingMeta, DrawingListItem } from './types'

const DATA_DIR = './data/drawings'

export const listDrawings = async (): Promise<DrawingListItem[]> => {
  const glob = new Bun.Glob('*.json')
  const items: DrawingListItem[] = []

  for await (const path of glob.scan(DATA_DIR)) {
    const file = Bun.file(`${DATA_DIR}/${path}`)
    const meta: DrawingMeta = await file.json()
    items.push({ id: meta.id, name: meta.name, updatedAt: meta.updatedAt })
  }

  items.sort((a, b) => b.updatedAt.localeCompare(a.updatedAt))
  return items
}

export const saveDrawing = async (
  name: string,
  imageData: string,
  width: number,
  height: number,
): Promise<DrawingMeta> => {
  const id = crypto.randomUUID()
  const now = new Date().toISOString()

  const meta: DrawingMeta = {
    id,
    name,
    width,
    height,
    layers: [{ id: 0, name: 'Composite', visible: true }],
    createdAt: now,
    updatedAt: now,
  }

  const base64 = imageData.replace(/^data:image\/png;base64,/, '')
  const buffer = Buffer.from(base64, 'base64')

  await Bun.write(`${DATA_DIR}/${id}.png`, buffer)
  await Bun.write(`${DATA_DIR}/${id}.json`, JSON.stringify(meta, null, 2))

  return meta
}

export const loadDrawing = async (id: string): Promise<{ meta: DrawingMeta; png: Uint8Array } | null> => {
  const metaFile = Bun.file(`${DATA_DIR}/${id}.json`)
  const pngFile = Bun.file(`${DATA_DIR}/${id}.png`)

  if (!(await metaFile.exists()) || !(await pngFile.exists())) return null

  const meta: DrawingMeta = await metaFile.json()
  const png = new Uint8Array(await pngFile.arrayBuffer())

  return { meta, png }
}

export const deleteDrawing = async (id: string): Promise<boolean> => {
  const metaFile = Bun.file(`${DATA_DIR}/${id}.json`)
  if (!(await metaFile.exists())) return false

  const { unlink } = await import('node:fs/promises')
  await unlink(`${DATA_DIR}/${id}.json`).catch(() => {})
  await unlink(`${DATA_DIR}/${id}.png`).catch(() => {})

  return true
}

export const clientScript = `
(function() {
  const CANVAS_W = 800;
  const CANVAS_H = 600;
  const MAX_UNDO = 50;
  const MAX_LAYERS = 10;
  const THUMB_W = 48;
  const THUMB_H = 36;

  // --- State ---
  const state = {
    tool: 'freehand',
    color: '#000000',
    brushSize: 4,
    layers: [],
    activeLayerId: 0,
    nextLayerId: 0,
    drawing: false,
    startX: 0,
    startY: 0,
    undoStack: [],
    redoStack: [],
  };

  // --- DOM ---
  const display = document.getElementById('display-canvas');
  const dCtx = display.getContext('2d');
  const tempCanvas = document.createElement('canvas');
  tempCanvas.width = CANVAS_W;
  tempCanvas.height = CANVAS_H;
  const tempCtx = tempCanvas.getContext('2d');

  // --- Helpers ---
  const $ = (sel) => document.querySelector(sel);
  const $$ = (sel) => document.querySelectorAll(sel);

  const activeLayer = () => state.layers.find(l => l.id === state.activeLayerId);

  // --- Layers ---
  const addLayer = (name) => {
    if (state.layers.length >= MAX_LAYERS) return;
    const c = document.createElement('canvas');
    c.width = CANVAS_W;
    c.height = CANVAS_H;
    const layer = {
      id: state.nextLayerId++,
      name: name || 'Layer ' + state.nextLayerId,
      visible: true,
      canvas: c,
      ctx: c.getContext('2d'),
    };
    state.layers.push(layer);
    state.activeLayerId = layer.id;
    renderLayerPanel();
    composite();
  };

  const removeLayer = (id) => {
    if (state.layers.length <= 1) return;
    state.layers = state.layers.filter(l => l.id !== id);
    if (state.activeLayerId === id) {
      state.activeLayerId = state.layers[state.layers.length - 1].id;
    }
    renderLayerPanel();
    composite();
  };

  const toggleVisibility = (id) => {
    const layer = state.layers.find(l => l.id === id);
    if (layer) layer.visible = !layer.visible;
    renderLayerPanel();
    composite();
  };

  const selectLayer = (id) => {
    state.activeLayerId = id;
    renderLayerPanel();
  };

  // --- Compositing ---
  const composite = () => {
    dCtx.clearRect(0, 0, CANVAS_W, CANVAS_H);
    // White background
    dCtx.fillStyle = '#ffffff';
    dCtx.fillRect(0, 0, CANVAS_W, CANVAS_H);
    for (const layer of state.layers) {
      if (!layer.visible) continue;
      dCtx.drawImage(layer.canvas, 0, 0);
    }
    // Draw temp canvas overlay (shape preview)
    if (state.drawing && state.tool !== 'freehand' && state.tool !== 'eraser') {
      dCtx.drawImage(tempCanvas, 0, 0);
    }
  };

  // --- History ---
  const captureState = () => {
    return state.layers.map(l => ({
      id: l.id,
      name: l.name,
      visible: l.visible,
      data: l.canvas.toDataURL(),
    }));
  };

  const restoreState = (snapshot) => {
    for (const snap of snapshot) {
      const layer = state.layers.find(l => l.id === snap.id);
      if (!layer) continue;
      layer.visible = snap.visible;
      const img = new Image();
      img.onload = () => {
        layer.ctx.clearRect(0, 0, CANVAS_W, CANVAS_H);
        layer.ctx.drawImage(img, 0, 0);
        composite();
        renderLayerPanel();
      };
      img.src = snap.data;
    }
  };

  const pushUndo = () => {
    state.undoStack.push(captureState());
    if (state.undoStack.length > MAX_UNDO) state.undoStack.shift();
    state.redoStack = [];
    updateHistoryButtons();
  };

  const undo = () => {
    if (state.undoStack.length === 0) return;
    state.redoStack.push(captureState());
    const prev = state.undoStack.pop();
    restoreState(prev);
    updateHistoryButtons();
  };

  const redo = () => {
    if (state.redoStack.length === 0) return;
    state.undoStack.push(captureState());
    const next = state.redoStack.pop();
    restoreState(next);
    updateHistoryButtons();
  };

  const updateHistoryButtons = () => {
    $('#btn-undo').disabled = state.undoStack.length === 0;
    $('#btn-redo').disabled = state.redoStack.length === 0;
  };

  // --- Drawing ---
  const getPos = (e) => {
    const rect = display.getBoundingClientRect();
    const scaleX = CANVAS_W / rect.width;
    const scaleY = CANVAS_H / rect.height;
    return {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY,
    };
  };

  const configureStroke = (ctx, isEraser) => {
    if (isEraser) {
      ctx.globalCompositeOperation = 'destination-out';
      ctx.strokeStyle = 'rgba(0,0,0,1)';
    } else {
      ctx.globalCompositeOperation = 'source-over';
      ctx.strokeStyle = state.color;
    }
    ctx.lineWidth = state.brushSize;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
  };

  const drawShape = (ctx, tool, x1, y1, x2, y2) => {
    ctx.beginPath();
    ctx.strokeStyle = state.color;
    ctx.lineWidth = state.brushSize;
    ctx.lineCap = 'round';
    if (tool === 'rect') {
      ctx.strokeRect(x1, y1, x2 - x1, y2 - y1);
    } else if (tool === 'circle') {
      const rx = Math.abs(x2 - x1) / 2;
      const ry = Math.abs(y2 - y1) / 2;
      const cx = Math.min(x1, x2) + rx;
      const cy = Math.min(y1, y2) + ry;
      ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2);
      ctx.stroke();
    } else if (tool === 'line') {
      ctx.moveTo(x1, y1);
      ctx.lineTo(x2, y2);
      ctx.stroke();
    }
  };

  const onPointerDown = (e) => {
    const layer = activeLayer();
    if (!layer) return;
    state.drawing = true;
    const pos = getPos(e);
    state.startX = pos.x;
    state.startY = pos.y;

    pushUndo();

    if (state.tool === 'freehand' || state.tool === 'eraser') {
      configureStroke(layer.ctx, state.tool === 'eraser');
      layer.ctx.beginPath();
      layer.ctx.moveTo(pos.x, pos.y);
    }
  };

  const onPointerMove = (e) => {
    if (!state.drawing) return;
    const pos = getPos(e);

    if (state.tool === 'freehand' || state.tool === 'eraser') {
      const layer = activeLayer();
      if (!layer) return;
      layer.ctx.lineTo(pos.x, pos.y);
      layer.ctx.stroke();
      composite();
    } else {
      tempCtx.clearRect(0, 0, CANVAS_W, CANVAS_H);
      drawShape(tempCtx, state.tool, state.startX, state.startY, pos.x, pos.y);
      composite();
    }
  };

  const onPointerUp = (e) => {
    if (!state.drawing) return;
    state.drawing = false;
    const layer = activeLayer();
    if (!layer) return;

    if (state.tool === 'eraser') {
      layer.ctx.globalCompositeOperation = 'source-over';
    }

    if (state.tool !== 'freehand' && state.tool !== 'eraser') {
      const pos = getPos(e);
      drawShape(layer.ctx, state.tool, state.startX, state.startY, pos.x, pos.y);
      tempCtx.clearRect(0, 0, CANVAS_W, CANVAS_H);
    }

    composite();
    renderLayerPanel();
  };

  // --- Layer Panel ---
  const renderLayerPanel = () => {
    const panel = $('#layer-list');
    panel.innerHTML = '';

    for (let i = state.layers.length - 1; i >= 0; i--) {
      const layer = state.layers[i];
      const item = document.createElement('div');
      item.className = 'layer-item' + (layer.id === state.activeLayerId ? ' active' : '');
      item.onclick = () => selectLayer(layer.id);

      const thumb = document.createElement('canvas');
      thumb.width = THUMB_W;
      thumb.height = THUMB_H;
      thumb.className = 'layer-thumb';
      const tCtx = thumb.getContext('2d');
      tCtx.fillStyle = '#e0e0e0';
      tCtx.fillRect(0, 0, THUMB_W, THUMB_H);
      tCtx.drawImage(layer.canvas, 0, 0, THUMB_W, THUMB_H);
      item.appendChild(thumb);

      const name = document.createElement('span');
      name.className = 'layer-name';
      name.textContent = layer.name;
      item.appendChild(name);

      const vis = document.createElement('button');
      vis.className = 'layer-vis';
      vis.textContent = layer.visible ? '\\u{1F441}' : '\\u{2014}';
      vis.title = layer.visible ? 'Hide layer' : 'Show layer';
      vis.onclick = (ev) => { ev.stopPropagation(); toggleVisibility(layer.id); };
      item.appendChild(vis);

      const del = document.createElement('button');
      del.className = 'layer-del';
      del.textContent = '\\u00D7';
      del.title = 'Remove layer';
      del.onclick = (ev) => { ev.stopPropagation(); removeLayer(layer.id); };
      item.appendChild(del);

      panel.appendChild(item);
    }
  };

  // --- Tool Selection ---
  const setTool = (tool) => {
    state.tool = tool;
    $$('.tool-btn').forEach(btn => {
      btn.classList.toggle('active', btn.dataset.tool === tool);
    });
    display.style.cursor = tool === 'eraser'
      ? 'crosshair'
      : 'default';
  };

  // --- Save / Load ---
  const saveDrawing = async () => {
    const name = prompt('Drawing name:', 'Untitled');
    if (!name) return;

    composite();
    const dataUrl = display.toDataURL('image/png');
    const resp = await fetch('/api/save', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ name, imageData: dataUrl, width: CANVAS_W, height: CANVAS_H }),
    });
    const result = await resp.json();
    if (result.id) {
      $('#status').textContent = 'Saved: ' + result.id;
      setTimeout(() => $('#status').textContent = '', 3000);
    }
  };

  const loadDrawing = async () => {
    const resp = await fetch('/api/drawings');
    const drawings = await resp.json();
    if (drawings.length === 0) {
      alert('No saved drawings.');
      return;
    }
    const list = drawings.map((d, i) => (i + 1) + '. ' + d.name + ' (' + d.id.slice(0, 8) + ')').join('\\n');
    const choice = prompt('Enter number to load:\\n' + list);
    if (!choice) return;
    const idx = parseInt(choice, 10) - 1;
    if (idx < 0 || idx >= drawings.length) return;

    const drawingId = drawings[idx].id;
    const img = new Image();
    img.crossOrigin = 'anonymous';
    img.onload = () => {
      pushUndo();
      const layer = activeLayer();
      if (layer) {
        layer.ctx.clearRect(0, 0, CANVAS_W, CANVAS_H);
        layer.ctx.drawImage(img, 0, 0);
        composite();
        renderLayerPanel();
        $('#status').textContent = 'Loaded: ' + drawings[idx].name;
        setTimeout(() => $('#status').textContent = '', 3000);
      }
    };
    img.src = '/api/load/' + drawingId;
  };

  // --- Clear ---
  const clearCanvas = () => {
    pushUndo();
    const layer = activeLayer();
    if (layer) {
      layer.ctx.clearRect(0, 0, CANVAS_W, CANVAS_H);
    }
    composite();
    renderLayerPanel();
  };

  // --- Init ---
  const init = () => {
    // Canvas events
    display.addEventListener('pointerdown', onPointerDown);
    display.addEventListener('pointermove', onPointerMove);
    display.addEventListener('pointerup', onPointerUp);
    display.addEventListener('pointerleave', onPointerUp);

    // Tool buttons
    $$('.tool-btn').forEach(btn => {
      btn.addEventListener('click', () => setTool(btn.dataset.tool));
    });

    // Color picker
    $('#color-picker').addEventListener('input', (e) => {
      state.color = e.target.value;
    });

    // Brush size
    $('#brush-size').addEventListener('input', (e) => {
      state.brushSize = parseInt(e.target.value, 10);
      $('#brush-size-label').textContent = state.brushSize + 'px';
    });

    // History
    $('#btn-undo').addEventListener('click', undo);
    $('#btn-redo').addEventListener('click', redo);

    // Clear
    $('#btn-clear').addEventListener('click', clearCanvas);

    // Save / Load
    $('#btn-save').addEventListener('click', saveDrawing);
    $('#btn-load').addEventListener('click', loadDrawing);

    // Add layer
    $('#btn-add-layer').addEventListener('click', () => addLayer());

    // Keyboard shortcuts
    document.addEventListener('keydown', (e) => {
      if (e.ctrlKey || e.metaKey) {
        if (e.key === 'z' && !e.shiftKey) { e.preventDefault(); undo(); }
        if (e.key === 'z' && e.shiftKey) { e.preventDefault(); redo(); }
        if (e.key === 's') { e.preventDefault(); saveDrawing(); }
      }
    });

    // Create initial layer
    addLayer('Background');
    updateHistoryButtons();
  };

  init();
})();
`

