import { renderPage } from './renderer'
import { saveDrawing, loadDrawing, listDrawings, deleteDrawing } from './storage'
import type { SaveRequest } from './types'

const PORT = parseInt(process.env.PORT || '3000', 10)

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string) =>
  new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)
    const path = url.pathname

    // Serve the drawing canvas UI
    if (path === '/' && req.method === 'GET') {
      return htmlResponse(renderPage())
    }

    // List saved drawings
    if (path === '/api/drawings' && req.method === 'GET') {
      const drawings = await listDrawings()
      return jsonResponse(drawings)
    }

    // Save a drawing
    if (path === '/api/save' && req.method === 'POST') {
      const body: SaveRequest = await req.json()
      if (!body.imageData || !body.name) {
        return jsonResponse({ error: 'Missing name or imageData' }, 400)
      }
      const meta = await saveDrawing(body.name, body.imageData, body.width, body.height)
      return jsonResponse(meta)
    }

    // Load a drawing PNG
    if (path.startsWith('/api/load/') && req.method === 'GET') {
      const id = path.replace('/api/load/', '')
      const result = await loadDrawing(id)
      if (!result) return jsonResponse({ error: 'Not found' }, 404)
      return new Response(result.png, {
        headers: { 'Content-Type': 'image/png' },
      })
    }

    // Delete a drawing
    if (path.startsWith('/api/drawings/') && req.method === 'DELETE') {
      const id = path.replace('/api/drawings/', '')
      const ok = await deleteDrawing(id)
      return ok ? jsonResponse({ ok: true }) : jsonResponse({ error: 'Not found' }, 404)
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
})

