import type { Song, Playlist, StoreData, PlaybackState } from './types'

const DATA_PATH = `${import.meta.dir}/data/playlists.json`

const defaultPlayback: PlaybackState = {
  currentPlaylistId: null,
  currentSongIndex: 0,
  isPlaying: false,
  progressSec: 0,
  shuffle: false,
  repeat: 'off',
  shuffleOrder: [],
}

const generateId = (): string => crypto.randomUUID()

export const loadStore = async (): Promise<StoreData> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    return file.json() as Promise<StoreData>
  }
  return { playlists: [], playback: { ...defaultPlayback } }
}

export const saveStore = async (data: StoreData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2))
}

export const createPlaylist = async (name: string): Promise<Playlist> => {
  const store = await loadStore()
  const now = new Date().toISOString()
  const playlist: Playlist = {
    id: generateId(),
    name,
    songs: [],
    createdAt: now,
    updatedAt: now,
  }
  store.playlists.push(playlist)
  await saveStore(store)
  return playlist
}

export const deletePlaylist = async (playlistId: string): Promise<void> => {
  const store = await loadStore()
  store.playlists = store.playlists.filter((p) => p.id !== playlistId)
  if (store.playback.currentPlaylistId === playlistId) {
    store.playback = { ...defaultPlayback }
  }
  await saveStore(store)
}

export const renamePlaylist = async (playlistId: string, name: string): Promise<Playlist | null> => {
  const store = await loadStore()
  const playlist = store.playlists.find((p) => p.id === playlistId)
  if (!playlist) return null
  playlist.name = name
  playlist.updatedAt = new Date().toISOString()
  await saveStore(store)
  return playlist
}

export const addSong = async (
  playlistId: string,
  song: Omit<Song, 'id'>,
): Promise<Song | null> => {
  const store = await loadStore()
  const playlist = store.playlists.find((p) => p.id === playlistId)
  if (!playlist) return null
  const newSong: Song = { id: generateId(), ...song }
  playlist.songs.push(newSong)
  playlist.updatedAt = new Date().toISOString()
  if (store.playback.currentPlaylistId === playlistId) {
    store.playback.shuffleOrder = buildShuffleOrder(playlist.songs.length)
  }
  await saveStore(store)
  return newSong
}

export const removeSong = async (playlistId: string, songId: string): Promise<void> => {
  const store = await loadStore()
  const playlist = store.playlists.find((p) => p.id === playlistId)
  if (!playlist) return
  const idx = playlist.songs.findIndex((s) => s.id === songId)
  if (idx === -1) return
  playlist.songs.splice(idx, 1)
  playlist.updatedAt = new Date().toISOString()
  if (store.playback.currentPlaylistId === playlistId) {
    const pb = store.playback
    if (pb.currentSongIndex >= playlist.songs.length) {
      pb.currentSongIndex = Math.max(0, playlist.songs.length - 1)
    }
    pb.shuffleOrder = buildShuffleOrder(playlist.songs.length)
  }
  await saveStore(store)
}

export const reorderSong = async (
  playlistId: string,
  fromIndex: number,
  toIndex: number,
): Promise<void> => {
  const store = await loadStore()
  const playlist = store.playlists.find((p) => p.id === playlistId)
  if (!playlist) return
  if (fromIndex < 0 || fromIndex >= playlist.songs.length) return
  if (toIndex < 0 || toIndex >= playlist.songs.length) return
  const [moved] = playlist.songs.splice(fromIndex, 1)
  playlist.songs.splice(toIndex, 0, moved)
  playlist.updatedAt = new Date().toISOString()
  if (store.playback.currentPlaylistId === playlistId) {
    const pb = store.playback
    if (pb.currentSongIndex === fromIndex) {
      pb.currentSongIndex = toIndex
    } else if (fromIndex < pb.currentSongIndex && toIndex >= pb.currentSongIndex) {
      pb.currentSongIndex--
    } else if (fromIndex > pb.currentSongIndex && toIndex <= pb.currentSongIndex) {
      pb.currentSongIndex++
    }
  }
  await saveStore(store)
}

export const getPlaylist = async (playlistId: string): Promise<Playlist | null> => {
  const store = await loadStore()
  return store.playlists.find((p) => p.id === playlistId) ?? null
}

export const getAllPlaylists = async (): Promise<Playlist[]> => {
  const store = await loadStore()
  return store.playlists
}

const buildShuffleOrder = (length: number): number[] => {
  const order = Array.from({ length }, (_, i) => i)
  for (let i = order.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[order[i], order[j]] = [order[j], order[i]]
  }
  return order
}

export { buildShuffleOrder }

import type { PlaybackState, RepeatMode, Song } from './types'
import { loadStore, saveStore, buildShuffleOrder } from './store'

const resolveIndex = (pb: PlaybackState): number => {
  if (pb.shuffle && pb.shuffleOrder.length > 0) {
    return pb.shuffleOrder[pb.currentSongIndex] ?? pb.currentSongIndex
  }
  return pb.currentSongIndex
}

const getCurrentSong = async (): Promise<{ song: Song | null; playback: PlaybackState }> => {
  const store = await loadStore()
  const pb = store.playback
  if (!pb.currentPlaylistId) return { song: null, playback: pb }
  const playlist = store.playlists.find((p) => p.id === pb.currentPlaylistId)
  if (!playlist || playlist.songs.length === 0) return { song: null, playback: pb }
  const idx = resolveIndex(pb)
  return { song: playlist.songs[idx] ?? null, playback: pb }
}

const play = async (playlistId?: string, songIndex?: number): Promise<void> => {
  const store = await loadStore()
  const pb = store.playback
  if (playlistId) {
    const playlist = store.playlists.find((p) => p.id === playlistId)
    if (!playlist || playlist.songs.length === 0) return
    pb.currentPlaylistId = playlistId
    pb.currentSongIndex = songIndex ?? 0
    pb.progressSec = 0
    pb.shuffleOrder = buildShuffleOrder(playlist.songs.length)
  }
  pb.isPlaying = true
  await saveStore(store)
}

const pause = async (): Promise<void> => {
  const store = await loadStore()
  store.playback.isPlaying = false
  await saveStore(store)
}

const togglePlayPause = async (): Promise<void> => {
  const store = await loadStore()
  store.playback.isPlaying = !store.playback.isPlaying
  await saveStore(store)
}

const skip = async (): Promise<void> => {
  const store = await loadStore()
  const pb = store.playback
  if (!pb.currentPlaylistId) return
  const playlist = store.playlists.find((p) => p.id === pb.currentPlaylistId)
  if (!playlist || playlist.songs.length === 0) return

  if (pb.repeat === 'one') {
    pb.progressSec = 0
    await saveStore(store)
    return
  }

  const nextIndex = pb.currentSongIndex + 1
  if (nextIndex >= playlist.songs.length) {
    if (pb.repeat === 'all') {
      pb.currentSongIndex = 0
      if (pb.shuffle) {
        pb.shuffleOrder = buildShuffleOrder(playlist.songs.length)
      }
    } else {
      pb.isPlaying = false
      pb.currentSongIndex = 0
    }
  } else {
    pb.currentSongIndex = nextIndex
  }
  pb.progressSec = 0
  await saveStore(store)
}

const previous = async (): Promise<void> => {
  const store = await loadStore()
  const pb = store.playback
  if (!pb.currentPlaylistId) return
  const playlist = store.playlists.find((p) => p.id === pb.currentPlaylistId)
  if (!playlist || playlist.songs.length === 0) return

  if (pb.progressSec > 3) {
    pb.progressSec = 0
    await saveStore(store)
    return
  }

  if (pb.repeat === 'one') {
    pb.progressSec = 0
    await saveStore(store)
    return
  }

  const prevIndex = pb.currentSongIndex - 1
  if (prevIndex < 0) {
    if (pb.repeat === 'all') {
      pb.currentSongIndex = playlist.songs.length - 1
    } else {
      pb.progressSec = 0
    }
  } else {
    pb.currentSongIndex = prevIndex
  }
  pb.progressSec = 0
  await saveStore(store)
}

const seek = async (positionSec: number): Promise<void> => {
  const store = await loadStore()
  store.playback.progressSec = Math.max(0, positionSec)
  await saveStore(store)
}

const toggleShuffle = async (): Promise<void> => {
  const store = await loadStore()
  const pb = store.playback
  pb.shuffle = !pb.shuffle
  if (pb.shuffle && pb.currentPlaylistId) {
    const playlist = store.playlists.find((p) => p.id === pb.currentPlaylistId)
    if (playlist) {
      pb.shuffleOrder = buildShuffleOrder(playlist.songs.length)
    }
  }
  await saveStore(store)
}

const setRepeat = async (mode: RepeatMode): Promise<void> => {
  const store = await loadStore()
  store.playback.repeat = mode
  await saveStore(store)
}

const cycleRepeat = async (): Promise<RepeatMode> => {
  const store = await loadStore()
  const order: RepeatMode[] = ['off', 'all', 'one']
  const currentIdx = order.indexOf(store.playback.repeat)
  const next = order[(currentIdx + 1) % order.length]
  store.playback.repeat = next
  await saveStore(store)
  return next
}

