const getDragDropScript = (): string => `
  (function() {
    let dragSrcIndex = null;
    let dragPlaylistId = null;

    document.addEventListener('dragstart', function(e) {
      const row = e.target.closest('[draggable]');
      if (!row) return;
      dragSrcIndex = parseInt(row.dataset.index, 10);
      dragPlaylistId = row.dataset.playlistId;
      e.dataTransfer.effectAllowed = 'move';
      row.style.opacity = '0.4';
    });

    document.addEventListener('dragover', function(e) {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
      const row = e.target.closest('[draggable]');
      document.querySelectorAll('.drag-over').forEach(el => el.classList.remove('drag-over'));
      if (row) row.classList.add('drag-over');
    });

    document.addEventListener('dragend', function(e) {
      const row = e.target.closest('[draggable]');
      if (row) row.style.opacity = '1';
      document.querySelectorAll('.drag-over').forEach(el => el.classList.remove('drag-over'));
    });

    document.addEventListener('drop', function(e) {
      e.preventDefault();
      document.querySelectorAll('.drag-over').forEach(el => el.classList.remove('drag-over'));
      const row = e.target.closest('[draggable]');
      if (!row || dragSrcIndex === null) return;
      const toIndex = parseInt(row.dataset.index, 10);
      if (dragSrcIndex === toIndex) return;
      fetch('/api/reorder', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          playlistId: dragPlaylistId,
          fromIndex: dragSrcIndex,
          toIndex: toIndex,
        }),
      }).then(function() { window.location.reload(); });
    });
  })();
`

