import { createPlaylistManager } from './index'

const manager = createPlaylistManager()

const parseBody = async (req: Request): Promise<Record<string, unknown>> => {
  const text = await req.text()
  return text ? JSON.parse(text) : {}
}

const json = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const html = (body: string, status = 200): Response =>
  new Response(body, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)
    const path = url.pathname
    const method = req.method

    // Page routes
    if (method === 'GET' && path === '/') {
      const body = await manager.render()
      return html(body)
    }

    if (method === 'GET' && path.startsWith('/playlist/')) {
      const playlistId = path.slice('/playlist/'.length)
      const body = await manager.render(playlistId)
      return html(body)
    }

    // API: Playlists
    if (method === 'GET' && path === '/api/playlists') {
      const playlists = await manager.getAllPlaylists()
      return json(playlists)
    }

    if (method === 'POST' && path === '/api/playlists') {
      const { name } = await parseBody(req) as { name: string }
      if (!name) return json({ error: 'name is required' }, 400)
      const playlist = await manager.createPlaylist(name)
      return json(playlist, 201)
    }

    if (method === 'DELETE' && path.startsWith('/api/playlists/')) {
      const id = path.slice('/api/playlists/'.length)
      await manager.deletePlaylist(id)
      return json({ ok: true })
    }

    if (method === 'PATCH' && path.startsWith('/api/playlists/')) {
      const id = path.slice('/api/playlists/'.length)
      const { name } = await parseBody(req) as { name: string }
      const updated = await manager.renamePlaylist(id, name)
      return updated ? json(updated) : json({ error: 'not found' }, 404)
    }

    // API: Songs
    if (method === 'POST' && path === '/api/songs') {
      const body = await parseBody(req) as {
        playlistId: string
        title: string
        artist: string
        album: string
        durationSec: number
        albumArtUrl: string
      }
      const { playlistId, title, artist, album, durationSec, albumArtUrl } = body
      if (!playlistId || !title || !artist) {
        return json({ error: 'playlistId, title, and artist are required' }, 400)
      }
      const song = await manager.addSong(playlistId, {
        title,
        artist,
        album: album || '',
        durationSec: Number(durationSec) || 0,
        albumArtUrl: albumArtUrl || '',
      })
      return song ? json(song, 201) : json({ error: 'playlist not found' }, 404)
    }

    if (method === 'DELETE' && path === '/api/songs') {
      const { playlistId, songId } = await parseBody(req) as { playlistId: string; songId: string }
      await manager.removeSong(playlistId, songId)
      return json({ ok: true })
    }

    // API: Reorder
    if (method === 'POST' && path === '/api/reorder') {
      const { playlistId, fromIndex, toIndex } = await parseBody(req) as {
        playlistId: string
        fromIndex: number
        toIndex: number
      }
      await manager.reorderSong(playlistId, fromIndex, toIndex)
      return json({ ok: true })
    }

    // API: Playback
    if (method === 'POST' && path === '/api/playback/play') {
      const { playlistId, songIndex } = await parseBody(req) as {
        playlistId?: string
        songIndex?: number
      }
      await manager.play(playlistId, songIndex)
      return json({ ok: true })
    }

    if (method === 'POST' && path === '/api/playback/pause') {
      await manager.pause()
      return json({ ok: true })
    }

    if (method === 'POST' && path === '/api/playback/toggle') {
      await manager.togglePlayPause()
      return json({ ok: true })
    }

    if (method === 'POST' && path === '/api/playback/skip') {
      await manager.skip()
      return json({ ok: true })
    }

    if (method === 'POST' && path === '/api/playback/previous') {
      await manager.previous()
      return json({ ok: true })
    }

    if (method === 'POST' && path === '/api/playback/seek') {
      const { positionSec } = await parseBody(req) as { positionSec: number }
      await manager.seek(positionSec)
      return json({ ok: true })
    }

    if (method === 'POST' && path === '/api/playback/shuffle') {
      await manager.toggleShuffle()
      return json({ ok: true })
    }

    if (method === 'POST' && path === '/api/playback/repeat') {
      const mode = await manager.cycleRepeat()
      return json({ repeat: mode })
    }

    if (method === 'GET' && path === '/api/playback/current') {
      const current = await manager.getCurrentSong()
      return json(current)
    }

    return json({ error: 'not found' }, 404)
  },
})

