  playback: {
    currentPlaylistId: null,
    currentSongIndex: 0,
    isPlaying: false,
    shuffle: false,
    repeat: 'none',
    elapsed: 0,
    shuffleOrder: [],
  },
}

const generateId = (): string => crypto.randomUUID()

const load = async (): Promise<AppState> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    return file.json()
  }
  return { ...defaultState, playlists: [] }
}

const save = async (state: AppState): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(state, null, 2))
}

const generateShuffleOrder = (length: number): number[] => {
  const order = Array.from({ length }, (_, i) => i)
  for (let i = order.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[order[i], order[j]] = [order[j], order[i]]
  }
  return order
}

export const createPlaylist = async (name: string, description = ''): Promise<Playlist> => {
  const state = await load()
  const playlist: Playlist = {
    id: generateId(),
    name,
    description,
    songs: [],
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  }
  state.playlists.push(playlist)
  await save(state)
  return playlist
}

export const deletePlaylist = async (playlistId: string): Promise<void> => {
  const state = await load()
  state.playlists = state.playlists.filter((p) => p.id !== playlistId)
  if (state.playback.currentPlaylistId === playlistId) {
    state.playback = { ...defaultState.playback }
  }
  await save(state)
}

export const addSong = async (
  playlistId: string,
  song: Omit<Song, 'id'>,
): Promise<Song | null> => {
  const state = await load()
  const playlist = state.playlists.find((p) => p.id === playlistId)
  if (!playlist) return null
  const newSong: Song = { ...song, id: generateId() }
  playlist.songs.push(newSong)
  playlist.updatedAt = new Date().toISOString()
  if (state.playback.currentPlaylistId === playlistId && state.playback.shuffle) {
    state.playback.shuffleOrder = generateShuffleOrder(playlist.songs.length)
  }
  await save(state)
  return newSong
}

export const removeSong = async (playlistId: string, songId: string): Promise<void> => {
  const state = await load()
  const playlist = state.playlists.find((p) => p.id === playlistId)
  if (!playlist) return
  const removedIndex = playlist.songs.findIndex((s) => s.id === songId)
  playlist.songs = playlist.songs.filter((s) => s.id !== songId)
  playlist.updatedAt = new Date().toISOString()
  if (state.playback.currentPlaylistId === playlistId) {
    if (state.playback.currentSongIndex >= playlist.songs.length) {
      state.playback.currentSongIndex = Math.max(0, playlist.songs.length - 1)
    } else if (removedIndex < state.playback.currentSongIndex) {
      state.playback.currentSongIndex--
    }
    if (state.playback.shuffle) {
      state.playback.shuffleOrder = generateShuffleOrder(playlist.songs.length)
    }
  }
  await save(state)
}

export const reorderSong = async (
  playlistId: string,
  fromIndex: number,
  toIndex: number,
): Promise<void> => {
  const state = await load()
  const playlist = state.playlists.find((p) => p.id === playlistId)
  if (!playlist) return
  if (fromIndex < 0 || fromIndex >= playlist.songs.length) return
  if (toIndex < 0 || toIndex >= playlist.songs.length) return
  const [moved] = playlist.songs.splice(fromIndex, 1)
  playlist.songs.splice(toIndex, 0, moved)
  playlist.updatedAt = new Date().toISOString()
  // Update current index if the playing song moved
  if (state.playback.currentPlaylistId === playlistId) {
    const current = state.playback.currentSongIndex
    if (current === fromIndex) {
      state.playback.currentSongIndex = toIndex
    } else if (fromIndex < current && toIndex >= current) {
      state.playback.currentSongIndex--
    } else if (fromIndex > current && toIndex <= current) {
      state.playback.currentSongIndex++
    }
  }
  await save(state)
}

export const play = async (playlistId: string, songIndex = 0): Promise<void> => {
  const state = await load()
  const playlist = state.playlists.find((p) => p.id === playlistId)
  if (!playlist || playlist.songs.length === 0) return
  const needNewShuffle = state.playback.currentPlaylistId !== playlistId
  state.playback.currentPlaylistId = playlistId
  state.playback.currentSongIndex = Math.min(songIndex, playlist.songs.length - 1)
  state.playback.isPlaying = true
  state.playback.elapsed = 0
  if (state.playback.shuffle && needNewShuffle) {
    state.playback.shuffleOrder = generateShuffleOrder(playlist.songs.length)
  }
  await save(state)
}

export const pause = async (): Promise<void> => {
  const state = await load()
  state.playback.isPlaying = false
  await save(state)
}

export const resume = async (): Promise<void> => {
  const state = await load()
  state.playback.isPlaying = true
  await save(state)
}

export const skipNext = async (): Promise<void> => {
  const state = await load()
  const playlist = state.playlists.find((p) => p.id === state.playback.currentPlaylistId)
  if (!playlist || playlist.songs.length === 0) return
  const len = playlist.songs.length
  if (state.playback.repeat === 'one') {
    state.playback.elapsed = 0
    await save(state)
    return
  }
  if (state.playback.shuffle) {
    const currentShuffleIdx = state.playback.shuffleOrder.indexOf(state.playback.currentSongIndex)
    const nextShuffleIdx = currentShuffleIdx + 1
    if (nextShuffleIdx >= len) {
      if (state.playback.repeat === 'all') {
        state.playback.shuffleOrder = generateShuffleOrder(len)
        state.playback.currentSongIndex = state.playback.shuffleOrder[0]
      } else {
        state.playback.isPlaying = false
      }
    } else {
      state.playback.currentSongIndex = state.playback.shuffleOrder[nextShuffleIdx]
    }
  } else {
    const next = state.playback.currentSongIndex + 1
    if (next >= len) {
      if (state.playback.repeat === 'all') {
        state.playback.currentSongIndex = 0
      } else {
        state.playback.isPlaying = false
      }
    } else {
      state.playback.currentSongIndex = next
    }
  }
  state.playback.elapsed = 0
  await save(state)
}

export const skipPrevious = async (): Promise<void> => {
  const state = await load()
  const playlist = state.playlists.find((p) => p.id === state.playback.currentPlaylistId)
  if (!playlist || playlist.songs.length === 0) return
  // If more than 3 seconds in, restart current song
  if (state.playback.elapsed > 3) {
    state.playback.elapsed = 0
    await save(state)
    return
  }
  const len = playlist.songs.length
  if (state.playback.shuffle) {
    const currentShuffleIdx = state.playback.shuffleOrder.indexOf(state.playback.currentSongIndex)
    if (currentShuffleIdx <= 0) {
      if (state.playback.repeat === 'all') {
        state.playback.currentSongIndex = state.playback.shuffleOrder[len - 1]
      } else {
        state.playback.elapsed = 0
      }
    } else {
      state.playback.currentSongIndex = state.playback.shuffleOrder[currentShuffleIdx - 1]
    }
  } else {
    const prev = state.playback.currentSongIndex - 1
    if (prev < 0) {
      if (state.playback.repeat === 'all') {
        state.playback.currentSongIndex = len - 1
      } else {
        state.playback.elapsed = 0
      }
    } else {
      state.playback.currentSongIndex = prev
    }
  }
  state.playback.elapsed = 0
  await save(state)
}

export const seek = async (seconds: number): Promise<void> => {
  const state = await load()
  state.playback.elapsed = Math.max(0, seconds)
  await save(state)
}

export const toggleShuffle = async (): Promise<void> => {
  const state = await load()
  state.playback.shuffle = !state.playback.shuffle
  if (state.playback.shuffle) {
    const playlist = state.playlists.find((p) => p.id === state.playback.currentPlaylistId)
    if (playlist) {
      state.playback.shuffleOrder = generateShuffleOrder(playlist.songs.length)
    }
  }
  await save(state)
}

export const cycleRepeat = async (): Promise<void> => {
  const state = await load()
  const modes: RepeatMode[] = ['none', 'all', 'one']
  const idx = modes.indexOf(state.playback.repeat)
  state.playback.repeat = modes[(idx + 1) % modes.length]
  await save(state)
}

export const getState = load

export const getPlaylist = async (playlistId: string): Promise<Playlist | undefined> => {
  const state = await load()
  return state.playlists.find((p) => p.id === playlistId)
}

export const getCurrentSong = async (): Promise<Song | null> => {
  const state = await load()
  const playlist = state.playlists.find((p) => p.id === state.playback.currentPlaylistId)
  if (!playlist || playlist.songs.length === 0) return null
  return playlist.songs[state.playback.currentSongIndex] ?? null
}

