import type { Song } from './types'
import { parseDuration } from './format'
import * as store from './store'

export type HandlerContext = {
  activePlaylistId: string | null
  showCreateModal: boolean
  showAddSongModal: boolean
  rerender: () => Promise<void>
}

export const createHandlers = (ctx: HandlerContext) => ({
  'select-playlist': async (evt: { target: { dataset: { playlistId: string } } }) => {
    ctx.activePlaylistId = evt.target.dataset.playlistId
    await ctx.rerender()
  },

  'show-create-playlist': async () => {
    ctx.showCreateModal = true
    await ctx.rerender()
  },

  'show-add-song': async () => {
    ctx.showAddSongModal = true
    await ctx.rerender()
  },

  'close-modal': async () => {
    ctx.showCreateModal = false
    ctx.showAddSongModal = false
    await ctx.rerender()
  },

  'modal-overlay-click': async (evt: { target: { getAttribute: (a: string) => string | null } }) => {
    // Only close if clicking the overlay itself
    if (evt.target.getAttribute('p-target')?.includes('modal')) {
      ctx.showCreateModal = false
      ctx.showAddSongModal = false
      await ctx.rerender()
    }
  },

  'create-playlist': async (evt: { preventDefault: () => void; target: { elements: Record<string, { value: string }> } }) => {
    evt.preventDefault()
    const name = evt.target.elements['name']?.value?.trim()
    const description = evt.target.elements['description']?.value?.trim() ?? ''
    if (!name) return
    const playlist = await store.createPlaylist(name, description)
    ctx.activePlaylistId = playlist.id
    ctx.showCreateModal = false
    await ctx.rerender()
  },

  'add-song': async (evt: { preventDefault: () => void; target: { dataset: { playlistId: string }; elements: Record<string, { value: string }> } }) => {
    evt.preventDefault()
    const playlistId = evt.target.dataset.playlistId
    const title = evt.target.elements['title']?.value?.trim()
    const artist = evt.target.elements['artist']?.value?.trim()
    const album = evt.target.elements['album']?.value?.trim()
    const durationStr = evt.target.elements['duration']?.value?.trim()
    const albumArtUrl = evt.target.elements['albumArtUrl']?.value?.trim() ?? ''
    if (!title || !artist || !album || !durationStr) return
    const song: Omit<Song, 'id'> = {
      title,
      artist,
      album,
      duration: parseDuration(durationStr),
      albumArtUrl,
    }
    await store.addSong(playlistId, song)
    ctx.showAddSongModal = false
    await ctx.rerender()
  },

  'remove-song': async (evt: { target: { dataset: { playlistId: string; songId: string } } }) => {
    const { playlistId, songId } = evt.target.dataset
    await store.removeSong(playlistId, songId)
    await ctx.rerender()
  },

  'delete-playlist': async (evt: { target: { dataset: { playlistId: string } } }) => {
    const { playlistId } = evt.target.dataset
    await store.deletePlaylist(playlistId)
    if (ctx.activePlaylistId === playlistId) {
      ctx.activePlaylistId = null
    }
    await ctx.rerender()
  },

  'play-song': async (evt: { target: { dataset: { playlistId: string; songIndex: string } } }) => {
    const { playlistId, songIndex } = evt.target.dataset
    await store.play(playlistId, parseInt(songIndex, 10))
    await ctx.rerender()
  },

  'toggle-play': async () => {
    const state = await store.getState()
    if (state.playback.isPlaying) {
      await store.pause()
    } else if (state.playback.currentPlaylistId) {
      await store.resume()
    } else if (ctx.activePlaylistId) {
      await store.play(ctx.activePlaylistId, 0)
    }
    await ctx.rerender()
  },

  'skip-next': async () => {
    await store.skipNext()
    await ctx.rerender()
  },

  'skip-previous': async () => {
    await store.skipPrevious()
    await ctx.rerender()
  },

  'toggle-shuffle': async () => {
    await store.toggleShuffle()
    await ctx.rerender()
  },

  'cycle-repeat': async () => {
    await store.cycleRepeat()
    await ctx.rerender()
  },

  'seek': async (evt: { offsetX: number; target: { getBoundingClientRect: () => { width: number } } }) => {
    const state = await store.getState()
    const currentSong = await store.getCurrentSong()
    if (!currentSong) return
    const barWidth = evt.target.getBoundingClientRect().width
    const pct = evt.offsetX / barWidth
    const seekTo = pct * currentSong.duration
    await store.seek(seekTo)
    await ctx.rerender()
  },

  // Drag and drop state
  _dragFromIndex: -1 as number,

  'song-dragstart': (evt: { target: { dataset: { index: string } }; dataTransfer: { effectAllowed: string; setData: (t: string, v: string) => void } }) => {
    const handlers = createHandlers(ctx)
    handlers._dragFromIndex = parseInt(evt.target.dataset.index, 10)
    evt.dataTransfer.effectAllowed = 'move'
    evt.dataTransfer.setData('text/plain', evt.target.dataset.index)
  },

  'song-dragover': (evt: { preventDefault: () => void; dataTransfer: { dropEffect: string } }) => {
    evt.preventDefault()
    evt.dataTransfer.dropEffect = 'move'
  },

  'song-drop': async (evt: { preventDefault: () => void; target: { closest: (s: string) => { dataset: { index: string; playlistId: string } } | null }; dataTransfer: { getData: (t: string) => string } }) => {
    evt.preventDefault()
    const fromIndex = parseInt(evt.dataTransfer.getData('text/plain'), 10)
    const dropTarget = evt.target.closest('[data-index]')
    if (!dropTarget) return
    const toIndex = parseInt(dropTarget.dataset.index, 10)
    const playlistId = dropTarget.dataset.playlistId
    if (fromIndex === toIndex || !playlistId) return
    await store.reorderSong(playlistId, fromIndex, toIndex)
    await ctx.rerender()
  },

  'song-dragend': () => {
    // cleanup
  },
})

import { createSSR } from 'plaited'
import { AppShell } from './components'
import { createHandlers, type HandlerContext } from './handlers'
import * as store from './store'

export { createPlaylist, addSong, removeSong, reorderSong } from './store'
export { play, pause, resume, skipNext, skipPrevious, seek } from './store'
export { toggleShuffle, cycleRepeat, getState, getPlaylist, getCurrentSong } from './store'
export type { Song, Playlist, PlaybackState, AppState } from './types'

const ctx: HandlerContext = {
  activePlaylistId: null,
  showCreateModal: false,
  showAddSongModal: false,
  rerender: async () => {},
}

export const handlers = createHandlers(ctx)

export const render = async (): Promise<string> => {
  const state = await store.getState()
  const currentSong = await store.getCurrentSong()

  // Auto-select first playlist if none active
  if (!ctx.activePlaylistId && state.playlists.length > 0) {
    ctx.activePlaylistId = state.playlists[0].id
  }

  const ssr = createSSR()
  const tree = AppShell({
    state,
    activePlaylistId: ctx.activePlaylistId,
    currentSong,
    showCreateModal: ctx.showCreateModal,
    showAddSongModal: ctx.showAddSongModal,
  })

  return ssr(tree)
}

// Simulated playback timer — advances elapsed time each second while playing
let playbackInterval: ReturnType<typeof setInterval> | null = null

export const startPlaybackLoop = (onTick?: () => void) => {
  if (playbackInterval) return
  playbackInterval = setInterval(async () => {
    const state = await store.getState()
    if (!state.playback.isPlaying) return
    const currentSong = await store.getCurrentSong()
    if (!currentSong) return

    const newElapsed = state.playback.elapsed + 1
    if (newElapsed >= currentSong.duration) {
      await store.skipNext()
    } else {
      await store.seek(newElapsed)
    }
    onTick?.()
  }, 1000)
}

export const stopPlaybackLoop = () => {
  if (playbackInterval) {
    clearInterval(playbackInterval)
    playbackInterval = null
  }
}

// Server entry point
export const serve = () => {
  startPlaybackLoop()
  return {
    async fetch(req: Request): Promise<Response> {
      const url = new URL(req.url)

      if (url.pathname === '/' || url.pathname === '') {
        const html = await render()
        const page = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8"/>
  <meta name="viewport" content="width=device-width, initial-scale=1"/>
  <title>Playlist Manager</title>
  <style>
    *, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }
    body { overflow: hidden; }
    [style*="progress"] div:last-child { opacity: 0 !important; }
    [style*="progress"]:hover div:last-child { opacity: 1 !important; }
    [draggable="true"]:hover { background-color: #2a2a2a; }
    [draggable="true"].dragging { opacity: 0.5; }
    .drag-over { background-color: #333333; border-top: 2px solid #1db954; }
  </style>
</head>
<body>${html}</body>
<script>
  // Minimal client-side event delegation for drag-and-drop and playback
  document.addEventListener('dragstart', (e) => {
    const el = e.target.closest('[draggable]');
    if (el) { el.classList.add('dragging'); e.dataTransfer.effectAllowed = 'move'; e.dataTransfer.setData('text/plain', el.dataset.index); }
  });
  document.addEventListener('dragend', (e) => {
    const el = e.target.closest('[draggable]');
    if (el) el.classList.remove('dragging');
    document.querySelectorAll('.drag-over').forEach(el => el.classList.remove('drag-over'));
  });
  document.addEventListener('dragover', (e) => {
    const el = e.target.closest('[draggable]');
    if (el) { e.preventDefault(); e.dataTransfer.dropEffect = 'move';
      document.querySelectorAll('.drag-over').forEach(el => el.classList.remove('drag-over'));
      el.classList.add('drag-over');
    }
  });
  document.addEventListener('drop', async (e) => {
    e.preventDefault();
    const el = e.target.closest('[draggable]');
    document.querySelectorAll('.drag-over').forEach(el => el.classList.remove('drag-over'));
    if (!el) return;
    const from = parseInt(e.dataTransfer.getData('text/plain'), 10);
    const to = parseInt(el.dataset.index, 10);
    const playlistId = el.dataset.playlistId;
    if (from === to || isNaN(from) || isNaN(to)) return;
    await fetch('/api/reorder', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({playlistId, from, to}) });
    location.reload();
  });
</script>
</html>`
        return new Response(page, { headers: { 'Content-Type': 'text/html; charset=utf-8' } })
      }

      // API routes
      if (req.method === 'POST') {
        const body = await req.json()

        if (url.pathname === '/api/playlist') {
          const pl = await store.createPlaylist(body.name, body.description)
          return Response.json(pl)
        }
        if (url.pathname === '/api/playlist/delete') {
          await store.deletePlaylist(body.playlistId)
          return Response.json({ ok: true })
        }
        if (url.pathname === '/api/song') {
          const song = await store.addSong(body.playlistId, body.song)
          return Response.json(song)
        }
        if (url.pathname === '/api/song/remove') {
          await store.removeSong(body.playlistId, body.songId)
          return Response.json({ ok: true })
        }
        if (url.pathname === '/api/reorder') {
          await store.reorderSong(body.playlistId, body.from, body.to)
          return Response.json({ ok: true })
        }
        if (url.pathname === '/api/play') {
          await store.play(body.playlistId, body.songIndex ?? 0)
          return Response.json({ ok: true })
        }
        if (url.pathname === '/api/pause') {
          await store.pause()
          return Response.json({ ok: true })
        }
        if (url.pathname === '/api/resume') {
          await store.resume()
          return Response.json({ ok: true })
        }
        if (url.pathname === '/api/skip-next') {
          await store.skipNext()
          return Response.json({ ok: true })
        }
        if (url.pathname === '/api/skip-previous') {
          await store.skipPrevious()
          return Response.json({ ok: true })
        }
        if (url.pathname === '/api/seek') {
          await store.seek(body.seconds)
          return Response.json({ ok: true })
        }
        if (url.pathname === '/api/shuffle') {
          await store.toggleShuffle()
          return Response.json({ ok: true })
        }
        if (url.pathname === '/api/repeat') {
          await store.cycleRepeat()
          return Response.json({ ok: true })
        }
      }

      if (req.method === 'GET' && url.pathname === '/api/state') {
        const state = await store.getState()
        const currentSong = await store.getCurrentSong()
        return Response.json({ state, currentSong })
      }

      return new Response('Not Found', { status: 404 })
    },
    stop: () => stopPlaybackLoop(),
  }
}

