import type { Song, Playlist, PlaylistStore } from './types'

const DATA_PATH = `${import.meta.dir}/data/playlists.json`

const generateId = (prefix: string): string =>
  `${prefix}-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`

export const loadStore = async (): Promise<PlaylistStore> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return { playlists: [] }
  return file.json()
}

export const saveStore = async (store: PlaylistStore): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(store, null, 2))
}

export const getPlaylists = async (): Promise<Playlist[]> => {
  const store = await loadStore()
  return store.playlists
}

export const getPlaylist = async (id: string): Promise<Playlist | undefined> => {
  const store = await loadStore()
  return store.playlists.find((p) => p.id === id)
}

export const createPlaylist = async (name: string, description = ''): Promise<Playlist> => {
  const store = await loadStore()
  const now = new Date().toISOString()
  const playlist: Playlist = {
    id: generateId('pl'),
    name,
    description,
    songs: [],
    createdAt: now,
    updatedAt: now,
  }
  store.playlists.push(playlist)
  await saveStore(store)
  return playlist
}

export const deletePlaylist = async (id: string): Promise<boolean> => {
  const store = await loadStore()
  const idx = store.playlists.findIndex((p) => p.id === id)
  if (idx === -1) return false
  store.playlists.splice(idx, 1)
  await saveStore(store)
  return true
}

export const updatePlaylist = async (
  id: string,
  updates: Partial<Pick<Playlist, 'name' | 'description'>>
): Promise<Playlist | undefined> => {
  const store = await loadStore()
  const playlist = store.playlists.find((p) => p.id === id)
  if (!playlist) return undefined
  if (updates.name !== undefined) playlist.name = updates.name
  if (updates.description !== undefined) playlist.description = updates.description
  playlist.updatedAt = new Date().toISOString()
  await saveStore(store)
  return playlist
}

export const addSong = async (
  playlistId: string,
  song: Omit<Song, 'id'>
): Promise<Song | undefined> => {
  const store = await loadStore()
  const playlist = store.playlists.find((p) => p.id === playlistId)
  if (!playlist) return undefined
  const newSong: Song = { ...song, id: generateId('song') }
  playlist.songs.push(newSong)
  playlist.updatedAt = new Date().toISOString()
  await saveStore(store)
  return newSong
}

export const removeSong = async (playlistId: string, songId: string): Promise<boolean> => {
  const store = await loadStore()
  const playlist = store.playlists.find((p) => p.id === playlistId)
  if (!playlist) return false
  const idx = playlist.songs.findIndex((s) => s.id === songId)
  if (idx === -1) return false
  playlist.songs.splice(idx, 1)
  playlist.updatedAt = new Date().toISOString()
  await saveStore(store)
  return true
}

export const reorderSong = async (
  playlistId: string,
  fromIndex: number,
  toIndex: number
): Promise<boolean> => {
  const store = await loadStore()
  const playlist = store.playlists.find((p) => p.id === playlistId)
  if (!playlist) return false
  if (fromIndex < 0 || fromIndex >= playlist.songs.length) return false
  if (toIndex < 0 || toIndex >= playlist.songs.length) return false
  const [song] = playlist.songs.splice(fromIndex, 1)
  playlist.songs.splice(toIndex, 0, song)
  playlist.updatedAt = new Date().toISOString()
  await saveStore(store)
  return true
}

import type { PlaybackState, RepeatMode, Song, Playlist } from './types'

export const createPlaybackState = (): PlaybackState => ({
  currentPlaylistId: null,
  currentSongIndex: 0,
  isPlaying: false,
  progressSeconds: 0,
  shuffle: false,
  repeat: 'off',
  shuffleOrder: [],
})

const generateShuffleOrder = (length: number, currentIndex: number): number[] => {
  const indices = Array.from({ length }, (_, i) => i).filter((i) => i !== currentIndex)
  for (let i = indices.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[indices[i], indices[j]] = [indices[j], indices[i]]
  }
  return [currentIndex, ...indices]
}

const getEffectiveIndex = (state: PlaybackState): number => {
  if (state.shuffle && state.shuffleOrder.length > 0) {
    return state.shuffleOrder[state.currentSongIndex] ?? 0
  }
  return state.currentSongIndex
}

export const getCurrentSong = (state: PlaybackState, playlist: Playlist): Song | undefined => {
  const idx = getEffectiveIndex(state)
  return playlist.songs[idx]
}

export const play = (state: PlaybackState, playlist: Playlist): PlaybackState => {
  if (playlist.songs.length === 0) return state
  const newState = { ...state, isPlaying: true, currentPlaylistId: playlist.id }
  if (newState.shuffle && newState.shuffleOrder.length === 0) {
    newState.shuffleOrder = generateShuffleOrder(playlist.songs.length, newState.currentSongIndex)
  }
  return newState
}

export const pause = (state: PlaybackState): PlaybackState => ({
  ...state,
  isPlaying: false,
})

export const stop = (state: PlaybackState): PlaybackState => ({
  ...state,
  isPlaying: false,
  progressSeconds: 0,
})

export const skip = (state: PlaybackState, playlist: Playlist): PlaybackState => {
  if (playlist.songs.length === 0) return state
  const total = playlist.songs.length

  if (state.repeat === 'one') {
    return { ...state, progressSeconds: 0, isPlaying: true }
  }

  let nextIndex = state.currentSongIndex + 1

  if (nextIndex >= total) {
    if (state.repeat === 'all') {
      nextIndex = 0
      const newState: PlaybackState = {
        ...state,
        currentSongIndex: nextIndex,
        progressSeconds: 0,
        isPlaying: true,
      }
      if (state.shuffle) {
        newState.shuffleOrder = generateShuffleOrder(total, 0)
      }
      return newState
    }
    return { ...state, isPlaying: false, progressSeconds: 0, currentSongIndex: 0 }
  }

  return { ...state, currentSongIndex: nextIndex, progressSeconds: 0, isPlaying: true }
}

export const previous = (state: PlaybackState, playlist: Playlist): PlaybackState => {
  if (playlist.songs.length === 0) return state

  if (state.progressSeconds > 3) {
    return { ...state, progressSeconds: 0 }
  }

  const prevIndex = state.currentSongIndex - 1
  if (prevIndex < 0) {
    if (state.repeat === 'all') {
      return {
        ...state,
        currentSongIndex: playlist.songs.length - 1,
        progressSeconds: 0,
        isPlaying: true,
      }
    }
    return { ...state, progressSeconds: 0 }
  }

  return { ...state, currentSongIndex: prevIndex, progressSeconds: 0, isPlaying: true }
}

export const seekTo = (state: PlaybackState, seconds: number): PlaybackState => ({
  ...state,
  progressSeconds: Math.max(0, seconds),
})

export const toggleShuffle = (state: PlaybackState, playlistLength: number): PlaybackState => {
  const newShuffle = !state.shuffle
  return {
    ...state,
    shuffle: newShuffle,
    shuffleOrder: newShuffle
      ? generateShuffleOrder(playlistLength, state.currentSongIndex)
      : [],
  }
}

export const cycleRepeat = (state: PlaybackState): PlaybackState => {
  const modes: RepeatMode[] = ['off', 'all', 'one']
  const currentIdx = modes.indexOf(state.repeat)
  const nextMode = modes[(currentIdx + 1) % modes.length]
  return { ...state, repeat: nextMode }
}

export const selectSong = (
  state: PlaybackState,
  songIndex: number,
  playlist: Playlist
): PlaybackState => {
  if (songIndex < 0 || songIndex >= playlist.songs.length) return state
  const newState: PlaybackState = {
    ...state,
    currentPlaylistId: playlist.id,
    currentSongIndex: songIndex,
    progressSeconds: 0,
    isPlaying: true,
  }
  if (newState.shuffle) {
    newState.shuffleOrder = generateShuffleOrder(playlist.songs.length, songIndex)
  }
  return newState
}

export const updateProgress = (
  state: PlaybackState,
  deltaSeconds: number,
  playlist: Playlist
): PlaybackState => {
  if (!state.isPlaying) return state
  const currentSong = getCurrentSong(state, playlist)
  if (!currentSong) return state

  const newProgress = state.progressSeconds + deltaSeconds
  if (newProgress >= currentSong.durationSeconds) {
    return skip(state, playlist)
  }
  return { ...state, progressSeconds: newProgress }
}

