): ReturnType<typeof h> =>
  h(
    'div',
    {
      style: { ...styles.songRow, ...(isCurrentSong ? styles.songRowPlaying : styles.songRowIdle) },
      draggable: 'true',
      'data-song-index': String(index),
      'data-playlist-id': playlistId,
      'p-trigger': JSON.stringify({
        dragstart: 'song-drag-start',
        dragover: 'song-drag-over',
        drop: 'song-drop',
        click: 'song-select',
      }),
    },
    h('span', { style: styles.dragHandle }, '\u2261'),
    h('span', { style: styles.songIndex }, isCurrentSong ? '\u266B' : String(index + 1)),
    h('img', { style: styles.songArtThumb, src: song.albumArtUrl, alt: `${song.album} cover`, loading: 'lazy' }),
    h(
      'div',
      { style: styles.songInfo },
      h('div', { style: { ...styles.songTitle, ...(isCurrentSong ? { color: '#1db954' } : {}) } }, song.title),
      h('div', { style: styles.songArtist }, `${song.artist} \u2022 ${song.album}`)
    ),
    h('span', { style: styles.songDuration }, formatDuration(song.durationSeconds)),
    h(
      'button',
      {
        style: styles.removeBtn,
        'data-song-id': song.id,
        'data-playlist-id': playlistId,
