const renderNowPlaying = (
  song: Song | undefined,
  state: PlaybackState
): ReturnType<typeof h> => {
  if (!song) {
    return h(
      'div',
      { style: styles.nowPlaying },
      h(
        'div',
        { style: { ...styles.nowPlayingArt, backgroundColor: '#282828', display: 'flex', alignItems: 'center', justifyContent: 'center' } },
        h('span', { style: { fontSize: '40px', color: '#535353' } }, '\u266B')
      ),
      h(
        'div',
        { style: styles.nowPlayingInfo },
        h('div', { style: styles.nowPlayingTitle }, 'No track selected'),
        h('div', { style: styles.nowPlayingArtist }, 'Select a song to start playing')
      )
    )
  }

  const progressPercent = song.durationSeconds > 0
    ? (state.progressSeconds / song.durationSeconds) * 100
    : 0

  return h(
    'div',
    { style: styles.nowPlaying },
    h('img', {
      style: styles.nowPlayingArt,
      src: song.albumArtUrl,
      alt: `${song.album} album art`,
      'p-target': 'now-playing-art',
    }),
    h(
      'div',
      { style: styles.nowPlayingInfo },
      h('div', { style: styles.nowPlayingTitle, 'p-target': 'now-playing-title' }, song.title),
      h('div', { style: styles.nowPlayingArtist, 'p-target': 'now-playing-artist' }, song.artist),
      h('div', { style: styles.nowPlayingAlbum, 'p-target': 'now-playing-album' }, song.album),
      h(
        'div',
        { style: styles.progressContainer },
        h('span', { style: styles.progressTime }, formatDuration(state.progressSeconds)),
        h(
          'div',
          {
            style: styles.progressBar,
            'p-trigger': JSON.stringify({ click: 'progress-seek' }),
            'p-target': 'progress-bar',
          },
          h('div', {
            style: { ...styles.progressFill, width: `${progressPercent}%` },
            'p-target': 'progress-fill',
          })
        ),
        h('span', { style: styles.progressTime }, formatDuration(song.durationSeconds))
      ),
      h(
        'div',
        { style: styles.controls },
        h(
          'button',
          {
            style: { ...styles.controlBtn, ...(state.shuffle ? styles.controlBtnActive : {}) },
            'p-trigger': JSON.stringify({ click: 'toggle-shuffle' }),
            'aria-label': state.shuffle ? 'Shuffle on' : 'Shuffle off',
            title: state.shuffle ? 'Shuffle on' : 'Shuffle off',
          },
          '\u21C6'
        ),
        h(
          'button',
          {
            style: styles.controlBtn,
            'p-trigger': JSON.stringify({ click: 'playback-previous' }),
            'aria-label': 'Previous',
          },
          '\u23EE'
        ),
        h(
          'button',
          {
            style: styles.playBtn,
            'p-trigger': JSON.stringify({ click: state.isPlaying ? 'playback-pause' : 'playback-play' }),
            'aria-label': state.isPlaying ? 'Pause' : 'Play',
          },
          state.isPlaying ? '\u23F8' : '\u25B6'
        ),
        h(
          'button',
          {
            style: styles.controlBtn,
            'p-trigger': JSON.stringify({ click: 'playback-skip' }),
            'aria-label': 'Next',
          },
          '\u23ED'
        ),
        h(
          'button',
          {
            style: {
              ...styles.controlBtn,
              ...(state.repeat !== 'off' ? styles.controlBtnActive : {}),
              fontSize: '14px',
            },
            'p-trigger': JSON.stringify({ click: 'cycle-repeat' }),
            'aria-label': repeatLabel(state.repeat),
            title: repeatLabel(state.repeat),
          },
          state.repeat === 'one' ? '\u{1F502}' : '\u{1F501}'
        )
      ),
      h('audio', {
        style: styles.audioPlaceholder,
        'p-target': 'audio-element',
        preload: 'none',
      })
    )
  )
}

