const renderPlaylistContent = (
  playlist: Playlist | undefined,
  playbackState: PlaybackState,
  currentSong: Song | undefined
): ReturnType<typeof h> => {
  if (!playlist) {
    return h(
      'div',
      { style: styles.main },
      h('div', { style: styles.emptyState }, 'Select a playlist to get started')
    )
  }

  const isThisPlaylistPlaying = playbackState.currentPlaylistId === playlist.id

  return h(
    'div',
    { style: styles.main },
    renderNowPlaying(isThisPlaylistPlaying ? currentSong : undefined, playbackState),
    h(
      'div',
      { style: { marginBottom: '16px' } },
      h('h2', { style: { fontSize: '24px', fontWeight: '700', marginBottom: '4px' } }, playlist.name),
      h('p', { style: { color: '#b3b3b3', fontSize: '13px', margin: '0 0 4px 0' } }, playlist.description),
      h('span', { style: { color: '#737373', fontSize: '12px' } }, `${playlist.songs.length} songs`)
    ),
    renderAddSongForm(playlist.id),
    playlist.songs.length === 0
      ? h('div', { style: styles.emptyState }, 'This playlist is empty. Add some songs!')
      : h(
          'div',
          {
            style: { marginTop: '8px' },
            'p-target': 'song-list',
            'p-trigger': JSON.stringify({
              dragover: 'song-list-dragover',
              drop: 'song-list-drop',
            }),
          },
          ...playlist.songs.map((song, idx) =>
            renderSongRow(
              song,
              idx,
              isThisPlaylistPlaying && playbackState.currentSongIndex === idx,
              playlist.id
            )
          )
        )
  )
}

export const renderApp = (
  playlists: Playlist[],
  activePlaylist: Playlist | undefined,
  playbackState: PlaybackState,
  currentSong: Song | undefined
): ReturnType<typeof h> =>
  h(
    'div',
    { style: styles.container },
    h('div', { style: styles.header }, '\u266B Playlist Manager'),
    h(
      'div',
      { style: styles.layout },
      renderPlaylistSidebar(playlists, activePlaylist?.id ?? null),
      renderPlaylistContent(activePlaylist, playbackState, currentSong)
    )
  )

import { createSSR } from 'plaited'
import type { Playlist, PlaybackState } from './types'
import {
  loadStore,
  getPlaylists,
  getPlaylist,
  createPlaylist,
  deletePlaylist,
  updatePlaylist,
  addSong,
  removeSong,
  reorderSong,
} from './playlist'
import {
  createPlaybackState,
  getCurrentSong,
  play,
  pause,
  stop,
  skip,
  previous,
  seekTo,
  toggleShuffle,
  cycleRepeat,
  selectSong,
  updateProgress,
} from './playback'
import { renderApp } from './ui'

export type AppState = {
  playlists: Playlist[]
  activePlaylistId: string | null
  playback: PlaybackState
}

const initState = async (): Promise<AppState> => {
  const playlists = await getPlaylists()
  return {
    playlists,
    activePlaylistId: playlists[0]?.id ?? null,
    playback: createPlaybackState(),
  }
}

const getActivePlaylist = (state: AppState): Playlist | undefined =>
  state.playlists.find((p) => p.id === state.activePlaylistId)

const getPlayingPlaylist = (state: AppState): Playlist | undefined =>
  state.playlists.find((p) => p.id === state.playback.currentPlaylistId)

const render = (state: AppState): string => {
  const activePlaylist = getActivePlaylist(state)
  const playingPlaylist = getPlayingPlaylist(state)
  const currentSong = playingPlaylist
    ? getCurrentSong(state.playback, playingPlaylist)
    : undefined

  const template = renderApp(state.playlists, activePlaylist, state.playback, currentSong)
  const ssr = createSSR()
  return ssr(template)
}

type ActionResult = {
  state: AppState
  html: string
}

const handleSelectPlaylist = (state: AppState, playlistId: string): ActionResult => {
  const newState = { ...state, activePlaylistId: playlistId }
  return { state: newState, html: render(newState) }
}

const handleCreatePlaylist = async (
  state: AppState,
  name: string,
  description = ''
): Promise<ActionResult> => {
  const playlist = await createPlaylist(name, description)
  const playlists = await getPlaylists()
  const newState = { ...state, playlists, activePlaylistId: playlist.id }
  return { state: newState, html: render(newState) }
}

const handleDeletePlaylist = async (state: AppState, playlistId: string): Promise<ActionResult> => {
  await deletePlaylist(playlistId)
  const playlists = await getPlaylists()
  const newPlayback =
    state.playback.currentPlaylistId === playlistId
      ? createPlaybackState()
      : state.playback
  const newState: AppState = {
    playlists,
    activePlaylistId: playlists[0]?.id ?? null,
    playback: newPlayback,
  }
  return { state: newState, html: render(newState) }
}

const handleAddSong = async (
  state: AppState,
  playlistId: string,
  title: string,
  artist: string,
  album: string,
  durationSeconds: number,
  albumArtUrl: string
): Promise<ActionResult> => {
  await addSong(playlistId, { title, artist, album, durationSeconds, albumArtUrl })
  const playlists = await getPlaylists()
  const newState = { ...state, playlists }
  return { state: newState, html: render(newState) }
}

const handleRemoveSong = async (
  state: AppState,
  playlistId: string,
  songId: string
): Promise<ActionResult> => {
  await removeSong(playlistId, songId)
  const playlists = await getPlaylists()
