            const seconds = Math.floor(percent * song.durationSeconds)
            const result = handleSeek(state, seconds)
            state = result.state
            return jsonResponse({ html: result.html })
          }
        }
        return jsonResponse({ html: render(state) })
      }

      if (path === '/api/toggle-shuffle' && req.method === 'POST') {
        const result = handleToggleShuffle(state)
