export type Dataset = number[]

export const parseDataset = (input: string): Dataset => {
  const trimmed = input.trim()

  // Try JSON array first
  if (trimmed.startsWith('[')) {
    const parsed = JSON.parse(trimmed)
    if (!Array.isArray(parsed)) throw new Error('Input is not an array')
    return parsed.map((v: unknown) => {
      const n = Number(v)
      if (Number.isNaN(n)) throw new Error(`Non-numeric value: ${v}`)
      return n
    })
  }

  // Fall back to comma-separated values
  return trimmed
    .split(',')
    .map((s) => s.trim())
    .filter((s) => s.length > 0)
    .map((s) => {
      const n = Number(s)
      if (Number.isNaN(n)) throw new Error(`Non-numeric value: "${s}"`)
      return n
    })
}

import type { Dataset } from './parser'

export type Stats = {
  count: number
  mean: number
  median: number
  mode: number[]
  stddev: number
  variance: number
  min: number
  max: number
  range: number
  q1: number
  q3: number
  iqr: number
}

const sorted = (data: Dataset): Dataset => [...data].sort((a, b) => a - b)

const quantile = (sortedData: Dataset, p: number): number => {
  const n = sortedData.length
  const pos = (n - 1) * p
  const lo = Math.floor(pos)
  const hi = Math.ceil(pos)
  if (lo === hi) return sortedData[lo]
  return sortedData[lo] + (sortedData[hi] - sortedData[lo]) * (pos - lo)
}

export const computeStats = (data: Dataset): Stats => {
  if (data.length === 0) throw new Error('Dataset must not be empty')

  const s = sorted(data)
  const count = s.length
  const min = s[0]
  const max = s[count - 1]
  const range = max - min

  const sum = s.reduce((a, b) => a + b, 0)
  const mean = sum / count

  const median = quantile(s, 0.5)
  const q1 = quantile(s, 0.25)
  const q3 = quantile(s, 0.75)
  const iqr = q3 - q1

  // Variance (population)
  const variance = s.reduce((acc, v) => acc + (v - mean) ** 2, 0) / count
  const stddev = Math.sqrt(variance)

  // Mode — values with highest frequency
  const freq = new Map<number, number>()
  for (const v of s) {
    freq.set(v, (freq.get(v) ?? 0) + 1)
  }
  const maxFreq = Math.max(...freq.values())
  const mode = maxFreq === 1
    ? [] // no repeated values → no mode
    : [...freq.entries()].filter(([, f]) => f === maxFreq).map(([v]) => v)

  return { count, mean, median, mode, stddev, variance, min, max, range, q1, q3, iqr }
}

export const formatNumber = (n: number): string =>
  Number.isInteger(n) ? String(n) : n.toFixed(4)

import { parseDataset, type Dataset } from './parser'

const DATA_PATH = new URL('./data/datasets.json', import.meta.url).pathname

export type DatasetMap = Record<string, Dataset>

export const loadDatasets = async (): Promise<DatasetMap> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return {}
  return file.json() as Promise<DatasetMap>
}

export const saveDatasets = async (datasets: DatasetMap): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(datasets, null, 2))
}

export const addDataset = async (name: string, input: string): Promise<Dataset> => {
  const data = parseDataset(input)
  const datasets = await loadDatasets()
  datasets[name] = data
  await saveDatasets(datasets)
  return data
}

export const removeDataset = async (name: string): Promise<void> => {
  const datasets = await loadDatasets()
  delete datasets[name]
  await saveDatasets(datasets)
}

export const getDataset = async (name: string): Promise<Dataset | undefined> => {
  const datasets = await loadDatasets()
  return datasets[name]
}

