// ── Box plot (SVG) ──────────────────────────────────────────────────
const BOX_PLOT_HEIGHT = 60
const PLOT_PADDING = 40

const renderBoxPlot = (entries: { name: string; data: Dataset; stats: Stats }[], width = 600) => {
  const allMin = Math.min(...entries.map((e) => e.stats.min))
  const allMax = Math.max(...entries.map((e) => e.stats.max))
  const dataRange = allMax - allMin || 1
  const plotW = width - PLOT_PADDING * 2
  const totalH = PLOT_PADDING + entries.length * (BOX_PLOT_HEIGHT + 10) + PLOT_PADDING

  const scale = (v: number) => PLOT_PADDING + ((v - allMin) / dataRange) * plotW

  const boxes = entries.map((e, i) => {
    const y = PLOT_PADDING + i * (BOX_PLOT_HEIGHT + 10)
    const midY = y + BOX_PLOT_HEIGHT / 2
    const boxTop = y + 10
    const boxH = BOX_PLOT_HEIGHT - 20
    const color = colorFor(i)

    const whiskerMin = scale(e.stats.min)
    const whiskerMax = scale(e.stats.max)
    const boxLeft = scale(e.stats.q1)
    const boxRight = scale(e.stats.q3)
    const medianX = scale(e.stats.median)

    return h(Fragment, {},
      // label
      h('text', { x: String(PLOT_PADDING - 4), y: String(midY + 4), 'text-anchor': 'end', 'font-size': '12', fill: color }, e.name),
      // whisker line
      h('line', { x1: String(whiskerMin), y1: String(midY), x2: String(whiskerMax), y2: String(midY), stroke: color, 'stroke-width': '1.5' }),
      // whisker caps
      h('line', { x1: String(whiskerMin), y1: String(boxTop), x2: String(whiskerMin), y2: String(boxTop + boxH), stroke: color, 'stroke-width': '1.5' }),
      h('line', { x1: String(whiskerMax), y1: String(boxTop), x2: String(whiskerMax), y2: String(boxTop + boxH), stroke: color, 'stroke-width': '1.5' }),
      // box
      h('rect', { x: String(boxLeft), y: String(boxTop), width: String(boxRight - boxLeft), height: String(boxH), fill: color, opacity: '0.25', stroke: color, 'stroke-width': '1.5' }),
      // median
      h('line', { x1: String(medianX), y1: String(boxTop), x2: String(medianX), y2: String(boxTop + boxH), stroke: color, 'stroke-width': '2.5' }),
    )
  })

  // axis ticks
  const tickCount = 6
  const ticks = Array.from({ length: tickCount }, (_, i) => allMin + (dataRange * i) / (tickCount - 1))
  const axisY = totalH - PLOT_PADDING + 20
  const tickElements = ticks.map((t) =>
    h(Fragment, {},
      h('line', { x1: String(scale(t)), y1: String(axisY - 4), x2: String(scale(t)), y2: String(axisY + 4), stroke: '#666', 'stroke-width': '1' }),
      h('text', { x: String(scale(t)), y: String(axisY + 16), 'text-anchor': 'middle', 'font-size': '10', fill: '#666' }, formatNumber(t)),
    ),
  )

  return h('div', { style: { marginBottom: '24px' } },
    h('h3', { style: { margin: '0 0 8px' } }, 'Box Plot'),
    h('svg', { width: String(width), height: String(totalH), viewBox: `0 0 ${width} ${totalH}`, xmlns: 'http://www.w3.org/2000/svg', style: { background: '#fafafa', borderRadius: '6px' } },
      // axis line
      h('line', { x1: String(PLOT_PADDING), y1: String(axisY), x2: String(PLOT_PADDING + plotW), y2: String(axisY), stroke: '#ccc', 'stroke-width': '1' }),
      ...tickElements,
      ...boxes,
    ),
  )
}

// ── Histogram (SVG) ─────────────────────────────────────────────────
const renderHistogram = (entries: { name: string; data: Dataset; stats: Stats }[], width = 600, height = 300) => {
  const allValues = entries.flatMap((e) => e.data)
  const globalMin = Math.min(...allValues)
  const globalMax = Math.max(...allValues)
  const dataRange = globalMax - globalMin || 1
  const binCount = Math.max(5, Math.min(20, Math.ceil(Math.sqrt(allValues.length))))
  const binWidth = dataRange / binCount
  const plotW = width - PLOT_PADDING * 2
  const plotH = height - PLOT_PADDING * 2

  // Build bins for each dataset
  const binnedEntries = entries.map((e) => {
    const bins = new Array<number>(binCount).fill(0)
    for (const v of e.data) {
      let idx = Math.floor((v - globalMin) / binWidth)
      if (idx >= binCount) idx = binCount - 1
      bins[idx]++
    }
    return { name: e.name, bins }
  })

  const maxBinVal = Math.max(...binnedEntries.flatMap((b) => b.bins))
  const barGroupW = plotW / binCount
  const barW = barGroupW / entries.length - 2

  const bars = binnedEntries.flatMap((entry, ei) =>
    entry.bins.map((count, bi) => {
      const barH = maxBinVal === 0 ? 0 : (count / maxBinVal) * plotH
      const x = PLOT_PADDING + bi * barGroupW + ei * (barW + 2)
      const y = PLOT_PADDING + plotH - barH
      return h('rect', {
        x: String(x),
        y: String(y),
        width: String(Math.max(barW, 1)),
        height: String(barH),
        fill: colorFor(ei),
        opacity: '0.7',
      })
    }),
  )

  // X-axis ticks
  const xTicks = Array.from({ length: binCount + 1 }, (_, i) => {
    const val = globalMin + i * binWidth
    const x = PLOT_PADDING + (i / binCount) * plotW
    return h(Fragment, {},
      h('line', { x1: String(x), y1: String(PLOT_PADDING + plotH), x2: String(x), y2: String(PLOT_PADDING + plotH + 4), stroke: '#666', 'stroke-width': '1' }),
      h('text', { x: String(x), y: String(PLOT_PADDING + plotH + 16), 'text-anchor': 'middle', 'font-size': '10', fill: '#666' }, formatNumber(val)),
    )
  })

  // Y-axis ticks
  const yTickCount = 5
  const yTicks = Array.from({ length: yTickCount }, (_, i) => {
    const val = Math.round((maxBinVal * i) / (yTickCount - 1))
    const y = PLOT_PADDING + plotH - (plotH * i) / (yTickCount - 1)
    return h(Fragment, {},
      h('line', { x1: String(PLOT_PADDING - 4), y1: String(y), x2: String(PLOT_PADDING), y2: String(y), stroke: '#666', 'stroke-width': '1' }),
      h('text', { x: String(PLOT_PADDING - 8), y: String(y + 4), 'text-anchor': 'end', 'font-size': '10', fill: '#666' }, String(val)),
    )
  })

  // Legend
  const legend = entries.map((e, i) =>
    h('span', { style: { marginRight: '16px', fontSize: '12px' } },
      h('span', { style: { display: 'inline-block', width: '12px', height: '12px', backgroundColor: colorFor(i), marginRight: '4px', verticalAlign: 'middle', borderRadius: '2px' } }),
      e.name,
    ),
  )

  return h('div', { style: { marginBottom: '24px' } },
    h('h3', { style: { margin: '0 0 8px' } }, 'Histogram'),
    h('div', { style: { marginBottom: '6px' } }, ...legend),
    h('svg', { width: String(width), height: String(height), viewBox: `0 0 ${width} ${height}`, xmlns: 'http://www.w3.org/2000/svg', style: { background: '#fafafa', borderRadius: '6px' } },
      // axes
      h('line', { x1: String(PLOT_PADDING), y1: String(PLOT_PADDING), x2: String(PLOT_PADDING), y2: String(PLOT_PADDING + plotH), stroke: '#ccc', 'stroke-width': '1' }),
      h('line', { x1: String(PLOT_PADDING), y1: String(PLOT_PADDING + plotH), x2: String(PLOT_PADDING + plotW), y2: String(PLOT_PADDING + plotH), stroke: '#ccc', 'stroke-width': '1' }),
      ...yTicks,
      ...xTicks,
      ...bars,
    ),
  )
}

// ── Full dashboard ──────────────────────────────────────────────────
export const renderDashboard = (datasets: NamedDatasets): string => {
  const entries = Object.entries(datasets).map(([name, data]) => ({
    name,
    data,
    stats: computeStats(data),
  }))

  if (entries.length === 0) {
    return '<p>No datasets provided.</p>'
  }

  const dashboard = h('div', { style: { fontFamily: 'system-ui, sans-serif', maxWidth: '720px', margin: '0 auto', padding: '24px' } },
    h('h2', { style: { marginBottom: '16px' } }, 'Statistics Dashboard'),
    renderSummaryTable(entries),
    renderBoxPlot(entries),
    renderHistogram(entries),
  )

  return String(dashboard)
}

export { parseDataset, type Dataset } from './parser'
export { computeStats, formatNumber, type Stats } from './stats'
export { loadDatasets, saveDatasets, addDataset, removeDataset, getDataset, type DatasetMap } from './store'
export { renderDashboard } from './render'

import { parseDataset } from './parser'
import { computeStats } from './stats'
import { addDataset, loadDatasets, removeDataset } from './store'
import { renderDashboard } from './render'

type Command =
  | { action: 'analyze'; input: string }
  | { action: 'add'; name: string; input: string }
  | { action: 'remove'; name: string }
  | { action: 'compare' }
  | { action: 'dashboard'; datasets: Record<string, string> }

export const run = async (cmd: Command): Promise<string> => {
  switch (cmd.action) {
    case 'analyze': {
      const data = parseDataset(cmd.input)
      const stats = computeStats(data)
      return renderDashboard({ dataset: data })
    }

    case 'add': {
      await addDataset(cmd.name, cmd.input)
      const all = await loadDatasets()
      return renderDashboard(all)
    }

    case 'remove': {
      await removeDataset(cmd.name)
      const all = await loadDatasets()
      return Object.keys(all).length > 0
        ? renderDashboard(all)
        : '<p>All datasets removed.</p>'
    }

    case 'compare': {
      const all = await loadDatasets()
      if (Object.keys(all).length === 0) return '<p>No stored datasets to compare.</p>'
      return renderDashboard(all)
    }

    case 'dashboard': {
      const parsed: Record<string, number[]> = {}
      for (const [name, input] of Object.entries(cmd.datasets)) {
        parsed[name] = parseDataset(input)
      }
      return renderDashboard(parsed)
    }
  }
}

// CLI entry point
const main = async () => {
  const args = process.argv.slice(2)
  if (args.length === 0) {
    console.log('Usage:')
    console.log('  bun run index.ts analyze "1,2,3,4,5"')
    console.log('  bun run index.ts add <name> "1,2,3,4,5"')
    console.log('  bun run index.ts remove <name>')
    console.log('  bun run index.ts compare')
    process.exit(0)
  }

  const action = args[0]
  let html: string

  switch (action) {
    case 'analyze':
      html = await run({ action: 'analyze', input: args[1] ?? '' })
      break
    case 'add':
      html = await run({ action: 'add', name: args[1] ?? 'default', input: args[2] ?? '' })
      break
    case 'remove':
      html = await run({ action: 'remove', name: args[1] ?? '' })
      break
    case 'compare':
      html = await run({ action: 'compare' })
      break
    default:
      // Treat bare argument as inline analyze
      html = await run({ action: 'analyze', input: args[0] })
  }

  console.log(html)
}

main().catch((err) => {
  console.error(err)
  process.exit(1)
})

