import type { DatasetInput } from './types';

export const parseDataset = (input: DatasetInput): number[] => {
  if (Array.isArray(input)) {
    return validateNumbers(input);
  }

  const trimmed = input.trim();

  // Try JSON array first
  if (trimmed.startsWith('[')) {
    try {
      const parsed = JSON.parse(trimmed);
      if (!Array.isArray(parsed)) {
        throw new Error('JSON input must be an array');
      }
      return validateNumbers(parsed);
    } catch (e) {
      if (e instanceof SyntaxError) {
        throw new Error(`Invalid JSON array: ${e.message}`);
      }
      throw e;
    }
  }

  // Fall back to comma-separated
  const parts = trimmed.split(',').map((s) => s.trim()).filter((s) => s.length > 0);
  const numbers = parts.map((s) => {
    const n = Number(s);
    if (Number.isNaN(n)) {
      throw new Error(`Invalid number: "${s}"`);
    }
    return n;
  });

  return validateNumbers(numbers);
};

const validateNumbers = (values: unknown[]): number[] => {
  if (values.length === 0) {
    throw new Error('Dataset must contain at least one number');
  }

  return values.map((v, i) => {
    if (typeof v !== 'number' || Number.isNaN(v)) {
      throw new Error(`Invalid value at index ${i}: ${JSON.stringify(v)}`);
    }
    if (!Number.isFinite(v)) {
      throw new Error(`Non-finite value at index ${i}: ${v}`);
    }
    return v;
  });
};

import type { Statistics } from './types';

const sorted = (values: number[]): number[] => [...values].sort((a, b) => a - b);

const sum = (values: number[]): number => values.reduce((acc, v) => acc + v, 0);

export const calcMean = (values: number[]): number => sum(values) / values.length;

export const calcMedian = (values: number[]): number => {
  const s = sorted(values);
  const mid = Math.floor(s.length / 2);
  return s.length % 2 === 0 ? (s[mid - 1] + s[mid]) / 2 : s[mid];
};

export const calcMode = (values: number[]): number[] => {
  const freq = new Map<number, number>();
  for (const v of values) {
    freq.set(v, (freq.get(v) ?? 0) + 1);
  }

  let maxFreq = 0;
  for (const count of freq.values()) {
    if (count > maxFreq) maxFreq = count;
  }

  // If every value appears the same number of times, there is no mode
  if (maxFreq === 1) return [];

  const modes: number[] = [];
  for (const [value, count] of freq.entries()) {
    if (count === maxFreq) modes.push(value);
  }

  return sorted(modes);
};

export const calcVariance = (values: number[]): number => {
  const mean = calcMean(values);
  const squaredDiffs = values.map((v) => (v - mean) ** 2);
  return sum(squaredDiffs) / values.length;
};

export const calcStandardDeviation = (values: number[]): number =>
  Math.sqrt(calcVariance(values));

export const calcMin = (values: number[]): number => Math.min(...values);

export const calcMax = (values: number[]): number => Math.max(...values);

export const calcRange = (values: number[]): number => calcMax(values) - calcMin(values);

/**
 * Calculate percentile using the linear interpolation method.
 */
const percentile = (sortedValues: number[], p: number): number => {
  if (sortedValues.length === 1) return sortedValues[0];
  const index = (p / 100) * (sortedValues.length - 1);
  const lower = Math.floor(index);
  const upper = Math.ceil(index);
  if (lower === upper) return sortedValues[lower];
  const fraction = index - lower;
  return sortedValues[lower] + fraction * (sortedValues[upper] - sortedValues[lower]);
};

export const calcQ1 = (values: number[]): number => percentile(sorted(values), 25);

export const calcQ3 = (values: number[]): number => percentile(sorted(values), 75);

export const calcIQR = (values: number[]): number => calcQ3(values) - calcQ1(values);

export const calculateAll = (values: number[]): Statistics => ({
  count: values.length,
  mean: calcMean(values),
  median: calcMedian(values),
  mode: calcMode(values),
  standardDeviation: calcStandardDeviation(values),
  variance: calcVariance(values),
  min: calcMin(values),
  max: calcMax(values),
  range: calcRange(values),
  q1: calcQ1(values),
  q3: calcQ3(values),
  iqr: calcIQR(values),
});

export const round = (value: number, decimals: number = 4): number =>
  Math.round(value * 10 ** decimals) / 10 ** decimals;

import { h, Fragment } from 'plaited';
import type { NamedDataset, Statistics } from './types';
