// ── Color palette for multiple datasets ──────────────────────────
const COLORS = [
  '#4e79a7', '#f28e2b', '#e15759', '#76b7b2',
  '#59a14f', '#edc948', '#b07aa1', '#ff9da7',
];

const colorFor = (index: number): string => COLORS[index % COLORS.length];

// ── Formatting helpers ───────────────────────────────────────────
const fmt = (v: number): string => round(v).toLocaleString('en-US');
const fmtMode = (mode: number[]): string =>
  mode.length === 0 ? 'N/A' : mode.map(fmt).join(', ');

// ── Summary table ────────────────────────────────────────────────
export const renderSummaryTable = (datasets: NamedDataset[]): string => {
  const statLabels: { label: string; get: (s: Statistics) => string }[] = [
    { label: 'Count', get: (s) => String(s.count) },
    { label: 'Mean', get: (s) => fmt(s.mean) },
    { label: 'Median', get: (s) => fmt(s.median) },
    { label: 'Mode', get: (s) => fmtMode(s.mode) },
    { label: 'Std Dev', get: (s) => fmt(s.standardDeviation) },
    { label: 'Variance', get: (s) => fmt(s.variance) },
    { label: 'Min', get: (s) => fmt(s.min) },
    { label: 'Max', get: (s) => fmt(s.max) },
    { label: 'Range', get: (s) => fmt(s.range) },
    { label: 'Q1', get: (s) => fmt(s.q1) },
    { label: 'Q3', get: (s) => fmt(s.q3) },
    { label: 'IQR', get: (s) => fmt(s.iqr) },
  ];

  const tableStyle = {
    width: '100%',
    borderCollapse: 'collapse',
    fontFamily: 'system-ui, sans-serif',
    fontSize: '14px',
  };

  const thStyle = {
    padding: '8px 12px',
    borderBottom: '2px solid #333',
    textAlign: 'left',
    backgroundColor: '#f5f5f5',
  };

  const tdStyle = {
    padding: '6px 12px',
    borderBottom: '1px solid #ddd',
  };

  const headerColorStyle = (i: number) => ({
    ...thStyle,
    borderTop: `3px solid ${colorFor(i)}`,
  });

  return h(
    'table',
    { style: tableStyle },
    h(
      'thead',
      {},
      h(
        'tr',
        {},
        h('th', { style: thStyle }, 'Statistic'),
        ...datasets.map((ds, i) =>
          h('th', { style: headerColorStyle(i) }, ds.name)
        )
      )
    ),
    h(
      'tbody',
      {},
      ...statLabels.map((row, ri) =>
        h(
          'tr',
          { style: ri % 2 === 0 ? {} : { backgroundColor: '#fafafa' } },
          h('td', { style: { ...tdStyle, fontWeight: 'bold' } }, row.label),
          ...datasets.map((ds) =>
            h('td', { style: tdStyle }, row.get(ds.statistics))
          )
        )
      )
    )
  );
};

// ── Box Plot (SVG) ───────────────────────────────────────────────
export const renderBoxPlot = (datasets: NamedDataset[]): string => {
  const padding = { top: 40, right: 30, bottom: 50, left: 60 };
  const boxHeight = 40;
  const boxGap = 20;
  const chartWidth = 600;
  const chartHeight =
    padding.top +
    datasets.length * (boxHeight + boxGap) -
    boxGap +
    padding.bottom;

  // Global min/max across all datasets for a shared x-axis
  const globalMin = Math.min(...datasets.map((d) => d.statistics.min));
  const globalMax = Math.max(...datasets.map((d) => d.statistics.max));
  const dataRange = globalMax - globalMin || 1;
  const axisMin = globalMin - dataRange * 0.05;
  const axisMax = globalMax + dataRange * 0.05;
  const axisRange = axisMax - axisMin;

  const scaleX = (v: number): number =>
    padding.left + ((v - axisMin) / axisRange) * (chartWidth - padding.left - padding.right);

  // Generate ~5 tick values
  const tickCount = 5;
  const tickStep = axisRange / tickCount;
  const ticks = Array.from({ length: tickCount + 1 }, (_, i) =>
    round(axisMin + i * tickStep, 2)
  );

  const boxes = datasets.map((ds, i) => {
    const { min, q1, median, q3, max } = ds.statistics;
    const y = padding.top + i * (boxHeight + boxGap);
    const midY = y + boxHeight / 2;
    const color = colorFor(i);

    return h(
      'g',
      {},
      // Whisker line (min to max)
      h('line', {
        x1: String(scaleX(min)),
        y1: String(midY),
        x2: String(scaleX(max)),
        y2: String(midY),
        stroke: color,
        'stroke-width': '1.5',
      }),
      // Min whisker cap
      h('line', {
        x1: String(scaleX(min)),
        y1: String(y + 8),
        x2: String(scaleX(min)),
        y2: String(y + boxHeight - 8),
        stroke: color,
        'stroke-width': '1.5',
      }),
      // Max whisker cap
      h('line', {
        x1: String(scaleX(max)),
        y1: String(y + 8),
        x2: String(scaleX(max)),
        y2: String(y + boxHeight - 8),
        stroke: color,
        'stroke-width': '1.5',
      }),
      // Box (Q1 to Q3)
      h('rect', {
        x: String(scaleX(q1)),
        y: String(y),
        width: String(scaleX(q3) - scaleX(q1)),
        height: String(boxHeight),
        fill: color,
        'fill-opacity': '0.3',
        stroke: color,
        'stroke-width': '2',
        rx: '3',
      }),
      // Median line
      h('line', {
        x1: String(scaleX(median)),
        y1: String(y),
        x2: String(scaleX(median)),
        y2: String(y + boxHeight),
        stroke: color,
        'stroke-width': '2.5',
      }),
      // Dataset label
      h(
        'text',
        {
          x: String(padding.left - 8),
          y: String(midY + 4),
          'text-anchor': 'end',
          'font-size': '12',
          'font-family': 'system-ui, sans-serif',
          fill: '#333',
        },
        ds.name
      )
    );
  });

  const axisY = chartHeight - padding.bottom + 15;
  const axisElements = h(
    'g',
    {},
    // Axis line
    h('line', {
      x1: String(padding.left),
      y1: String(axisY),
      x2: String(chartWidth - padding.right),
      y2: String(axisY),
      stroke: '#666',
      'stroke-width': '1',
    }),
    // Ticks
    ...ticks.map((t) =>
      h(
        'g',
        {},
        h('line', {
          x1: String(scaleX(t)),
          y1: String(axisY),
          x2: String(scaleX(t)),
          y2: String(axisY + 5),
          stroke: '#666',
          'stroke-width': '1',
        }),
        h(
          'text',
          {
            x: String(scaleX(t)),
            y: String(axisY + 18),
            'text-anchor': 'middle',
            'font-size': '11',
            'font-family': 'system-ui, sans-serif',
            fill: '#666',
          },
          String(t)
        )
      )
    )
  );

  const title = h(
    'text',
    {
      x: String(chartWidth / 2),
      y: '20',
      'text-anchor': 'middle',
      'font-size': '16',
      'font-weight': 'bold',
      'font-family': 'system-ui, sans-serif',
      fill: '#333',
    },
    'Box Plot'
  );

  return h(
    'svg',
    {
      xmlns: 'http://www.w3.org/2000/svg',
      viewBox: `0 0 ${chartWidth} ${chartHeight}`,
      width: String(chartWidth),
      height: String(chartHeight),
      style: { backgroundColor: '#fff', borderRadius: '8px', border: '1px solid #e0e0e0' },
    },
    title,
    ...boxes,
    axisElements
  );
};

// ── Histogram (SVG) ──────────────────────────────────────────────
export const renderHistogram = (datasets: NamedDataset[], binCount: number = 10): string => {
  const padding = { top: 40, right: 30, bottom: 60, left: 50 };
  const chartWidth = 600;
  const chartHeight = 350;
  const plotWidth = chartWidth - padding.left - padding.right;
  const plotHeight = chartHeight - padding.top - padding.bottom;

  // Shared bin boundaries across all datasets
  const globalMin = Math.min(...datasets.map((d) => d.statistics.min));
  const globalMax = Math.max(...datasets.map((d) => d.statistics.max));
  const dataRange = globalMax - globalMin || 1;
  const binWidth = dataRange / binCount;

  // Compute bin counts for each dataset
  const allBins = datasets.map((ds) => {
    const bins = new Array<number>(binCount).fill(0);
    for (const v of ds.values) {
      let idx = Math.floor((v - globalMin) / binWidth);
      if (idx >= binCount) idx = binCount - 1;
      if (idx < 0) idx = 0;
      bins[idx]++;
    }
    return bins;
  });

  const maxBinCount = Math.max(...allBins.flat());
  const scaleY = (count: number): number =>
    padding.top + plotHeight - (count / (maxBinCount || 1)) * plotHeight;

  const barGroupWidth = plotWidth / binCount;
  const barWidth = barGroupWidth / datasets.length;

  const bars = datasets.flatMap((ds, di) =>
    allBins[di].map((count, bi) => {
      const x = padding.left + bi * barGroupWidth + di * barWidth;
      const y = scaleY(count);
      const height = padding.top + plotHeight - y;
      return h('rect', {
        x: String(x),
        y: String(y),
        width: String(Math.max(barWidth - 1, 1)),
        height: String(height),
        fill: colorFor(di),
        'fill-opacity': '0.7',
        stroke: colorFor(di),
        'stroke-width': '0.5',
      });
    })
  );

  // X-axis labels
  const xLabels = Array.from({ length: binCount + 1 }, (_, i) => {
    const val = round(globalMin + i * binWidth, 2);
    const x = padding.left + i * barGroupWidth;
    return h(
      'text',
      {
        x: String(x),
        y: String(chartHeight - padding.bottom + 18),
        'text-anchor': 'middle',
        'font-size': '10',
        'font-family': 'system-ui, sans-serif',
        fill: '#666',
      },
      String(val)
    );
  });

  // Y-axis labels (~5 ticks)
  const yTickCount = 5;
  const yTicks = Array.from({ length: yTickCount + 1 }, (_, i) => {
    const count = Math.round((maxBinCount / yTickCount) * i);
    return h(
      'text',
      {
        x: String(padding.left - 8),
        y: String(scaleY(count) + 4),
        'text-anchor': 'end',
        'font-size': '11',
        'font-family': 'system-ui, sans-serif',
        fill: '#666',
      },
      String(count)
    );
  });

  // Legend
  const legend = datasets.map((ds, i) =>
    h(
      'g',
      {},
      h('rect', {
        x: String(padding.left + i * 120),
        y: String(chartHeight - 15),
        width: '12',
        height: '12',
        fill: colorFor(i),
        rx: '2',
      }),
      h(
        'text',
        {
          x: String(padding.left + i * 120 + 16),
          y: String(chartHeight - 5),
          'font-size': '12',
          'font-family': 'system-ui, sans-serif',
          fill: '#333',
        },
        ds.name
      )
    )
  );

  const title = h(
    'text',
    {
      x: String(chartWidth / 2),
      y: '24',
      'text-anchor': 'middle',
      'font-size': '16',
      'font-weight': 'bold',
      'font-family': 'system-ui, sans-serif',
      fill: '#333',
    },
    'Histogram'
  );

  return h(
    'svg',
    {
      xmlns: 'http://www.w3.org/2000/svg',
      viewBox: `0 0 ${chartWidth} ${chartHeight}`,
      width: String(chartWidth),
      height: String(chartHeight),
      style: { backgroundColor: '#fff', borderRadius: '8px', border: '1px solid #e0e0e0' },
    },
    title,
    ...bars,
    ...xLabels,
    ...yTicks,
    ...legend
  );
};

