import type { DatasetStore } from './types';

const DATA_PATH = new URL('./data/datasets.json', import.meta.url).pathname;

export const loadStore = async (): Promise<DatasetStore> => {
  try {
    const file = Bun.file(DATA_PATH);
    const text = await file.text();
    return JSON.parse(text) as DatasetStore;
  } catch {
    return { datasets: {} };
  }
};

export const saveStore = async (store: DatasetStore): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(store, null, 2));
};

export const addDataset = async (name: string, values: number[]): Promise<DatasetStore> => {
  const store = await loadStore();
  store.datasets[name] = values;
  await saveStore(store);
  return store;
};

export const removeDataset = async (name: string): Promise<DatasetStore> => {
  const store = await loadStore();
  delete store.datasets[name];
  await saveStore(store);
  return store;
};

export const listDatasetNames = async (): Promise<string[]> => {
  const store = await loadStore();
  return Object.keys(store.datasets);
};

import type { DatasetInput, NamedDataset } from './types';
import { parseDataset } from './parser';
import { calculateAll } from './stats';
import { renderPage, renderSummaryTable, renderBoxPlot, renderHistogram } from './render';
import { loadStore, addDataset, removeDataset, listDatasetNames } from './store';

// ── Public API ───────────────────────────────────────────────────

/**
 * Parse input and compute all statistics for a single dataset.
 */
export const computeStatistics = (input: DatasetInput): NamedDataset => {
  const values = parseDataset(input);
  return {
    name: 'Dataset',
    values,
    statistics: calculateAll(values),
  };
};

/**
 * Parse and store a named dataset, then return its statistics.
 */
export const addNamedDataset = async (
  name: string,
  input: DatasetInput
): Promise<NamedDataset> => {
  const values = parseDataset(input);
  await addDataset(name, values);
  return {
    name,
    values,
    statistics: calculateAll(values),
  };
};

/**
 * Remove a dataset by name.
 */
export const removeNamedDataset = async (name: string): Promise<void> => {
  await removeDataset(name);
};

/**
 * Load all stored datasets and compute their statistics.
 */
export const loadAllDatasets = async (): Promise<NamedDataset[]> => {
  const store = await loadStore();
  return Object.entries(store.datasets).map(([name, values]) => ({
    name,
    values,
    statistics: calculateAll(values),
  }));
};

/**
 * Render the full statistics dashboard as an HTML string.
 */
export const renderDashboard = async (): Promise<string> => {
  const datasets = await loadAllDatasets();
  return renderPage(datasets);
};

/**
 * Render just the summary comparison table.
 */
export const renderComparisonTable = async (): Promise<string> => {
  const datasets = await loadAllDatasets();
  return renderSummaryTable(datasets);
};

/**
 * Render the box plot SVG for all stored datasets.
 */
export const renderBoxPlotSVG = async (): Promise<string> => {
  const datasets = await loadAllDatasets();
  return renderBoxPlot(datasets);
};

/**
 * Render the histogram SVG for all stored datasets.
 */
export const renderHistogramSVG = async (binCount?: number): Promise<string> => {
  const datasets = await loadAllDatasets();
  return renderHistogram(datasets, binCount);
};

// ── CLI entry point ──────────────────────────────────────────────

const main = async () => {
  const args = process.argv.slice(2);
  const command = args[0];

  if (command === 'add' && args.length >= 3) {
    const name = args[1];
    const input = args.slice(2).join(' ');
    const ds = await addNamedDataset(name, input);
    console.log(`Added dataset "${ds.name}" (${ds.statistics.count} values)`);
    console.log(JSON.stringify(ds.statistics, null, 2));
    return;
  }

  if (command === 'remove' && args[1]) {
    await removeNamedDataset(args[1]);
    console.log(`Removed dataset "${args[1]}"`);
    return;
  }

  if (command === 'list') {
    const names = await listDatasetNames();
    if (names.length === 0) {
      console.log('No datasets stored.');
    } else {
      console.log('Stored datasets:', names.join(', '));
    }
    return;
  }

  if (command === 'stats') {
    const datasets = await loadAllDatasets();
    if (datasets.length === 0) {
      console.log('No datasets. Use "add <name> <data>" first.');
      return;
    }
    for (const ds of datasets) {
      console.log(`\n── ${ds.name} ──`);
      console.log(JSON.stringify(ds.statistics, null, 2));
    }
    return;
  }

  if (command === 'render') {
    const html = await renderDashboard();
    console.log(html);
    return;
  }

  if (command === 'calc') {
    const input = args.slice(1).join(' ');
    if (!input) {
      console.log('Usage: calc <comma-separated numbers or JSON array>');
      return;
    }
    const ds = computeStatistics(input);
    console.log(JSON.stringify(ds.statistics, null, 2));
    return;
  }

  console.log(`Statistics Calculator

Usage:
  bun run index.ts add <name> <data>     Add a named dataset (CSV or JSON array)
  bun run index.ts remove <name>         Remove a dataset
  bun run index.ts list                  List stored datasets
  bun run index.ts stats                 Show statistics for all datasets
  bun run index.ts calc <data>           Calculate stats without storing
  bun run index.ts render                Render full HTML dashboard`);
};

main().catch(console.error);

