const styleStr = (obj: Record<string, string | number>): string =>
  Object.entries(obj)
    .map(([k, v]) => {
      const prop = k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)
      return `${prop}:${typeof v === 'number' ? `${v}px` : v}`
    })
    .join(';')

export const renderSummaryTable = (datasets: DatasetStats[]): string => {
  const statRows: { label: string; key: keyof DatasetStats }[] = [
    { label: 'Count', key: 'count' },
    { label: 'Mean', key: 'mean' },
    { label: 'Median', key: 'median' },
    { label: 'Mode', key: 'mode' },
    { label: 'Std Dev', key: 'standardDeviation' },
    { label: 'Variance', key: 'variance' },
    { label: 'Min', key: 'min' },
    { label: 'Max', key: 'max' },
    { label: 'Range', key: 'range' },
    { label: 'Q1', key: 'q1' },
    { label: 'Q3', key: 'q3' },
    { label: 'IQR', key: 'iqr' },
  ]

  const formatCell = (ds: DatasetStats, key: keyof DatasetStats): string => {
    const val = ds[key]
    if (key === 'mode') {
      const modeArr = val as number[]
      return modeArr.length === 0 ? 'none' : modeArr.map(fmt).join(', ')
    }
    return fmt(val as number)
  }

  const headerCells = datasets.map((ds, i) =>
    h('th', { style: `${styleStr(styles.th)};color:${COLORS[i % COLORS.length]}` }, ds.name),
  )

  const bodyRows = statRows.map((row) =>
    h(
      'tr',
      {},
      h('td', { style: `${styleStr(styles.td)};font-weight:600` }, row.label),
      ...datasets.map((ds) => h('td', { style: styleStr(styles.td) }, formatCell(ds, row.key))),
    ),
  )

  return h(
    'div',
    { style: styleStr(styles.section) },
    h('h2', { style: styleStr(styles.subheading) }, 'Summary Statistics'),
    h(
      'table',
      { style: styleStr(styles.table) },
      h('thead', {}, h('tr', {}, h('th', { style: styleStr(styles.th) }, 'Statistic'), ...headerCells)),
      h('tbody', {}, ...bodyRows),
    ),
  ).toString()
}

export const renderBoxPlot = (datasets: DatasetStats[]): string => {
  const svgWidth = 800
  const svgHeight = 60 * datasets.length + 80
  const plotLeft = 120
  const plotRight = svgWidth - 40
  const plotWidth = plotRight - plotLeft
  const rowHeight = 60

  const globalMin = Math.min(...datasets.map((d) => d.min))
  const globalMax = Math.max(...datasets.map((d) => d.max))
  const padding = (globalMax - globalMin) * 0.05 || 1
  const scaleMin = globalMin - padding
  const scaleMax = globalMax + padding

  const x = (val: number): number =>
    plotLeft + ((val - scaleMin) / (scaleMax - scaleMin)) * plotWidth

  const tickCount = 6
  const tickStep = (scaleMax - scaleMin) / (tickCount - 1)
  const ticks = Array.from({ length: tickCount }, (_, i) => scaleMin + i * tickStep)

  const tickLines = ticks.map((t) => {
    const tx = x(t)
    return h('g', {},
      h('line', { x1: String(tx), y1: '40', x2: String(tx), y2: String(svgHeight - 30), stroke: '#e2e8f0', 'stroke-width': '1' }),
      h('text', { x: String(tx), y: String(svgHeight - 10), 'text-anchor': 'middle', 'font-size': '11', fill: '#718096' }, fmt(t)),
    )
  })

  const boxes = datasets.map((ds, i) => {
    const cy = 60 + i * rowHeight
    const boxH = 28
    const color = COLORS[i % COLORS.length]
    const whiskerLow = Math.max(ds.min, ds.q1 - 1.5 * ds.iqr)
    const whiskerHigh = Math.min(ds.max, ds.q3 + 1.5 * ds.iqr)
    const outliers = ds.values.filter((v) => v < whiskerLow || v > whiskerHigh)

    return h('g', {},
      h('text', { x: String(plotLeft - 8), y: String(cy + 4), 'text-anchor': 'end', 'font-size': '13', fill: color, 'font-weight': '600' }, ds.name),
      h('line', { x1: String(x(whiskerLow)), y1: String(cy), x2: String(x(ds.q1)), y2: String(cy), stroke: color, 'stroke-width': '2' }),
      h('line', { x1: String(x(ds.q3)), y1: String(cy), x2: String(x(whiskerHigh)), y2: String(cy), stroke: color, 'stroke-width': '2' }),
      h('line', { x1: String(x(whiskerLow)), y1: String(cy - boxH / 4), x2: String(x(whiskerLow)), y2: String(cy + boxH / 4), stroke: color, 'stroke-width': '2' }),
      h('line', { x1: String(x(whiskerHigh)), y1: String(cy - boxH / 4), x2: String(x(whiskerHigh)), y2: String(cy + boxH / 4), stroke: color, 'stroke-width': '2' }),
      h('rect', {
        x: String(x(ds.q1)),
        y: String(cy - boxH / 2),
        width: String(x(ds.q3) - x(ds.q1)),
        height: String(boxH),
        fill: `${color}33`,
        stroke: color,
        'stroke-width': '2',
        rx: '3',
      }),
      h('line', { x1: String(x(ds.median)), y1: String(cy - boxH / 2), x2: String(x(ds.median)), y2: String(cy + boxH / 2), stroke: color, 'stroke-width': '3' }),
      ...outliers.map((o) =>
        h('circle', { cx: String(x(o)), cy: String(cy), r: '3', fill: 'none', stroke: color, 'stroke-width': '1.5' }),
      ),
    )
  })

  const svg = h(
    'svg',
    { xmlns: 'http://www.w3.org/2000/svg', width: String(svgWidth), height: String(svgHeight), viewBox: `0 0 ${svgWidth} ${svgHeight}` },
    h('text', { x: String(svgWidth / 2), y: '24', 'text-anchor': 'middle', 'font-size': '15', 'font-weight': '600', fill: '#2d3748' }, 'Box Plot'),
    ...tickLines,
    ...boxes,
  )

  return h('div', { style: styleStr(styles.svgContainer) }, svg).toString()
}

export const renderHistogram = (datasets: DatasetStats[]): string => {
  const binCount = 12
  const svgWidth = 800
  const svgHeight = 320
  const plotLeft = 60
  const plotRight = svgWidth - 40
  const plotTop = 40
  const plotBottom = svgHeight - 50
  const plotWidth = plotRight - plotLeft
  const plotHeight = plotBottom - plotTop

  const globalMin = Math.min(...datasets.map((d) => d.min))
  const globalMax = Math.max(...datasets.map((d) => d.max))
  const binWidth = (globalMax - globalMin) / binCount || 1

  const allBins = datasets.map((ds) => {
    const bins = Array.from({ length: binCount }, () => 0)
    for (const v of ds.values) {
      let idx = Math.floor((v - globalMin) / binWidth)
      if (idx >= binCount) idx = binCount - 1
      if (idx < 0) idx = 0
      bins[idx]++
    }
    return bins
  })

  const maxCount = Math.max(...allBins.flat(), 1)

  const x = (bin: number): number => plotLeft + (bin / binCount) * plotWidth
  const y = (count: number): number => plotBottom - (count / maxCount) * plotHeight
  const barGroupWidth = plotWidth / binCount
  const barWidth = barGroupWidth / datasets.length - 1

  const bars = datasets.flatMap((ds, di) =>
    allBins[di].map((count, bi) => {
      const bx = x(bi) + di * (barWidth + 1) + 1
      const by = y(count)
      const bh = plotBottom - by
      const color = COLORS[di % COLORS.length]
      return h('rect', {
        x: String(bx),
        y: String(by),
        width: String(Math.max(barWidth, 1)),
        height: String(Math.max(bh, 0)),
        fill: `${color}AA`,
        stroke: color,
        'stroke-width': '1',
        rx: '1',
      })
    }),
  )

  const yTickCount = 5
  const yTicks = Array.from({ length: yTickCount }, (_, i) =>
    Math.round((maxCount / (yTickCount - 1)) * i),
  )

  const xLabels = Array.from({ length: binCount + 1 }, (_, i) => {
    const val = globalMin + i * binWidth
    return h('text', {
      x: String(x(i)),
      y: String(plotBottom + 20),
      'text-anchor': 'middle',
      'font-size': '10',
      fill: '#718096',
    }, fmt(val))
  })

  const yLabels = yTicks.map((t) =>
    h('g', {},
      h('line', { x1: String(plotLeft), y1: String(y(t)), x2: String(plotRight), y2: String(y(t)), stroke: '#e2e8f0', 'stroke-width': '1' }),
      h('text', { x: String(plotLeft - 8), y: String(y(t) + 4), 'text-anchor': 'end', 'font-size': '11', fill: '#718096' }, String(t)),
    ),
  )

  const legend = datasets.map((ds, i) =>
    h('g', { transform: `translate(${plotLeft + i * 140}, ${svgHeight - 10})` },
      h('rect', { x: '0', y: '-9', width: '12', height: '12', fill: COLORS[i % COLORS.length], rx: '2' }),
      h('text', { x: '16', y: '0', 'font-size': '12', fill: '#4a5568' }, ds.name),
    ),
  )

  const svg = h(
    'svg',
    { xmlns: 'http://www.w3.org/2000/svg', width: String(svgWidth), height: String(svgHeight), viewBox: `0 0 ${svgWidth} ${svgHeight}` },
    h('text', { x: String(svgWidth / 2), y: '24', 'text-anchor': 'middle', 'font-size': '15', 'font-weight': '600', fill: '#2d3748' }, 'Histogram'),
    ...yLabels,
    ...bars,
    ...xLabels,
    h('line', { x1: String(plotLeft), y1: String(plotBottom), x2: String(plotRight), y2: String(plotBottom), stroke: '#a0aec0', 'stroke-width': '1' }),
    h('line', { x1: String(plotLeft), y1: String(plotTop), x2: String(plotLeft), y2: String(plotBottom), stroke: '#a0aec0', 'stroke-width': '1' }),
    ...legend,
  )

  return h('div', { style: styleStr(styles.svgContainer) }, svg).toString()
}

export const renderPage = (datasets: DatasetStats[]): string => {
  const inner = [
    h('h1', { style: styleStr(styles.heading) }, 'Statistics Calculator'),
    renderSummaryTable(datasets),
    renderBoxPlot(datasets),
    renderHistogram(datasets),
  ].join('')

  return `<!DOCTYPE html>
<html lang="en">
<head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Statistics Calculator</title></head>
<body style="${styleStr(styles.container)}">${inner}</body>
</html>`
}

import { calculateStats, parseInput } from './stats.ts'
import type { DatasetStats } from './stats.ts'
import { renderPage, renderSummaryTable, renderBoxPlot, renderHistogram } from './render.ts'

export type DatasetInput = {
  name: string
  data: string | number[]
}

export type CalculatorResult = {
  datasets: DatasetStats[]
  html: string
  table: string
  boxPlot: string
  histogram: string
}

const dataPath = './data/datasets.json'

const loadStoredDatasets = async (): Promise<Record<string, number[]>> => {
  const file = Bun.file(dataPath)
  if (await file.exists()) {
    return (await file.json()) as Record<string, number[]>
  }
  return {}
}

const saveDatasets = async (datasets: Record<string, number[]>): Promise<void> => {
  await Bun.write(dataPath, JSON.stringify(datasets, null, 2))
}

export const processDatasets = (inputs: DatasetInput[]): CalculatorResult => {
  const datasets = inputs.map((input) => {
    const values = typeof input.data === 'string' ? parseInput(input.data) : input.data
    return calculateStats(input.name, values)
  })

  return {
    datasets,
    html: renderPage(datasets),
    table: renderSummaryTable(datasets),
    boxPlot: renderBoxPlot(datasets),
    histogram: renderHistogram(datasets),
  }
}

export const addDataset = async (name: string, data: string | number[]): Promise<void> => {
  const stored = await loadStoredDatasets()
  stored[name] = typeof data === 'string' ? parseInput(data) : data
  await saveDatasets(stored)
}

export const removeDataset = async (name: string): Promise<boolean> => {
  const stored = await loadStoredDatasets()
  if (!(name in stored)) return false
  delete stored[name]
  await saveDatasets(stored)
  return true
}

export const listDatasets = async (): Promise<string[]> => {
  const stored = await loadStoredDatasets()
  return Object.keys(stored)
}

export const analyzeStored = async (): Promise<CalculatorResult> => {
  const stored = await loadStoredDatasets()
  const inputs: DatasetInput[] = Object.entries(stored).map(([name, data]) => ({ name, data }))
  return processDatasets(inputs)
}

export const analyzeInline = (
  ...args: Array<{ name: string; data: string | number[] }>
): CalculatorResult => processDatasets(args)

export const serve = (port = 3000) => {
  return Bun.serve({
    port,
    fetch: async (req) => {
      const url = new URL(req.url)

      if (req.method === 'POST' && url.pathname === '/api/analyze') {
        const body = (await req.json()) as { datasets: DatasetInput[] }
        const result = processDatasets(body.datasets)
        return Response.json(result.datasets)
      }

      if (req.method === 'POST' && url.pathname === '/api/dataset') {
        const body = (await req.json()) as DatasetInput
        await addDataset(body.name, body.data)
        return Response.json({ ok: true })
      }

      if (req.method === 'DELETE' && url.pathname.startsWith('/api/dataset/')) {
        const name = decodeURIComponent(url.pathname.slice('/api/dataset/'.length))
        const removed = await removeDataset(name)
        return Response.json({ removed })
      }

      if (req.method === 'GET' && url.pathname === '/api/datasets') {
        const names = await listDatasets()
        return Response.json(names)
      }

      if (req.method === 'GET' && url.pathname === '/') {
        const result = await analyzeStored()
        return new Response(result.html, {
          headers: { 'Content-Type': 'text/html; charset=utf-8' },
        })
      }

      return new Response('Not found', { status: 404 })
    },
  })
}

