import type {
  PendulumParams,
  PendulumState,
  ProjectileParams,
  ProjectileState,
  SpringParams,
  SpringState,
  SimState,
  SimParams,
  SimulationType,
  Vec2,
} from './types'

// --- Pendulum Physics ---
// Uses 4th-order Runge-Kutta integration for accuracy
// θ'' = -(g/L)sin(θ) - damping * θ'

export const createPendulumState = (params: PendulumParams): PendulumState => {
  const { length, initialAngle } = params
  return {
    type: 'pendulum',
    theta: initialAngle,
    omega: 0,
    alpha: -(params.gravity / length) * Math.sin(initialAngle),
    time: 0,
    bobPosition: {
      x: length * Math.sin(initialAngle),
      y: length * Math.cos(initialAngle),
    },
  }
}

export const stepPendulum = (
  state: PendulumState,
  params: PendulumParams,
  dt: number
): PendulumState => {
  const { length, gravity, damping } = params
  const { theta, omega } = state

  // RK4 integration
  const f = (th: number, om: number): { dTheta: number; dOmega: number } => ({
    dTheta: om,
    dOmega: -(gravity / length) * Math.sin(th) - damping * om,
  })

  const k1 = f(theta, omega)
  const k2 = f(theta + k1.dTheta * dt / 2, omega + k1.dOmega * dt / 2)
  const k3 = f(theta + k2.dTheta * dt / 2, omega + k2.dOmega * dt / 2)
  const k4 = f(theta + k3.dTheta * dt, omega + k3.dOmega * dt)

  const newTheta = theta + (dt / 6) * (k1.dTheta + 2 * k2.dTheta + 2 * k3.dTheta + k4.dTheta)
  const newOmega = omega + (dt / 6) * (k1.dOmega + 2 * k2.dOmega + 2 * k3.dOmega + k4.dOmega)
  const newAlpha = -(gravity / length) * Math.sin(newTheta) - damping * newOmega
  const newTime = state.time + dt

  return {
    type: 'pendulum',
    theta: newTheta,
    omega: newOmega,
    alpha: newAlpha,
    time: newTime,
    bobPosition: {
      x: length * Math.sin(newTheta),
      y: length * Math.cos(newTheta),
    },
  }
}

// --- Projectile Physics ---
// Kinematic equations under uniform gravity
// x(t) = v0 cos(α) t
// y(t) = v0 sin(α) t - ½gt²

export const createProjectileState = (params: ProjectileParams): ProjectileState => {
  const angleRad = (params.angle * Math.PI) / 180
  return {
    type: 'projectile',
    position: { x: 0, y: 0 },
    velocity: {
      x: params.initialVelocity * Math.cos(angleRad),
      y: params.initialVelocity * Math.sin(angleRad),
    },
    acceleration: { x: 0, y: -params.gravity },
    time: 0,
    trajectory: [{ x: 0, y: 0 }],
    landed: false,
  }
}

export const stepProjectile = (
  state: ProjectileState,
  params: ProjectileParams,
  dt: number
): ProjectileState => {
  if (state.landed) return state

  const newVx = state.velocity.x
  const newVy = state.velocity.y - params.gravity * dt

  const newX = state.position.x + state.velocity.x * dt
  const newY = state.position.y + state.velocity.y * dt - 0.5 * params.gravity * dt * dt

  const landed = newY <= 0 && state.time > 0
  const clampedY = landed ? 0 : newY

  const newPos: Vec2 = { x: newX, y: clampedY }
  const newTrajectory = [...state.trajectory, { ...newPos }]

  return {
    type: 'projectile',
    position: newPos,
    velocity: { x: landed ? 0 : newVx, y: landed ? 0 : newVy },
    acceleration: { x: 0, y: landed ? 0 : -params.gravity },
    time: state.time + dt,
    trajectory: newTrajectory,
    landed,
  }
}

// --- Spring-Mass Physics ---
// Uses RK4 integration for accuracy
// x'' = -(k/m)x - damping * x'

export const createSpringState = (params: SpringParams): SpringState => {
  const { springConstant, mass, initialDisplacement } = params
  return {
    type: 'spring',
    displacement: initialDisplacement,
    velocity: 0,
    acceleration: -(springConstant / mass) * initialDisplacement,
    time: 0,
  }
}

export const stepSpring = (
  state: SpringState,
  params: SpringParams,
  dt: number
): SpringState => {
  const { springConstant, mass, damping } = params
  const { displacement, velocity } = state

  // RK4 integration
  const f = (x: number, v: number): { dx: number; dv: number } => ({
    dx: v,
    dv: -(springConstant / mass) * x - damping * v,
  })

  const k1 = f(displacement, velocity)
  const k2 = f(displacement + k1.dx * dt / 2, velocity + k1.dv * dt / 2)
  const k3 = f(displacement + k2.dx * dt / 2, velocity + k2.dv * dt / 2)
  const k4 = f(displacement + k3.dx * dt, velocity + k3.dv * dt)

  const newDisplacement = displacement + (dt / 6) * (k1.dx + 2 * k2.dx + 2 * k3.dx + k4.dx)
  const newVelocity = velocity + (dt / 6) * (k1.dv + 2 * k2.dv + 2 * k3.dv + k4.dv)
  const newAcceleration = -(springConstant / mass) * newDisplacement - damping * newVelocity

  return {
    type: 'spring',
    displacement: newDisplacement,
    velocity: newVelocity,
    acceleration: newAcceleration,
    time: state.time + dt,
  }
}

// --- Factory helpers ---

export const createInitialState = (simType: SimulationType, params: SimParams): SimState => {
  switch (simType) {
    case 'pendulum':
      return createPendulumState(params as PendulumParams)
    case 'projectile':
      return createProjectileState(params as ProjectileParams)
    case 'spring':
      return createSpringState(params as SpringParams)
  }
}

export const stepSimulation = (
  state: SimState,
  params: SimParams,
  dt: number
): SimState => {
  switch (state.type) {
    case 'pendulum':
      return stepPendulum(state, params as PendulumParams, dt)
    case 'projectile':
      return stepProjectile(state, params as ProjectileParams, dt)
    case 'spring':
      return stepSpring(state, params as SpringParams, dt)
  }
}

// --- Analytical helpers ---

export const pendulumPeriod = (length: number, gravity: number): number =>
  2 * Math.PI * Math.sqrt(length / gravity)

export const pendulumEnergy = (
  state: PendulumState,
  params: PendulumParams
): { kinetic: number; potential: number; total: number } => {
  const { length, gravity } = params
  const mass = 1 // normalized
  const kinetic = 0.5 * mass * (length * state.omega) ** 2
  const potential = mass * gravity * length * (1 - Math.cos(state.theta))
  return { kinetic, potential, total: kinetic + potential }
}

export const projectileRange = (params: ProjectileParams): number => {
  const angleRad = (params.angle * Math.PI) / 180
  return (params.initialVelocity ** 2 * Math.sin(2 * angleRad)) / params.gravity
}

export const projectileMaxHeight = (params: ProjectileParams): number => {
  const angleRad = (params.angle * Math.PI) / 180
  return (params.initialVelocity ** 2 * Math.sin(angleRad) ** 2) / (2 * params.gravity)
}

export const springPeriod = (springConstant: number, mass: number): number =>
  2 * Math.PI * Math.sqrt(mass / springConstant)

export const springEnergy = (
  state: SpringState,
  params: SpringParams
): { kinetic: number; potential: number; total: number } => {
  const kinetic = 0.5 * params.mass * state.velocity ** 2
  const potential = 0.5 * params.springConstant * state.displacement ** 2
  return { kinetic, potential, total: kinetic + potential }
}

