// --- SVG Renderers ---

const SVG_W = 560
const SVG_H = 320

const renderPendulumSVG = (state: PendulumState, params: PendulumParams) => {
  const pivotX = SVG_W / 2
  const pivotY = 40
  const scale = 120 / params.length
  const bobX = pivotX + state.bobPosition.x * scale
  const bobY = pivotY + state.bobPosition.y * scale

  // Trail arc
  const arcRadius = params.length * scale
  const arcStartAngle = -Math.PI / 2 - params.initialAngle
  const arcEndAngle = -Math.PI / 2 + params.initialAngle
  const arcX1 = pivotX + arcRadius * Math.cos(arcStartAngle)
  const arcY1 = pivotY - arcRadius * Math.sin(arcStartAngle)
  const arcX2 = pivotX + arcRadius * Math.cos(arcEndAngle)
  const arcY2 = pivotY - arcRadius * Math.sin(arcEndAngle)

  return h('svg', {
    width: String(SVG_W),
    height: String(SVG_H),
    viewBox: `0 0 ${SVG_W} ${SVG_H}`,
    style: styles.canvas,
  },
    // Background grid
    ...renderGrid(),
    // Arc path
    h('path', {
      d: `M ${arcX1} ${arcY1} A ${arcRadius} ${arcRadius} 0 0 1 ${arcX2} ${arcY2}`,
      fill: 'none',
      stroke: '#c7d2fe',
      'stroke-width': '1.5',
      'stroke-dasharray': '4,4',
    }),
    // Pivot mount
    h('rect', { x: String(pivotX - 30), y: '0', width: '60', height: '8', rx: '2', fill: '#9ca3af' }),
    // Rod
    h('line', {
      x1: String(pivotX),
      y1: String(pivotY),
      x2: String(bobX),
      y2: String(bobY),
      stroke: '#374151',
      'stroke-width': '2.5',
      'stroke-linecap': 'round',
    }),
    // Pivot point
    h('circle', { cx: String(pivotX), cy: String(pivotY), r: '5', fill: '#6b7280' }),
    // Bob
    h('circle', { cx: String(bobX), cy: String(bobY), r: '18', fill: '#4f46e5', stroke: '#3730a3', 'stroke-width': '2' }),
    // Velocity arrow
    ...renderVelocityArrow(bobX, bobY, state.omega * params.length * scale * 0.3, state.theta),
    // Time label
    h('text', { x: '16', y: String(SVG_H - 12), 'font-size': '12', fill: '#9ca3af' }, `t = ${fmt(state.time)}s`),
  )
}

const renderProjectileSVG = (state: ProjectileState, params: ProjectileParams) => {
  const range = projectileRange(params)
  const maxH = projectileMaxHeight(params)
  const scaleX = (SVG_W - 80) / Math.max(range, 1)
  const scaleY = (SVG_H - 80) / Math.max(maxH, 1)
  const scale = Math.min(scaleX, scaleY)
  const originX = 40
  const originY = SVG_H - 40

  const toScreen = (p: { x: number; y: number }) => ({
    x: originX + p.x * scale,
    y: originY - p.y * scale,
  })

  const trajectoryPoints = state.trajectory
    .map(toScreen)
    .map((p) => `${p.x},${p.y}`)
    .join(' ')

  const currentPos = toScreen(state.position)

  // Axis ticks
  const xTicks = generateTicks(0, range, 5)
  const yTicks = generateTicks(0, maxH, 4)

  return h('svg', {
    width: String(SVG_W),
    height: String(SVG_H),
    viewBox: `0 0 ${SVG_W} ${SVG_H}`,
    style: styles.canvas,
  },
    ...renderGrid(),
    // Ground line
    h('line', { x1: String(originX), y1: String(originY), x2: String(SVG_W - 20), y2: String(originY), stroke: '#9ca3af', 'stroke-width': '1.5' }),
    // Y axis
    h('line', { x1: String(originX), y1: '20', x2: String(originX), y2: String(originY), stroke: '#9ca3af', 'stroke-width': '1.5' }),
    // Axis labels
    h('text', { x: String(SVG_W / 2), y: String(SVG_H - 8), 'font-size': '11', fill: '#9ca3af', 'text-anchor': 'middle' }, 'Distance (m)'),
    h('text', { x: '12', y: String(SVG_H / 2), 'font-size': '11', fill: '#9ca3af', 'text-anchor': 'middle', transform: `rotate(-90, 12, ${SVG_H / 2})` }, 'Height (m)'),
    // X-axis ticks
    ...xTicks.map((v) => {
      const sx = originX + v * scale
      return h(Fragment, {},
        h('line', { x1: String(sx), y1: String(originY), x2: String(sx), y2: String(originY + 5), stroke: '#9ca3af', 'stroke-width': '1' }),
        h('text', { x: String(sx), y: String(originY + 16), 'font-size': '10', fill: '#9ca3af', 'text-anchor': 'middle' }, fmt(v, 0)),
      )
    }),
    // Y-axis ticks
    ...yTicks.map((v) => {
      const sy = originY - v * scale
      return h(Fragment, {},
        h('line', { x1: String(originX - 5), y1: String(sy), x2: String(originX), y2: String(sy), stroke: '#9ca3af', 'stroke-width': '1' }),
        h('text', { x: String(originX - 8), y: String(sy + 4), 'font-size': '10', fill: '#9ca3af', 'text-anchor': 'end' }, fmt(v, 0)),
      )
    }),
    // Trajectory path
    state.trajectory.length > 1
      ? h('polyline', { points: trajectoryPoints, fill: 'none', stroke: '#818cf8', 'stroke-width': '2', 'stroke-linecap': 'round' })
      : null,
    // Current position
    h('circle', { cx: String(currentPos.x), cy: String(currentPos.y), r: '8', fill: '#4f46e5', stroke: '#3730a3', 'stroke-width': '2' }),
    // Launcher
    (() => {
      const launchAngleRad = (params.angle * Math.PI) / 180
      const launchLen = 30
      return h('line', {
        x1: String(originX),
        y1: String(originY),
        x2: String(originX + launchLen * Math.cos(launchAngleRad)),
        y2: String(originY - launchLen * Math.sin(launchAngleRad)),
        stroke: '#374151',
        'stroke-width': '3',
        'stroke-linecap': 'round',
      })
    })(),
    // Time label
    h('text', { x: String(SVG_W - 16), y: String(SVG_H - 12), 'font-size': '12', fill: '#9ca3af', 'text-anchor': 'end' }, `t = ${fmt(state.time)}s`),
  )
}

const renderSpringSVG = (state: SpringState, params: SpringParams) => {
