    h('line', { x1: String(eqX), y1: String(centerY - 60), x2: String(eqX), y2: String(centerY + 60), stroke: '#c7d2fe', 'stroke-width': '1', 'stroke-dasharray': '6,4' }),
    h('text', { x: String(eqX), y: String(centerY - 68), 'font-size': '10', fill: '#a5b4fc', 'text-anchor': 'middle' }, 'x = 0'),
    // Spring coil
    h('polyline', {
