const renderGrid = () => {
  const lines = []
  for (let x = 0; x <= SVG_W; x += 40) {
    lines.push(h('line', { x1: String(x), y1: '0', x2: String(x), y2: String(SVG_H), stroke: '#f3f4f6', 'stroke-width': '1' }))
  }
  for (let y = 0; y <= SVG_H; y += 40) {
    lines.push(h('line', { x1: '0', y1: String(y), x2: String(SVG_W), y2: String(y), stroke: '#f3f4f6', 'stroke-width': '1' }))
  }
  return lines
}

const renderVelocityArrow = (cx: number, cy: number, magnitude: number, theta: number) => {
  if (Math.abs(magnitude) < 0.5) return []
  const perpAngle = theta + Math.PI / 2
  const tipX = cx + magnitude * Math.cos(perpAngle)
  const tipY = cy - magnitude * Math.sin(perpAngle)
  return [
    h('line', {
      x1: String(cx),
      y1: String(cy),
      x2: String(tipX),
      y2: String(tipY),
      stroke: '#22c55e',
      'stroke-width': '2',
      'marker-end': 'url(#arrowGreen)',
    }),
    h('defs', {},
      h('marker', { id: 'arrowGreen', markerWidth: '8', markerHeight: '6', refX: '8', refY: '3', orient: 'auto' },
        h('path', { d: 'M0,0 L8,3 L0,6 Z', fill: '#22c55e' }),
      ),
    ),
  ]
}

const generateSpringPath = (x1: number, y1: number, x2: number, _y2: number, coils: number): string => {
  const dx = x2 - x1
  const segLen = dx / (coils * 2 + 2)
  const amplitude = 14
  const points: string[] = [`${x1},${y1}`]
  // Lead-in segment
  points.push(`${x1 + segLen},${y1}`)
  for (let i = 0; i < coils * 2; i++) {
    const px = x1 + segLen + segLen * (i + 0.5)
    const py = y1 + (i % 2 === 0 ? -amplitude : amplitude)
    points.push(`${px},${py}`)
  }
  // Lead-out
  points.push(`${x2 - segLen},${y1}`)
  points.push(`${x2},${y1}`)
  return points.join(' ')
}

const generateTicks = (min: number, max: number, count: number): number[] => {
  const step = (max - min) / count
  const ticks: number[] = []
  for (let i = 1; i <= count; i++) {
    ticks.push(min + step * i)
  }
  return ticks
}

