  )
}

import { createSSR } from 'plaited'
import {
  createInitialState,
  stepSimulation,
  pendulumPeriod,
  projectileRange,
  projectileMaxHeight,
  springPeriod,
  springEnergy,
  pendulumEnergy,
} from './physics'
import { renderSimulation } from './renderer'
import type {
  SimulationType,
  SimState,
  SimParams,
  PendulumParams,
  ProjectileParams,
  SpringParams,
  PlaybackState,
  SimulatorConfig,
} from './types'

// --- Simulator class ---

export type Simulator = {
  getState: () => SimState
  getParams: () => SimParams
  getPlaybackState: () => PlaybackState
  getSpeed: () => number
  getActiveTab: () => SimulationType
  play: () => void
  pause: () => void
  reset: () => void
  setSpeed: (speed: number) => void
  setSimType: (simType: SimulationType) => void
  updateParams: (updates: Partial<SimParams>) => void
  tick: () => SimState
  render: () => string
}

const defaultParams: Record<SimulationType, SimParams> = {
  pendulum: {
    length: 1.5,
    gravity: 9.81,
    initialAngle: 0.785,
    damping: 0,
  } as PendulumParams,
  projectile: {
    angle: 45,
    initialVelocity: 20,
    gravity: 9.81,
  } as ProjectileParams,
  spring: {
    springConstant: 10,
    mass: 1.0,
    initialDisplacement: 1.0,
    damping: 0,
  } as SpringParams,
}

export const createSimulator = (
  initialType: SimulationType = 'pendulum',
  initialParams?: Partial<SimParams>,
  config?: Partial<SimulatorConfig>,
): Simulator => {
  const dt = config?.dt ?? 0.016
  let speed = config?.speed ?? 1.0
  let activeTab: SimulationType = initialType
  let playbackState: PlaybackState = 'stopped'

  let params: SimParams = {
    ...defaultParams[initialType],
    ...(initialParams ?? {}),
  }
  let state: SimState = createInitialState(initialType, params)

  const getState = (): SimState => state
  const getParams = (): SimParams => params
  const getPlaybackState = (): PlaybackState => playbackState
  const getSpeed = (): number => speed
  const getActiveTab = (): SimulationType => activeTab

  const play = () => {
    playbackState = 'playing'
  }

  const pause = () => {
    playbackState = 'paused'
  }

  const reset = () => {
    playbackState = 'stopped'
    state = createInitialState(activeTab, params)
  }

  const setSpeed = (newSpeed: number) => {
    speed = Math.max(0.25, Math.min(4, newSpeed))
  }

  const setSimType = (simType: SimulationType) => {
    activeTab = simType
    params = { ...defaultParams[simType] }
    state = createInitialState(simType, params)
    playbackState = 'stopped'
  }

  const updateParams = (updates: Partial<SimParams>) => {
    params = { ...params, ...updates }
    state = createInitialState(activeTab, params)
    playbackState = 'stopped'
  }

  const tick = (): SimState => {
    if (playbackState !== 'playing') return state
    const scaledDt = dt * speed
    state = stepSimulation(state, params, scaledDt)
    return state
  }

  const render = (): string => {
    const template = renderSimulation(state, params, playbackState, speed, activeTab)
    const ssr = createSSR()
    return ssr(template)
  }

  return {
    getState,
    getParams,
    getPlaybackState,
    getSpeed,
    getActiveTab,
    play,
    pause,
    reset,
    setSpeed,
    setSimType,
    updateParams,
    tick,
    render,
  }
}

// --- Server entry point ---

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const simType = (url.searchParams.get('sim') ?? 'pendulum') as SimulationType
  const validTypes: SimulationType[] = ['pendulum', 'projectile', 'spring']
  const safeSimType = validTypes.includes(simType) ? simType : 'pendulum'

  if (url.pathname === '/api/state') {
    return handleAPIState(req, safeSimType)
  }

  if (url.pathname === '/api/tick') {
    return handleAPITick(req)
  }

  const sim = createSimulator(safeSimType)
  const html = renderFullPage(sim)

  return new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

const handleAPIState = async (_req: Request, simType: SimulationType): Promise<Response> => {
  const sim = createSimulator(simType)
  return Response.json({
    state: sim.getState(),
    params: sim.getParams(),
    playbackState: sim.getPlaybackState(),
    speed: sim.getSpeed(),
    activeTab: sim.getActiveTab(),
  })
}

const handleAPITick = async (req: Request): Promise<Response> => {
  const body = await req.json() as {
    simType: SimulationType
    state: SimState
    params: SimParams
    speed: number
  }

  const sim = createSimulator(body.simType, body.params)
  // Restore the state from the client
  sim.play()
  const newState = stepSimulation(body.state, body.params, 0.016 * body.speed)

  return Response.json({ state: newState })
}

