const getClientScript = (): string => `
(function() {
  // --- Client-side simulation engine ---
  const defaultParams = {
    pendulum: { length: 1.5, gravity: 9.81, initialAngle: 0.785, damping: 0 },
    projectile: { angle: 45, initialVelocity: 20, gravity: 9.81 },
    spring: { springConstant: 10, mass: 1.0, initialDisplacement: 1.0, damping: 0 },
  };

  let activeTab = 'pendulum';
  let params = { ...defaultParams[activeTab] };
  let playbackState = 'stopped';
  let speed = 1.0;
  let state = null;
  let animFrameId = null;

  // --- Physics (client mirror) ---
  const createState = (type, p) => {
    if (type === 'pendulum') {
      return {
        type: 'pendulum', theta: p.initialAngle, omega: 0,
        alpha: -(p.gravity / p.length) * Math.sin(p.initialAngle), time: 0,
        bobPosition: { x: p.length * Math.sin(p.initialAngle), y: p.length * Math.cos(p.initialAngle) }
      };
    }
    if (type === 'projectile') {
      const ar = p.angle * Math.PI / 180;
      return {
        type: 'projectile', position: {x:0,y:0},
        velocity: { x: p.initialVelocity * Math.cos(ar), y: p.initialVelocity * Math.sin(ar) },
        acceleration: {x:0, y:-p.gravity}, time: 0, trajectory: [{x:0,y:0}], landed: false
      };
    }
    return {
      type: 'spring', displacement: p.initialDisplacement, velocity: 0,
      acceleration: -(p.springConstant / p.mass) * p.initialDisplacement, time: 0
    };
  };

  const stepState = (s, p, dt) => {
    if (s.type === 'pendulum') {
      const f = (th, om) => ({ dT: om, dO: -(p.gravity/p.length)*Math.sin(th) - p.damping*om });
      const k1 = f(s.theta, s.omega);
      const k2 = f(s.theta+k1.dT*dt/2, s.omega+k1.dO*dt/2);
      const k3 = f(s.theta+k2.dT*dt/2, s.omega+k2.dO*dt/2);
      const k4 = f(s.theta+k3.dT*dt, s.omega+k3.dO*dt);
      const nT = s.theta + (dt/6)*(k1.dT+2*k2.dT+2*k3.dT+k4.dT);
      const nO = s.omega + (dt/6)*(k1.dO+2*k2.dO+2*k3.dO+k4.dO);
      return {
        type:'pendulum', theta:nT, omega:nO,
        alpha: -(p.gravity/p.length)*Math.sin(nT) - p.damping*nO,
        time: s.time+dt,
        bobPosition: { x: p.length*Math.sin(nT), y: p.length*Math.cos(nT) }
      };
    }
    if (s.type === 'projectile') {
      if (s.landed) return s;
      const nvx = s.velocity.x;
      const nvy = s.velocity.y - p.gravity*dt;
      const nx = s.position.x + s.velocity.x*dt;
      let ny = s.position.y + s.velocity.y*dt - 0.5*p.gravity*dt*dt;
      const landed = ny <= 0 && s.time > 0;
      if (landed) ny = 0;
      const np = {x:nx, y:ny};
      return {
        type:'projectile', position:np,
        velocity: landed ? {x:0,y:0} : {x:nvx,y:nvy},
        acceleration: landed ? {x:0,y:0} : {x:0,y:-p.gravity},
        time: s.time+dt, trajectory: [...s.trajectory, {...np}], landed
      };
    }
    // spring
    const fS = (x,v) => ({ dx:v, dv: -(p.springConstant/p.mass)*x - p.damping*v });
    const k1 = fS(s.displacement, s.velocity);
    const k2 = fS(s.displacement+k1.dx*dt/2, s.velocity+k1.dv*dt/2);
    const k3 = fS(s.displacement+k2.dx*dt/2, s.velocity+k2.dv*dt/2);
    const k4 = fS(s.displacement+k3.dx*dt, s.velocity+k3.dv*dt);
    const nd = s.displacement + (dt/6)*(k1.dx+2*k2.dx+2*k3.dx+k4.dx);
    const nv = s.velocity + (dt/6)*(k1.dv+2*k2.dv+2*k3.dv+k4.dv);
    return {
      type:'spring', displacement:nd, velocity:nv,
      acceleration: -(p.springConstant/p.mass)*nd - p.damping*nv,
      time: s.time+dt
    };
  };

  // --- Initialize ---
  state = createState(activeTab, params);

  // --- Re-render helper (fetches from server) ---
  const rerender = async () => {
    try {
      const resp = await fetch('/?sim=' + activeTab);
      const html = await resp.text();
      const parser = new DOMParser();
      const doc = parser.parseFromString(html, 'text/html');
      const newApp = doc.getElementById('app');
      if (newApp) {
        document.getElementById('app').innerHTML = newApp.innerHTML;
        bindEvents();
      }
    } catch(e) {
      // Server-side re-render failed, use local update
      updateDisplay();
    }
  };

  // --- Local display update (DOM manipulation) ---
  const fmt = (n, d=2) => n.toFixed(d);

  const updateDisplay = () => {
    // Update readout values
    const cards = document.querySelectorAll('[style*="readout"]');
    // We'll do a full server re-render for simplicity
  };

  // --- Animation loop ---
  const loop = () => {
    if (playbackState === 'playing') {
      const dt = 0.016 * speed;
      // Take multiple substeps for stability at high speed
      const steps = Math.max(1, Math.round(speed));
      const subDt = dt / steps;
      for (let i = 0; i < steps; i++) {
        state = stepState(state, params, subDt);
      }
      // Auto-pause if projectile landed
      if (state.type === 'projectile' && state.landed) {
        playbackState = 'paused';
      }
      rerender();
    }
    animFrameId = requestAnimationFrame(loop);
  };

  // --- Event binding ---
  const bindEvents = () => {
    document.querySelectorAll('[p-trigger]').forEach(el => {
      const trigger = el.getAttribute('p-trigger');
      const parts = trigger.split(':');
      const eventType = parts[0];
      const action = parts[1];
      const arg = parts[2];

      el.addEventListener(eventType, (e) => {
        handleAction(action, arg, e);
      }, { once: false });
    });
  };

  const handleAction = (action, arg, event) => {
    switch(action) {
      case 'play':
        playbackState = 'playing';
        rerender();
        break;
      case 'pause':
        playbackState = 'paused';
        rerender();
        break;
      case 'reset':
        playbackState = 'stopped';
        state = createState(activeTab, params);
        rerender();
        break;
      case 'setSpeed':
        speed = parseFloat(event.target.value);
        rerender();
        break;
      case 'selectTab':
        activeTab = arg;
        params = { ...defaultParams[arg] };
        state = createState(arg, params);
        playbackState = 'stopped';
        rerender();
        break;
      case 'setLength':
        params.length = parseFloat(event.target.value);
        state = createState(activeTab, params);
        rerender();
        break;
      case 'setGravity':
        params.gravity = parseFloat(event.target.value);
        state = createState(activeTab, params);
        rerender();
        break;
      case 'setInitialAngle':
        params.initialAngle = parseFloat(event.target.value) * Math.PI / 180;
        state = createState(activeTab, params);
        rerender();
        break;
      case 'setDamping':
        params.damping = parseFloat(event.target.value);
        state = createState(activeTab, params);
        rerender();
        break;
      case 'setAngle':
        params.angle = parseFloat(event.target.value);
        state = createState(activeTab, params);
        rerender();
        break;
      case 'setVelocity':
        params.initialVelocity = parseFloat(event.target.value);
        state = createState(activeTab, params);
        rerender();
        break;
      case 'setSpringK':
        params.springConstant = parseFloat(event.target.value);
        state = createState(activeTab, params);
        rerender();
        break;
      case 'setMass':
        params.mass = parseFloat(event.target.value);
        state = createState(activeTab, params);
        rerender();
        break;
      case 'setDisplacement':
        params.initialDisplacement = parseFloat(event.target.value);
        state = createState(activeTab, params);
        rerender();
        break;
    }
  };

  // --- Start ---
  bindEvents();
  animFrameId = requestAnimationFrame(loop);
})();
`

