// --- Pendulum Physics ---
// Uses the full nonlinear equation: α = -(g/L)sin(θ) - b·ω

export const createPendulumState = (params: PendulumParams): PendulumState => {
  const { length, gravity, initialAngle } = params
  const period = 2 * Math.PI * Math.sqrt(length / gravity)
  const x = length * Math.sin(initialAngle)
  const y = -length * Math.cos(initialAngle)
  return {
    angle: initialAngle,
    angularVelocity: 0,
    angularAcceleration: -(gravity / length) * Math.sin(initialAngle),
    period,
    position: { x, y },
    time: 0,
  }
}

export const stepPendulum = (
  state: PendulumState,
  params: PendulumParams,
  dt: number
): PendulumState => {
  const { length, gravity, damping } = params
  const { angle, angularVelocity, time } = state

  // Runge-Kutta 4th order for accuracy
  const deriv = (theta: number, omega: number): [number, number] => {
    const alpha = -(gravity / length) * Math.sin(theta) - damping * omega
    return [omega, alpha]
  }

  const [k1v, k1a] = deriv(angle, angularVelocity)
  const [k2v, k2a] = deriv(angle + 0.5 * dt * k1v, angularVelocity + 0.5 * dt * k1a)
  const [k3v, k3a] = deriv(angle + 0.5 * dt * k2v, angularVelocity + 0.5 * dt * k2a)
  const [k4v, k4a] = deriv(angle + dt * k3v, angularVelocity + dt * k3a)

  const newAngle = angle + (dt / 6) * (k1v + 2 * k2v + 2 * k3v + k4v)
  const newOmega = angularVelocity + (dt / 6) * (k1a + 2 * k2a + 2 * k3a + k4a)
  const newAlpha = -(gravity / length) * Math.sin(newAngle) - damping * newOmega

  const x = length * Math.sin(newAngle)
  const y = -length * Math.cos(newAngle)

  return {
    angle: newAngle,
    angularVelocity: newOmega,
    angularAcceleration: newAlpha,
    period: 2 * Math.PI * Math.sqrt(length / gravity),
    position: { x, y },
    time: time + dt,
  }
}

// --- Projectile Physics ---
// Uses kinematic equations under uniform gravity

export const createProjectileState = (params: ProjectileParams): ProjectileState => {
  const angleRad = (params.angle * Math.PI) / 180
  const vx = params.initialVelocity * Math.cos(angleRad)
  const vy = params.initialVelocity * Math.sin(angleRad)
  return {
    position: { x: 0, y: params.height },
    velocity: { x: vx, y: vy },
    acceleration: { x: 0, y: -params.gravity },
    time: 0,
    maxHeight: params.height,
    range: 0,
    landed: false,
    trajectory: [{ x: 0, y: params.height }],
  }
}

export const stepProjectile = (
  state: ProjectileState,
  params: ProjectileParams,
  dt: number
): ProjectileState => {
  if (state.landed) return state

  const { position, velocity, time, trajectory } = state
  const { gravity } = params

  const newVx = velocity.x
  const newVy = velocity.y - gravity * dt

  const newX = position.x + velocity.x * dt
  const newY = position.y + velocity.y * dt - 0.5 * gravity * dt * dt

  const landed = newY <= 0 && time > 0
  const clampedY = landed ? 0 : newY

  const newPos: Vec2 = { x: newX, y: clampedY }
  const maxHeight = Math.max(state.maxHeight, clampedY)
  const range = landed ? newX : state.range

  // Sample trajectory at intervals to avoid huge arrays
  const newTrajectory = [...trajectory]
  if (newTrajectory.length < 500) {
    newTrajectory.push({ ...newPos })
  }

  return {
    position: newPos,
    velocity: { x: newVx, y: landed ? 0 : newVy },
    acceleration: { x: 0, y: landed ? 0 : -gravity },
    time: time + dt,
    maxHeight,
    range: landed ? newX : range,
    landed,
    trajectory: newTrajectory,
  }
}

// --- Spring-Mass Physics ---
// Uses Hooke's law: F = -kx - bv  =>  a = -(k/m)x - (b/m)v

export const createSpringMassState = (params: SpringMassParams): SpringMassState => {
  const { springConstant, mass, initialDisplacement } = params
  const pe = 0.5 * springConstant * initialDisplacement * initialDisplacement
  return {
    displacement: initialDisplacement,
    velocity: 0,
    acceleration: -(springConstant / mass) * initialDisplacement,
    potentialEnergy: pe,
    kineticEnergy: 0,
    totalEnergy: pe,
    time: 0,
  }
}

export const stepSpringMass = (
  state: SpringMassState,
  params: SpringMassParams,
  dt: number
): SpringMassState => {
  const { springConstant, mass, damping } = params
  const { displacement, velocity, time } = state

  // RK4 integration
  const deriv = (x: number, v: number): [number, number] => {
    const a = -(springConstant / mass) * x - (damping / mass) * v
    return [v, a]
  }

  const [k1v, k1a] = deriv(displacement, velocity)
  const [k2v, k2a] = deriv(displacement + 0.5 * dt * k1v, velocity + 0.5 * dt * k1a)
  const [k3v, k3a] = deriv(displacement + 0.5 * dt * k2v, velocity + 0.5 * dt * k2a)
  const [k4v, k4a] = deriv(displacement + dt * k3v, velocity + dt * k3a)

  const newX = displacement + (dt / 6) * (k1v + 2 * k2v + 2 * k3v + k4v)
  const newV = velocity + (dt / 6) * (k1a + 2 * k2a + 2 * k3a + k4a)
  const newA = -(springConstant / mass) * newX - (damping / mass) * newV

  const pe = 0.5 * springConstant * newX * newX
  const ke = 0.5 * mass * newV * newV

  return {
    displacement: newX,
    velocity: newV,
    acceleration: newA,
    potentialEnergy: pe,
    kineticEnergy: ke,
    totalEnergy: pe + ke,
    time: time + dt,
  }
}

