const renderProjectileSVG = (state: ProjectileState, params: ProjectileParams) => {
  // Compute scale to fit trajectory
  const angleRad = (params.angle * Math.PI) / 180
  const v0 = params.initialVelocity
  const g = params.gravity
  const theoreticalRange = (v0 * v0 * Math.sin(2 * angleRad)) / g
  const theoreticalMaxH = (v0 * v0 * Math.sin(angleRad) * Math.sin(angleRad)) / (2 * g) + params.height

  const padX = 60
  const padY = 40
  const plotW = 900 - 2 * padX
  const plotH = 400 - 2 * padY
  const scaleX = theoreticalRange > 0 ? plotW / (theoreticalRange * 1.1) : 1
  const scaleY = theoreticalMaxH > 0 ? plotH / (theoreticalMaxH * 1.2) : 1

  const toSvg = (p: Vec2): Vec2 => ({
    x: padX + p.x * scaleX,
    y: 400 - padY - p.y * scaleY,
  })

  // Build trajectory path
  const pathPoints = state.trajectory.map(toSvg)
  const pathD = pathPoints.length > 1
    ? `M ${pathPoints[0].x} ${pathPoints[0].y} ` + pathPoints.slice(1).map(p => `L ${p.x} ${p.y}`).join(' ')
    : ''

  const current = toSvg(state.position)
  const groundY = 400 - padY

  return h('svg', { viewBox: '0 0 900 400', style: styles.svg },
    // Grid
    h('defs', {},
      h('pattern', { id: 'gridP', width: '50', height: '50', patternUnits: 'userSpaceOnUse' },
        h('path', { d: 'M 50 0 L 0 0 0 50', fill: 'none', stroke: '#1a2744', 'stroke-width': '0.5' })
      )
    ),
    h('rect', { width: '900', height: '400', fill: 'url(#gridP)' }),
    // Ground
    h('line', {
      x1: String(padX), y1: String(groundY),
      x2: String(900 - padX), y2: String(groundY),
      stroke: '#4a6741', 'stroke-width': '2',
    }),
    // Trajectory path
    pathD ? h('path', {
      d: pathD, fill: 'none', stroke: '#fdcb6e', 'stroke-width': '2', opacity: '0.7',
    }) : h(Fragment, {}),
    // Projectile
    h('circle', {
