      y2: String(current.y - state.velocity.y * 1.5),
      stroke: '#74b9ff', 'stroke-width': '2', 'marker-end': 'url(#arrowBlue)',
    }),
    // Labels
    h('text', { x: '20', y: '25', fill: '#64ffda', 'font-size': '13', 'font-family': 'monospace' },
      `x = ${fmt(state.position.x, 1)}m  y = ${fmt(state.position.y, 1)}m`
    ),
    h('text', { x: '20', y: '45', fill: '#8892b0', 'font-size': '13', 'font-family': 'monospace' },
