    }) : h(Fragment, {}),
  )
}

const renderSpringMassSVG = (state: SpringMassState, params: SpringMassParams) => {
  const anchorX = 100
  const centerY = 200
  const restX = 500
  const scale = 120
  const massX = restX + state.displacement * scale
  const massSize = 40

  // Spring zigzag
  const coils = 16
  const springPath = (() => {
    const pts: string[] = [`M ${anchorX} ${centerY}`]
    const segLen = (massX - anchorX - massSize / 2) / (coils * 2)
    for (let i = 0; i < coils * 2; i++) {
      const x = anchorX + segLen * (i + 1)
      const y = centerY + (i % 2 === 0 ? -15 : 15)
      pts.push(`L ${x} ${y}`)
    }
    pts.push(`L ${massX - massSize / 2} ${centerY}`)
    return pts.join(' ')
  })()

  // Energy bar heights
  const maxE = state.totalEnergy > 0 ? state.totalEnergy : 1
  const peH = (state.potentialEnergy / maxE) * 120
  const keH = (state.kineticEnergy / maxE) * 120

  return h('svg', { viewBox: '0 0 900 400', style: styles.svg },
    h('defs', {},
      h('pattern', { id: 'gridS', width: '50', height: '50', patternUnits: 'userSpaceOnUse' },
        h('path', { d: 'M 50 0 L 0 0 0 50', fill: 'none', stroke: '#1a2744', 'stroke-width': '0.5' })
      )
    ),
    h('rect', { width: '900', height: '400', fill: 'url(#gridS)' }),
    // Wall
    h('rect', { x: String(anchorX - 15), y: String(centerY - 50), width: '15', height: '100', fill: '#233554' }),
    h('line', { x1: String(anchorX - 15), y1: String(centerY - 50), x2: String(anchorX - 15), y2: String(centerY + 50), stroke: '#64ffda', 'stroke-width': '2' }),
    // Equilibrium line
    h('line', {
      x1: String(restX), y1: String(centerY - 80),
      x2: String(restX), y2: String(centerY + 80),
      stroke: '#8892b0', 'stroke-width': '1', 'stroke-dasharray': '6,4', opacity: '0.4',
    }),
    h('text', { x: String(restX - 8), y: String(centerY + 100), fill: '#8892b0', 'font-size': '11', 'font-family': 'monospace' }, 'x=0'),
    // Spring
    h('path', { d: springPath, fill: 'none', stroke: '#64ffda', 'stroke-width': '2' }),
    // Mass block
    h('rect', {
      x: String(massX - massSize / 2), y: String(centerY - massSize / 2),
      width: String(massSize), height: String(massSize),
      rx: '4', fill: '#e17055', stroke: '#fab1a0', 'stroke-width': '2',
    }),
    h('text', {
      x: String(massX), y: String(centerY + 5), fill: '#fff',
      'font-size': '13', 'font-family': 'monospace', 'text-anchor': 'middle',
    }, 'm'),
    // Velocity arrow
    h('defs', {},
      h('marker', { id: 'arrowV', markerWidth: '8', markerHeight: '6', refX: '8', refY: '3', orient: 'auto' },
        h('polygon', { points: '0 0, 8 3, 0 6', fill: '#00b894' })
      )
    ),
    Math.abs(state.velocity) > 0.01
      ? h('line', {
          x1: String(massX), y1: String(centerY - massSize / 2 - 10),
