        })
      : h(Fragment, {}),
    // Energy bars
    h('text', { x: '760', y: '60', fill: '#8892b0', 'font-size': '11', 'font-family': 'monospace', 'text-anchor': 'middle' }, 'Energy'),
    // PE bar
    h('rect', {
