  return h('div', { style: styles.container },
    h('h1', { style: styles.header }, "Newton's Laws Simulator"),
    renderTabBar(activeTab),
    h('div', { style: styles.canvas }, canvas),
    renderControls(isPlaying, speed),
    h('div', { style: { ...styles.panelRow, marginBottom: '20px' } }, params),
    data,
  )
}

import { createSSR } from 'plaited'
import type {
  SimulationType,
  PlaybackState,
  PendulumParams,
  PendulumState,
  ProjectileParams,
  ProjectileState,
  SpringMassParams,
  SpringMassState,
  SimulationConfig,
  SimulatorControls,
} from './types'
import {
  createPendulumState,
  stepPendulum,
  createProjectileState,
  stepProjectile,
  createSpringMassState,
  stepSpringMass,
} from './physics'
import { renderSimulator, type RenderInput } from './renderer'

// --- Default parameters ---

const DEFAULT_PENDULUM: PendulumParams = {
  length: 1.5,
  gravity: 9.81,
  initialAngle: 0.5,
  damping: 0,
}

const DEFAULT_PROJECTILE: ProjectileParams = {
  angle: 45,
  initialVelocity: 30,
  gravity: 9.81,
  height: 0,
}

const DEFAULT_SPRING_MASS: SpringMassParams = {
  springConstant: 10,
  mass: 1.0,
  damping: 0,
  initialDisplacement: 1.0,
}

// --- Simulator State Machine ---

type SimulatorState = {
  activeTab: SimulationType
  playback: PlaybackState
  config: SimulationConfig
  pendulumParams: PendulumParams
  pendulumState: PendulumState
  projectileParams: ProjectileParams
  projectileState: ProjectileState
  springMassParams: SpringMassParams
  springMassState: SpringMassState
}

const createInitialState = (): SimulatorState => ({
  activeTab: 'pendulum',
  playback: 'stopped',
  config: { speed: 1.0, dt: 0.016 },
  pendulumParams: { ...DEFAULT_PENDULUM },
  pendulumState: createPendulumState(DEFAULT_PENDULUM),
  projectileParams: { ...DEFAULT_PROJECTILE },
  projectileState: createProjectileState(DEFAULT_PROJECTILE),
  springMassParams: { ...DEFAULT_SPRING_MASS },
  springMassState: createSpringMassState(DEFAULT_SPRING_MASS),
})

export const createSimulator = (overrides?: {
  type?: SimulationType
  pendulum?: Partial<PendulumParams>
  projectile?: Partial<ProjectileParams>
  springMass?: Partial<SpringMassParams>
  speed?: number
}): SimulatorControls & {
  step: () => void
  render: () => string
  setTab: (tab: SimulationType) => void
  updateParams: (key: string, value: number) => void
  getFullState: () => SimulatorState
} => {
  const state: SimulatorState = createInitialState()

  if (overrides?.type) state.activeTab = overrides.type
  if (overrides?.speed) state.config.speed = overrides.speed

  if (overrides?.pendulum) {
    Object.assign(state.pendulumParams, overrides.pendulum)
    state.pendulumState = createPendulumState(state.pendulumParams)
  }
  if (overrides?.projectile) {
    Object.assign(state.projectileParams, overrides.projectile)
    state.projectileState = createProjectileState(state.projectileParams)
  }
  if (overrides?.springMass) {
    Object.assign(state.springMassParams, overrides.springMass)
    state.springMassState = createSpringMassState(state.springMassParams)
  }

  const step = () => {
    if (state.playback !== 'playing') return
    const dt = state.config.dt * state.config.speed

    switch (state.activeTab) {
      case 'pendulum':
        state.pendulumState = stepPendulum(state.pendulumState, state.pendulumParams, dt)
        break
      case 'projectile':
        state.projectileState = stepProjectile(state.projectileState, state.projectileParams, dt)
        break
      case 'springMass':
        state.springMassState = stepSpringMass(state.springMassState, state.springMassParams, dt)
        break
    }
  }

  const play = () => {
    state.playback = 'playing'
  }

  const pause = () => {
    state.playback = 'paused'
  }

  const reset = () => {
    state.playback = 'stopped'
    state.pendulumState = createPendulumState(state.pendulumParams)
    state.projectileState = createProjectileState(state.projectileParams)
    state.springMassState = createSpringMassState(state.springMassParams)
  }

  const setSpeed = (speed: number) => {
    state.config.speed = Math.max(0.25, Math.min(4, speed))
  }

  const setTab = (tab: SimulationType) => {
    state.activeTab = tab
  }

  const updateParams = (key: string, value: number) => {
    const wasPlaying = state.playback === 'playing'
    state.playback = 'stopped'

    switch (state.activeTab) {
      case 'pendulum': {
        const params = state.pendulumParams
        if (key === 'length') params.length = value
        else if (key === 'gravity') params.gravity = value
        else if (key === 'initialAngle') params.initialAngle = (value * Math.PI) / 180
        else if (key === 'damping') params.damping = value
        state.pendulumState = createPendulumState(params)
        break
      }
      case 'projectile': {
        const params = state.projectileParams
        if (key === 'angle') params.angle = value
        else if (key === 'initialVelocity') params.initialVelocity = value
        else if (key === 'gravity') params.gravity = value
        else if (key === 'height') params.height = value
        state.projectileState = createProjectileState(params)
        break
      }
      case 'springMass': {
        const params = state.springMassParams
        if (key === 'springConstant') params.springConstant = value
        else if (key === 'mass') params.mass = value
        else if (key === 'damping') params.damping = value
        else if (key === 'initialDisplacement') params.initialDisplacement = value
        state.springMassState = createSpringMassState(params)
        break
      }
    }

    if (wasPlaying) state.playback = 'playing'
  }

  const getState = (): PendulumState | ProjectileState | SpringMassState => {
    switch (state.activeTab) {
      case 'pendulum':
        return { ...state.pendulumState }
      case 'projectile':
        return { ...state.projectileState }
      case 'springMass':
        return { ...state.springMassState }
    }
  }

  const isPlaying = () => state.playback === 'playing'

  const render = (): string => {
    const input: RenderInput = {
      activeTab: state.activeTab,
      isPlaying: state.playback === 'playing',
      speed: state.config.speed,
      pendulumState: state.pendulumState,
      pendulumParams: state.pendulumParams,
      projectileState: state.projectileState,
      projectileParams: state.projectileParams,
      springMassState: state.springMassState,
      springMassParams: state.springMassParams,
    }
    const template = renderSimulator(input)
    const ssr = createSSR()
    return ssr.render(template)
  }

  const getFullState = () => ({ ...state })

  return { play, pause, reset, setSpeed, step, render, setTab, updateParams, getState, isPlaying, getFullState }
}

// --- Server Endpoint ---

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const sim = createSimulator()

  if (url.searchParams.has('type')) {
    const tab = url.searchParams.get('type') as SimulationType
    if (['pendulum', 'projectile', 'springMass'].includes(tab)) {
      sim.setTab(tab)
    }
  }

  if (req.method === 'POST') {
    const body = await req.json() as { action: string; payload?: Record<string, number> }
    switch (body.action) {
      case 'step':
        sim.play()
        for (let i = 0; i < (body.payload?.steps ?? 1); i++) sim.step()
        return Response.json({ state: sim.getState() })
      case 'state':
        return Response.json({ state: sim.getFullState() })
    }
  }

  const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Newton's Laws Simulator</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { background: #0f0f23; min-height: 100vh; display: flex; justify-content: center; padding: 40px 16px; }
  </style>
</head>
<body>
  ${sim.render()}
  <script>
    const state = {
      activeTab: 'pendulum',
      playing: false,
      speed: 1.0,
      params: {
        pendulum: { length: 1.5, gravity: 9.81, initialAngle: 0.5, damping: 0 },
        projectile: { angle: 45, initialVelocity: 30, gravity: 9.81, height: 0 },
        springMass: { springConstant: 10, mass: 1.0, damping: 0, initialDisplacement: 1.0 },
      },
    };

    document.addEventListener('click', (e) => {
      const trigger = e.target.closest('[p-trigger]');
      if (!trigger) return;
      const action = trigger.getAttribute('p-trigger');
      if (action === 'play') { state.playing = true; }
      else if (action === 'pause') { state.playing = false; }
      else if (action === 'reset') { state.playing = false; location.reload(); }
      else if (action.startsWith('tab:')) {
        state.activeTab = action.split(':')[1];
        location.href = '?type=' + state.activeTab;
      }
    });

    document.addEventListener('input', (e) => {
      const trigger = e.target.closest('[p-trigger]');
      if (!trigger) return;
      const action = trigger.getAttribute('p-trigger');
      if (action === 'speed-change') {
        state.speed = parseFloat(e.target.value);
      }
    });
  </script>
</body>
</html>`

  return new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

export default {
  fetch: handleRequest,
}

