export type SimulationType = 'pendulum' | 'projectile' | 'spring'

export type PhysicsValues = {
  position: Vector2D | { x: number }
  velocity: Vector2D | { x: number }
  acceleration: Vector2D | { x: number }
  extras?: Record<string, number | string>
}

import type { PendulumParams, PendulumState } from '../types'

const INITIAL_STATE: PendulumState = {
  angle: 0,
  angularVelocity: 0,
  angularAcceleration: 0,
  position: { x: 0, y: 0 },
  velocity: { x: 0, y: 0 },
  acceleration: { x: 0, y: 0 },
}

export const createPendulum = (params: PendulumParams) => {
  let state: PendulumState = {
    ...INITIAL_STATE,
    angle: params.initialAngle,
    position: {
      x: params.length * Math.sin(params.initialAngle),
      y: -params.length * Math.cos(params.initialAngle),
    },
  }

  const reset = (newParams?: Partial<PendulumParams>) => {
    if (newParams) {
      params = { ...params, ...newParams }
    }
    state = {
      ...INITIAL_STATE,
      angle: params.initialAngle,
      angularAcceleration: -(params.gravity / params.length) * Math.sin(params.initialAngle),
      position: {
        x: params.length * Math.sin(params.initialAngle),
        y: -params.length * Math.cos(params.initialAngle),
      },
    }
    return state
  }

  // Runge-Kutta 4th order integration for accuracy
  const step = (dt: number): PendulumState => {
    const { length, gravity, damping } = params
    const derive = (angle: number, omega: number) => {
      const alpha = -(gravity / length) * Math.sin(angle) - damping * omega
      return { dAngle: omega, dOmega: alpha }
    }

    const { angle, angularVelocity } = state

    const k1 = derive(angle, angularVelocity)
    const k2 = derive(angle + k1.dAngle * dt / 2, angularVelocity + k1.dOmega * dt / 2)
    const k3 = derive(angle + k2.dAngle * dt / 2, angularVelocity + k2.dOmega * dt / 2)
    const k4 = derive(angle + k3.dAngle * dt, angularVelocity + k3.dOmega * dt)

    const newAngle = angle + (dt / 6) * (k1.dAngle + 2 * k2.dAngle + 2 * k3.dAngle + k4.dAngle)
    const newOmega = angularVelocity + (dt / 6) * (k1.dOmega + 2 * k2.dOmega + 2 * k3.dOmega + k4.dOmega)
    const newAlpha = -(gravity / length) * Math.sin(newAngle) - damping * newOmega

    const x = length * Math.sin(newAngle)
    const y = -length * Math.cos(newAngle)
    const vx = length * newOmega * Math.cos(newAngle)
    const vy = length * newOmega * Math.sin(newAngle)
    const ax = length * (newAlpha * Math.cos(newAngle) - newOmega * newOmega * Math.sin(newAngle))
    const ay = length * (newAlpha * Math.sin(newAngle) + newOmega * newOmega * Math.cos(newAngle))

    state = {
      angle: newAngle,
      angularVelocity: newOmega,
      angularAcceleration: newAlpha,
      position: { x, y },
      velocity: { x: vx, y: vy },
      acceleration: { x: ax, y: ay },
    }

    return state
  }

  const getState = () => state
  const getParams = () => ({ ...params })

  return { step, reset, getState, getParams }
}

export type PendulumSimulator = ReturnType<typeof createPendulum>

import type { ProjectileParams, ProjectileState, Vector2D } from '../types'

const MAX_TRAJECTORY_POINTS = 500

export const createProjectile = (params: ProjectileParams) => {
  const toRad = (deg: number) => (deg * Math.PI) / 180

  let time = 0
  let state: ProjectileState = {
    position: { x: 0, y: params.height },
    velocity: {
      x: params.initialVelocity * Math.cos(toRad(params.angle)),
      y: params.initialVelocity * Math.sin(toRad(params.angle)),
    },
    acceleration: { x: 0, y: -params.gravity },
    trajectory: [{ x: 0, y: params.height }],
    landed: false,
  }

  const reset = (newParams?: Partial<ProjectileParams>) => {
    if (newParams) {
      params = { ...params, ...newParams }
    }
    time = 0
    state = {
      position: { x: 0, y: params.height },
      velocity: {
        x: params.initialVelocity * Math.cos(toRad(params.angle)),
        y: params.initialVelocity * Math.sin(toRad(params.angle)),
      },
      acceleration: { x: 0, y: -params.gravity },
      trajectory: [{ x: 0, y: params.height }],
      landed: false,
    }
    return state
  }

  const step = (dt: number): ProjectileState => {
    if (state.landed) return state

    time += dt

    const { initialVelocity, angle, gravity, height } = params
    const rad = toRad(angle)

    const x = initialVelocity * Math.cos(rad) * time
    const y = height + initialVelocity * Math.sin(rad) * time - 0.5 * gravity * time * time

    if (y <= 0 && time > 0) {
      // Find exact landing time via quadratic formula
      const a = -0.5 * gravity
      const b = initialVelocity * Math.sin(rad)
      const c = height
      const disc = b * b - 4 * a * c
      const tLand = disc >= 0 ? (-b - Math.sqrt(disc)) / (2 * a) : time

      const landX = initialVelocity * Math.cos(rad) * tLand
      const landPoint: Vector2D = { x: landX, y: 0 }

      state = {
        position: landPoint,
        velocity: {
          x: initialVelocity * Math.cos(rad),
          y: initialVelocity * Math.sin(rad) - gravity * tLand,
        },
        acceleration: { x: 0, y: -gravity },
        trajectory: [...state.trajectory, landPoint],
        landed: true,
      }
      return state
    }

    const newPos: Vector2D = { x, y }
    const trajectory = [...state.trajectory, newPos]
    if (trajectory.length > MAX_TRAJECTORY_POINTS) {
      trajectory.splice(0, trajectory.length - MAX_TRAJECTORY_POINTS)
    }

    state = {
      position: newPos,
      velocity: {
        x: initialVelocity * Math.cos(rad),
        y: initialVelocity * Math.sin(rad) - gravity * time,
      },
      acceleration: { x: 0, y: -gravity },
      trajectory,
      landed: false,
    }

    return state
  }

  const getState = () => state
  const getParams = () => ({ ...params })
  const getTime = () => time

  return { step, reset, getState, getParams, getTime }
}

export type ProjectileSimulator = ReturnType<typeof createProjectile>

import type { SpringParams, SpringState } from '../types'

export const createSpring = (params: SpringParams) => {
  let state: SpringState = {
    displacement: params.initialDisplacement,
    velocity: 0,
    acceleration: -(params.springConstant / params.mass) * params.initialDisplacement,
    kineticEnergy: 0,
    potentialEnergy: 0.5 * params.springConstant * params.initialDisplacement * params.initialDisplacement,
    totalEnergy: 0.5 * params.springConstant * params.initialDisplacement * params.initialDisplacement,
  }

  const reset = (newParams?: Partial<SpringParams>) => {
    if (newParams) {
      params = { ...params, ...newParams }
    }
    const pe = 0.5 * params.springConstant * params.initialDisplacement * params.initialDisplacement
    state = {
      displacement: params.initialDisplacement,
      velocity: 0,
      acceleration: -(params.springConstant / params.mass) * params.initialDisplacement,
      kineticEnergy: 0,
      potentialEnergy: pe,
      totalEnergy: pe,
    }
    return state
  }

  // Runge-Kutta 4th order for spring-mass system
  const step = (dt: number): SpringState => {
    const { springConstant: k, mass: m, damping: c } = params

    const derive = (x: number, v: number) => ({
      dx: v,
      dv: -(k / m) * x - (c / m) * v,
    })

    const { displacement: x, velocity: v } = state

    const k1 = derive(x, v)
    const k2 = derive(x + k1.dx * dt / 2, v + k1.dv * dt / 2)
    const k3 = derive(x + k2.dx * dt / 2, v + k2.dv * dt / 2)
    const k4 = derive(x + k3.dx * dt, v + k3.dv * dt)

    const newX = x + (dt / 6) * (k1.dx + 2 * k2.dx + 2 * k3.dx + k4.dx)
    const newV = v + (dt / 6) * (k1.dv + 2 * k2.dv + 2 * k3.dv + k4.dv)
    const newA = -(k / m) * newX - (c / m) * newV

    const ke = 0.5 * m * newV * newV
    const pe = 0.5 * k * newX * newX

    state = {
      displacement: newX,
      velocity: newV,
      acceleration: newA,
      kineticEnergy: ke,
      potentialEnergy: pe,
      totalEnergy: ke + pe,
    }

    return state
  }

  const getState = () => state
  const getParams = () => ({ ...params })

  return { step, reset, getState, getParams }
}

export type SpringSimulator = ReturnType<typeof createSpring>

import type { SimulationType, SimulationState, PendulumParams, ProjectileParams, SpringParams } from './types'
import { createPendulum } from './physics/pendulum'
import { createProjectile } from './physics/projectile'
import { createSpring } from './physics/spring'

const DEFAULT_DT = 1 / 60
const SPEED_OPTIONS = [0.25, 0.5, 1, 2, 4] as const

export type SpeedOption = (typeof SPEED_OPTIONS)[number]

export type SimulationEngine = {
  tick: () => void
  play: () => void
  pause: () => void
  reset: () => void
  setSpeed: (speed: SpeedOption) => void
  setSimulation: (sim: SimulationType) => void
  updateParams: (params: Record<string, number>) => void
  getSimState: () => SimulationState
  getCurrentType: () => SimulationType
  getPendulum: () => ReturnType<typeof createPendulum>
  getProjectile: () => ReturnType<typeof createProjectile>
  getSpring: () => ReturnType<typeof createSpring>
  getSpeedOptions: () => readonly SpeedOption[]
}

export const createEngine = (
  pendulumParams: PendulumParams,
  projectileParams: ProjectileParams,
  springParams: SpringParams,
): SimulationEngine => {
  const pendulum = createPendulum(pendulumParams)
  const projectile = createProjectile(projectileParams)
  const spring = createSpring(springParams)

  let currentType: SimulationType = 'pendulum'
  let simState: SimulationState = {
    time: 0,
    running: false,
    speed: 1,
  }

  const tick = () => {
    if (!simState.running) return

    const dt = DEFAULT_DT * simState.speed

    switch (currentType) {
      case 'pendulum':
        pendulum.step(dt)
        break
      case 'projectile':
        projectile.step(dt)
        break
      case 'spring':
        spring.step(dt)
        break
    }

    simState = { ...simState, time: simState.time + dt }
  }

  const play = () => {
    simState = { ...simState, running: true }
  }

  const pause = () => {
    simState = { ...simState, running: false }
  }

  const reset = () => {
    simState = { ...simState, time: 0, running: false }
    pendulum.reset()
    projectile.reset()
    spring.reset()
  }

  const setSpeed = (speed: SpeedOption) => {
    simState = { ...simState, speed }
  }

  const setSimulation = (sim: SimulationType) => {
    currentType = sim
    simState = { ...simState, time: 0, running: false }
    pendulum.reset()
    projectile.reset()
    spring.reset()
  }

  const updateParams = (newParams: Record<string, number>) => {
    simState = { ...simState, time: 0, running: false }
    switch (currentType) {
      case 'pendulum':
        pendulum.reset(newParams as Partial<PendulumParams>)
        break
      case 'projectile':
        projectile.reset(newParams as Partial<ProjectileParams>)
        break
      case 'spring':
        spring.reset(newParams as Partial<SpringParams>)
        break
    }
  }

  return {
    tick,
    play,
    pause,
    reset,
    setSpeed,
    setSimulation,
    updateParams,
    getSimState: () => simState,
    getCurrentType: () => currentType,
    getPendulum: () => pendulum,
    getProjectile: () => projectile,
    getSpring: () => spring,
    getSpeedOptions: () => SPEED_OPTIONS,
  }
}

