const renderProjectileCanvas = (engine: SimulationEngine) => {
  const state = engine.getProjectile().getState()
  const params = engine.getProjectile().getParams()
  const trajectory = state.trajectory

  // Auto-scale to fit trajectory
  const maxX = Math.max(40, ...trajectory.map((p) => p.x)) * 1.1
  const maxY = Math.max(20, ...trajectory.map((p) => p.y)) * 1.3

  const toSvgX = (x: number) => 60 + (x / maxX) * 820
  const toSvgY = (y: number) => 360 - (y / maxY) * 320

  const pathData = trajectory.length > 1
    ? trajectory.map((p, i) => `${i === 0 ? 'M' : 'L'} ${fmt(toSvgX(p.x))} ${fmt(toSvgY(p.y))}`).join(' ')
    : ''

  const projX = toSvgX(state.position.x)
  const projY = toSvgY(state.position.y)

  return h(
    'svg',
    {
      viewBox: '0 0 920 400',
      style: styleToStr(styles.svg),
      xmlns: 'http://www.w3.org/2000/svg',
    },
    // ground
