      stroke: colors.textDim, 'stroke-width': '1', 'stroke-dasharray': '6,4',
    }),
    // trajectory path
    pathData
      ? h('path', {
          d: pathData,
          fill: 'none',
          stroke: colors.accent,
          'stroke-width': '2',
          opacity: '0.6',
        })
      : h(Fragment, {}),
    // projectile
    h('circle', {
      cx: String(projX),
      cy: String(projY),
      r: '10',
      fill: colors.danger,
      stroke: '#ff8a80',
      'stroke-width': '2',
    }),
    // velocity vector
    h('line', {
      x1: String(projX),
      y1: String(projY),
      x2: String(projX + state.velocity.x * 2),
      y2: String(projY - state.velocity.y * 2),
