    }),
    // axis labels
    h('text', { x: '460', y: '390', fill: colors.textDim, 'font-size': '12', 'text-anchor': 'middle' }, 'Distance (m)'),
    h(
      'text',
      {
        x: '20', y: '200', fill: colors.textDim, 'font-size': '12',
        'text-anchor': 'middle',
        transform: 'rotate(-90, 20, 200)',
      },
      'Height (m)',
    ),
    // info
    h('text', { x: '20', y: '30', fill: colors.textDim, 'font-size': '13' }, `\u03B1 = ${fmt(params.angle)}\u00B0`),
    h('text', { x: '20', y: '50', fill: colors.textDim, 'font-size': '13' }, `v\u2080 = ${fmt(params.initialVelocity)} m/s`),
    state.landed
      ? h('text', {
          x: '460', y: '200', fill: colors.yellow, 'font-size': '18',
          'text-anchor': 'middle', 'font-weight': 'bold',
        }, `Landed at x = ${fmt(state.position.x)} m`)
      : h(Fragment, {}),
  )
}

const renderSpringCanvas = (engine: SimulationEngine) => {
  const state = engine.getSpring().getState()
  const params = engine.getSpring().getParams()

  const wallX = 100
  const centerY = 200
  const scale = 120
  const massX = 460 + state.displacement * scale
  const massW = 50
  const massH = 50

  // Draw spring as zigzag
  const coils = 12
  const springStartX = wallX
  const springEndX = massX - massW / 2
  const springLen = springEndX - springStartX
  const segLen = springLen / (coils * 2)
  const amplitude = 15

  let zigzag = `M ${wallX} ${centerY}`
  for (let i = 0; i < coils * 2; i++) {
    const x = springStartX + segLen * (i + 1)
    const y = centerY + (i % 2 === 0 ? -amplitude : amplitude)
    zigzag += ` L ${fmt(x)} ${y}`
  }
  zigzag += ` L ${fmt(springEndX)} ${centerY}`

  // Energy bar heights
  const maxE = state.totalEnergy > 0 ? state.totalEnergy : 1
  const keHeight = (state.kineticEnergy / maxE) * 120
  const peHeight = (state.potentialEnergy / maxE) * 120

  return h(
    'svg',
    {
      viewBox: '0 0 920 400',
      style: styleToStr(styles.svg),
      xmlns: 'http://www.w3.org/2000/svg',
    },
    // wall
    h('rect', { x: '80', y: '140', width: '20', height: '120', fill: colors.textDim, rx: '2' }),
    h('line', {
      x1: '80', y1: '140', x2: '80', y2: '260',
      stroke: colors.text, 'stroke-width': '2',
    }),
    // hatching
    ...Array.from({ length: 6 }, (_, i) =>
      h('line', {
        x1: '80', y1: String(145 + i * 20),
        x2: '65', y2: String(155 + i * 20),
        stroke: colors.textDim, 'stroke-width': '1.5',
      }),
    ),
    // spring
    h('path', { d: zigzag, fill: 'none', stroke: colors.spring, 'stroke-width': '2.5' }),
    // mass
    h('rect', {
      x: String(massX - massW / 2),
      y: String(centerY - massH / 2),
      width: String(massW),
      height: String(massH),
      fill: colors.accent,
      rx: '6',
      stroke: colors.accentHover,
      'stroke-width': '2',
    }),
    h(
      'text',
      {
        x: String(massX),
        y: String(centerY + 5),
        fill: '#fff',
        'font-size': '14',
        'text-anchor': 'middle',
        'font-weight': 'bold',
      },
      `${fmt(params.mass)}kg`,
    ),
    // equilibrium line
    h('line', {
      x1: '460', y1: '140', x2: '460', y2: '260',
      stroke: colors.textDim, 'stroke-width': '1', 'stroke-dasharray': '4,4',
    }),
    h('text', { x: '460', y: '280', fill: colors.textDim, 'font-size': '11', 'text-anchor': 'middle' }, 'equilibrium'),
    // displacement arrow
    state.displacement !== 0
      ? h(Fragment, {},
          h('line', {
            x1: '460', y1: '310', x2: String(massX), y2: '310',
            stroke: colors.yellow, 'stroke-width': '2',
          }),
          h('text', {
            x: String((460 + massX) / 2), y: '330',
            fill: colors.yellow, 'font-size': '12', 'text-anchor': 'middle',
          }, `x = ${fmt(state.displacement)} m`),
        )
      : h(Fragment, {}),
    // energy bars
    h('text', { x: '780', y: '130', fill: colors.textDim, 'font-size': '12', 'text-anchor': 'middle' }, 'Energy'),
    h('rect', {
      x: '760', y: String(350 - keHeight), width: '18', height: String(keHeight),
      fill: colors.success, rx: '2',
    }),
    h('rect', {
      x: '790', y: String(350 - peHeight), width: '18', height: String(peHeight),
      fill: colors.accent, rx: '2',
    }),
    h('text', { x: '769', y: '370', fill: colors.success, 'font-size': '10', 'text-anchor': 'middle' }, 'KE'),
    h('text', { x: '799', y: '370', fill: colors.accent, 'font-size': '10', 'text-anchor': 'middle' }, 'PE'),
    // params
    h('text', { x: '20', y: '30', fill: colors.textDim, 'font-size': '13' }, `k = ${fmt(params.springConstant)} N/m`),
    h('text', { x: '20', y: '50', fill: colors.textDim, 'font-size': '13' }, `m = ${fmt(params.mass)} kg`),
    h('text', { x: '20', y: '70', fill: colors.spring, 'font-size': '13' }, `\u03C9 = ${fmt(Math.sqrt(params.springConstant / params.mass))} rad/s`),
  )
}

const renderValues = (engine: SimulationEngine) => {
  const sim = engine.getCurrentType()
  let rows: [string, string][] = []

  if (sim === 'pendulum') {
    const s = engine.getPendulum().getState()
    rows = [
      ['\u03B8 (angle)', `${fmt((s.angle * 180) / Math.PI)}\u00B0`],
      ['\u03C9 (angular vel)', `${fmt(s.angularVelocity)} rad/s`],
      ['\u03B1 (angular acc)', `${fmt(s.angularAcceleration)} rad/s\u00B2`],
      ['Position x', `${fmt(s.position.x)} m`],
      ['Position y', `${fmt(s.position.y)} m`],
      ['Velocity x', `${fmt(s.velocity.x)} m/s`],
      ['Velocity y', `${fmt(s.velocity.y)} m/s`],
      ['Accel x', `${fmt(s.acceleration.x)} m/s\u00B2`],
      ['Accel y', `${fmt(s.acceleration.y)} m/s\u00B2`],
    ]
  } else if (sim === 'projectile') {
    const s = engine.getProjectile().getState()
    rows = [
      ['Position x', `${fmt(s.position.x)} m`],
      ['Position y', `${fmt(s.position.y)} m`],
      ['Velocity x', `${fmt(s.velocity.x)} m/s`],
      ['Velocity y', `${fmt(s.velocity.y)} m/s`],
      ['Speed', `${fmt(Math.sqrt(s.velocity.x ** 2 + s.velocity.y ** 2))} m/s`],
      ['Accel x', `${fmt(s.acceleration.x)} m/s\u00B2`],
      ['Accel y', `${fmt(s.acceleration.y)} m/s\u00B2`],
      ['Status', s.landed ? 'Landed' : 'In flight'],
    ]
  } else {
    const s = engine.getSpring().getState()
    rows = [
      ['Displacement', `${fmt(s.displacement)} m`],
      ['Velocity', `${fmt(s.velocity)} m/s`],
      ['Acceleration', `${fmt(s.acceleration)} m/s\u00B2`],
      ['Kinetic Energy', `${fmt(s.kineticEnergy)} J`],
      ['Potential Energy', `${fmt(s.potentialEnergy)} J`],
      ['Total Energy', `${fmt(s.totalEnergy)} J`],
    ]
  }

  return h(
    'div',
    { style: styleToStr(styles.valuesPanel) },
    h('div', { style: styleToStr(styles.panelTitle) }, 'Real-Time Values'),
    ...rows.map(([label, value]) =>
      h(
        'div',
        { style: styleToStr(styles.valueRow) },
        h('span', { style: styleToStr(styles.valueLabel) }, label),
        h('span', { style: styleToStr(styles.valueNum) }, value),
      ),
    ),
  )
}

type SliderConfig = {
  id: string
  label: string
  min: number
  max: number
  step: number
  value: number
  unit: string
}

const renderSliders = (engine: SimulationEngine) => {
  const sim = engine.getCurrentType()
  let sliders: SliderConfig[] = []

  if (sim === 'pendulum') {
    const p = engine.getPendulum().getParams()
    sliders = [
      { id: 'length', label: 'Length', min: 0.5, max: 5, step: 0.1, value: p.length, unit: 'm' },
      { id: 'gravity', label: 'Gravity', min: 1, max: 25, step: 0.1, value: p.gravity, unit: 'm/s\u00B2' },
      { id: 'initialAngle', label: 'Initial Angle', min: 5, max: 170, step: 1, value: (p.initialAngle * 180) / Math.PI, unit: '\u00B0' },
    ]
  } else if (sim === 'projectile') {
    const p = engine.getProjectile().getParams()
    sliders = [
      { id: 'angle', label: 'Launch Angle', min: 5, max: 85, step: 1, value: p.angle, unit: '\u00B0' },
      { id: 'initialVelocity', label: 'Initial Velocity', min: 5, max: 50, step: 1, value: p.initialVelocity, unit: 'm/s' },
      { id: 'gravity', label: 'Gravity', min: 1, max: 25, step: 0.1, value: p.gravity, unit: 'm/s\u00B2' },
    ]
  } else {
    const p = engine.getSpring().getParams()
    sliders = [
      { id: 'springConstant', label: 'Spring Constant (k)', min: 1, max: 50, step: 0.5, value: p.springConstant, unit: 'N/m' },
      { id: 'mass', label: 'Mass', min: 0.1, max: 10, step: 0.1, value: p.mass, unit: 'kg' },
      { id: 'initialDisplacement', label: 'Initial Displacement', min: 0.1, max: 3, step: 0.1, value: p.initialDisplacement, unit: 'm' },
    ]
  }

  return h(
    'div',
    { style: styleToStr(styles.valuesPanel) },
    h('div', { style: styleToStr(styles.panelTitle) }, 'Parameters'),
    ...sliders.map((s) =>
      h(
        'div',
        { style: styleToStr(styles.sliderGroup) },
        h(
          'div',
          { style: styleToStr(styles.sliderLabel) },
          h('span', { style: styleToStr(styles.valueLabel) }, s.label),
          h('span', { style: styleToStr(styles.valueNum) }, `${fmt(s.value)} ${s.unit}`),
        ),
        h('input', {
          type: 'range',
          min: String(s.min),
          max: String(s.max),
          step: String(s.step),
          value: String(s.value),
          style: styleToStr(styles.slider),
          'p-trigger': `param-${s.id}`,
          'data-param': s.id,
        }),
      ),
    ),
  )
}

export const renderSimulator = (engine: SimulationEngine) => {
  const sim = engine.getCurrentType()
  const { time } = engine.getSimState()

  let canvas
  switch (sim) {
    case 'pendulum':
      canvas = renderPendulumCanvas(engine)
      break
    case 'projectile':
      canvas = renderProjectileCanvas(engine)
      break
    case 'spring':
      canvas = renderSpringCanvas(engine)
      break
  }

  return h(
    'div',
    { style: styleToStr(styles.container), 'p-target': 'simulator-root' },
    h(
      'div',
      { style: styleToStr(styles.header) },
      h('h1', { style: styleToStr(styles.title) }, "Newton's Laws Simulator"),
      h('p', { style: styleToStr(styles.subtitle) }, 'Interactive physics simulations with real-time tracking'),
    ),
    renderTabs(sim),
    h(
      'div',
      { style: styleToStr(styles.canvas) },
      canvas,
    ),
    h('div', { style: styleToStr(styles.timeDisplay) }, `Time: ${fmt(time, 1)}s`),
    renderControls(engine),
    h(
      'div',
      { style: styleToStr(styles.grid) },
      renderValues(engine),
      renderSliders(engine),
    ),
  )
}

import { createSSR } from 'plaited'
import { createEngine } from './engine'
import type { SpeedOption } from './engine'
import type { SimulationType, PendulumParams, ProjectileParams, SpringParams } from './types'
import { renderSimulator } from './render'

const DEFAULT_PENDULUM: PendulumParams = {
  length: 2.0,
  gravity: 9.81,
  initialAngle: Math.PI / 4,
  damping: 0,
}

const DEFAULT_PROJECTILE: ProjectileParams = {
  angle: 45,
  initialVelocity: 20,
  gravity: 9.81,
  height: 0,
}

const DEFAULT_SPRING: SpringParams = {
  springConstant: 10,
  mass: 1.0,
  initialDisplacement: 1.0,
  damping: 0,
}

export const createSimulatorApp = () => {
  const engine = createEngine(DEFAULT_PENDULUM, DEFAULT_PROJECTILE, DEFAULT_SPRING)

  const render = () => {
    const template = renderSimulator(engine)
    const ssr = createSSR()
    return ssr(template)
  }

  const handleEvent = (event: string, data?: Record<string, string>) => {
    if (event === 'toggle-play') {
      const { running } = engine.getSimState()
      running ? engine.pause() : engine.play()
    } else if (event === 'reset') {
      engine.reset()
    } else if (event.startsWith('tab-')) {
      const sim = event.replace('tab-', '') as SimulationType
      engine.setSimulation(sim)
    } else if (event === 'speed-change' && data?.value) {
      engine.setSpeed(Number(data.value) as SpeedOption)
    } else if (event.startsWith('param-') && data?.value) {
      const paramName = event.replace('param-', '')
      let value = Number(data.value)

      // Convert degrees to radians for pendulum angle
      if (paramName === 'initialAngle' && engine.getCurrentType() === 'pendulum') {
        value = (value * Math.PI) / 180
      }

      engine.updateParams({ [paramName]: value })
    }
  }

  const tick = () => {
    engine.tick()
  }

  return { render, handleEvent, tick, engine }
}

// Server entry point
const startServer = async () => {
  const app = createSimulatorApp()

  const html = (body: string) => `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Newton's Laws Simulator</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body {
      background: #0f1117;
      color: #e1e4ed;
      min-height: 100vh;
    }
    input[type="range"] {
      -webkit-appearance: none;
      height: 6px;
      border-radius: 3px;
      background: #2a2d3a;
      outline: none;
    }
    input[type="range"]::-webkit-slider-thumb {
      -webkit-appearance: none;
      width: 16px;
      height: 16px;
      border-radius: 50%;
      background: #4f8ff7;
      cursor: pointer;
    }
    select {
      outline: none;
    }
    button:hover {
      opacity: 0.9;
      transform: scale(1.02);
    }
    button:active {
      transform: scale(0.98);
    }
  </style>
</head>
<body>
  <div id="app">${body}</div>
  <script>
    const FPS = 60;
    let animFrameId = null;

    const postEvent = async (event, data) => {
      const res = await fetch('/event', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ event, data }),
      });
      const html = await res.text();
      document.getElementById('app').innerHTML = html;
      bindEvents();
    };

    const bindEvents = () => {
      document.querySelectorAll('[p-trigger]').forEach(el => {
        const trigger = el.getAttribute('p-trigger');
        if (el.tagName === 'BUTTON') {
          el.onclick = () => postEvent(trigger);
        } else if (el.tagName === 'SELECT') {
          el.onchange = (e) => postEvent(trigger, { value: e.target.value });
        } else if (el.tagName === 'INPUT') {
          el.oninput = (e) => postEvent(trigger, { value: e.target.value });
        }
      });
    };

    const tickLoop = async () => {
      const res = await fetch('/tick', { method: 'POST' });
      const html = await res.text();
      document.getElementById('app').innerHTML = html;
      bindEvents();
    };

    setInterval(tickLoop, 1000 / FPS);
    bindEvents();
  </script>
</body>
</html>`

  const server = Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url)

      if (url.pathname === '/' && req.method === 'GET') {
        const body = app.render()
        return new Response(html(body), {
          headers: { 'Content-Type': 'text/html' },
        })
      }

      if (url.pathname === '/tick' && req.method === 'POST') {
        app.tick()
        const body = app.render()
        return new Response(body, {
          headers: { 'Content-Type': 'text/html' },
        })
      }

      if (url.pathname === '/event' && req.method === 'POST') {
        const { event, data } = await req.json() as { event: string; data?: Record<string, string> }
        app.handleEvent(event, data)
        const body = app.render()
        return new Response(body, {
          headers: { 'Content-Type': 'text/html' },
        })
      }

      return new Response('Not Found', { status: 404 })
    },
  })

  console.log(`Physics Simulator running at http://localhost:${server.port}`)
}

