    .element-cell { min-height: 44px; padding: 2px; }
    .element-sym { font-size: 0.85rem; }
    .element-name { display: none; }
    .detail-grid { grid-template-columns: 1fr 1fr; }
  }
`;

import { h, Fragment } from 'plaited';
import type { Element, Category, RenderOptions } from './types';
import { categoryColors, categoryLabels, allCategories, tableStyles } from './styles';

const formatTemp = (temp: number | null): string =>
  temp !== null ? `${temp} °C` : 'Unknown';

const formatOxStates = (states: number[]): string =>
  states.length > 0 ? states.map(s => (s > 0 ? `+${s}` : `${s}`)).join(', ') : 'None observed';

const isElementVisible = (el: Element, query: string, activeCategories: Category[]): boolean => {
  const matchesCategory = activeCategories.length === 0 || activeCategories.includes(el.category);
  if (!query) return matchesCategory;
  const q = query.toLowerCase();
  const matchesQuery =
    el.name.toLowerCase().includes(q) ||
    el.symbol.toLowerCase().includes(q) ||
    String(el.z).includes(q);
  return matchesQuery && matchesCategory;
};

const renderElementCell = (el: Element, isSelected: boolean, isDimmed: boolean) => {
  const bgColor = categoryColors[el.category];
  const textColor = ['transition-metal', 'unknown'].includes(el.category) ? '#1a1a2e' : '#1a1a2e';
  const classes = ['element-cell', isSelected ? 'selected' : '', isDimmed ? 'dimmed' : ''].filter(Boolean).join(' ');

  return h('div', {
    class: classes,
    style: {
      gridRow: String(el.row),
      gridColumn: String(el.col),
      backgroundColor: bgColor,
      color: textColor,
    },
    'data-z': String(el.z),
    'p-trigger': `click:selectElement`,
  },
    h('span', { class: 'element-z' }, String(el.z)),
    h('span', { class: 'element-sym' }, el.symbol),
    h('span', { class: 'element-name' }, el.name),
    h('span', { class: 'element-mass' }, el.mass.toFixed(el.mass < 10 ? 4 : el.mass < 100 ? 3 : 2)),
  );
};

const renderPlaceholderCell = (row: number, col: number, label: string, color: string) =>
  h('div', {
    class: 'placeholder-cell',
    style: { gridRow: String(row), gridColumn: String(col), borderColor: color },
  }, label);

const renderSeriesLabel = (row: number, label: string) =>
  h('div', {
    class: 'series-label',
    style: { gridRow: String(row), gridColumn: '1 / 3' },
  }, label);

const renderDetailPanel = (el: Element | undefined) => {
  if (!el) {
    return h('div', { class: 'detail-panel', 'p-target': 'detailPanel', id: 'detail-panel' });
  }

  const bgColor = categoryColors[el.category];

  return h('div', {
    class: 'detail-panel visible',
    'p-target': 'detailPanel',
    id: 'detail-panel',
  },
    h('button', { class: 'detail-close', 'p-trigger': 'click:closeDetail' }, 'Close'),
    h('div', { class: 'detail-header' },
      h('span', { class: 'detail-symbol', style: { color: bgColor } }, el.symbol),
      h('span', { class: 'detail-name' }, el.name),
      h('span', { class: 'detail-number' }, `#${el.z}`),
    ),
    h('div', { class: 'detail-grid' },
      h('div', { class: 'detail-item' },
        h('div', { class: 'detail-label' }, 'Atomic Mass'),
        h('div', { class: 'detail-value' }, `${el.mass} u`),
      ),
      h('div', { class: 'detail-item' },
        h('div', { class: 'detail-label' }, 'Category'),
        h('div', { class: 'detail-value' }, categoryLabels[el.category]),
      ),
      h('div', { class: 'detail-item' },
        h('div', { class: 'detail-label' }, 'Electron Configuration'),
        h('div', { class: 'detail-value' }, el.electronConfig),
      ),
      h('div', { class: 'detail-item' },
        h('div', { class: 'detail-label' }, 'Oxidation States'),
        h('div', { class: 'detail-value' }, formatOxStates(el.oxidationStates)),
      ),
      h('div', { class: 'detail-item' },
        h('div', { class: 'detail-label' }, 'Melting Point'),
        h('div', { class: 'detail-value' }, formatTemp(el.meltingPoint)),
      ),
      h('div', { class: 'detail-item' },
        h('div', { class: 'detail-label' }, 'Boiling Point'),
        h('div', { class: 'detail-value' }, formatTemp(el.boilingPoint)),
      ),
      h('div', { class: 'detail-item' },
        h('div', { class: 'detail-label' }, 'Discovery Year'),
        h('div', { class: 'detail-value' }, el.discoveryYear ? String(el.discoveryYear) : 'Known since antiquity'),
      ),
    ),
    h('div', { class: 'detail-desc' }, el.description),
  );
};

const renderCategoryFilters = (activeCategories: Category[]) =>
  h('div', { class: 'category-filters' },
    ...allCategories.map(cat =>
      h('button', {
        class: `category-btn${activeCategories.includes(cat) ? ' active' : ''}`,
        style: { backgroundColor: categoryColors[cat], color: '#1a1a2e' },
        'data-category': cat,
        'p-trigger': 'click:toggleCategory',
      }, categoryLabels[cat])
    ),
  );

const renderLegend = () =>
  h('div', { class: 'legend' },
    ...allCategories.map(cat =>
      h('div', { class: 'legend-item' },
        h('div', { class: 'legend-swatch', style: { backgroundColor: categoryColors[cat] } }),
        h('span', null, categoryLabels[cat]),
      )
    ),
  );

const renderClientScript = () =>
  h('script', null, `
    (function() {
      const elements = document.querySelectorAll('.element-cell');
      const detailPanel = document.getElementById('detail-panel');
      const searchBar = document.getElementById('search-bar');
      const categoryBtns = document.querySelectorAll('.category-btn');
      let activeCategories = new Set();

      const elementsData = {};
      document.querySelectorAll('[data-element-json]').forEach(function(el) {
        try {
          const data = JSON.parse(el.getAttribute('data-element-json'));
          elementsData[data.z] = data;
        } catch(e) {}
      });

      elements.forEach(function(cell) {
        cell.addEventListener('click', function() {
          const z = parseInt(cell.getAttribute('data-z'));
          const data = elementsData[z];
          if (!data) return;

          elements.forEach(function(c) { c.classList.remove('selected'); });
          cell.classList.add('selected');

          detailPanel.className = 'detail-panel visible';
          detailPanel.innerHTML = '<button class="detail-close" id="close-btn">Close</button>'
            + '<div class="detail-header">'
            + '<span class="detail-symbol" style="color:' + (cell.style.backgroundColor || '#ccc') + '">' + data.symbol + '</span>'
            + '<span class="detail-name">' + data.name + '</span>'
            + '<span class="detail-number">#' + data.z + '</span>'
            + '</div>'
            + '<div class="detail-grid">'
            + '<div class="detail-item"><div class="detail-label">Atomic Mass</div><div class="detail-value">' + data.mass + ' u</div></div>'
            + '<div class="detail-item"><div class="detail-label">Category</div><div class="detail-value">' + data.categoryLabel + '</div></div>'
            + '<div class="detail-item"><div class="detail-label">Electron Configuration</div><div class="detail-value">' + data.electronConfig + '</div></div>'
            + '<div class="detail-item"><div class="detail-label">Oxidation States</div><div class="detail-value">' + (data.oxidationStates.length > 0 ? data.oxidationStates.map(function(s){ return s > 0 ? '+'+s : ''+s; }).join(', ') : 'None observed') + '</div></div>'
            + '<div class="detail-item"><div class="detail-label">Melting Point</div><div class="detail-value">' + (data.meltingPoint !== null ? data.meltingPoint + ' \\u00B0C' : 'Unknown') + '</div></div>'
            + '<div class="detail-item"><div class="detail-label">Boiling Point</div><div class="detail-value">' + (data.boilingPoint !== null ? data.boilingPoint + ' \\u00B0C' : 'Unknown') + '</div></div>'
            + '<div class="detail-item"><div class="detail-label">Discovery Year</div><div class="detail-value">' + (data.discoveryYear ? data.discoveryYear : 'Known since antiquity') + '</div></div>'
            + '</div>'
            + '<div class="detail-desc">' + data.description + '</div>';

          document.getElementById('close-btn').addEventListener('click', function() {
            detailPanel.className = 'detail-panel';
            elements.forEach(function(c) { c.classList.remove('selected'); });
          });

          detailPanel.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
        });
      });

      if (searchBar) {
        searchBar.addEventListener('input', function() {
          var q = searchBar.value.toLowerCase();
          elements.forEach(function(cell) {
            var z = cell.getAttribute('data-z');
            var data = elementsData[parseInt(z)];
            if (!data) return;
            var match = !q || data.name.toLowerCase().indexOf(q) !== -1
              || data.symbol.toLowerCase().indexOf(q) !== -1
              || String(data.z).indexOf(q) !== -1;
            var catMatch = activeCategories.size === 0 || activeCategories.has(data.category);
            cell.classList.toggle('dimmed', !(match && catMatch));
          });
        });
      }

      categoryBtns.forEach(function(btn) {
        btn.addEventListener('click', function() {
          var cat = btn.getAttribute('data-category');
          if (activeCategories.has(cat)) {
            activeCategories.delete(cat);
            btn.classList.remove('active');
          } else {
            activeCategories.add(cat);
            btn.classList.add('active');
          }
          var q = searchBar ? searchBar.value.toLowerCase() : '';
          elements.forEach(function(cell) {
            var z = cell.getAttribute('data-z');
            var data = elementsData[parseInt(z)];
            if (!data) return;
            var match = !q || data.name.toLowerCase().indexOf(q) !== -1
              || data.symbol.toLowerCase().indexOf(q) !== -1
              || String(data.z).indexOf(q) !== -1;
            var catMatch = activeCategories.size === 0 || activeCategories.has(data.category);
            cell.classList.toggle('dimmed', !(match && catMatch));
          });
        });
      });
    })();
  `);

export const renderPeriodicTable = (allElements: Element[], options: RenderOptions = {}) => {
  const { selectedElement, query = '', categories = [] } = options;
  const selectedEl = selectedElement ? allElements.find(el => el.z === selectedElement) : undefined;

  const hasActiveFilter = query.length > 0 || categories.length > 0;

  return h(Fragment, null,
    h('html', { lang: 'en' },
      h('head', null,
        h('meta', { charset: 'UTF-8' }),
        h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1.0' }),
        h('title', null, 'Periodic Table Explorer'),
        h('style', null, tableStyles),
      ),
      h('body', null,
        h('div', { class: 'periodic-table-container' },
          h('h1', null, 'Periodic Table of Elements'),
          h('div', { class: 'controls' },
            h('input', {
              type: 'text',
              class: 'search-bar',
              id: 'search-bar',
              placeholder: 'Search by name, symbol, or atomic number...',
              value: query,
            }),
          ),
          renderCategoryFilters(categories),
          h('div', { class: 'table-grid' },
            ...allElements.map(el => {
              const isDimmed = hasActiveFilter && !isElementVisible(el, query, categories);
              const isSelected = el.z === selectedElement;
              return renderElementCell(el, isSelected, isDimmed);
            }),
            // Placeholder cells for lanthanide/actinide indicators
            renderPlaceholderCell(6, 3, '57-71', categoryColors['lanthanide']),
            renderPlaceholderCell(7, 3, '89-103', categoryColors['actinide']),
            // Gap row
            h('div', { class: 'separator-row', style: { gridRow: '8' } }),
            // Series labels
            renderSeriesLabel(9, 'Lanthanides'),
            renderSeriesLabel(10, 'Actinides'),
          ),
          renderLegend(),
          renderDetailPanel(selectedEl),
          // Hidden data elements for client-side JavaScript
          ...allElements.map(el =>
            h('div', {
              style: { display: 'none' },
              'data-element-json': JSON.stringify({
                z: el.z,
                symbol: el.symbol,
                name: el.name,
                mass: el.mass,
                category: el.category,
                categoryLabel: categoryLabels[el.category],
                electronConfig: el.electronConfig,
                oxidationStates: el.oxidationStates,
                meltingPoint: el.meltingPoint,
                boilingPoint: el.boilingPoint,
                discoveryYear: el.discoveryYear,
                description: el.description,
              }),
            })
          ),
          renderClientScript(),
        ),
      ),
    ),
  );
};

import { createSSR } from 'plaited';
import { elements } from './data';
import { renderPeriodicTable } from './render';
import type { RenderOptions, Element, Category } from './types';

export type { Element, Category, RenderOptions };

export { elements };

export const render = (options: RenderOptions = {}): string => {
  const template = renderPeriodicTable(elements, options);
  const { html } = createSSR(template);
  return `<!DOCTYPE html>${html}`;
};

export const getElementById = (z: number): Element | undefined =>
  elements.find(el => el.z === z);

export const getElementsByCategory = (category: Category): Element[] =>
  elements.filter(el => el.category === category);

export const searchElements = (query: string): Element[] => {
  const q = query.toLowerCase();
  return elements.filter(el =>
    el.name.toLowerCase().includes(q) ||
    el.symbol.toLowerCase().includes(q) ||
    String(el.z).includes(q)
  );
};

export const serve = async (port = 3000) => {
  const server = Bun.serve({
    port,
    fetch: async (req) => {
      const url = new URL(req.url);
      const query = url.searchParams.get('q') ?? '';
      const selectedStr = url.searchParams.get('element');
      const selectedElement = selectedStr ? parseInt(selectedStr, 10) : undefined;
      const catParam = url.searchParams.get('categories');
      const categories = catParam ? catParam.split(',') as Category[] : [];

      const html = render({ query, selectedElement, categories });
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      });
    },
  });

  console.log(`Periodic Table Explorer running at http://localhost:${server.port}`);
  return server;
};

if (import.meta.main) {
  serve();
}

