import { h, Fragment } from 'plaited'
import type { Element, ElementCategory } from './types.ts'
import { CATEGORY_META } from './types.ts'
import { styles } from './styles.ts'
import { renderDetailPanel } from './detail-panel.ts'

const MAIN_TABLE_ROWS = 7
const MAIN_TABLE_COLS = 18

type GridPosition = {
  row: number
  col: number
}

const buildGrid = (elements: Element[]) => {
  const mainGrid: Map<string, Element> = new Map()
  const lanthanideRow: Map<number, Element> = new Map()
  const actinideRow: Map<number, Element> = new Map()

  for (const el of elements) {
    if (el.row === 9) {
      lanthanideRow.set(el.col, el)
    } else if (el.row === 10) {
      actinideRow.set(el.col, el)
    } else {
      mainGrid.set(`${el.row}-${el.col}`, el)
    }
  }

  return { mainGrid, lanthanideRow, actinideRow }
}

const renderElementCell = (
  el: Element,
  dimmed: boolean,
) => {
  return h('div', {
    style: styles.elementCell(el.category, dimmed),
    'p-trigger': `click:selectElement:${el.atomicNumber}`,
    title: `${el.name} (${el.symbol})`,
    'data-atomic': String(el.atomicNumber),
  },
    h('span', { style: styles.atomicNumber }, String(el.atomicNumber)),
    h('span', { style: styles.symbol }, el.symbol),
    h('span', { style: styles.elementName }, el.name),
    h('span', { style: styles.atomicMass }, el.atomicMass),
  )
}

const renderEmptyCell = () => {
  return h('div', { style: styles.emptyCell }, '')
}

const renderLegend = () => {
  const categories = Object.keys(CATEGORY_META) as ElementCategory[]

  return h('div', { style: styles.legend },
    ...categories.map((cat) =>
      h('div', { style: styles.legendItem(cat) },
        h('span', { style: styles.legendSwatch(cat) }),
        CATEGORY_META[cat].label,
      ),
    ),
  )
}

export const renderPeriodicTable = (
  elements: Element[],
  searchQuery: string,
  categoryFilter: ElementCategory | 'all',
  selectedElement: Element | null,
) => {
  const { mainGrid, lanthanideRow, actinideRow } = buildGrid(elements)
  const query = searchQuery.toLowerCase().trim()

  const matchesFilter = (el: Element): boolean => {
    const matchesCategory = categoryFilter === 'all' || el.category === categoryFilter
    const matchesSearch = query === '' ||
      el.name.toLowerCase().includes(query) ||
      el.symbol.toLowerCase().includes(query) ||
      String(el.atomicNumber).includes(query)
    return matchesCategory && matchesSearch
  }

  const hasActiveFilter = query !== '' || categoryFilter !== 'all'

  const categoryOptions = Object.entries(CATEGORY_META).map(([key, meta]) =>
    h('option', { value: key }, meta.label),
  )

  const mainCells = []
  for (let row = 1; row <= MAIN_TABLE_ROWS; row++) {
    for (let col = 1; col <= MAIN_TABLE_COLS; col++) {
      const el = mainGrid.get(`${row}-${col}`)
      if (el) {
        const dimmed = hasActiveFilter && !matchesFilter(el)
        mainCells.push(renderElementCell(el, dimmed))
      } else if (row === 6 && col === 3) {
        mainCells.push(
          h('div', {
            style: {
              ...styles.elementCell('lanthanide', false),
              fontSize: '10px',
              cursor: 'default',
              minHeight: '72px',
              opacity: '0.7',
            },
          },
            h('span', { style: { fontSize: '9px' } }, '57-71'),
            h('span', { style: { fontSize: '11px', fontWeight: '600' } }, 'La-Lu'),
            h('span', { style: { fontSize: '8px' } }, 'Lanthanides'),
          ),
        )
      } else if (row === 7 && col === 3) {
        mainCells.push(
          h('div', {
            style: {
              ...styles.elementCell('actinide', false),
              fontSize: '10px',
              cursor: 'default',
              minHeight: '72px',
              opacity: '0.7',
            },
          },
            h('span', { style: { fontSize: '9px' } }, '89-103'),
            h('span', { style: { fontSize: '11px', fontWeight: '600' } }, 'Ac-Lr'),
            h('span', { style: { fontSize: '8px' } }, 'Actinides'),
          ),
        )
      } else {
        mainCells.push(renderEmptyCell())
      }
    }
  }

  const lanthanideCells = []
  for (let col = 1; col <= MAIN_TABLE_COLS; col++) {
    if (col < 3 || col > 17) {
      lanthanideCells.push(renderEmptyCell())
    } else {
      const el = lanthanideRow.get(col)
      if (el) {
        const dimmed = hasActiveFilter && !matchesFilter(el)
        lanthanideCells.push(renderElementCell(el, dimmed))
      } else {
        lanthanideCells.push(renderEmptyCell())
      }
    }
  }

  const actinideCells = []
  for (let col = 1; col <= MAIN_TABLE_COLS; col++) {
    if (col < 3 || col > 17) {
      actinideCells.push(renderEmptyCell())
    } else {
      const el = actinideRow.get(col)
      if (el) {
        const dimmed = hasActiveFilter && !matchesFilter(el)
        actinideCells.push(renderElementCell(el, dimmed))
      } else {
        actinideCells.push(renderEmptyCell())
      }
    }
  }

  return h('div', { style: styles.container },
    h('div', { style: styles.header },
      h('h1', { style: styles.title }, 'Periodic Table of Elements'),
    ),
    h('div', { style: styles.controls },
      h('input', {
        type: 'text',
        placeholder: 'Search by name, symbol, or number...',
        value: searchQuery,
        style: styles.searchInput,
        'p-trigger': 'input:search',
        'p-target': 'searchInput',
      }),
      h('select', {
        style: styles.filterSelect,
        'p-trigger': 'change:filterCategory',
        'p-target': 'categoryFilter',
      },
        h('option', { value: 'all' }, 'All Categories'),
        ...categoryOptions,
      ),
    ),
    renderLegend(),
    h('div', { style: styles.tableWrapper },
      h('div', { style: styles.table }, ...mainCells),
      h('div', { style: styles.lanthanideActinideSection },
        ...lanthanideCells,
        ...actinideCells,
      ),
    ),
    selectedElement ? renderDetailPanel(selectedElement) : h(Fragment, null),
  )
}

import { createSSR } from 'plaited'
import type { Element, ElementCategory } from './types.ts'
import { loadElements } from './data.ts'
import { renderPeriodicTable } from './periodic-table.ts'

type AppState = {
  elements: Element[]
  searchQuery: string
  categoryFilter: ElementCategory | 'all'
  selectedElement: Element | null
}

const createApp = async () => {
  const elements = await loadElements()

  const state: AppState = {
    elements,
    searchQuery: '',
    categoryFilter: 'all',
    selectedElement: null,
  }

  const render = () => {
    return renderPeriodicTable(
      state.elements,
      state.searchQuery,
      state.categoryFilter,
      state.selectedElement,
    )
  }

  const handleSearch = (query: string) => {
    state.searchQuery = query
  }

  const handleFilterCategory = (category: string) => {
    state.categoryFilter = category as ElementCategory | 'all'
  }

  const handleSelectElement = (atomicNumber: number) => {
    state.selectedElement = state.elements.find(
      (el) => el.atomicNumber === atomicNumber,
    ) ?? null
  }

  const handleCloseDetail = () => {
    state.selectedElement = null
  }

  return {
    state,
    render,
    handlers: {
      search: handleSearch,
      filterCategory: handleFilterCategory,
      selectElement: handleSelectElement,
      closeDetail: handleCloseDetail,
    },
  }
}

export const servePeriodicTable = async (
  searchQuery = '',
  categoryFilter: ElementCategory | 'all' = 'all',
  selectedAtomicNumber: number | null = null,
) => {
  const elements = await loadElements()

  const selectedElement = selectedAtomicNumber
    ? elements.find((el) => el.atomicNumber === selectedAtomicNumber) ?? null
    : null

  const template = renderPeriodicTable(
    elements,
    searchQuery,
    categoryFilter,
    selectedElement,
  )

  const ssr = createSSR()
  return ssr(template)
}

