const styleToString = (style: Record<string, string | number>): string =>
  Object.entries(style)
    .map(([key, value]) => {
      const cssKey = key.replace(/([A-Z])/g, '-$1').toLowerCase()
      return `${cssKey}: ${value}`
    })
    .join('; ')

const renderElementCell = (el: Element, isVisible: boolean, isSelected: boolean): string => {
  const categoryInfo = CATEGORIES[el.category]
  const cellStyle = {
    ...styles.cell,
    backgroundColor: categoryInfo.color,
    color: categoryInfo.textColor,
    ...(isSelected ? { transform: 'scale(1.1)', boxShadow: '0 0 12px rgba(255,255,255,0.5)', zIndex: '10' } : {}),
    ...(!isVisible ? styles.cellHidden : {}),
    gridColumn: `${el.col}`,
    gridRow: `${el.row}`,
  }

  return h('div', {
    style: styleToString(cellStyle),
    'p-trigger': `click:select-element`,
    'data-number': `${el.number}`,
  },
    h('span', { style: styleToString(styles.cellNumber) }, `${el.number}`),
    h('span', { style: styleToString(styles.cellSymbol) }, el.symbol),
    h('span', { style: styleToString(styles.cellName) }, el.name),
    h('span', { style: styleToString(styles.cellMass) }, el.mass),
