export const renderPeriodicTable = (state: AppState): string => {
  const query = state.searchQuery.toLowerCase().trim()
  const selectedElement = state.selectedElement !== null
    ? elements.find(el => el.number === state.selectedElement) ?? null
    : null

  const isElementVisible = (el: Element): boolean => {
    const matchesCategory = state.categoryFilter === 'all' || el.category === state.categoryFilter
    const matchesSearch = query === '' ||
      el.name.toLowerCase().includes(query) ||
      el.symbol.toLowerCase().includes(query) ||
      `${el.number}` === query
    return matchesCategory && matchesSearch
  }

  const categoryOptions = [
    h('option', { value: 'all' }, 'All Categories'),
    ...Object.entries(CATEGORIES).map(([key, info]) =>
      h('option', {
        value: key,
        ...(state.categoryFilter === key ? { selected: '' } : {}),
      }, info.label)
    ),
  ]

  return h('div', { style: styleToString(styles.page) },
    h('div', { style: styleToString(styles.header) },
      h('h1', { style: styleToString(styles.title) }, 'Periodic Table of Elements'),
      h('div', { style: styleToString(styles.controls) },
        h('input', {
          type: 'text',
          placeholder: 'Search by name, symbol, or number...',
          value: state.searchQuery,
          style: styleToString(styles.searchInput),
          'p-trigger': 'input:search',
          'p-target': 'search-input',
        }),
        h('select', {
          style: styleToString(styles.select),
          'p-trigger': 'change:filter-category',
          'p-target': 'category-select',
        }, ...categoryOptions),
      ),
    ),
    h('div', { style: styleToString(styles.tableContainer) },
      h('div', { style: styleToString(styles.table) },
        // Lanthanide/Actinide row labels
        h('div', { style: styleToString(styles.lanthanideLabel) }, '57-71'),
        h('div', { style: styleToString(styles.actinideLabel) }, '89-103'),
        // Placeholder cells in main table for lanthanides/actinides
        h('div', {
          style: styleToString({
            ...styles.cell,
            gridColumn: '3',
            gridRow: '6',
            backgroundColor: '#f2b5d4',
            color: '#000',
            fontSize: '9px',
          }),
        },
          h('span', { style: styleToString({ fontSize: '10px', fontWeight: '700' }) }, 'La-Lu'),
          h('span', { style: styleToString({ fontSize: '8px' }) }, '57-71'),
        ),
        h('div', {
          style: styleToString({
            ...styles.cell,
            gridColumn: '3',
            gridRow: '7',
            backgroundColor: '#d4a0c0',
            color: '#000',
            fontSize: '9px',
          }),
        },
          h('span', { style: styleToString({ fontSize: '10px', fontWeight: '700' }) }, 'Ac-Lr'),
          h('span', { style: styleToString({ fontSize: '8px' }) }, '89-103'),
        ),
        // Gap indicator (row 8)
        h('div', {
          style: styleToString({
            gridColumn: '3 / 18',
            gridRow: '8',
            height: '8px',
          }),
        }),
        // All element cells
        ...elements.map(el =>
          renderElementCell(el, isElementVisible(el), state.selectedElement === el.number)
        ),
      ),
    ),
    renderLegend(),
    selectedElement ? renderDetailPanel(selectedElement) : '',
  )
}

import type { AppState, ElementCategory } from './types'
import { elements } from './elements'
import { renderPeriodicTable } from './render'

const STATE_PATH = './data/state.json'

const loadState = async (): Promise<AppState> => {
  const file = Bun.file(STATE_PATH)
  if (await file.exists()) {
    return await file.json() as AppState
  }
  return { selectedElement: null, searchQuery: '', categoryFilter: 'all' }
}

const saveState = async (state: AppState): Promise<void> => {
  await Bun.write(STATE_PATH, JSON.stringify(state, null, 2))
}

const selectElement = async (atomicNumber: number): Promise<string> => {
  const el = elements.find(e => e.number === atomicNumber)
  if (!el) return renderPeriodicTable(await loadState())

  const state = await loadState()
  state.selectedElement = atomicNumber
  await saveState(state)
  return renderPeriodicTable(state)
}

const closeDetail = async (): Promise<string> => {
  const state = await loadState()
  state.selectedElement = null
  await saveState(state)
  return renderPeriodicTable(state)
}

const search = async (query: string): Promise<string> => {
  const state = await loadState()
  state.searchQuery = query
  await saveState(state)
  return renderPeriodicTable(state)
}

const filterByCategory = async (category: string): Promise<string> => {
  const state = await loadState()
  state.categoryFilter = category as ElementCategory | 'all'
  await saveState(state)
  return renderPeriodicTable(state)
}

const getElementByNumber = (atomicNumber: number) =>
  elements.find(e => e.number === atomicNumber) ?? null

const getElementBySymbol = (symbol: string) =>
  elements.find(e => e.symbol.toLowerCase() === symbol.toLowerCase()) ?? null

const getElementsByCategory = (category: ElementCategory) =>
  elements.filter(e => e.category === category)

const searchElements = (query: string) => {
  const q = query.toLowerCase().trim()
  if (!q) return elements
  return elements.filter(el =>
    el.name.toLowerCase().includes(q) ||
    el.symbol.toLowerCase().includes(q) ||
    `${el.number}` === q
  )
}

const render = async (): Promise<string> => {
  const state = await loadState()
  return renderPeriodicTable(state)
}

export {
  render,
  selectElement,
  closeDetail,
  search,
  filterByCategory,
  getElementByNumber,
  getElementBySymbol,
  getElementsByCategory,
  searchElements,
  elements,
}
